import React, { createContext, useContext, useEffect, ReactNode } from 'react';
import { useGameStore } from '../../store/gameStore';

interface ThemeContextType {
  archetype: string | undefined;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a GlobalThemeProvider');
  }
  return context;
};

interface GlobalThemeProviderProps {
  children: ReactNode;
}

export const GlobalThemeProvider: React.FC<GlobalThemeProviderProps> = ({ children }) => {
  const archetype = useGameStore(s => s.gameState?.studio?.archetype);

  useEffect(() => {
    // Sync theme class to document element
    const themes = ['theme-major', 'theme-mid-tier', 'theme-indie'];
    document.documentElement.classList.remove(...themes);

    if (archetype) {
      document.documentElement.classList.add(`theme-${archetype}`);
    }
  }, [archetype]);

  return (
    <ThemeContext.Provider value={{ archetype }}>
      {children}
    </ThemeContext.Provider>
  );
};

import React from 'react';
import { FinancialOverviewWidget } from './FinancialOverviewWidget';
import { DemographicsWidget } from './DemographicsWidget';
import { StudioPulse } from './StudioPulse';
import { StudioHeader } from './StudioHeader';
import { StudioStatsGrid } from './StudioStatsGrid';
import { IntelligenceFeed } from './IntelligenceFeed';
import { useGameStore } from '@/store/gameStore';
import { useShallow } from 'zustand/react/shallow';
import { formatMoney } from '@/engine/utils';
import { NewsEvent } from '@/engine/types';

export const CommandCenter: React.FC = () => {
  const gameState = useGameStore(useShallow((state) => state.gameState));

  if (!gameState || !gameState.studio || !gameState.industry) return null;

  const projects = Object.values(gameState.entities?.projects || {});
  const normalizedTalents = gameState.entities?.talents || {};
  const normalizedRivals = gameState.entities?.rivals || {};
  const newsHistory = gameState?.industry?.newsHistory ?? [];
  const finance = gameState.finance;

  const activeProjectsCount = projects.filter(p => p.state !== 'released' && p.state !== 'post_release' && p.state !== 'archived').length;
  const releasedProjectsCount = projects.filter(p => p.state === 'released' || p.state === 'post_release').length;
  const talentCount = Object.keys(normalizedTalents).length;
  const rivalCount = Object.keys(normalizedRivals).length;

  // Calculate cash trend
  const cashHistory = finance.weeklyHistory?.slice(-8).map(h => h.cash) || [];
  const cashTrend = cashHistory.length > 1 
    ? (cashHistory[cashHistory.length - 1] - cashHistory[0]) / Math.abs(cashHistory[0] || 1) * 100
    : 0;

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-1000 ease-out">
      {/* Studio Executive Header */}
      <StudioHeader gameState={gameState} />

      {/* Studio Pulse Widget */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1">
          <StudioPulse />
        </div>

        <StudioStatsGrid
          finance={finance}
          activeProjectsCount={activeProjectsCount}
          releasedProjectsCount={releasedProjectsCount}
          prestige={gameState.studio.prestige}
          talentCount={talentCount}
          rivalCount={rivalCount}
          cashHistory={cashHistory}
          cashTrend={cashTrend}
        />
      </div>

      {/* Strategic Visualization Row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 lg:gap-8 text-left">
        <div className="lg:col-span-2 relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-primary/20 via-transparent to-transparent rounded-3xl blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none" />
          <FinancialOverviewWidget />
        </div>
        <div className="lg:col-span-1 relative group">
          <div className="absolute -inset-1 bg-gradient-to-l from-secondary/20 via-transparent to-transparent rounded-3xl blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none" />
          <DemographicsWidget />
        </div>
      </div>

      {/* Recent Industry Intelligence */}
      <IntelligenceFeed newsHistory={newsHistory} />
    </div>
  );
};

import React from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { ChartContainer, ChartTooltip, ChartTooltipContent } from '@/components/ui/chart';
import { Bar, BarChart, ResponsiveContainer, XAxis, YAxis, Cell } from 'recharts';
import { useGameStore } from '@/store/gameStore';
import { cn } from '@/lib/utils';

import { useShallow } from 'zustand/react/shallow';

export const DemographicsWidget: React.FC = () => {
  const genrePopularity = useGameStore(useShallow((state) => state.gameState?.studio?.culture?.genrePopularity));
  if (!genrePopularity) return null;

  // Transform engine culture data into chart data
  const chartData = Object.entries(genrePopularity)
    .map(([genre, popularity]) => ({
      genre: genre.charAt(0).toUpperCase() + genre.slice(1),
      popularity: Math.round(popularity * 100),
      fill: `var(--color-${genre})`, // We can map these to CSS variables later
    }))
    .sort((a, b) => b.popularity - a.popularity)
    .slice(0, 5); // Show top 5 genres

  const chartConfig = {
    popularity: {
      label: "Popularity",
      color: "hsl(var(--primary))",
    },
  };

  return (
    <Card aria-label="Demographics Chart" className={cn("col-span-1 animate-in zoom-in-95 lg:col-span-1 relative overflow-hidden group h-full", "bg-gradient-to-br from-card/90 to-card/50 backdrop-blur-2xl border border-white/20 shadow-2xl hover:shadow-[0_0_30px_hsl(var(--primary)/0.15)] transition-all duration-300")}>
      <div className="absolute top-0 right-0 w-96 h-96 bg-primary/10 rounded-full blur-[140px] pointer-events-none group-hover:bg-primary/20 group-hover:scale-110 transition-all duration-1000" />
      <div className="absolute -bottom-20 -left-20 w-64 h-64 bg-secondary/5 rounded-full blur-[100px] pointer-events-none group-hover:bg-secondary/10 transition-colors duration-1000" />
      <div className="absolute inset-0 bg-[url('/noise.png')] opacity-[0.03] mix-blend-overlay pointer-events-none" />

      <CardHeader className={cn("pb-6 relative z-10 p-6", "bg-background/60 backdrop-blur-xl border-b border-white/5")}>
        <CardTitle className="text-sm font-black text-white/90 uppercase tracking-[0.25em] flex items-center justify-between">
          <span className="flex items-center gap-3">
            <div className="relative flex items-center justify-center p-1.5 rounded-lg bg-primary/20 border border-primary/30 shadow-[0_0_15px_hsl(var(--primary)_/_0.3)]">
              <div className="w-2 h-2 rounded-full bg-primary relative z-10 shadow-[0_0_12px_hsl(var(--primary))] animate-pulse" />
            </div>
            <span className="group-hover:text-white transition-colors tracking-widest drop-shadow-md">Audience Trends</span>
          </span>
          <span className="text-[10px] px-3 py-1.5 rounded-md bg-black/60 font-mono tracking-[0.2em] border border-white/10 shadow-[inset_0_1px_4px_rgba(0,0,0,0.5)] text-foreground/90 backdrop-blur-md">DATA</span>
        </CardTitle>
        <CardDescription className="text-xs uppercase tracking-[0.2em] font-bold mt-3 text-muted-foreground/80 group-hover:text-muted-foreground/90 transition-colors duration-500">
          Current hottest genres
        </CardDescription>
      </CardHeader>

      <CardContent className="relative z-10 pt-8 pb-8 px-8">
        <div className="h-[280px] w-full mt-2 relative">
          <div className="absolute inset-0 bg-gradient-to-t from-background/20 to-transparent pointer-events-none z-0" />
          <ChartContainer config={chartConfig} className="h-full w-full relative z-10">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} layout="vertical" margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                <defs>
                  <linearGradient id="barGradient" x1="0" y1="0" x2="1" y2="0">
                    <stop offset="0%" stopColor="hsl(var(--primary))" stopOpacity={0.6} />
                    <stop offset="50%" stopColor="hsl(var(--primary))" stopOpacity={0.8} />
                    <stop offset="100%" stopColor="hsl(var(--primary))" stopOpacity={1} />
                  </linearGradient>
                  <filter id="barShadow" x="-20%" y="-20%" width="140%" height="140%">
                    <feDropShadow dx="0" dy="8" stdDeviation="8" floodColor="rgba(0,0,0,0.6)" />
                  </filter>
                  <filter id="barGlow" x="-20%" y="-20%" width="140%" height="140%">
                    <feGaussianBlur stdDeviation="4" result="blur" />
                    <feComposite in="SourceGraphic" in2="blur" operator="over" />
                  </filter>
                </defs>
                <XAxis type="number" hide domain={[0, 100]} />
                <YAxis 
                  dataKey="genre" 
                  type="category" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: 'hsl(var(--foreground))', fontSize: 13, fontWeight: 800 }}
                  width={120}
                />
                <ChartTooltip
                  cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                  content={<ChartTooltipContent className="bg-black/90 border-white/20 backdrop-blur-3xl text-xs font-mono uppercase shadow-[0_16px_48px_rgba(0,0,0,0.6)] rounded-xl px-5 py-4" />}
                />
                <Bar 
                  dataKey="popularity" 
                  radius={[0, 12, 12, 0]}
                  barSize={28}
                  animationDuration={2000}
                  animationEasing="ease-out"
                  background={{ fill: 'rgba(255,255,255,0.03)', radius: [0, 12, 12, 0] as any }}
                >
                  {chartData.map((entry, index) => (
                    <Cell
                      key={`cell-${index}`}
                      fill="url(#barGradient)"
                      style={{ filter: 'url(#barShadow) url(#barGlow)' }}
                      className="hover:opacity-100 hover:brightness-125 hover:drop-shadow-[0_0_15px_hsl(var(--primary))] transition-all duration-300 cursor-pointer"
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </ChartContainer>
        </div>
      </CardContent>
    </Card>
  );
};

import React, { useMemo } from 'react';
import { useGameStore } from '@/store/gameStore';
import { useUIStore, TabId } from '@/store/uiStore';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import {
  Activity, AlertTriangle,
  Users, Film, DollarSign, Zap, CheckCircle2,
  Clock, AlertCircle
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { ProgressIndicator } from '@/components/shared/ProgressIndicator';
import { SparklineChart } from '@/components/shared/SparklineChart';
import { TooltipWrapper } from '@/components/ui/tooltip-wrapper';

interface PulseAlert {
  id: string;
  type: 'warning' | 'danger' | 'info' | 'success';
  title: string;
  description: string;
  action?: string;
  tab?: string;
}

export const StudioPulse: React.FC = () => {
  const gameState = useGameStore(s => s.gameState);
  const setActiveTab = useUIStore(s => s.setActiveTab);

  const { finance, entities } = gameState || {};
  const projects = useMemo(() => entities ? Object.values(entities.projects) : [], [entities?.projects]);
  const talents = useMemo(() => entities ? Object.values(entities.talents) : [], [entities?.talents]);

  // Calculate health metrics
  const healthMetrics = useMemo(() => {
    if (!gameState || !finance) {
      return {
        runway: 999,
        runwayWeeks: 999,
        activeProjects: 0,
        atRiskProjects: 0,
        cashTrend: 0,
        cashHistory: [],
        talentCount: 0,
        marketSentiment: 50,
      };
    }

    const cash = finance.cash;
    const weeklyBurn = projects
      .filter(p => p.state === 'production' || p.state === 'development')
      .reduce((sum, p) => sum + (p.weeklyCost || 0), 0);
    const runway = weeklyBurn > 0 ? cash / weeklyBurn : 999;

    const activeProjects = projects.filter(p =>
      p.state !== 'released' && p.state !== 'archived'
    ).length;

    const atRiskProjects = projects.filter(p => {
      // Projects in turnaround or with high accumulated cost vs budget are at risk
      const isOverBudget = (p.accumulatedCost || 0) > (p.budget || 0) * 1.2;
      const isTroubled = p.state === 'turnaround' || p.state === 'needs_greenlight';
      return (isOverBudget || isTroubled) && p.state !== 'released' && p.state !== 'archived';
    }).length;

    const cashHistory = finance.weeklyHistory?.slice(-8).map(h => h.cash) || [];
    const cashTrend = cashHistory.length > 1
      ? (cashHistory[cashHistory.length - 1] - cashHistory[0]) / Math.abs(cashHistory[0] || 1)
      : 0;

    return {
      runway,
      runwayWeeks: Math.floor(runway),
      activeProjects,
      atRiskProjects,
      cashTrend,
      cashHistory,
      talentCount: talents.length,
      marketSentiment: finance.marketState?.sentiment || 50,
    };
  }, [gameState, finance, projects, talents]);

  // Generate alerts based on game state
  const alerts: PulseAlert[] = useMemo(() => {
    const list: PulseAlert[] = [];

    if (healthMetrics.runway < 4 && healthMetrics.runway > 0) {
      list.push({
        id: 'cash-critical',
        type: 'danger',
        title: 'Critical Cash Shortage',
        description: `Only ${healthMetrics.runwayWeeks} weeks of runway remaining.`,
        action: 'View Finance',
        tab: 'finance',
      });
    } else if (healthMetrics.runway < 8) {
      list.push({
        id: 'cash-warning',
        type: 'warning',
        title: 'Low Cash Reserves',
        description: `${healthMetrics.runwayWeeks} weeks of runway - consider cost reductions.`,
        action: 'View Finance',
        tab: 'finance',
      });
    }

    if (healthMetrics.atRiskProjects > 0) {
      list.push({
        id: 'projects-at-risk',
        type: 'warning',
        title: 'Projects At Risk',
        description: `${healthMetrics.atRiskProjects} project${healthMetrics.atRiskProjects > 1 ? 's' : ''} require attention.`,
        action: 'View Pipeline',
        tab: 'pipeline',
      });
    }

    if (healthMetrics.marketSentiment < 30) {
      // Only show market alert if we have significant active projects
      list.push({
        id: 'market-poor',
        type: 'info',
        title: 'Bear Market Conditions',
        description: 'Market sentiment is low. Consider delaying major releases.',
        action: 'View Industry',
        tab: 'industry',
      });
    }

    return list;
  }, [healthMetrics]);

  const healthScore = useMemo(() => {
    let score = 100;
    if (healthMetrics.runway < 4) score -= 30;
    else if (healthMetrics.runway < 8) score -= 15;
    if (healthMetrics.atRiskProjects > 0) score -= healthMetrics.atRiskProjects * 5;
    if (healthMetrics.marketSentiment < 30) score -= 10;
    return Math.max(0, Math.min(100, score));
  }, [healthMetrics]);

  if (!gameState) return null;

  const handleAlertAction = (tab?: string) => {
    if (tab) {
      setActiveTab(tab as TabId);
    }
  };

  const healthColor = healthScore >= 80 ? 'success' : healthScore >= 50 ? 'warning' : 'destructive';

  return (
    <Card className={cn("overflow-hidden", "bg-gradient-to-br from-card/80 to-card/40 backdrop-blur-xl border border-white/10 hover:border-white/20 transition-all duration-300")}>
      <CardHeader className="pb-3 border-b border-border/30">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={cn(
              "p-2 rounded-lg transition-colors",
              healthColor === 'success' && "bg-emerald-500/10 text-emerald-500",
              healthColor === 'warning' && "bg-amber-500/10 text-amber-500",
              healthColor === 'destructive' && "bg-red-500/10 text-red-500",
            )}>
              <Activity className="w-5 h-5" />
            </div>
            <div>
              <CardTitle className="text-sm font-black uppercase tracking-wider">Studio Pulse</CardTitle>
              <p className="text-[10px] text-muted-foreground font-medium">
                Operational Health & Active Alerts
              </p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <TooltipWrapper tooltip="Overall studio health score based on cash, projects, and market conditions">
              <div className="flex items-center gap-2">
                <ProgressIndicator
                  value={healthScore}
                  max={100}
                  size="sm"
                  color={healthColor}
                  showValue={false}
                  className="w-24"
                />
                <span className={cn(
                  "text-lg font-black font-display",
                  healthColor === 'success' && "text-emerald-400",
                  healthColor === 'warning' && "text-amber-400",
                  healthColor === 'destructive' && "text-red-400",
                )}>
                  {healthScore}%
                </span>
              </div>
            </TooltipWrapper>
          </div>
        </div>
      </CardHeader>

      <CardContent className="p-4 space-y-4">
        {/* Quick Stats Row */}
        <div className="grid grid-cols-4 gap-3">
          <TooltipWrapper tooltip="Weeks of operation remaining at current burn rate">
            <div className={cn("p-3 rounded-lg bg-background/50 border", "border-white/10 hover:border-white/20 focus:border-primary/50", "space-y-2")}>
              <div className="flex items-center gap-1.5">
                <Clock className="w-3.5 h-3.5 text-muted-foreground" />
                <span className="text-[9px] font-bold uppercase tracking-wider text-muted-foreground">Runway</span>
              </div>
              <div className="flex items-baseline gap-1">
                <span className={cn(
                  "text-xl font-black font-display",
                  healthMetrics.runwayWeeks < 4 ? "text-red-400" : 
                  healthMetrics.runwayWeeks < 8 ? "text-amber-400" : "text-emerald-400"
                )}>
                  {healthMetrics.runwayWeeks}
                </span>
                <span className="text-[10px] text-muted-foreground">wks</span>
              </div>
            </div>
          </TooltipWrapper>

          <TooltipWrapper tooltip="Active projects in development or production">
            <div className={cn("p-3 rounded-lg bg-background/50 border", "border-white/10 hover:border-white/20 focus:border-primary/50", "space-y-2")}>
              <div className="flex items-center gap-1.5">
                <Film className="w-3.5 h-3.5 text-muted-foreground" />
                <span className="text-[9px] font-bold uppercase tracking-wider text-muted-foreground">Active</span>
              </div>
              <div className="flex items-baseline gap-1">
                <span className="text-xl font-black font-display text-primary">{healthMetrics.activeProjects}</span>
                <span className="text-[10px] text-muted-foreground">projects</span>
              </div>
            </div>
          </TooltipWrapper>

          <TooltipWrapper tooltip="Contracted talent on your roster">
            <div className={cn("p-3 rounded-lg bg-background/50 border", "border-white/10 hover:border-white/20 focus:border-primary/50", "space-y-2")}>
              <div className="flex items-center gap-1.5">
                <Users className="w-3.5 h-3.5 text-muted-foreground" />
                <span className="text-[9px] font-bold uppercase tracking-wider text-muted-foreground">Talent</span>
              </div>
              <div className="flex items-baseline gap-1">
                <span className="text-xl font-black font-display text-secondary">{healthMetrics.talentCount}</span>
                <span className="text-[10px] text-muted-foreground">signed</span>
              </div>
            </div>
          </TooltipWrapper>

          <TooltipWrapper tooltip="8-week cash trend">
            <div className={cn("p-3 rounded-lg bg-background/50 border", "border-white/10 hover:border-white/20 focus:border-primary/50", "space-y-1")}>
              <div className="flex items-center gap-1.5">
                <DollarSign className="w-3.5 h-3.5 text-muted-foreground" />
                <span className="text-[9px] font-bold uppercase tracking-wider text-muted-foreground">Trend</span>
              </div>
              <div className="flex items-center justify-between">
                {healthMetrics.cashHistory.length > 1 ? (
                  <SparklineChart
                    data={healthMetrics.cashHistory}
                    width={60}
                    height={24}
                    trend={healthMetrics.cashTrend > 0.05 ? 'up' : healthMetrics.cashTrend < -0.05 ? 'down' : 'neutral'}
                  />
                ) : (
                  <span className="text-[10px] text-muted-foreground">No data</span>
                )}
                {healthMetrics.cashTrend !== 0 && (
                  <span className={cn(
                    "text-[10px] font-bold",
                    healthMetrics.cashTrend > 0 ? "text-emerald-400" : "text-red-400"
                  )}>
                    {healthMetrics.cashTrend > 0 ? '+' : ''}{Math.round(healthMetrics.cashTrend * 100)}%
                  </span>
                )}
              </div>
            </div>
          </TooltipWrapper>
        </div>

        {/* Alerts Section */}
        {alerts.length > 0 ? (
          <div className="space-y-2">
            <div className="flex items-center gap-2">
              <AlertCircle className="w-3.5 h-3.5 text-amber-500" />
              <span className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">
                Active Alerts ({alerts.length})
              </span>
            </div>
            <div className="space-y-2">
              {alerts.map(alert => (
                <div
                  key={alert.id}
                  className={cn(
                    "flex items-center justify-between p-3 rounded-lg border transition-colors",
                    alert.type === 'danger' && "bg-red-500/5 border-red-500/20",
                    alert.type === 'warning' && "bg-amber-500/5 border-amber-500/20",
                    alert.type === 'info' && "bg-blue-500/5 border-blue-500/20",
                    alert.type === 'success' && "bg-emerald-500/5 border-emerald-500/20",
                  )}
                >
                  <div className="flex items-start gap-2.5">
                    {alert.type === 'danger' && <AlertTriangle className="w-4 h-4 text-red-500 shrink-0 mt-0.5" />}
                    {alert.type === 'warning' && <AlertCircle className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" />}
                    {alert.type === 'info' && <Zap className="w-4 h-4 text-blue-500 shrink-0 mt-0.5" />}
                    {alert.type === 'success' && <CheckCircle2 className="w-4 h-4 text-emerald-500 shrink-0 mt-0.5" />}
                    <div>
                      <p className="text-xs font-bold text-foreground">{alert.title}</p>
                      <p className="text-[10px] text-muted-foreground">{alert.description}</p>
                    </div>
                  </div>
                  {alert.action && (
                    <Button
                      variant="ghost"
                      size="sm"
                      className="h-7 text-[10px] font-bold uppercase tracking-wider shrink-0"
                      onClick={() => handleAlertAction(alert.tab)}
                    >
                      {alert.action}
                    </Button>
                  )}
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="flex items-center gap-3 p-3 rounded-lg bg-emerald-500/5 border border-emerald-500/20">
            <CheckCircle2 className="w-5 h-5 text-emerald-500" />
            <div>
              <p className="text-xs font-bold text-emerald-400">All Systems Operational</p>
              <p className="text-[10px] text-muted-foreground">No immediate action required</p>
            </div>
          </div>
        )}

        {/* Quick Actions */}
        <div className="flex gap-2 pt-2 border-t border-border/30">
          <Button
            variant="outline"
            size="sm"
            className="flex-1 h-8 text-[10px] font-bold uppercase tracking-wider"
            onClick={() => setActiveTab('pipeline' as TabId)}
          >
            <Film className="w-3.5 h-3.5 mr-1.5" />
            Pipeline
          </Button>
          <Button
            variant="outline"
            size="sm"
            className="flex-1 h-8 text-[10px] font-bold uppercase tracking-wider"
            onClick={() => setActiveTab('finance' as TabId)}
          >
            <DollarSign className="w-3.5 h-3.5 mr-1.5" />
            Finances
          </Button>
          <Button
            variant="outline"
            size="sm"
            className="flex-1 h-8 text-[10px] font-bold uppercase tracking-wider"
            onClick={() => setActiveTab('talent' as TabId)}
          >
            <Users className="w-3.5 h-3.5 mr-1.5" />
            Talent
          </Button>
        </div>
      </CardContent>
    </Card>
  );
};

import { StatCard } from '@/components/shared/StatCard';
import { Clapperboard, DollarSign, Award, Users } from 'lucide-react';
import { formatMoney } from '@/engine/utils';
import { SparklineChart } from '@/components/shared/SparklineChart';
import { ProgressIndicator } from '@/components/shared/ProgressIndicator';

interface StudioStatsGridProps {
  finance: any;
  activeProjectsCount: number;
  releasedProjectsCount: number;
  prestige: number;
  talentCount: number;
  rivalCount: number;
  cashHistory: number[];
  cashTrend: number;
}

export const StudioStatsGrid = ({
  finance,
  activeProjectsCount,
  releasedProjectsCount,
  prestige,
  talentCount,
  rivalCount,
  cashHistory,
  cashTrend
}: StudioStatsGridProps) => {
  return (
    <div className="lg:col-span-2 grid grid-cols-2 gap-4">
      <StatCard
        title="Cash Reserves"
        value={formatMoney(finance.cash)}
        subtitle="Available liquidity"
        icon={DollarSign}
        color={finance.cash > 100000000 ? 'success' : finance.cash > 50000000 ? 'primary' : 'warning'}
        trend={cashTrend > 5 ? 'up' : cashTrend < -5 ? 'down' : 'neutral'}
        trendValue={cashTrend !== 0 ? `${Math.abs(Math.round(cashTrend))}%` : undefined}
        size="md"
      >
        {cashHistory.length > 1 && (
          <SparklineChart 
            data={cashHistory} 
            width={200} 
            height={30}
            trend={cashTrend > 5 ? 'up' : cashTrend < -5 ? 'down' : 'neutral'}
          />
        )}
      </StatCard>

      <StatCard
        title="Active Pipeline"
        value={activeProjectsCount}
        subtitle={`${releasedProjectsCount} released to date`}
        icon={Clapperboard}
        color="primary"
        trend="up"
        size="md"
      />

      <StatCard
        title="Prestige Rating"
        value={prestige}
        subtitle="Industry reputation"
        icon={Award}
        color="secondary"
        size="md"
      >
        <ProgressIndicator 
          value={prestige} 
          max={100} 
          size="sm" 
          color="secondary"
          showValue={false}
        />
      </StatCard>

      <StatCard
        title="Talent Network"
        value={talentCount}
        subtitle={`vs ${rivalCount} rival studios`}
        icon={Users}
        color="info"
        size="md"
      />
    </div>
  );
};

import { calculateWeeklyCosts, calculateWeeklyRevenue, calculateStudioNetWorth, generateCashflowForecast } from '@/engine/systems/finance';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Area, XAxis, YAxis, Tooltip, ResponsiveContainer, ComposedChart, Line } from 'recharts';
import { YearInReviewChart } from '@/components/finance/YearInReviewChart';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Sheet, SheetContent, SheetDescription, SheetHeader, SheetTitle, SheetTrigger } from '@/components/ui/sheet';
import { Button } from '@/components/ui/button';
import { History, LayoutDashboard, ReceiptText, TrendingUp, Package, Coins } from 'lucide-react';
import { MarketRatesWidget } from '@/components/finance/MarketRatesWidget';
import { SummaryCards } from '@/components/finance/SummaryCards';
import { ActiveProjectCosts } from '@/components/finance/ActiveProjectCosts';
import { EconomicAnalytics } from '@/components/finance/EconomicAnalytics';
import { ProjectROIAnalytics } from '@/components/finance/ProjectROIAnalytics';
import { RecoupmentTracker } from '@/components/finance/RecoupmentTracker';
import { PiracyImpactMonitor } from '@/components/finance/PiracyImpactMonitor';
import { PassiveIncomePanel } from '@/components/finance/PassiveIncomePanel';
import { useMemo } from 'react';
import { useGameStore } from '@/store/gameStore';
import { useShallow } from 'zustand/react/shallow';
import { formatMoney } from '@/engine/utils';
import { selectProjects } from '@/store/selectors';
import { useFinanceHistory } from '@/hooks/useFinanceHistory';

const EMPTY_HISTORY: import('@/engine/types/state.types').FinancialSnapshot[] = [];
const EMPTY_PROJECTS: import('@/engine/types').Project[] = [];

export const FinancePanel = () => {
  // Use atomic selectors to prevent unnecessary re-renders when unrelated gameState parts change
  const cash = useGameStore(s => s.gameState?.finance?.cash ?? 0);
  const prestige = useGameStore(s => s.gameState?.studio?.prestige ?? 75);
  const snapshots = useGameStore(useShallow(s => s.snapshots || []));

  // Use useShallow for arrays/objects extracted from state
  // ⚡ Bolt: Removed inline array allocation using Object.values() to prevent unnecessary re-renders
  const projectsMemo = useGameStore(useShallow(s => s.gameState ? selectProjects(s.gameState) : EMPTY_PROJECTS));

  // Data Shedding: Use TanStack Query for historical data
  const financeHistory = useFinanceHistory() ?? EMPTY_HISTORY;

  // Need entire gameState for complex calculations like Net Worth and Forecasts
  // ⚡ The Framerate Fanatic: Moved complex calculations inside the Zustand selector with useShallow to prevent React from re-rendering unless the final computed numbers actually change.
  const { weeklyCosts, netDelta, studioNetWorth, forecast } = useGameStore(useShallow(s => {
    const state = s.gameState;
    if (!state) return { weeklyCosts: 0, netDelta: 0, studioNetWorth: 0, forecast: [] };
    const costs = calculateWeeklyCosts(state);
    const rev = calculateWeeklyRevenue(state);
    return {
      weeklyCosts: costs,
      netDelta: rev - costs,
      studioNetWorth: calculateStudioNetWorth(state),
      forecast: generateCashflowForecast(state, 12)
    };
  }));

  const activeProjects = useMemo(() =>
    projectsMemo.filter(p => p.state === 'development' || p.state === 'production'),
    [projectsMemo]
  );

  const releasedProjects = useMemo(() => 
    projectsMemo.filter(p => p.state === 'released' || p.state === 'post_release' || p.state === 'archived').sort((a,b) => (b.revenue || 0) - (a.revenue || 0)),
    [projectsMemo]
  );

  const recoupmentData = useMemo(() => releasedProjects.map(p => {
    const revenue = p.revenue || 0;
    const budget = p.budget || 1;
    const recouped = Math.min(100, Math.round((revenue / budget) * 100));
    return {
      projectId: p.id,
      projectTitle: p.title,
      format: (p.format === 'film' ? 'film' : p.format === 'tv' ? 'tv' : 'streaming') as 'film' | 'tv' | 'streaming',
      budget,
      revenue,
      recouped,
      status: revenue >= budget * 2 ? 'profitable' as const : revenue >= budget ? 'recouped' as const : revenue >= budget * 0.7 ? 'in_progress' as const : 'at_risk' as const,
      profitMargin: budget > 0 ? Math.round(((revenue - budget) / budget) * 100) : 0,
    };
  }), [releasedProjects]);

  const piracyData = useMemo(() => releasedProjects.slice(0, 5).map(p => ({
    projectId: p.id,
    projectTitle: p.title,
    format: (p.format === 'film' ? 'film' : 'tv') as 'film' | 'tv',
    totalDownloads: 0,
    estimatedRevenueLoss: 0,
    byRegion: [],
    daysSinceRelease: 0,
  })), [releasedProjects]);

  const passiveStreams = useMemo(() => releasedProjects.slice(0, 5).map(p => ({
    type: 'library' as const,
    source: p.title,
    weeklyRevenue: Math.round((p.revenue || 0) * 0.005),
    totalToDate: Math.round((p.revenue || 0) * 0.05),
    growth: 2,
    trend: 'stable' as const,
  })), [releasedProjects]);

  const passiveTotalWeekly = useMemo(() => passiveStreams.reduce((s, p) => s + p.weeklyRevenue, 0), [passiveStreams]);
  const passiveTotalYTD = useMemo(() => passiveStreams.reduce((s, p) => s + p.totalToDate, 0), [passiveStreams]);

  const latestFinanceSnapshot = useMemo(() =>
    financeHistory.length > 0 ? financeHistory[financeHistory.length - 1] : null,
    [financeHistory]
  );

  const chartData = useMemo(() => {
    if (!financeHistory || financeHistory.length === 0) return [];

    // Convert snapshots to chart format
    const history = financeHistory.map((h: any) => ({
      week: h.week,
      isForecast: false,
      histCash: h.cash,
      histRevenue: h.revenue.theatrical + h.revenue.streaming + h.revenue.merch + h.revenue.passive,
      histCosts: h.expenses.production + h.expenses.marketing + h.expenses.burn + h.expenses.interest + h.expenses.royalties,
      ...h.revenue,
      ...h.expenses
    }));

    const projected = forecast.map(f => ({
      week: f.week,
      isForecast: true,
      projCash: f.projected,
      projRevenue: 0,
      projCosts: 0
    }));

    if (history.length > 0 && projected.length > 0) {
      const last = history[history.length - 1];
      projected.unshift({
        ...last,
        projCash: last.histCash,
        projRevenue: last.histRevenue,
        projCosts: last.histCosts,
        isForecast: true,
      } as any);
    }

    return [...history, ...projected];
  }, [financeHistory, forecast]);

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-12">
      <div className="flex items-center justify-between border-b border-border/40 pb-4 bg-gradient-to-r from-background to-transparent">
        <h2 className="text-3xl font-display font-black tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-foreground to-foreground/70 drop-shadow-sm">
          Financials & Forecasts
        </h2>

        <Sheet>
          <SheetTrigger asChild>
            <Button 
              variant="outline" 
              size="sm" 
              tooltip="Access comprehensive historical financial records and audit logs"
              className="font-display font-black uppercase tracking-widest text-[10px] gap-2 hover:bg-primary/10 hover:text-primary transition-all"
            >
              <ReceiptText className="w-3 h-3" />
              View Full Ledger
            </Button>
          </SheetTrigger>
          <SheetContent className="w-[400px] sm:w-[540px] border-l border-border/40 bg-background/95 backdrop-blur-xl">
            <SheetHeader className="border-b border-border/20 pb-6">
              <SheetTitle className="font-display text-2xl font-black uppercase tracking-tight flex items-center gap-2">
                <Coins className="w-6 h-6 text-primary" />
                Studio Ledger
              </SheetTitle>
              <SheetDescription className="text-xs font-medium tracking-wide">
                Historical record of yearly performance and financial benchmarks.
              </SheetDescription>
            </SheetHeader>
            <div className="mt-8 space-y-4 overflow-y-auto max-h-[calc(100vh-180px)] pr-2 custom-scrollbar">
              {snapshots.slice().reverse().map((s, i) => (
                <Card key={i} className="border-border/40 bg-card/40 backdrop-blur-md shadow-sm group hover:border-primary/30 transition-all duration-300">
                  <CardContent className="p-5">
                    <div className="flex justify-between items-start mb-4">
                      <div className="space-y-1">
                        <p className="text-[10px] text-muted-foreground uppercase font-black tracking-widest">Fiscal Year</p>
                        <p className="text-2xl font-display font-black text-foreground">{s.year}</p>
                      </div>
                      <Badge variant="outline" className="text-[9px] font-black tracking-widest uppercase bg-primary/5 text-primary border-primary/20">
                        Snapshot Taken
                      </Badge>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="bg-background/40 p-3 rounded-lg border border-border/20">
                        <p className="text-[9px] text-muted-foreground uppercase font-black tracking-widest mb-1 flex items-center gap-1">
                          <TrendingUp className="w-2 h-2" /> Total Funds
                        </p>
                        <p className="text-sm font-bold font-mono text-success">{formatMoney(s.funds)}</p>
                      </div>
                      <div className="bg-background/40 p-3 rounded-lg border border-border/20">
                        <p className="text-[9px] text-muted-foreground uppercase font-black tracking-widest mb-1 flex items-center gap-1">
                          <Package className="w-2 h-2" /> Projects
                        </p>
                        <p className="text-sm font-bold font-mono">{s.completedProjects} Completed</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
              {(snapshots.length === 0) && (
                <div className="text-center py-12 opacity-50 px-8">
                   <History className="w-12 h-12 mx-auto mb-4 text-muted-foreground/30" />
                   <p className="text-sm font-bold uppercase tracking-widest mb-2">No Records Yet</p>
                   <p className="text-[10px] font-medium leading-relaxed">The ledger is updated automatically at the end of every fiscal year (Week 52).</p>
                </div>
              )}
            </div>
          </SheetContent>
        </Sheet>
      </div>

      <Tabs defaultValue="current" className="space-y-6">
        <TabsList className="bg-muted/30 backdrop-blur-md border border-border/40 p-1">
          <TabsTrigger value="current" className="gap-2 font-display font-black uppercase tracking-widest text-[10px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground transition-all px-6">
            <LayoutDashboard className="w-3 h-3" />
            Current Operations
          </TabsTrigger>
          <TabsTrigger value="history" className="gap-2 font-display font-black uppercase tracking-widest text-[10px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground transition-all px-6">
            <History className="w-3 h-3" />
            Historical Trends
          </TabsTrigger>
        </TabsList>

        <TabsContent value="current" className="space-y-6 m-0 outline-none">

      {/* Summary Cards */}
      <SummaryCards metrics={[
        { label: 'Available Cash', value: formatMoney(cash), color: cash < 0 ? 'text-destructive drop-shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'text-primary drop-shadow-[0_0_8px_rgba(234,179,8,0.4)]', bg: 'from-card/80 to-card/40', tooltip: 'Total liquid capital available for studio operations and project funding.' },
        { label: 'Total Net Worth', value: formatMoney(studioNetWorth), color: 'text-foreground', bg: 'from-card/80 to-card/40', tooltip: 'Estimated total value of all studio assets, including cash, IP, and talent contracts.' },
        { label: 'Projected Net Delta', value: `${netDelta >= 0 ? '+' : ''}${formatMoney(netDelta)}/wk`, color: netDelta >= 0 ? 'text-success drop-shadow-[0_0_8px_rgba(34,197,94,0.4)]' : 'text-destructive drop-shadow-[0_0_8px_rgba(239,68,68,0.4)]', bg: netDelta >= 0 ? 'from-success/5 to-transparent' : 'from-destructive/5 to-transparent', tooltip: 'Estimated weekly profit or loss based on current revenue streams and production burn.' },
        { label: '12-Wk Forecast Cash', value: formatMoney(forecast.length > 0 ? forecast[forecast.length - 1].projected : 0), color: 'text-purple-400 drop-shadow-[0_0_8px_rgba(192,132,252,0.4)]', bg: 'from-purple-500/5 to-transparent', tooltip: 'Projected cash position in 12 weeks based on current trajectory and known milestones.' },
      ]} />

      <div className="grid grid-cols-3 gap-6 h-[400px]">
        {/* Cash Flow Chart */}
        <div className="col-span-2 flex flex-col h-full">
          <div className="mb-6">
            <MarketRatesWidget />
          </div>

          <Card className="border-border/40 bg-card/60 bg-gradient-to-br from-card/80 to-transparent backdrop-blur-md shadow-sm hover:shadow-[0_8px_30px_rgb(0,0,0,0.12)] transition-all duration-300 flex-1 flex flex-col">
            <CardHeader className="pb-4 border-b border-border/30 bg-background/40 backdrop-blur-sm shrink-0 flex flex-row items-center justify-between">
              <CardTitle className="text-xs font-display font-black uppercase tracking-widest text-foreground/80 drop-shadow-sm">
                Cashflow & Forecast
              </CardTitle>
              <div className="flex items-center gap-3 text-[10px] font-bold tracking-widest uppercase">
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-success"></div> Revenue</div>
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-destructive"></div> Costs</div>
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-primary"></div> Cash History</div>
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-purple-500"></div> Forecast</div>
              </div>
            </CardHeader>
            <CardContent className="pt-6 flex-1 min-h-0">
              <ResponsiveContainer width="100%" height="100%">
                <ComposedChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <defs>
                     <linearGradient id="revGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="hsl(142, 71%, 45%)" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="hsl(142, 71%, 45%)" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="costGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="hsl(0, 84%, 60%)" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="hsl(0, 84%, 60%)" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="week" stroke="hsl(215, 20%, 35%)" fontSize={11} tickLine={false} axisLine={false} tickFormatter={v => `W${v}`} />
                  <YAxis stroke="hsl(215, 20%, 35%)" fontSize={11} tickFormatter={v => formatMoney(v)} tickLine={false} axisLine={false} />
                  <Tooltip
                    contentStyle={{ background: 'rgba(15, 23, 42, 0.8)', border: '1px solid rgba(51, 65, 85, 0.6)', borderRadius: '8px', fontSize: '12px', backdropFilter: 'blur(12px)', boxShadow: '0 4px 20px rgba(0,0,0,0.4)' }}
                    itemStyle={{ fontWeight: 600 }}
                    formatter={(value: number, name: string) => [formatMoney(value), name.replace('hist', '').replace('proj', 'Pred ')]}
                    labelFormatter={l => `Week ${l}`}
                  />

                  {/* Historical Stack */}
                  <Area type="monotone" dataKey="histRevenue" stackId="1" stroke="hsl(142, 71%, 45%)" fill="url(#revGrad)" />
                  <Area type="monotone" dataKey="histCosts" stackId="2" stroke="hsl(0, 84%, 60%)" fill="url(#costGrad)" />

                  {/* Historical Cash Line */}
                  <Line type="monotone" dataKey="histCash" stroke="hsl(48, 96%, 53%)" strokeWidth={3} dot={false} style={{ filter: 'drop-shadow(0 0 4px rgba(234,179,8,0.4))' }} />

                  {/* Forecast Cash Line */}
                  <Line type="monotone" dataKey="projCash" stroke="#a855f7" strokeWidth={3} strokeDasharray="5 5" dot={false} style={{ filter: 'drop-shadow(0 0 4px rgba(168,85,247,0.4))' }} />
                </ComposedChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
        </div>

        {/* Active Project Costs */}
        <div className="col-span-1 flex flex-col h-full">
          <ActiveProjectCosts activeProjects={activeProjects} weeklyCosts={weeklyCosts} />
        </div>
      </div>

      {/* Deep Economic Analytics */}
      <EconomicAnalytics 
        financeHistory={financeHistory} 
        latestFinanceSnapshot={latestFinanceSnapshot} 
        prestige={prestige} 
      />

      {/* Project ROI Analytics */}
      <ProjectROIAnalytics releasedProjects={releasedProjects} />

      {/* Recoupment Tracker */}
      {recoupmentData.length > 0 && (
        <RecoupmentTracker projects={recoupmentData} />
      )}

      {/* Passive Income Streams */}
      {passiveStreams.length > 0 && (
        <PassiveIncomePanel
          streams={passiveStreams}
          totalWeekly={passiveTotalWeekly}
          totalYTD={passiveTotalYTD}
          topPerformingSource={passiveStreams[0]?.source ?? ''}
        />
      )}

      {/* Piracy Impact Monitor */}
      {piracyData.length > 0 && (
        <PiracyImpactMonitor
          projects={piracyData}
          totalLoss={0}
          studioRiskLevel="low"
          activeProtections={['DRM', 'Watermarking']}
        />
      )}

        </TabsContent>

        <TabsContent value="history" className="m-0 outline-none">
          <YearInReviewChart />
        </TabsContent>
      </Tabs>
    </div>
  );
};

import React from 'react';
import { cn, formatCurrency } from '@/lib/utils';
import { Coins, Film, Tv, Music, BookOpen, TrendingUp } from 'lucide-react';
import { Section } from '@/components/layout/Section';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { tokens } from '@/lib/tokens';

interface PassiveIncomeStream {
  type: 'library' | 'syndication' | 'music' | 'publishing' | 'merchandise' | 'streaming_back_catalog';
  source: string;
  weeklyRevenue: number;
  totalToDate: number;
  growth: number; // percentage
  trend: 'up' | 'stable' | 'down';
}

interface PassiveIncomePanelProps {
  streams: PassiveIncomeStream[];
  totalWeekly: number;
  totalYTD: number;
  topPerformingSource: string;
}

export const PassiveIncomePanel: React.FC<PassiveIncomePanelProps> = ({
  streams,
  totalWeekly,
  totalYTD,
  topPerformingSource,
}) => {
  const formatCurrency = (value: number) => {
    if (value >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `$${(value / 1000).toFixed(1)}K`;
    return `$${value}`;
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'library':
      case 'streaming_back_catalog':
        return <Film className="h-4 w-4" />;
      case 'syndication':
        return <Tv className="h-4 w-4" />;
      case 'music':
        return <Music className="h-4 w-4" />;
      case 'publishing':
        return <BookOpen className="h-4 w-4" />;
      default:
        return <Coins className="h-4 w-4" />;
    }
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case 'library': return 'bg-blue-500';
      case 'syndication': return 'bg-purple-500';
      case 'music': return 'bg-pink-500';
      case 'publishing': return 'bg-amber-500';
      case 'merchandise': return 'bg-emerald-500';
      case 'streaming_back_catalog': return 'bg-cyan-500';
      default: return 'bg-slate-500';
    }
  };

  const getTrendIcon = (trend: string) => {
    switch (trend) {
      case 'up': return <TrendingUp className="h-4 w-4 text-emerald-500" />;
      case 'down': return <TrendingUp className="h-4 w-4 text-red-500 rotate-180" />;
      default: return <div className="h-4 w-4 rounded-full bg-slate-400" />;
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Summary Card */}
      <Card className={cn('p-6', tokens.border.default)}>
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="font-bold text-lg">Passive Income Dashboard</h3>
            <p className={cn('text-sm', tokens.text.caption)}>
              {streams.length} active revenue streams
            </p>
          </div>
          <div className="text-right">
            <div className="flex items-center gap-2">
              <Coins className="h-6 w-6 text-emerald-500" />
              <span className="text-3xl font-bold text-emerald-500">
                {formatCurrency(totalWeekly)}
              </span>
            </div>
            <p className={cn('text-xs', tokens.text.caption)}>/week</p>
          </div>
        </div>

        <div className="grid grid-cols-3 gap-4 text-center pt-4 border-t border-border/30">
          <div>
            <p className="text-2xl font-bold text-emerald-500">{formatCurrency(totalYTD)}</p>
            <p className={cn('text-[10px]', tokens.text.caption)}>Year to Date</p>
          </div>
          <div>
            <p className="text-2xl font-bold">{streams.length}</p>
            <p className={cn('text-[10px]', tokens.text.caption)}>Revenue Streams</p>
          </div>
          <div>
            <p className="text-2xl font-bold">{topPerformingSource || 'N/A'}</p>
            <p className={cn('text-[10px]', tokens.text.caption)}>Top Source</p>
          </div>
        </div>
      </Card>

      {/* Income Streams */}
      <Section
        title="Revenue Streams"
        subtitle="Breakdown by income source"
        icon={Coins}
      >
        {streams.length === 0 ? (
          <div className={cn('text-center py-8', tokens.border.default, 'border-dashed rounded-xl')}>
            <Coins className="h-10 w-10 mx-auto mb-3 opacity-20" />
            <p className={cn('text-sm', tokens.text.caption)}>
              No passive income streams yet
            </p>
            <p className={cn('text-xs mt-1', tokens.text.caption)}>
              Build your library to generate ongoing revenue
            </p>
          </div>
        ) : (
          <div className="space-y-3">
            {streams
              .sort((a, b) => b.weeklyRevenue - a.weeklyRevenue)
              .map((stream) => (
              <Card
                key={`${stream.type}-${stream.source}`}
                className={cn('p-4', tokens.border.default)}
