          title="Revenue Mix"
          subtitle="Distribution by category"
          icon={TrendingUp}
        >
          <div className="h-4 bg-muted rounded-full overflow-hidden flex">
            {streams.map((stream, idx) => {
              const percentage = (stream.weeklyRevenue / totalWeekly) * 100;
              return (
                <div
