          </div>
          <div className="flex flex-wrap gap-3 mt-3">
            {streams.map((stream) => (
              <div key={stream.source} className="flex items-center gap-1 text-[10px]">
                <div className={cn('w-2 h-2 rounded-full', getTypeColor(stream.type))} />
                <span>{stream.source}</span>
              </div>
            ))}
          </div>
        </Section>
      )}
    </div>
  );
};

