import { useUIStore } from '@/store/uiStore';
import { useGameStore } from '@/store/gameStore';
import { formatMoney } from '@/engine/utils';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Separator } from '@/components/ui/separator';
import { useState } from 'react';
import { Headline } from '@/engine/types';
import { NewsStoryModal } from './NewsStoryModal';

export const WeekSummaryModal = () => {
  const { activeModal, resolveCurrentModal } = useUIStore();
  const snapshots = useGameStore(s => s.snapshots);
  const [selectedHeadline, setSelectedHeadline] = useState<Headline | null>(null);

  if (!activeModal || activeModal.type !== 'SUMMARY') return null;

  const weekSummary = activeModal.payload as any;
  const { toWeek, cashBefore, cashAfter, totalRevenue, totalCosts, projectUpdates, newHeadlines, events } = weekSummary;
  const netDelta = cashAfter - cashBefore;

  const isYearEnd = (toWeek - 1) % 52 === 0 && toWeek > 1;
  const currentSnapshot = isYearEnd ? snapshots[snapshots.length - 1] : null;
  const previousSnapshot = isYearEnd && snapshots.length > 1 ? snapshots[snapshots.length - 2] : null;

  const displayCashAfter = isYearEnd && currentSnapshot ? currentSnapshot.funds : cashAfter;
  const displayNetDelta = isYearEnd && currentSnapshot ? (currentSnapshot.funds - (previousSnapshot?.funds || 0)) : netDelta;

  let yearlyDelta = 0;
  if (isYearEnd && currentSnapshot) {
    yearlyDelta = previousSnapshot ? currentSnapshot.funds - previousSnapshot.funds : currentSnapshot.funds - (cashAfter - totalRevenue + totalCosts); 
  }

  return (
    <>
      <Dialog open={true} onOpenChange={() => resolveCurrentModal()}>
        <DialogContent 
          className="max-w-md border-border/50 bg-background/95 backdrop-blur-xl shadow-2xl"
          onPointerDownOutside={(e) => e.preventDefault()}
        >
          <DialogHeader>
            <DialogTitle className={`font-display text-2xl font-black tracking-tight bg-clip-text text-transparent ${isYearEnd ? 'bg-gradient-to-r from-amber-400 to-yellow-600' : 'bg-gradient-to-r from-primary to-primary/70'}`}>
              {isYearEnd ? 'Yearly Studio Report' : `Week ${toWeek} Report`}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4">
            {/* Yearly Highlight */}
            {isYearEnd && (
              <div className="p-4 rounded-xl bg-primary/5 border border-primary/20 shadow-inner animate-in zoom-in-95 duration-500 relative overflow-hidden group">
                <div className="absolute inset-0 bg-gradient-to-br from-primary/10 via-transparent to-transparent opacity-50" />
                <div className="relative z-10 flex justify-between items-end">
                  <div>
                    <p className="text-[10px] text-muted-foreground uppercase font-black tracking-widest mb-1">Annual Net Results</p>
                    <p className={`text-2xl font-display font-black tracking-tighter ${yearlyDelta >= 0 ? 'text-success drop-shadow-[0_0_8px_rgba(34,197,94,0.3)]' : 'text-destructive drop-shadow-[0_0_8px_rgba(239,68,68,0.3)]'}`}>
                      {yearlyDelta >= 0 ? '+' : ''}{formatMoney(yearlyDelta)}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] text-muted-foreground uppercase font-black tracking-widest mb-1">Year Completed</p>
                    <p className="text-2xl font-display font-black text-foreground drop-shadow-sm">{Math.floor((toWeek - 2) / 52) + 1}</p>
                  </div>
                </div>
              </div>
            )}
            {/* Financial Summary */}
            <div className="space-y-2">
              <h4 className="text-[10px] font-display uppercase tracking-widest text-primary font-black">💰 Financials</h4>
              <div className="grid grid-cols-3 gap-3">
                <div className="p-2.5 rounded-lg border border-border/40 bg-card/40 backdrop-blur-sm text-center shadow-sm">
                  <p className="text-[10px] text-muted-foreground">Revenue</p>
                  <p className="text-sm font-semibold text-success">+{formatMoney(totalRevenue)}</p>
                </div>
                <div className="p-2.5 rounded-lg border border-border/40 bg-card/40 backdrop-blur-sm text-center shadow-sm">
                  <p className="text-[10px] text-muted-foreground">Costs</p>
                  <p className="text-sm font-semibold text-destructive">-{formatMoney(totalCosts)}</p>
                </div>
                <div className="p-2.5 rounded-lg border border-border/40 bg-card/40 backdrop-blur-sm text-center shadow-sm">
                  <p className="text-[10px] text-muted-foreground">Net</p>
                  <p className={`text-sm font-semibold ${displayNetDelta >= 0 ? 'text-success' : 'text-destructive'}`}>
                    {displayNetDelta >= 0 ? '+' : ''}{formatMoney(displayNetDelta)}
                  </p>
                </div>
              </div>
              <p className="text-xs text-muted-foreground text-center">
                Cash: {formatMoney(cashBefore)} → <span className={displayCashAfter < 0 ? 'text-destructive' : 'text-primary'}>{formatMoney(displayCashAfter)}</span>
              </p>
            </div>

            {/* Project Updates */}
            {projectUpdates.length > 0 && (
              <>
                <Separator />
                <div className="space-y-2">
                  <h4 className="text-[10px] font-display uppercase tracking-widest text-secondary font-black">🎬 Project Updates</h4>
                  {projectUpdates.map((u: string, i: number) => {
                    const hasPositiveTrend = u.includes('(+');
                    const hasNegativeTrend = u.includes('(-');

                    if (hasPositiveTrend) {
                      const parts = u.split('(+');
                      return (
                        <p key={i} className="text-sm text-foreground">
                          • {parts[0]}
                          <span className="text-emerald-400 font-bold">(+{parts[1]}</span>
                        </p>
                      );
                    }

                    if (hasNegativeTrend) {
                      const parts = u.split('(-');
                      return (
                        <p key={i} className="text-sm text-foreground">
                          • {parts[0]}
                          <span className="text-destructive font-bold">(-{parts[1]}</span>
                        </p>
                      );
                    }

                    return <p key={i} className="text-sm text-foreground">• {u}</p>;
                  })}
                </div>
              </>
            )}

            {/* Events - More descriptive */}
            {events.length > 0 && (
              <>
                <Separator />
                <div className="space-y-2">
                  <h4 className="text-[10px] font-display uppercase tracking-widest text-primary font-black">⚡ Events</h4>
                  {events.map((e: string, i: number) => (
                    <div key={i} className="text-sm text-foreground p-2 rounded-lg bg-muted/20 border border-border/30 hover:bg-muted/40 transition-colors">
                      {e}
                    </div>
                  ))}
                </div>
              </>
            )}

            {/* Headlines - Now clickable */}
            {newHeadlines.length > 0 && (
              <>
                <Separator />
                <div className="space-y-2">
                  <h4 className="text-[10px] font-display uppercase tracking-widest text-muted-foreground font-black">📰 The Trades</h4>
                  {newHeadlines.map((h: Headline) => (
                    <button
                      key={h.id}
                      onClick={() => setSelectedHeadline(h)}
                      className="w-full text-left text-xs text-muted-foreground hover:text-primary transition-colors p-2 rounded-lg hover:bg-primary/5 border border-transparent hover:border-primary/20 group flex items-start gap-2"
                    >
                      <span className="text-primary/40 group-hover:text-primary transition-colors">—</span>
                      <span className="group-hover:underline decoration-primary/30">{h.text}</span>
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>

          <DialogFooter>
            <Button onClick={resolveCurrentModal} className="w-full font-display font-bold tracking-wide transition-all hover:shadow-[0_0_15px_rgba(234,179,8,0.4)] hover:-translate-y-0.5">Continue →</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <NewsStoryModal 
        headline={selectedHeadline} 
        open={!!selectedHeadline} 
        onClose={() => setSelectedHeadline(null)} 
      />
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Search,
  Film,
  Users,
  TrendingUp,
  DollarSign,
  Briefcase,
  Globe,
  LayoutDashboard,
  ArrowRight,
  Clock,
  Sparkles,
  AlertTriangle,
  Activity,
  Zap,
  Flame,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { tokens } from '@/lib/tokens';
import { transitions } from '@/lib/animations';
import { useUIStore } from '@/store/uiStore';
import { useGameStore } from '@/store/gameStore';

interface CommandItem {
  id: string;
  title: string;
  subtitle?: string;
  icon: React.ComponentType<{ className?: string; size?: number | string }>;
  shortcut?: string;
  action: () => void;
  section: string;
  keywords?: string[];
}

interface CommandPaletteProps {
  /** Is palette open */
  isOpen: boolean;
  /** Close handler */
  onClose: () => void;
}

/**
 * CommandPalette - Quick navigation and action center
 * 
 * Provides keyboard-driven access to:
 * - Hub navigation (Cmd+1, Cmd+2, etc.)
 * - Recent actions
 * - Project/talent search
 * - Common actions (new project, etc.)
 */
export const CommandPalette: React.FC<CommandPaletteProps> = ({
  isOpen,
  onClose,
}) => {
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const { openCreateProject, setActiveHub, setActiveSubTab } = useUIStore();
  const doAdvanceWeek = useGameStore((s) => s.doAdvanceWeek);

  // Build command list
  const commands: CommandItem[] = React.useMemo(() => {
    const list: CommandItem[] = [
      // Navigation
      {
        id: 'nav-hq',
        title: 'Studio HQ',
        subtitle: 'Overview, operations, strategy',
        icon: LayoutDashboard,
        shortcut: '⌘1',
        action: () => setActiveHub('hq'),
        section: 'Navigation',
      },
      {
        id: 'nav-production',
        title: 'Production',
        subtitle: 'Slate, development, distribution',
        icon: Film,
        shortcut: '⌘2',
        action: () => setActiveHub('production'),
        section: 'Navigation',
      },
      {
        id: 'nav-talent',
        title: 'Talent & Deals',
        subtitle: 'Roster, marketplace, agencies',
        icon: Users,
        shortcut: '⌘3',
        action: () => setActiveHub('talent'),
        section: 'Navigation',
      },
      {
        id: 'nav-intelligence',
        title: 'Intelligence',
        subtitle: 'Rivals, awards, market, financials',
        icon: Globe,
        shortcut: '⌘4',
        action: () => setActiveHub('intelligence'),
        section: 'Navigation',
      },
      // Actions
      {
        id: 'action-new-project',
        title: 'New Project',
        subtitle: 'Create a new film or TV project',
        icon: Sparkles,
        shortcut: '⌘N',
        action: () => openCreateProject(),
        section: 'Actions',
      },
      {
        id: 'action-week',
        title: 'Advance Week',
        subtitle: 'Progress to next production week',
        icon: Clock,
        action: () => { doAdvanceWeek(); },
        section: 'Actions',
      },
      // Crisis Management
      {
        id: 'crisis-dashboard',
        title: 'Crisis Dashboard',
        subtitle: 'View all active crises and issues',
        icon: AlertTriangle,
        shortcut: '⌘⇧C',
        action: () => {
          setActiveHub('hq');
          setActiveSubTab('operations');
        },
        section: 'Crisis Management',
        keywords: ['emergency', 'problems', 'issues', 'alerts'],
      },
      {
        id: 'greenlight-queue',
        title: 'Greenlight Queue',
        subtitle: 'Review projects awaiting approval',
        icon: Zap,
        action: () => {
          setActiveHub('production');
          setActiveSubTab('slate');
        },
        section: 'Crisis Management',
        keywords: ['approve', 'projects', 'slate'],
      },
      // Intelligence Views
      {
        id: 'market-trends',
        title: 'Market Trends',
        subtitle: 'View genre trends and market sentiment',
        icon: TrendingUp,
        action: () => {
          setActiveHub('intelligence');
          setActiveSubTab('market');
        },
        section: 'Intelligence',
        keywords: ['genres', 'trends', 'market', 'analysis'],
      },
      {
        id: 'studio-health',
        title: 'Studio Health',
        subtitle: 'Check overall studio performance metrics',
        icon: Activity,
        action: () => {
          setActiveHub('hq');
          setActiveSubTab('overview');
        },
        section: 'Intelligence',
        keywords: ['health', 'metrics', 'performance', 'dashboard'],
      },
      // Talent Views  
      {
        id: 'talent-morale',
        title: 'Talent Morale',
        subtitle: 'Check roster satisfaction levels',
        icon: Users,
        action: () => {
          setActiveHub('talent');
          setActiveSubTab('roster');
        },
        section: 'Talent',
        keywords: ['morale', 'happiness', 'satisfaction', 'roster'],
      },
      {
        id: 'deal-history',
        title: 'Deal History',
        subtitle: 'View negotiation history and offers',
        icon: Briefcase,
        action: () => {
          setActiveHub('talent');
          setActiveSubTab('negotiations');
        },
        section: 'Talent',
        keywords: ['offers', 'negotiations', 'deals', 'history'],
      },
      // Financial Views
      {
        id: 'budget-burn',
        title: 'Budget Burn Rate',
        subtitle: 'Monitor production spending vs planned',
        icon: Flame,
        action: () => {
          setActiveHub('production');
          setActiveSubTab('development');
        },
        section: 'Finance',
        keywords: ['budget', 'spending', 'overrun', 'costs'],
      },
      {
        id: 'cash-flow',
        title: 'Cash Flow',
        subtitle: 'View revenue and expense trends',
        icon: DollarSign,
        action: () => {
          setActiveHub('intelligence');
          setActiveSubTab('financials');
        },
        section: 'Finance',
        keywords: ['cash', 'revenue', 'expenses', 'financials'],
      },
    ];

    return list;
  }, [setActiveHub, setActiveSubTab, openCreateProject]);

  // Filter commands based on query
  const filteredCommands = React.useMemo(() => {
    if (!query) return commands;
    const lowerQuery = query.toLowerCase();
    return commands.filter(
      (cmd) =>
        cmd.title.toLowerCase().includes(lowerQuery) ||
        cmd.subtitle?.toLowerCase().includes(lowerQuery) ||
        cmd.section.toLowerCase().includes(lowerQuery) ||
        cmd.keywords?.some((k) => k.toLowerCase().includes(lowerQuery))
    );
  }, [commands, query]);

  // Group commands by section
  const groupedCommands = React.useMemo(() => {
    const groups: Record<string, CommandItem[]> = {};
    filteredCommands.forEach((cmd) => {
      if (!groups[cmd.section]) groups[cmd.section] = [];
      groups[cmd.section].push(cmd);
    });
    return groups;
  }, [filteredCommands]);

  // Reset selection when query changes
  useEffect(() => {
    setSelectedIndex(0);
  }, [query]);

  // Keyboard navigation
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onClose();
        return;
      }

      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIndex((prev) =>
          Math.min(prev + 1, filteredCommands.length - 1)
        );
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIndex((prev) => Math.max(prev - 1, 0));
      } else if (e.key === 'Enter') {
        e.preventDefault();
        const selected = filteredCommands[selectedIndex];
        if (selected) {
          selected.action();
          onClose();
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose, filteredCommands, selectedIndex]);

  // Focus input on open
  useEffect(() => {
    if (isOpen) {
      setQuery('');
      setSelectedIndex(0);
    }
  }, [isOpen]);

  // Get selected item from flat list
  const flatCommands = Object.values(groupedCommands).flat();

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50"
            onClick={onClose}
          />

          {/* Palette */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: -20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: -20 }}
            transition={{ ...transitions.spring }}
            className="fixed top-[20%] left-1/2 -translate-x-1/2 w-full max-w-2xl z-50"
          >
            <div className="bg-card/95 backdrop-blur-2xl border border-white/10 rounded-xl shadow-2xl overflow-hidden">
              {/* Search header */}
              <div className="flex items-center gap-3 px-4 py-4 border-b border-white/5">
                <Search className="w-5 h-5 text-muted-foreground" />
                <input
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="Search commands, navigate, or run actions..."
                  className="flex-1 bg-transparent border-none outline-none text-sm placeholder:text-muted-foreground"
                  autoFocus
                />
                <kbd className="px-2 py-1 bg-muted rounded text-xs text-muted-foreground">
                  ESC
                </kbd>
              </div>

              {/* Results */}
              <div className="max-h-[400px] overflow-y-auto py-2">
                {flatCommands.length === 0 ? (
                  <div className="px-4 py-8 text-center text-muted-foreground">
                    <p>No commands found</p>
                    <p className="text-xs mt-1">
                      Try a different search term
                    </p>
                  </div>
                ) : (
                  Object.entries(groupedCommands).map(([section, items]) => (
                    <div key={section}>
                      <div className="px-4 py-2 text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                        {section}
                      </div>
                      {items.map((item) => {
                        const flatIdx = flatCommands.indexOf(item);
                        const isSelected = flatIdx === selectedIndex;
                        const Icon = item.icon;

                        return (
                          <button
                            key={item.id}
                            onClick={() => {
                              item.action();
                              onClose();
                            }}
                            onMouseEnter={() => setSelectedIndex(flatIdx)}
                            className={cn(
                              'w-full flex items-center gap-3 px-4 py-3 text-left',
                              'hover:bg-white/5',
                              isSelected && 'bg-white/10',
                              tokens.transition.fast
                            )}
                          >
                            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                              <Icon className="w-4 h-4 text-primary" />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-foreground">
                                {item.title}
                              </p>
                              {item.subtitle && (
                                <p className="text-xs text-muted-foreground truncate">
                                  {item.subtitle}
                                </p>
                              )}
                            </div>
                            {item.shortcut && (
                              <kbd className="px-2 py-1 bg-muted rounded text-xs text-muted-foreground shrink-0">
                                {item.shortcut}
                              </kbd>
                            )}
                          </button>
                        );
                      })}
                    </div>
                  ))
                )}
              </div>

              {/* Footer */}
              <div className="px-4 py-3 bg-muted/30 border-t border-white/5 flex items-center justify-between text-xs text-muted-foreground">
                <div className="flex items-center gap-4">
                  <span className="flex items-center gap-1">
                    <ArrowRight className="w-3 h-3" /> to select
                  </span>
                  <span className="flex items-center gap-1">
                    <kbd className="px-1.5 py-0.5 bg-muted rounded text-[10px]">
                      ↵
                    </kbd>{' '}
                    to run
                  </span>
                </div>
                <span>{flatCommands.length} commands</span>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

/**
 * Hook to manage command palette state
 */
export const useCommandPalette = () => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Cmd+K or Ctrl+K
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsOpen((prev) => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  return {
    isOpen,
    open: () => setIsOpen(true),
    close: () => setIsOpen(false),
    toggle: () => setIsOpen((prev) => !prev),
  };
};

export default CommandPalette;

import React, { useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Download, RefreshCw, X } from 'lucide-react';
import { cn } from '@/lib/utils';

/**
 * Handles two banners:
 * 1. "Install" — shown when the browser fires beforeinstallprompt (Chrome/Edge on Mac)
 * 2. "Update ready" — shown when a new service worker is waiting
 * 
 * NOTE: PWA functionality is disabled for Electron desktop app
 */

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

// Check if running in Electron environment
const isElectron = typeof window !== 'undefined' && 'electronAPI' in window;

// Stub PWA functionality since PWA plugin is removed for Electron
const needRefresh = false;
const updateServiceWorker = () => {};

// Try to load PWA module if available (for web version)
try {
  // @ts-expect-error - Virtual module provided by vite-plugin-pwa (may not exist)
  require('virtual:pwa-register/react');
} catch {
  // PWA module not available (Electron or plugin removed)
  console.log('PWA module not available (expected for Electron)');
}

export function InstallPrompt() {
  const [installEvent, setInstallEvent] = useState<BeforeInstallPromptEvent | null>(null);
  const [dismissed, setDismissed] = useState(false);

  // Load dismissed state from electron-store or localStorage
  useEffect(() => {
    const loadDismissedState = async () => {
      if (isElectron && window.electronAPI) {
        try {
          const dismissed = await window.electronAPI.store.get('pwa-install-dismissed');
          setDismissed(dismissed === '1');
        } catch (e) {
          console.error('Failed to load dismissed state from electron-store:', e);
        }
      } else {
        try {
          setDismissed(localStorage.getItem('pwa-install-dismissed') === '1');
        } catch (e) {
          console.error('Failed to load dismissed state from localStorage:', e);
        }
      }
    };
    loadDismissedState();
  }, []);

  useEffect(() => {
    // Only add beforeinstallprompt listener in web mode
    if (!isElectron) {
      const handler = (e: Event) => {
        e.preventDefault();
        setInstallEvent(e as BeforeInstallPromptEvent);
      };
      window.addEventListener('beforeinstallprompt', handler);
      return () => window.removeEventListener('beforeinstallprompt', handler);
    }
  }, []);

  const handleInstall = async () => {
    if (!installEvent) return;
    await installEvent.prompt();
    const { outcome } = await installEvent.userChoice;
    if (outcome === 'accepted') setInstallEvent(null);
  };

  const handleDismiss = async () => {
    setDismissed(true);
    if (isElectron && window.electronAPI) {
      try {
        await window.electronAPI.store.set('pwa-install-dismissed', '1');
      } catch (e) {
        console.error('Failed to save dismissed state to electron-store:', e);
      }
    } else {
      try {
        localStorage.setItem('pwa-install-dismissed', '1');
      } catch (e) {
        console.error('Failed to save dismissed state to localStorage:', e);
      }
    }
    setInstallEvent(null);
  };

  // PWA features are disabled in Electron
  if (isElectron) {
    return null;
  }

  // Update banner (only in web mode with PWA)
  if (needRefresh && !isElectron) {
    return (
      <div className={cn(
        'fixed bottom-6 left-1/2 -translate-x-1/2 z-[9999]',
        'flex items-center gap-3 px-5 py-3 rounded-xl',
        'bg-indigo-950/95 border border-indigo-500/40 backdrop-blur-md shadow-2xl',
        'text-white'
      )}>
        <RefreshCw className="w-5 h-5 text-indigo-400" />
        <span className="text-sm font-medium">Update available</span>
        <Button
          size="sm"
          variant="outline"
          className="bg-white/10 border-white/20 hover:bg-white/20 text-white"
          onClick={() => updateServiceWorker()}
        >
          Update
        </Button>
        <button
          onClick={handleDismiss}
          className="p-1 hover:bg-white/10 rounded-lg transition-colors"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    );
  }

  // Install banner (only in browsers, not Electron)
  if (!isElectron && installEvent && !dismissed) {
    return (
      <div className={cn(
        'fixed bottom-6 left-1/2 -translate-x-1/2 z-[9999]',
        'flex items-center gap-3 px-5 py-3 rounded-xl',
        'bg-indigo-950/95 border border-indigo-500/40 backdrop-blur-md shadow-2xl',
        'text-white'
      )}>
        <Download className="w-5 h-5 text-indigo-400" />
        <span className="text-sm font-medium">Install Studio Boss</span>
        <Button
          size="sm"
          variant="outline"
          className="bg-white/10 border-white/20 hover:bg-white/20 text-white"
          onClick={handleInstall}
        >
          Install
        </Button>
        <button
          onClick={handleDismiss}
          className="p-1 hover:bg-white/10 rounded-lg transition-colors"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    );
  }

  return null;
}

import React from 'react';
import { cn, formatCurrency } from '@/lib/utils';
import { History, DollarSign, CheckCircle2, XCircle, Clock } from 'lucide-react';
import { Section } from '@/components/layout/Section';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { tokens } from '@/lib/tokens';
import { TalentNameLink } from '@/components/shared/TalentNameLink';

interface OfferAction {
  type: 'made' | 'countered' | 'accepted' | 'rejected' | 'expired';
  date: number; // week number
  amount: number;
  by: 'player' | 'talent' | 'agent';
  note?: string;
}

interface OfferHistory {
  offerId: string;
  talentName: string;
  talentId: string;
  role: string;
  projectTitle?: string;
  initialOffer: number;
  finalAmount?: number;
  status: 'pending' | 'accepted' | 'rejected' | 'expired';
  actions: OfferAction[];
  weeksActive: number;
}

interface OfferHistoryLogProps {
  offers: OfferHistory[];
  onViewOffer?: (offerId: string) => void;
}

export const OfferHistoryLog: React.FC<OfferHistoryLogProps> = ({
  offers,
  onViewOffer,
}) => {
  const pending = offers.filter(o => o.status === 'pending');
  const resolved = offers.filter(o => o.status !== 'pending');

  const formatCurrency = (value: number) => {
    if (value >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `$${(value / 1000).toFixed(1)}K`;
    return `$${value}`;
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'accepted':
        return <Badge className="text-[9px] bg-emerald-500/20 text-emerald-500">Accepted</Badge>;
      case 'rejected':
        return <Badge className="text-[9px] bg-red-500/20 text-red-500">Rejected</Badge>;
      case 'expired':
        return <Badge variant="secondary" className="text-[9px]">Expired</Badge>;
      default:
        return <Badge className="text-[9px] bg-amber-500/20 text-amber-500">Pending</Badge>;
    }
  };

  const getActionIcon = (type: string) => {
    switch (type) {
      case 'made': return <DollarSign className="h-3 w-3" />;
      case 'accepted': return <CheckCircle2 className="h-3 w-3 text-emerald-500" />;
      case 'rejected': return <XCircle className="h-3 w-3 text-red-500" />;
      default: return <Clock className="h-3 w-3" />;
    }
  };

  const renderOfferCard = (offer: OfferHistory) => (
    <Card
      key={offer.offerId}
      className={cn('p-4', tokens.border.default)}
    >
      <div className="flex items-center justify-between mb-3">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <TalentNameLink talentId={offer.talentId} name={offer.talentName} className="font-bold text-sm" />
            {getStatusBadge(offer.status)}
          </div>
          <p className={cn('text-[10px]', tokens.text.caption)}>
            {offer.role}
            {offer.projectTitle && ` • ${offer.projectTitle}`}
          </p>
        </div>
        <div className="text-right">
          <p className="text-lg font-bold">{formatCurrency(offer.initialOffer)}</p>
          {offer.finalAmount && offer.finalAmount !== offer.initialOffer && (
            <p className={cn('text-[10px]', tokens.text.caption)}>
              Final: {formatCurrency(offer.finalAmount)}
            </p>
          )}
        </div>
      </div>

      {/* Offer Timeline */}
      <div className="space-y-2 mb-3">
        {offer.actions.map((action, idx) => (
          <div key={idx} className="flex items-center gap-2 text-[10px]">
            {getActionIcon(action.type)}
            <span className={cn(
              'capitalize',
              action.by === 'player' ? 'text-primary' : 'text-muted-foreground'
            )}>
              {action.by === 'player' ? 'You' : action.by}
            </span>
            <span>{action.type}</span>
            <span className="font-medium">{formatCurrency(action.amount)}</span>
            <span className={tokens.text.caption}>• Week {action.date}</span>
            {action.note && (
              <span className="italic text-muted-foreground">"{action.note}"</span>
            )}
          </div>
        ))}
      </div>

      {offer.status === 'pending' && (
        <button
          className="text-[10px] text-primary hover:underline"
          onClick={() => onViewOffer?.(offer.offerId)}
        >
          View Negotiation →
        </button>
      )}
    </Card>
  );

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Summary */}
      <div className="grid grid-cols-3 gap-4">
        <Card className={cn('p-4', tokens.border.default)}>
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-lg bg-amber-500/10">
              <Clock className="h-5 w-5 text-amber-500" />
            </div>
            <div>
              <p className={cn('text-[10px] uppercase', tokens.text.caption)}>Pending</p>
              <p className="text-2xl font-bold">{pending.length}</p>
            </div>
          </div>
        </Card>

        <Card className={cn('p-4', tokens.border.default)}>
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-lg bg-emerald-500/10">
              <CheckCircle2 className="h-5 w-5 text-emerald-500" />
            </div>
            <div>
              <p className={cn('text-[10px] uppercase', tokens.text.caption)}>Accepted</p>
              <p className="text-2xl font-bold">
                {resolved.filter(o => o.status === 'accepted').length}
              </p>
            </div>
          </div>
        </Card>

        <Card className={cn('p-4', tokens.border.default)}>
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-lg bg-blue-500/10">
              <History className="h-5 w-5 text-blue-500" />
            </div>
            <div>
              <p className={cn('text-[10px] uppercase', tokens.text.caption)}>Total Offers</p>
              <p className="text-2xl font-bold">{offers.length}</p>
            </div>
          </div>
        </Card>
      </div>

      {/* Pending Offers */}
      {pending.length > 0 && (
        <Section
          title="Pending Offers"
          subtitle={`${pending.length} negotiation${pending.length > 1 ? 's' : ''} in progress`}
          icon={Clock}
        >
          <div className="space-y-3">
            {pending.map(renderOfferCard)}
          </div>
        </Section>
      )}

      {/* Offer History */}
      <Section
        title="Offer History"
        subtitle="Past negotiations and outcomes"
        icon={History}
      >
        {resolved.length === 0 ? (
          <div className={cn('text-center py-8', tokens.border.default, 'border-dashed rounded-xl')}>
            <History className="h-10 w-10 mx-auto mb-3 opacity-20" />
            <p className={cn('text-sm', tokens.text.caption)}>
              No offer history yet
            </p>
          </div>
        ) : (
          <div className="space-y-3">
            {resolved.map(renderOfferCard)}
          </div>
        )}
      </Section>
    </div>
  );
};

export default OfferHistoryLog;

