    return (
      <Tooltip>
        <TooltipTrigger asChild>{buttonElement}</TooltipTrigger>
        <TooltipContent 
          side={tooltipSide} 
          align={tooltipAlign}
          className="font-black text-[10px] uppercase tracking-widest bg-card border-white/10 text-foreground animate-in fade-in-0 zoom-in-95"
