import { ArchetypeKey, RivalStudio, GameState } from '../types/studio.types';
import { MarketState } from '../types/state.types';
import { ALL_GENRES, initializeTrends } from '../systems/trends';
import { ARCHETYPES } from '../data/archetypes';
import { RandomGenerator } from '../utils/rng';
import { generateOpportunity } from '../generators/opportunities';
import { Talent } from '@/engine/types';
import {
  generateRivals,
  assignInitialPactsToRivals,
  generatePlayerProjects,
  initializePlayerStudio,
  generateTalentPoolWithRelationships,
  initializeMarket
} from './generators';

export function initializeGame(studioName: string, archetype: ArchetypeKey, seed: number): GameState {
  const rng = new RandomGenerator(seed);
  const playerStudioId = rng.uuid('PLR'); // 🌌 Standardized player ID
  const arch = ARCHETYPES[archetype];
  const rivalArchetypes: ArchetypeKey[] = ['major', 'mid-tier', 'indie'];
  const usedNames = new Set<string>([studioName]);

  // Generate 10 Rivals
  const rivals = generateRivals(rng, { rivalArchetypes, usedNames });

  // Generate talent pool with agencies, agents, families, and relationships
  const {
    talentPool,
    talentPoolArray,
    agencies,
    agents,
    families,
    talentAgentRelationships
  } = generateTalentPoolWithRelationships(rng);

  // Initialize some initial pacts for rivals to make the world feel alive
  assignInitialPactsToRivals(rivals, talentPoolArray, rng);

  // Generate Player Projects based on Archetype
  const playerProjects = generatePlayerProjects(rng, playerStudioId, archetype);

  const initialTrends = initializeTrends(rng);
  const genrePopularity: Record<string, number> = {};
  ALL_GENRES.forEach(g => {
    const trend = initialTrends.find(t => t.genre === g);
    genrePopularity[g.toLowerCase()] = trend ? trend.heat / 100 : rng.range(0.2, 0.5);
  });

  // Initialize market (buyers, platforms)
  const { initialBuyers, playerOwnedPlatforms } = initializeMarket(
    rng,
    rivals,
    playerStudioId,
    archetype,
    studioName
  );

  return {
    week: 1,
    gameSeed: seed,
    tickCount: 0,
    rngState: rng.getState(),
    game: { currentWeek: 1 },
    finance: {
      cash: arch.startingCash,
      ledger: [],
      weeklyHistory: [],
      marketState: {
        baseRate: 0.045,
        savingsYield: 0.025,
        debtRate: 0.095,
        loanRate: 0.07,
        rateHistory: [{ week: 1, rate: 0.045 }],
        sentiment: 50,
        cycle: 'STABLE'
      } as MarketState
    },
    news: {
      headlines: [
        {
          id: rng.uuid('NWS'),
          text: `${studioName} launches operations — the industry takes notice.`,
          week: 1,
          category: 'general' as const,
        },
      ],
    },
    ip: {
      vault: [],
      franchises: {},
    },
    studio: {
      ...initializePlayerStudio(studioName, archetype, playerStudioId, arch),
      ownedPlatforms: playerOwnedPlatforms,
      culture: {
        ...initializePlayerStudio(studioName, archetype, playerStudioId, arch).culture,
        genrePopularity
      }
    },
    market: {
      opportunities: Array.from({ length: 4 }, () => generateOpportunity(rng, 1, Object.keys(talentPool))),
      buyers: initialBuyers,
    },
    industry: {
      families,
      agencies,
      agents,
      awards: [],
      newsHistory: [],
    },
    entities: {
      projects: {
        ...playerProjects,
        ...Object.values(rivals).reduce((acc, r) => {
          // Backward compatibility for projects field
          const rivalProjects = ('projects' in r && r.projects) ? (r as any).projects : {};
          Object.assign(acc, rivalProjects);
          return acc;
        }, {} as Record<string, any>)
      },
      contracts: {},
      talents: talentPool,
      rivals: rivals.reduce((acc, r) => {
        acc[r.id] = r;
        return acc;
      }, {} as Record<string, RivalStudio>),
    },
    deals: {
      activeDeals: [],
      pendingOffers: [],
      expiredDeals: [],
    },
    relationships: {
      relationships: {}
    },
    talentAgentRelationships,
    history: [],
    eventHistory: [],
  };
}

import { ArchetypeKey, RivalStudio } from '../../types/studio.types';
import { BrandSystem } from '../../generators/BrandSystem';
import { generateBuyers } from '../../generators/buyers';
import { RandomGenerator } from '../../utils/rng';
import { StreamerPlatform } from '@/engine/types';

interface MarketInitializerOptions {
  networks?: number;
  premium?: number;
  streamers?: number;
}

export function initializeMarket(
  rng: RandomGenerator,
  rivals: RivalStudio[],
  playerStudioId: string,
  playerArchetype: ArchetypeKey,
  studioName: string,
  options: MarketInitializerOptions = {}
): {
  initialBuyers: any[];
  playerOwnedPlatforms: string[];
} {
  const { networks = 4, premium = 4, streamers = 5 } = options;

  const initialBuyers = generateBuyers(rng, { networks, premium, streamers });
  const playerOwnedPlatforms: string[] = [];

  // Vertical Integration: Assign starting platforms to Majors/Mid-tiers
  if (playerArchetype !== 'indie') {
    const playerBrand = { core: studioName.split(' ')[0], isConglomerate: true };
    const playerStreamer: StreamerPlatform = {
      id: rng.uuid('BUY'),
      name: BrandSystem.getStreamingName(playerBrand, rng),
      archetype: 'streamer',
      foundedWeek: 1,
      parentBrand: playerBrand.core,
      ownerId: playerStudioId,
      subscribers: playerArchetype === 'major' ? 25_000_000 : 10_000_000,
      churnRate: 0.05,
      contentLibraryQuality: 60,
      marketingSpend: 2_000_000,
      marketShare: playerArchetype === 'major' ? 0.35 : 0.15,
      reach: playerArchetype === 'major' ? 95 : 70,
      subscriberHistory: [],
      activeLicenses: []
    };
    initialBuyers.push(playerStreamer);
    playerOwnedPlatforms.push(playerStreamer.id);
  }

  // Assign streamers to Rivals
  rivals.forEach(rival => {
    if (rival.archetype !== 'indie' && rng.next() < 0.7) {
      const rivalBrand = { core: rival.parentBrand!, isConglomerate: true };
      const rivalStreamer: StreamerPlatform = {
        id: rng.uuid('BUY'),
        name: BrandSystem.getStreamingName(rivalBrand, rng),
        archetype: 'streamer',
        foundedWeek: 1,
        parentBrand: rivalBrand.core,
        ownerId: rival.id,
        subscribers: rival.archetype === 'major' ? 20_000_000 : 8_000_000,
        churnRate: 0.05,
        contentLibraryQuality: 50,
        marketingSpend: 1_500_000,
        marketShare: rival.archetype === 'major' ? 0.30 : 0.12,
        reach: rival.archetype === 'major' ? 90 : 65,
        subscriberHistory: [],
        activeLicenses: []
      };
      initialBuyers.push(rivalStreamer);
      rival.ownedPlatforms = [rivalStreamer.id];
    }
  });

  return { initialBuyers, playerOwnedPlatforms };
}

