import { ArchetypeKey, RivalStudio } from '../../types/studio.types';
import { ARCHETYPES } from '../../data/archetypes';
import { BrandSystem } from '../../generators/BrandSystem';
import { generateMotto, generateProjectName } from '../../generators/names';
import { RandomGenerator } from '../../utils/rng';
import { ALL_GENRES } from '../../systems/trends';
import { StudioMotivation, TalentPact, Contract } from '@/engine/types';

interface RivalGeneratorOptions {
  count?: number;
  rivalArchetypes?: ArchetypeKey[];
  usedNames?: Set<string>;
}

export function generateRivals(
  rng: RandomGenerator,
  options: RivalGeneratorOptions = {}
): RivalStudio[] {
  const { count = 10, rivalArchetypes = ['major', 'mid-tier', 'indie'], usedNames = new Set<string>() } = options;

  return Array.from({ length: count }, () => {
    const ident = BrandSystem.generateIdentity(usedNames, rng);
    const name = BrandSystem.getStudioName(ident, rng);
    usedNames.add(name);
    usedNames.add(ident.core);

    const rArch = rng.pick(rivalArchetypes);
    const rArchData = ARCHETYPES[rArch];

    const motivationProfile = {
      financial: rArch === 'major' ? 80 : (rArch === 'mid-tier' ? 60 : 40),
      prestige: rArch === 'indie' ? 90 : (rArch === 'mid-tier' ? 60 : 40),
      legacy: rArch === 'major' ? 70 : 30,
      aggression: rng.rangeInt(40, 80)
    };

    const motivations: StudioMotivation[] = ['CASH_CRUNCH', 'AWARD_CHASE', 'FRANCHISE_BUILDING', 'MARKET_DISRUPTION', 'STABILITY'];

    const rProjects: Record<string, any> = {};
    const projCount = rng.rangeInt(2, 5);
    for (let i = 0; i < projCount; i++) {
      const pId = rng.uuid('PRJ');
      const isProd = rng.next() < 0.5;
      const isTv = rng.next() < 0.3;
      const genre = rng.pick(ALL_GENRES);
      const format = isTv ? 'tv' : 'film';

      rProjects[pId] = {
        id: pId,
        title: generateProjectName(format, genre, rng),
        type: isTv ? 'SERIES' : 'FILM',
        state: isProd ? 'production' : 'development',
        weeksInPhase: rng.rangeInt(1, 10),
        productionWeeks: rng.rangeInt(12, 26),
        developmentWeeks: rng.rangeInt(4, 12),
        budget: rng.rangeInt(10, 150) * 1_000_000,
        buzz: rng.rangeInt(20, 60),
        genre,
        format,
        reviewScore: 50,
        revenue: 0,
        accumulatedCost: 0
      };

      if (isTv) {
        rProjects[pId].tvDetails = {
          currentSeason: 1,
          episodesOrdered: 10,
          episodesCompleted: 0,
          episodesAired: 0,
          averageRating: 0,
          status: 'IN_DEVELOPMENT'
        };
      }
    }

    return {
      id: rng.uuid('RIV'),
      name,
      motto: generateMotto(rng),
      archetype: rArch,
      foundedWeek: 1,
      parentBrand: ident.core,
      strength: rng.rangeInt(40, 80),
      cash: rArchData.startingCash * rng.range(0.5, 1.2),
      prestige: rArchData.startingPrestige + rng.rangeInt(-10, 10),
      recentActivity: 'Setting up operations for the new season',
      projectCount: projCount,
      motivationProfile,
      currentMotivation: rng.pick(motivations),
      projects: rProjects,
      contracts: [],
      ownedPlatforms: [],
      projectIds: Object.keys(rProjects),
      contractIds: [],
      ipAssetIds: [],
      archetypeId: rArchData.id || rArch
    } as any;
  });
}

export function assignInitialPactsToRivals(
  rivals: RivalStudio[],
  talentPoolArray: any[],
  rng: RandomGenerator
): void {
  const availableTopTalents = talentPoolArray.filter(t => t.tier === 1 || t.tier === 2);
  let topTalentIndex = 0;

  rivals.forEach(rival => {
    const pactCount = rival.archetype === 'major' ? 3 : (rival.archetype === 'mid-tier' ? 1 : 0);
    for (let i = 0; i < pactCount; i++) {
      let topTalent = undefined;
      while (topTalentIndex < availableTopTalents.length) {
        const candidate = availableTopTalents[topTalentIndex];
        topTalentIndex++;
        if (!candidate.contractId) {
          topTalent = candidate;
          break;
        }
      }

      if (topTalent) {
        const pact: TalentPact = {
          id: rng.uuid('PCT'),
          talentId: topTalent.id,
          studioId: rival.id,
          type: 'first_look',
          exclusivity: true,
          weeklyOverhead: topTalent.fee * 0.05,
          startDate: 1,
          endDate: 52,
          status: 'active'
        };
        const rivalContracts = ('contracts' in rival && rival.contracts) ? (rival as any).contracts : [];
        rivalContracts.push(pact as unknown as Contract);
        topTalent.contractId = pact.id;
      }
    }
  });
}

import { Talent } from '@/engine/types';
import { generateFamilies, generateTalentPool } from '../../generators/talent';
import { generateAgencies, generateAgents } from '../../generators/agencies';
import { RandomGenerator } from '../../utils/rng';
import { TalentAgentInteractionEngine } from '../../systems/talent/talentAgentInteractions';

interface TalentPoolGeneratorOptions {
  talentCount?: number;
  agencyCount?: number;
  agentsPerAgency?: number;
  familyCount?: number;
}

export function generateTalentPoolWithRelationships(
  rng: RandomGenerator,
  options: TalentPoolGeneratorOptions = {}
): {
  talentPool: Record<string, Talent>;
  talentPoolArray: Talent[];
  agencies: any[];
  agents: any[];
  families: any[];
  talentAgentRelationships: Record<string, any>;
} {
  const {
    talentCount = 500,
    agencyCount = 5,
    agentsPerAgency = 4,
    familyCount = 5
  } = options;

  const agencies = generateAgencies(rng, agencyCount);
  const agents = generateAgents(rng, agencies, agentsPerAgency);
  const families = generateFamilies(rng, familyCount);

  // Pre-index for O(1) lookups
  const agenciesMap = new Map(agencies.map(a => [a.id, a]));
  const agentsMap = new Map(agents.map(a => [a.id, a]));

  const talentPoolArray = generateTalentPool(rng, talentCount);
  const talentPool = talentPoolArray.reduce((acc, t) => {
    acc[t.id] = t;
    return acc;
  }, {} as Record<string, Talent>);

  // Initialize talent-agent relationships
  const talentAgentRelationships: Record<string, any> = {};

  for (const [talentId, talent] of Object.entries(talentPool)) {
    if (talent.agentId) {
      const agent = agentsMap.get(talent.agentId);
      if (agent && talent.personality) {
        const agentPersonality = agent.personality || derivePersonalityFromAgent(agent);
        const agency = agenciesMap.get(agent.agencyId);

        const relationship = TalentAgentInteractionEngine.createRelationship(
          talentId,
          talent.agentId,
          talent.personality,
          agentPersonality,
          agency?.tier
        );
        talentAgentRelationships[`${talentId}-${talent.agentId}`] = relationship;
      }
    }
  }

  return {
    talentPool,
    talentPoolArray,
    agencies,
    agents,
    families,
    talentAgentRelationships
  };
}

function derivePersonalityFromAgent(agent: any): any {
  const tacticMap: Record<string, any> = {
    'SHARK': 'shark',
    'DIPLOMAT': 'diplomat',
    'VOLUME': 'volume',
    'PRESTIGE': 'prestige'
  };
  return tacticMap[agent.negotiationTactic] || 'diplomat';
}

import { GameState, StateImpact, Franchise } from '@/engine/types';

/**
 * Industry-related impact handlers
 * Pure functions that apply industry-related state impacts
 */

export function handleIndustryUpdate(state: GameState, impact: StateImpact): GameState {
  const payload = impact.payload as any;
  let nextState = { ...state };

  // Generic Deep-Path Updates
  if (payload.update && typeof payload.update === 'object' && !Array.isArray(payload.update)) {
    for (const [path, value] of Object.entries(payload.update)) {
      const parts = (path as string).split('.');
      let current: any = nextState;

      for (let i = 0; i < parts.length - 1; i++) {
        const part = parts[i];

        if (part === '__proto__' || part === 'constructor' || part === 'prototype') break;

        if (Array.isArray(current[part])) {
          current[part] = [...current[part]];
        } else if (typeof current[part] === 'object' && current[part] !== null) {
          current[part] = { ...current[part] };
        } else {
          current[part] = {};
        }

        current = current[part];
      }

      const lastPart = parts[parts.length - 1];
      if (lastPart !== '__proto__' && lastPart !== 'constructor' && lastPart !== 'prototype') {
        current[lastPart] = value;
      }
    }
  }

  // Merger Logic
  const { mergedRivalId, acquirerId } = payload;
  if (mergedRivalId) {
    const target = state.entities.rivals[mergedRivalId];
    if (target) {
      if (acquirerId === 'player') {
        const mergedProjects = { ...nextState.entities.projects };
        const mergedVault = nextState.ip.vault.map(asset => {
          if (asset.ownerStudioId === mergedRivalId) {
            return { ...asset, rightsOwner: 'STUDIO' as const, ownerStudioId: undefined };
          }
          return asset;
        });

        nextState = {
          ...nextState,
          entities: {
            ...nextState.entities,
            projects: mergedProjects
          },
          ip: { ...nextState.ip, vault: mergedVault }
        };
      } else {
        const rivals = { ...nextState.entities.rivals };
        if (rivals[acquirerId]) {
          const acquirer = rivals[acquirerId];
          rivals[acquirerId] = {
            ...acquirer,
            projectIds: [...(acquirer.projectIds || []), ...(target.projectIds || [])],
            ownedPlatforms: [...(acquirer.ownedPlatforms || []), ...(target.ownedPlatforms || [])]
          };
        }

        const mergedVault = nextState.ip.vault.map(asset => {
          if (asset.ownerStudioId === mergedRivalId) {
            return { ...asset, rightsOwner: 'RIVAL' as const, ownerStudioId: acquirerId };
          }
          return asset;
        });

        const mergedProjects = { ...nextState.entities.projects };

        nextState = { 
            ...nextState, 
            entities: {
              ...nextState.entities,
              projects: mergedProjects,
              rivals
            },
            ip: { ...nextState.ip, vault: mergedVault }
        };
      }

      const rivals = { ...nextState.entities.rivals };
      delete rivals[mergedRivalId];
      nextState = {
        ...nextState,
        entities: {
          ...nextState.entities,
          rivals
        }
      };
    }
  }

  if (payload['market.opportunities']) {
    nextState = { ...nextState, market: { ...nextState.market, opportunities: payload['market.opportunities'] } };
  }

  return nextState;
}

export function handleScandalAdded(state: GameState, impact: StateImpact): GameState {
  const { scandal } = impact.payload;
  let newPrestige = state.studio.prestige;

  const prestigeHit = Math.floor((scandal.severity / 5) * 3.0);
  newPrestige = Math.max(0, newPrestige - prestigeHit);

  const projects = { ...state.entities.projects };

  const projectIds: string[] = [];
  const contractsRaw = state.entities.contracts;
  for (const key in contractsRaw) {
    if (Object.prototype.hasOwnProperty.call(contractsRaw, key)) {
      const c = contractsRaw[key];
      if (c.talentId === scandal.talentId) {
        projectIds.push(c.projectId);
      }
    }
  }

  for (const pid of projectIds) {
      const project = projects[pid];
      if (project) {
          const format = project.format;
          const genre = project.genre ? project.genre.toLowerCase() : '';
          if (format === 'unscripted' || genre.includes('horror')) {
                projects[pid] = { ...project, buzz: Math.min(100, (project.buzz || 0) + scandal.severity * 3.0) };
          } else {
                projects[pid] = { ...project, buzz: Math.max(0, (project.buzz || 0) - Math.floor(scandal.severity)) };
          }
      }
  }

  return {
    ...state,
    studio: {
      ...state.studio,
      prestige: newPrestige
    },
    entities: {
      ...state.entities,
      projects
    },
    industry: {
      ...state.industry,
      scandals: [...(state.industry.scandals || []), scandal]
    }
  };
}

export function handleScandalRemoved(state: GameState, impact: StateImpact): GameState {
  const { scandalId } = impact.payload;
  return {
    ...state,
    industry: {
      ...state.industry,
      scandals: (state.industry.scandals || []).filter(s => s.id !== scandalId)
    }
  };
}

export function handleRivalUpdated(state: GameState, impact: StateImpact): GameState {
  const { rivalId, update } = impact.payload;
  if (!state.entities?.rivals) return state;
  const rivals = { ...state.entities.rivals };
  if (rivals[rivalId]) {
    rivals[rivalId] = { ...rivals[rivalId], ...update };
  }
  return {
    ...state,
    entities: {
      ...state.entities,
      rivals
    }
  };
}

export function handleMergerOffered(state: GameState, impact: StateImpact): GameState {
  const merger = impact.payload.merger;
  if (!merger) return state;
  return {
    ...state,
    industry: {
      ...state.industry,
      activeMergers: [...(state.industry.activeMergers || []), merger]
    }
  };
}

export function handleMergerResolved(state: GameState, impact: StateImpact): GameState {
  const { mergerId } = impact.payload;
  return {
    ...state,
    industry: {
      ...state.industry,
      activeMergers: (state.industry.activeMergers || []).filter(m => m.id !== mergerId)
    }
  };
}

