export function handleTalentRemoved(state: GameState, impact: StateImpact): GameState {
  if (!impact.payload) return state;
  const { talentId } = impact.payload;
  if (!talentId || !state.entities?.talents) return state;
  const talents = { ...state.entities.talents };
  delete talents[talentId];
  return {
    ...state,
    entities: {
      ...state.entities,
      talents
    }
  };
}

export function handleCastingConstraintChecked(state: GameState, impact: StateImpact): GameState {
  if (!impact.payload) return state;
  const { talentId, comfortLevel, premiumRates } = impact.payload;
  if (!talentId) return state;

  return {
    ...state,
    entities: {
      ...state.entities,
      talents: {
        ...state.entities.talents,
        [talentId]: {
          ...state.entities.talents?.[talentId],
          comfortLevel,
          comfortPremiumRates: premiumRates,
        },
      },
    },
  };
}

export function handleMedicalLeaveTriggered(state: GameState, impact: StateImpact): GameState {
  const { talentId, weeks } = impact.payload as { talentId: string; weeks: number };
  const talents = { ...state.entities.talents };
  const talent = talents[talentId];
  if (talent) {
    talents[talentId] = {
      ...talent,
      onMedicalLeave: true,
      medicalLeaveEndsWeek: state.week + weeks,
      fatigue: Math.max(0, talent.fatigue - 20),
    };
  }
  return { ...state, entities: { ...state.entities, talents } };
}

import { z } from 'zod';
import { RandomGenerator } from '../../utils/rng';

/**
 * The Bard Engine Archive Schema
 * Structured by Domain -> SubDomain -> Tier
 */

export const NarrativeTierSchema = z.array(z.string());

// A subdomain can contain either flat tiers (string -> string[]) 
// or nested tones/variants (string -> string -> string[])
export const NarrativeSubDomainSchema = z.record(
  z.string(),
  z.union([
    NarrativeTierSchema,
    z.record(z.string(), NarrativeTierSchema),
    z.record(z.string(), z.record(z.string(), NarrativeTierSchema)) // Support Options nesting
  ])
);

export const NarrativeDomainSchema = z.record(z.string(), z.union([NarrativeSubDomainSchema, NarrativeTierSchema]));

export const NarrativeArchiveSchema = z.record(z.string(), NarrativeDomainSchema);

export type NarrativeArchive = z.infer<typeof NarrativeArchiveSchema>;

export interface NarrativeContext {
  actor?: string;
  target?: string;
  project?: string;
  rival?: string;
  amount?: string | number;
  pct?: string | number;
  genre?: string;
  platform?: string;
  week?: number;
  [key: string]: any;
}

/**
 * Metadata Mapper helper types
 */
export type NarrativeDomainKey = 'Review' | 'Greenlight' | 'Talent' | 'Industry' | 'Market' | 'Crisis' | 'Scandal' | 'Festival' | 'Trend' | 'Project' | 'Dictionary';

export type NarrativeTone = 'Trade' | 'Tabloid' | 'Social' | 'Standard';

export interface ResolutionRequest {
  domain: NarrativeDomainKey;
  subDomain: string;
  intensity: number; // 0-100
  tone?: NarrativeTone;
  variant?: string; // Specific key in the SubDomain (e.g. for Options or specific story beats)
  context?: NarrativeContext;
  rng?: RandomGenerator;
}

import { RandomGenerator } from '../utils/rng';
import { pick } from '../utils';
import { 
  CONGLOMERATE_PREFIXES, 
  PREFIXES, 
  NETWORK_SUFFIXES, 
} from '../data/names.data';

export type BrandIdentity = {
  core: string;
  isConglomerate: boolean;
};

/**
 * Studio Boss - Procedural Branding Engine
 * Generates brand identities that can be used to label multiple subsidiaries.
 */
export class BrandSystem {
  /**
   * Generates a new brand identity.
   * 50% chance of being a Conglomerate.
   */
  static generateIdentity(existing: Set<string>, rng: RandomGenerator): BrandIdentity {
    let core: string;
    const isConglomerate = rng.next() > 0.5;
    let attempts = 0;

    do {
      core = isConglomerate ? pick(CONGLOMERATE_PREFIXES, rng) : pick(PREFIXES, rng);
      attempts++;
    } while (existing.has(core) && attempts < 50);

    return { core, isConglomerate };
  }

  /**
   * Generates a studio name based on a brand identity.
   */
  static getStudioName(identity: BrandIdentity, rng: RandomGenerator): string {
    const suffixes = ['Pictures', 'Studios', 'Entertainment', 'Films', 'Media', 'Productions'];
    const suffix = pick(suffixes, rng);
    return `${identity.core} ${suffix}`;
  }

  /**
   * Generates a streaming platform name based on a brand identity.
   */
  static getStreamingName(identity: BrandIdentity, rng: RandomGenerator): string {
    if (identity.isConglomerate) {
      const suffixes = ['+', 'Plus', 'Max', 'Go', 'Play', 'Hub'];
      const suffix = pick(suffixes, rng);
      return `${identity.core}${suffix}`;
    } else {
      const suffixes = ['Cinema', 'Select', 'Direct', 'Watch', 'Premier', 'On Demand'];
      const suffix = pick(suffixes, rng);
      return `${identity.core} ${suffix}`;
    }
  }

  /**
   * Generates a network name based on a brand identity.
   */
  static getNetworkName(identity: BrandIdentity, rng: RandomGenerator): string {
    const suffix = pick([...NETWORK_SUFFIXES], rng);
    return `${identity.core} ${suffix}`;
  }

  /**
   * Generates a standalone "Legacy" name.
   */
  static generateLegacyStandalone(existing: Set<string>, rng: RandomGenerator): string {
    const identity = this.generateIdentity(existing, rng as any);
    return this.getStudioName(identity, rng);
  }
}

import { AvatarFeatures, ColorPalette } from '../types';
import { darkenColor } from '../utils';

/**
 * Returns the SVG path for a specific eye shape.
 */
function getEyeShapePath(
  shape: AvatarFeatures['eyeShape'],
  cx: number, cy: number, w: number, h: number,
  skin: ColorPalette
): string {
  switch (shape) {
    case 'almond':
      return `<ellipse cx="${cx}" cy="${cy}" rx="${w}" ry="${h}" fill="#FFFDF5" stroke="${skin.shadow}" stroke-width="0.5"/>`;
    case 'round':
      return `<circle cx="${cx}" cy="${cy}" r="${w}" fill="#FFFDF5" stroke="${skin.shadow}" stroke-width="0.5"/>`;
    case 'hooded':
      return `<path d="M ${cx - w} ${cy - h * 0.3} Q ${cx - w} ${cy + h} ${cx} ${cy + h} Q ${cx + w} ${cy + h} ${cx + w} ${cy - h * 0.3} Q ${cx + w * 0.5} ${cy - h} ${cx} ${cy - h} Q ${cx - w * 0.5} ${cy - h} ${cx - w} ${cy - h * 0.3}" fill="#FFFDF5" stroke="${skin.shadow}" stroke-width="0.5"/>`;
    case 'monolid':
      return `<rect x="${cx - w}" y="${cy - h * 0.8}" width="${w * 2}" height="${h * 1.6}" rx="${w * 0.5}" fill="#FFFDF5" stroke="${skin.shadow}" stroke-width="0.5"/>`;
    case 'deep-set':
      return `<ellipse cx="${cx}" cy="${cy}" rx="${w * 0.85}" ry="${h * 0.85}" fill="#FFFDF5" stroke="${skin.shadow}" stroke-width="0.8"/>`;
    case 'upturned':
      return `<path d="M ${cx - w} ${cy + h * 0.2} Q ${cx - w * 0.7} ${cy - h} ${cx} ${cy - h * 0.8} Q ${cx + w * 0.7} ${cy - h} ${cx + w} ${cy + h * 0.2} Q ${cx + w * 0.5} ${cy + h} ${cx} ${cy + h * 0.8} Q ${cx - w * 0.5} ${cy + h} ${cx - w} ${cy + h * 0.2}" fill="#FFFDF5" stroke="${skin.shadow}" stroke-width="0.5"/>`;
    default:
      return `<ellipse cx="${cx}" cy="${cy}" rx="${w}" ry="${h}" fill="#FFFDF5" stroke="${skin.shadow}" stroke-width="0.5"/>`;
  }
}

/**
 * Renders the eyes, eyebrows, and eyelashes.
 * Includes blinking animation via CSS.
 */
export function renderEyes(f: AvatarFeatures, cx: number, cy: number, faceW: number, faceH: number, skin: ColorPalette): string {
  const eyeY = cy - faceH * 0.08;
  const eyeSpacing = 12 + f.eyeSpacing * 10;
  let eyeW = 8 + f.eyeSize * 7;
  let eyeH = 5 + f.eyeSize * 5;
  const slant = f.eyeSlant * 5;
  const irisR = eyeH * 0.7;
  const pupilR = irisR * 0.45;

  // Apply eye size asymmetry
  const leftEyeW = eyeW * (1 + f.eyeSizeAsymmetry);
  const rightEyeW = eyeW * (1 - f.eyeSizeAsymmetry);
  const leftEyeH = eyeH * (1 + f.eyeSizeAsymmetry * 0.5);
  const rightEyeH = eyeH * (1 - f.eyeSizeAsymmetry * 0.5);

  const browY = cy - faceH * 0.18;
  const browSpacing = 12 + f.eyeSpacing * 10;
  const browLen = 14 + f.browThickness * 6;
  const browThick = 2 + f.browThickness * 2.5;
  const browArch = f.browArch * 5;
  const browColor = darkenColor(f.hairColor.primary, 0.2);

  // Apply brow height asymmetry
  const leftBrowY = browY + f.browHeightAsymmetry * 5;
  const rightBrowY = browY - f.browHeightAsymmetry * 5;

  let svg = '';

  // ── Eyebrows ──
  // Left brow
  svg += `<path d="M ${cx - browSpacing - browLen/2} ${leftBrowY + 1} Q ${cx - browSpacing} ${leftBrowY - browArch} ${cx - browSpacing + browLen/2} ${leftBrowY + 1}" stroke="${browColor}" stroke-width="${browThick}" stroke-linecap="round" fill="none"/>`;
  // Right brow
  svg += `<path d="M ${cx + browSpacing - browLen/2} ${rightBrowY + 1} Q ${cx + browSpacing} ${rightBrowY - browArch} ${cx + browSpacing + browLen/2} ${rightBrowY + 1}" stroke="${browColor}" stroke-width="${browThick}" stroke-linecap="round" fill="none"/>`;

  // Helper function to render eye based on shape
  const renderEye = (eyeX: number, eyeY: number, eW: number, eH: number, rotation: number) => {
    const eyePath = getEyeShapePath(f.eyeShape, eyeX, eyeY, eW, eH, skin);
    const iR = eH * 0.7;
    const pR = iR * 0.45;

    return `
      <g transform="rotate(${rotation} ${eyeX} ${eyeY})">
        ${eyePath}
        <circle cx="${eyeX}" cy="${eyeY}" r="${iR}" fill="${f.eyeColor}"/>
        <circle cx="${eyeX}" cy="${eyeY}" r="${pR}" fill="#0A0A0A"/>
        <circle cx="${eyeX + iR * 0.3}" cy="${eyeY - iR * 0.3}" r="${pR * 0.5}" fill="white" opacity="0.7"/>
        <!-- Eyelid (Blinking Animation) -->
        <path class="av-blink" d="M ${eyeX - eW - 1} ${eyeY - eH - 1} L ${eyeX + eW + 1} ${eyeY - eH - 1} L ${eyeX + eW + 1} ${eyeY + eH + 1} L ${eyeX - eW - 1} ${eyeY + eH + 1} Z" fill="${skin.base}" transform-origin="${eyeX} ${eyeY - eH}" style="transform: scaleY(0); animation: av-blinking 4s infinite;"/>
      </g>
    `;
  };

  // ── Eyes (Left) ──
  svg += renderEye(cx - eyeSpacing, eyeY, leftEyeW, leftEyeH, slant);

  // ── Eyes (Right) ──
  svg += renderEye(cx + eyeSpacing, eyeY, rightEyeW, rightEyeH, -slant);

  // Epicanthic fold
  if (f.hasEpicanthicFold) {
    svg += `<path d="M ${cx - eyeSpacing - eyeW + 2} ${eyeY + 1} Q ${cx - eyeSpacing - eyeW + 4} ${eyeY - 2} ${cx - eyeSpacing - eyeW + 8} ${eyeY}" stroke="${skin.shadow}" stroke-width="0.8" fill="none"/>`;
    svg += `<path d="M ${cx + eyeSpacing + eyeW - 2} ${eyeY + 1} Q ${cx + eyeSpacing + eyeW - 4} ${eyeY - 2} ${cx + eyeSpacing + eyeW - 8} ${eyeY}" stroke="${skin.shadow}" stroke-width="0.8" fill="none"/>`;
  }

  return svg;
}

/**
 * CSS for blinking animation.
 */
export const EYE_ANIMATION_CSS = `
  @keyframes av-blinking {
    0%, 90%, 100% { transform: scaleY(0); }
    95% { transform: scaleY(1.2); }
  }
`;

