import { AvatarFeatures } from '../types';

/**
 * Renders the back layer of the hair (for long styles).
 */
export function renderHairBack(f: AvatarFeatures, cx: number, cy: number, faceW: number, faceH: number): string {
  const topY = cy - faceH / 2;
  const color = f.hairColor.primary;

  switch (f.hairStyle) {
    case 'long-straight':
    case 'long-wavy':
    case 'long-curly':
      return `<path d="M ${cx - faceW/2 - 5} ${topY + 15} Q ${cx - faceW/2 - 10} ${topY + 80} ${cx - faceW/3} ${topY + 110} L ${cx + faceW/3} ${topY + 110} Q ${cx + faceW/2 + 10} ${topY + 80} ${cx + faceW/2 + 5} ${topY + 15}" fill="${color}" opacity="0.9"/>`;
    case 'shoulder-bob':
      return `<path d="M ${cx - faceW/2 - 4} ${topY + 20} Q ${cx - faceW/2 - 8} ${topY + 50} ${cx} ${topY + 60} Q ${cx + faceW/2 + 8} ${topY + 50} ${cx + faceW/2 + 4} ${topY + 20}" fill="${color}"/>`;
    case 'dreadlocks':
      let dreads = '';
      for (let i = 0; i < 8; i++) {
        const x = cx - faceW/2 + 10 + i * 12;
        dreads += `<path d="M ${x} ${topY + 10} Q ${x + (i % 2 ? 5 : -5)} ${topY + 60} ${x} ${topY + 100}" stroke="${color}" stroke-width="4" fill="none"/>`;
      }
      return dreads;
    case 'bun':
    case 'double-bun':
      return `<circle cx="${cx}" cy="${topY - 20}" r="18" fill="${color}"/>`;
    default:
      return '';
  }
}

/**
 * Renders the front layer of the hair.
 */
export function renderHairFront(f: AvatarFeatures, cx: number, cy: number, faceW: number, faceH: number): string {
  const topY = cy - faceH / 2;
  const hl = f.hairLine; // 0-1
  const color = f.hairColor.primary;
  const secondary = f.hairColor.secondary;
  const shine = f.hairColor.shine || f.hairColor.secondary;

  switch (f.hairStyle) {
    case 'short-crop':
      return `
        <path d="M ${cx - faceW/2 - 2} ${topY + 10} Q ${cx} ${topY - 15 - hl*5} ${cx + faceW/2 + 2} ${topY + 10} Q ${cx + faceW/2} ${topY + 20} ${cx} ${topY + 25 - hl*10} Q ${cx - faceW/2} ${topY + 20} ${cx - faceW/2 - 2} ${topY + 10}" fill="${color}"/>
        <path d="M ${cx - faceW/3} ${topY - 5} Q ${cx} ${topY - 10} ${cx + faceW/3} ${topY - 5}" stroke="${shine}" stroke-width="2" opacity="0.3" fill="none"/>
      `.trim();

    case 'side-part':
      return `
        <path d="M ${cx - faceW/2 - 4} ${topY + 5} Q ${cx - faceW/4} ${topY - 22} ${cx + faceW/2 + 4} ${topY + 5} Q ${cx + faceW/2} ${topY + 20} ${cx} ${topY + 20} Q ${cx - faceW/2} ${topY + 20} ${cx - faceW/2 - 4} ${topY + 5}" fill="${color}"/>
        <line x1="${cx - faceW/6}" y1="${topY - 18}" x2="${cx - faceW/6 + 2}" y2="${topY + 5}" stroke="${secondary}" stroke-width="1.5" opacity="0.4"/>
      `.trim();

    case 'textured-fade':
      let circles = '';
      for (let i = 0; i < 12; i++) {
        const ang = (i / 12) * Math.PI;
        const tx = cx + Math.cos(ang) * (faceW/2);
        const ty = topY + Math.sin(ang) * 5;
        circles += `<circle cx="${tx}" cy="${ty}" r="4" fill="${color}"/>`;
      }
      return `
        <path d="M ${cx - faceW/2} ${topY + 10} Q ${cx} ${topY - 10} ${cx + faceW/2} ${topY + 10}" fill="${color}"/>
        ${circles}
      `.trim();

    case 'long-straight':
      return `
        <path d="M ${cx - faceW/2 - 6} ${topY + 10} Q ${cx} ${topY - 25} ${cx + faceW/2 + 6} ${topY + 10} L ${cx + faceW/2 + 8} ${topY + 90} Q ${cx} ${topY + 100} ${cx - faceW/2 - 8} ${topY + 90} Z" fill="${color}"/>
        <path d="M ${cx - faceW/6} ${topY - 15} Q ${cx} ${topY - 20} ${cx + faceW/6} ${topY - 15}" stroke="${shine}" stroke-width="3" opacity="0.2" fill="none"/>
      `.trim();

    case 'top-knot':
      return `
        <circle cx="${cx}" cy="${topY - 18}" r="14" fill="${color}"/>
        <path d="M ${cx - faceW/2} ${topY + 15} Q ${cx} ${topY - 10} ${cx + faceW/2} ${topY + 15}" fill="${color}"/>
      `.trim();

    case 'afro-round':
      return `<circle cx="${cx}" cy="${cy - 20}" r="${faceW * 0.65}" fill="${color}" opacity="0.95"/>`;

    case 'buzz-cut':
      return `<path d="M ${cx - faceW/2} ${topY + 15} Q ${cx} ${topY - 8} ${cx + faceW/2} ${topY + 15}" fill="${color}" opacity="0.4"/>`;

    case 'pixie':
      return `
        <path d="M ${cx - faceW/2 - 2} ${topY + 5} Q ${cx} ${topY - 20} ${cx + faceW/2 + 2} ${topY + 5} Q ${cx + faceW/2} ${topY + 15} ${cx} ${topY + 15} Q ${cx - faceW/2} ${topY + 15} ${cx - faceW/2 - 2} ${topY + 5}" fill="${color}"/>
        <path d="M ${cx - faceW/2} ${topY + 10} L ${cx - faceW/2 - 5} ${topY + 25}" stroke="${color}" stroke-width="4" stroke-linecap="round"/>
        <path d="M ${cx + faceW/2} ${topY + 10} L ${cx + faceW/2 + 5} ${topY + 25}" stroke="${color}" stroke-width="4" stroke-linecap="round"/>
      `.trim();

    case 'ponytail':
      return `
        <path d="M ${cx - faceW/2} ${topY + 15} Q ${cx} ${topY - 15} ${cx + faceW/2} ${topY + 15}" fill="${color}"/>
        <path d="M ${cx + faceW/2} ${topY} Q ${cx + faceW/2 + 20} ${topY + 10} ${cx + faceW/2 + 10} ${topY + 60}" fill="${color}" stroke="${secondary}" stroke-width="1"/>
      `.trim();

    case 'curls-medium':
      let curls = '';
      for (let i = 0; i < 15; i++) {
        const x = cx - faceW/2 + (i/15) * faceW;
        const y = topY + (Math.sin(i * 1.5) * 5);
        curls += `<circle cx="${x}" cy="${y}" r="6" fill="${color}"/>`;
      }
      return `
        <path d="M ${cx - faceW/2 - 5} ${topY + 10} Q ${cx} ${topY - 20} ${cx + faceW/2 + 5} ${topY + 10}" fill="${color}"/>
        ${curls}
      `.trim();

    case 'slick-back':
      return `
        <path d="M ${cx - faceW/2} ${topY + 10} Q ${cx} ${topY - 25} ${cx + faceW/2} ${topY + 10} L ${cx + faceW/2 - 5} ${topY + 15} Q ${cx} ${topY + 10} ${cx - faceW/2 + 5} ${topY + 15} Z" fill="${color}"/>
        <path d="M ${cx - 10} ${topY - 10} Q ${cx} ${topY - 15} ${cx + 10} ${topY - 10}" stroke="${shine}" stroke-width="1.5" opacity="0.3" fill="none"/>
      `.trim();

    case 'wavy-shoulder':
      return `
        <path d="M ${cx - faceW/2 - 8} ${topY + 10} Q ${cx} ${topY - 30} ${cx + faceW/2 + 8} ${topY + 10} Q ${cx + faceW/2 + 15} ${topY + 40} ${cx + faceW/2} ${topY + 70} Q ${cx} ${topY + 65} ${cx - faceW/2} ${topY + 70} Q ${cx - faceW/2 - 15} ${topY + 40} ${cx - faceW/2 - 8} ${topY + 10}" fill="${color}"/>
      `.trim();

    case 'cornrows':
      let rows = '';
      for (let i = 0; i < 6; i++) {
        const y = topY - 10 + i * 6;
        rows += `<path d="M ${cx - faceW/2 + 5} ${y} Q ${cx} ${y - 3} ${cx + faceW/2 - 5} ${y}" stroke="${color}" stroke-width="2.5" fill="none"/>`;
      }
      return rows.trim();

    case 'dreadlocks':
      let frontDreads = '';
      for (let i = 0; i < 5; i++) {
        const x = cx - faceW/2 + 10 + i * 15;
        frontDreads += `<path d="M ${x} ${topY} Q ${x + (i % 2 ? 3 : -3)} ${topY + 20} ${x} ${topY + 40}" stroke="${color}" stroke-width="3" fill="none"/>`;
      }
      return frontDreads.trim();

    case 'mohawk':
      return `
        <path d="M ${cx - 8} ${topY + 5} Q ${cx} ${topY - 20} ${cx + 8} ${topY + 5}" fill="${color}"/>
        <path d="M ${cx - 5} ${topY} L ${cx - 5} ${topY + 30}" stroke="${color}" stroke-width="3"/>
        <path d="M ${cx} ${topY - 5} L ${cx} ${topY + 35}" stroke="${color}" stroke-width="3"/>
        <path d="M ${cx + 5} ${topY} L ${cx + 5} ${topY + 30}" stroke="${color}" stroke-width="3"/>
      `.trim();

    case 'undercut':
      return `
        <path d="M ${cx - faceW/2} ${topY + 15} Q ${cx} ${topY - 15} ${cx + faceW/2} ${topY + 15}" fill="${color}"/>
        <path d="M ${cx - faceW/2} ${topY + 15} L ${cx - faceW/2} ${topY + 25}" stroke="${color}" stroke-width="2"/>
        <path d="M ${cx + faceW/2} ${topY + 15} L ${cx + faceW/2} ${topY + 25}" stroke="${color}" stroke-width="2"/>
      `.trim();

    case 'afro-short':
      return `<circle cx="${cx}" cy="${topY}" r="${faceW * 0.5}" fill="${color}" opacity="0.95"/>`;

    case 'box-braids':
      let braids = '';
      for (let i = 0; i < 7; i++) {
        const x = cx - faceW/2 + 8 + i * 12;
        braids += `<path d="M ${x} ${topY} Q ${x + 2} ${topY + 25} ${x - 2} ${topY + 50}" stroke="${color}" stroke-width="2.5" fill="none"/>`;
      }
      return braids.trim();

    case 'bun':
      return `
        <path d="M ${cx - faceW/2} ${topY + 10} Q ${cx} ${topY - 15} ${cx + faceW/2} ${topY + 10}" fill="${color}"/>
      `.trim();

    case 'double-bun':
      return `
        <path d="M ${cx - faceW/2} ${topY + 10} Q ${cx} ${topY - 15} ${cx + faceW/2} ${topY + 10}" fill="${color}"/>
        <circle cx="${cx - 15}" cy="${topY - 10}" r="10" fill="${color}"/>
        <circle cx="${cx + 15}" cy="${topY - 10}" r="10" fill="${color}"/>
      `.trim();

    case 'long-curly':
      let longCurls = '';
      for (let i = 0; i < 20; i++) {
        const x = cx - faceW/2 - 5 + (i/20) * (faceW + 10);
        const y = topY + (Math.sin(i * 2) * 8);
        longCurls += `<circle cx="${x}" cy="${y}" r="5" fill="${color}"/>`;
      }
      return `
        <path d="M ${cx - faceW/2 - 6} ${topY + 10} Q ${cx} ${topY - 25} ${cx + faceW/2 + 6} ${topY + 10}" fill="${color}"/>
        ${longCurls}
      `.trim();

    case 'bangs':
      return `
        <path d="M ${cx - faceW/2 - 2} ${topY + 10} Q ${cx} ${topY - 20} ${cx + faceW/2 + 2} ${topY + 10}" fill="${color}"/>
        <path d="M ${cx - faceW/2} ${topY + 5} Q ${cx - faceW/4} ${topY + 15} ${cx} ${topY + 12} Q ${cx + faceW/4} ${topY + 15} ${cx + faceW/2} ${topY + 5}" fill="${secondary}"/>
      `.trim();

    case 'bald':
    default:
      return '';
  }
}

import { AvatarFeatures } from './types';
import { getFaceShapePath, renderEars } from './geometry/faceShapes';
import { renderHairBack, renderHairFront } from './features/hairStyles';
import { renderEyes, EYE_ANIMATION_CSS } from './features/eyes';
import { renderMouth } from './features/mouth';
import { renderNose } from './features/nose';
import { renderClothing, CLOTHING_ANIMATION_CSS } from './features/clothing';
import { renderFacialHair, renderAccessories } from './features/accessories';
import { darkenColor } from './utils';

/**
 * Assembles the full SVG for the procedural avatar.
 */
export function renderAvatarSVG(f: AvatarFeatures): string {
  const cx = 100;
  const cy = 100;
  const faceW = (68 + (f.faceWidth - 1) * 40) * f.faceWidth;
  const faceH = (78 + (f.faceHeight - 1) * 36) * f.faceHeight;
  const uid = `av-${f.seed.toString(36)}`;

  const facePath = getFaceShapePath(f.faceShape, cx, cy, faceW, faceH, f.jawWidth, f.chinPointiness);

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" fill="none">`;

  // ── CSS Animations ──
  svg += `<style>
    ${EYE_ANIMATION_CSS}
    ${CLOTHING_ANIMATION_CSS}
    .av-skin { transition: fill 0.3s ease; }
    .av-breathe { transform-box: fill-box; transform-origin: center bottom; }
  </style>`;

  // ── Defs (Filters & Gradients) ──
  svg += `<defs>`;
  // Skin Gradient
  svg += `<radialGradient id="${uid}-skin" cx="45%" cy="35%" r="60%">
    <stop offset="0%" stop-color="${f.skin.highlight}"/>
    <stop offset="60%" stop-color="${f.skin.base}"/>
    <stop offset="100%" stop-color="${f.skin.shadow}"/>
  </radialGradient>`;

  // Lighting Filter (Soft volume)
  svg += `<filter id="${uid}-glow" x="-20%" y="-20%" width="140%" height="140%">
    <feGaussianBlur in="SourceAlpha" stdDeviation="2" result="blur"/>
    <feOffset in="blur" dx="1" dy="1" result="offsetBlur"/>
    <feComposite in="SourceGraphic" in2="offsetBlur" operator="over"/>
  </filter>`;

  // Shadow Filter (Depth)
  svg += `<filter id="${uid}-shadow">
    <feDropShadow dx="0" dy="2" stdDeviation="3" flood-opacity="0.3"/>
  </filter>`;

  svg += `</defs>`;

  // ── Background & Canvas ──
  svg += `<circle cx="100" cy="100" r="95" fill="${darkenColor(f.skin.shadow, 0.4)}" opacity="0.1"/>`;

  // ── Layered Rendering ──

  // 1. Clothing (Shoulders/Neck) - includes breathing animation
  svg += renderClothing(f, cx, cy, faceW, faceH, f.skin);

  // 2. Ears
  svg += renderEars(cx, cy, faceW, faceH, f.skin);

  // 3. Hair Back
  svg += renderHairBack(f, cx, cy, faceW, faceH);

  // 4. Face Base
  svg += `<path d="${facePath}" fill="url(#${uid}-skin)" stroke="${f.skin.shadow}" stroke-width="0.5" filter="url(#${uid}-shadow)"/>`;

  // 5. Features
  svg += renderNose(f, cx, cy, faceW, faceH, f.skin);
  svg += renderMouth(f, cx, cy, faceW, faceH, f.skin);
  svg += renderEyes(f, cx, cy, faceW, faceH, f.skin);
  svg += renderFacialHair(f, cx, cy, faceW, faceH);

  // 6. Accessories
  svg += renderAccessories(f, cx, cy, faceW, faceH);

  // 7. Hair Front
  svg += renderHairFront(f, cx, cy, faceW, faceH);

  // 8. Overlays & Aging
  if (f.wrinkleOpacity > 0.1) {
    svg += renderWrinkleLines(f, cx, cy, faceW, faceH);
  }

  // 9. Skin Details
  svg += renderSkinDetails(f, cx, cy, faceW, faceH);

  // Final Lighting Overlay (Rim Light)
  svg += `<ellipse cx="100" cy="80" rx="90" ry="85" stroke="white" stroke-width="0.5" opacity="0.1" pointer-events="none"/>`;

  svg += `</svg>`;
  return svg;
}

function renderWrinkleLines(f: AvatarFeatures, cx: number, cy: number, faceW: number, faceH: number): string {
  const opacity = f.wrinkleOpacity * 0.3;
  const shadow = f.skin.shadow;
  const browY = cy - faceH * 0.18;
  const eyeY = cy - faceH * 0.08;
  const mouthY = cy + faceH * 0.28;
  const chinY = cy + faceH * 0.48;

  let lines = '';
  // Forehead
  if (f.age >= 40) {
    lines += `<path d="M ${cx - faceW/4} ${browY - 8} Q ${cx} ${browY - 10} ${cx + faceW/4} ${browY - 8}" stroke="${shadow}" stroke-width="0.5" opacity="${opacity}"/>`;
    lines += `<path d="M ${cx - faceW/5} ${browY - 14} Q ${cx} ${browY - 16} ${cx + faceW/5} ${browY - 14}" stroke="${shadow}" stroke-width="0.5" opacity="${opacity * 0.7}"/>`;
  }
  // Crow's feet (around eyes)
  if (f.age >= 45) {
    lines += `<path d="M ${cx - faceW/3} ${eyeY} Q ${cx - faceW/3 - 5} ${eyeY - 5} ${cx - faceW/3 - 3} ${eyeY - 8}" stroke="${shadow}" stroke-width="0.4" fill="none" opacity="${opacity * 0.8}"/>`;
    lines += `<path d="M ${cx + faceW/3} ${eyeY} Q ${cx + faceW/3 + 5} ${eyeY - 5} ${cx + faceW/3 + 3} ${eyeY - 8}" stroke="${shadow}" stroke-width="0.4" fill="none" opacity="${opacity * 0.8}"/>`;
  }
  // Laugh lines
  if (f.age >= 50) {
    lines += `<path d="M ${cx - 15} ${eyeY + 15} Q ${cx - 18} ${mouthY} ${cx - 12} ${mouthY + 5}" stroke="${shadow}" stroke-width="0.8" fill="none" opacity="${opacity * 1.5}"/>`;
    lines += `<path d="M ${cx + 15} ${eyeY + 15} Q ${cx + 18} ${mouthY} ${cx + 12} ${mouthY + 5}" stroke="${shadow}" stroke-width="0.8" fill="none" opacity="${opacity * 1.5}"/>`;
  }
  // Marionette lines (mouth to chin)
  if (f.age >= 55) {
    lines += `<path d="M ${cx - 10} ${mouthY + 5} Q ${cx - 12} ${chinY} ${cx - 8} ${chinY + 3}" stroke="${shadow}" stroke-width="0.6" fill="none" opacity="${opacity * 1.2}"/>`;
    lines += `<path d="M ${cx + 10} ${mouthY + 5} Q ${cx + 12} ${chinY} ${cx + 8} ${chinY + 3}" stroke="${shadow}" stroke-width="0.6" fill="none" opacity="${opacity * 1.2}"/>`;
  }
  // Jowl rendering
  if (f.jowlAmount > 0.1) {
    const jowlOpacity = f.jowlAmount * 0.4;
    lines += `<path d="M ${cx - faceW/3} ${chinY} Q ${cx - faceW/3 + 3} ${chinY + 5} ${cx - faceW/4} ${chinY + 2}" fill="${f.skin.shadow}" opacity="${jowlOpacity}"/>`;
    lines += `<path d="M ${cx + faceW/3} ${chinY} Q ${cx + faceW/3 - 3} ${chinY + 5} ${cx + faceW/4} ${chinY + 2}" fill="${f.skin.shadow}" opacity="${jowlOpacity}"/>`;
  }
  return lines;
}

function renderSkinDetails(f: AvatarFeatures, cx: number, cy: number, faceW: number, faceH: number): string {
  let details = '';
  const mouthY = cy + faceH * 0.28;

  // Beauty mark
  if (f.hasBeautyMark) {
    details += `<circle cx="${cx + (f.beautyMarkPosition.x - 0.5) * faceW}" cy="${cy + (f.beautyMarkPosition.y - 0.5) * faceH}" r="1.2" fill="#5D4037" opacity="0.7"/>`;
  }

  // Age spots
  if (f.hasAgeSpots) {
    for (let i = 0; i < 3; i++) {
      const spotX = cx + (Math.random() - 0.5) * faceW * 0.6;
      const spotY = cy + (Math.random() - 0.3) * faceH * 0.6;
      details += `<circle cx="${spotX}" cy="${spotY}" r="${1 + Math.random() * 1.5}" fill="#8B7355" opacity="0.3"/>`;
    }
  }

  // Rosy cheeks
  if (f.hasRosyCheeks) {
    const cheekY = cy + faceH * 0.1;
    details += `<ellipse cx="${cx - faceW * 0.3}" cy="${cheekY}" rx="8" ry="5" fill="#FFB6C1" opacity="0.15"/>`;
    details += `<ellipse cx="${cx + faceW * 0.3}" cy="${cheekY}" rx="8" ry="5" fill="#FFB6C1" opacity="0.15"/>`;
  }

  // Skin texture
  if (f.skinTexture === 'pores') {
    for (let i = 0; i < 15; i++) {
      const texX = cx + (Math.random() - 0.5) * faceW * 0.8;
      const texY = cy + (Math.random() - 0.3) * faceH * 0.8;
      details += `<circle cx="${texX}" cy="${texY}" r="0.3" fill="${f.skin.shadow}" opacity="0.1"/>`;
    }
  } else if (f.skinTexture === 'rough') {
    for (let i = 0; i < 25; i++) {
      const texX = cx + (Math.random() - 0.5) * faceW * 0.8;
      const texY = cy + (Math.random() - 0.3) * faceH * 0.8;
      details += `<circle cx="${texX}" cy="${texY}" r="0.4" fill="${f.skin.shadow}" opacity="0.15"/>`;
    }
  }

  return details;
}

import { RandomGenerator } from '../utils/rng';
import { BardResolver } from '../systems/bardResolver';
import { generateProjectTitle } from './titles';
import { ProjectFormat } from '@/engine/types';

/**
 * Generates a studio name using the Bard Engine.
 */
export function generateStudioName(_existing: string[], rng: RandomGenerator): string {
  // We use intensity 50 as a neutral default for name generation
  const prefix = BardResolver.resolve({ 
    domain: 'Dictionary' as any, 
    subDomain: 'STUDIO_PREFIX', 
    intensity: rng.range(0, 100) 
  });
  const suffix = BardResolver.resolve({ 
    domain: 'Dictionary' as any, 
    subDomain: 'STUDIO_SUFFIX', 
    intensity: rng.range(0, 100) 
  });
  return `${prefix} ${suffix}`;
}

/**
 * Generates a studio motto using the Bard Engine.
 */
export function generateMotto(rng: RandomGenerator): string {
  return BardResolver.resolve({
    domain: 'Dictionary' as any,
    subDomain: 'STUDIO_MOTTO',
    intensity: rng.range(0, 100)
  });
}

/**
 * Generates a character name using the Bard Engine.
 */
export function generateDemographicName(
  gender: 'MALE' | 'FEMALE' | 'NON_BINARY', 
  _country: string, 
  _ethnicity: string, 
  rng: RandomGenerator
): string {
  const firstSubDomain = gender === 'FEMALE' ? 'FIRST_NAME_FEMALE' : 'FIRST_NAME_MALE';

  const first = BardResolver.resolve({
    domain: 'Dictionary' as any,
    subDomain: firstSubDomain,
    intensity: rng.range(0, 100)
  });

  const last = BardResolver.resolve({
    domain: 'Dictionary' as any,
    subDomain: 'LAST_NAME',
    intensity: rng.range(0, 100)
  });

  return `${first} ${last}`;
}

/**
 * Redirects to the centralized Project Title generator in the Bard Engine.
 */
export function generateProjectName(_format: ProjectFormat, genre: string, rng: RandomGenerator): string {
  return generateProjectTitle(genre, rng);
}

import { Talent, TalentRole, Family, TalentTier, DirectorArchetype } from '../../types/talent.types';
import { generateDemographics } from './demographicsGenerator';
import { generatePsychology } from './psychologyGenerator';
import { generateDemographicName } from '../names';
import { RandomGenerator } from '../../utils/rng';
import { generateArchetypeForRole, generatePersonalityTrait, generateCareerTrajectory } from '../../data/talentArchetypes';
import { applyComfortLevelToTalent } from '../../systems/talent/CastingConstraintSystem';

const TALENT_QUIRKS = [
  'method_actor', 'difficult', 'box_office_draw', 'critics_darling', 
  'party_animal', 'professional', 'under_rehab', 'social_media_star',
  'indie_spirit', 'franchise_loyalist', 'secret_addiction', 'hidden_gem'
];

export function generateTalent(rng: RandomGenerator, params: { role: TalentRole; tier: TalentTier; localCountry?: string }): Talent {
  const isGlobalSuperstar = params.tier === 1;

  const demographics = generateDemographics(rng, isGlobalSuperstar, params.localCountry);
  const psychology = generatePsychology(rng, params.tier === 1 ? 'S_LIST' : params.tier === 2 ? 'A_LIST' : 'B_LIST'); // Mapping for legacy compat until psychology is updated
  const name = generateDemographicName(demographics.gender, demographics.country, demographics.ethnicity, rng);

  const isNepo = rng.next() < 0.1;
  const nepoBump = isNepo ? 15 : 0;
  const prestige = rng.rangeInt(10, 80) + nepoBump;
  const draw = rng.rangeInt(10, 80) + nepoBump;
  const fee = rng.rangeInt(100_000, 5_000_000) + (isNepo ? 1_000_000 : 0);

  // Generate random perks
  const perksCount = rng.rangeInt(0, 2);
  const perksPool = [...TALENT_QUIRKS];
  const perks: string[] = [];
  for (let i = 0; i < perksCount; i++) {
    if (perksPool.length > 0) {
      const selected = rng.pick(perksPool);
      perks.push(selected);
      const index = perksPool.indexOf(selected);
      if (index > -1) {
        perksPool.splice(index, 1);
      }
    }
  }

  const GENRES = ['Action', 'Comedy', 'Drama', 'Horror', 'Sci-Fi', 'Thriller', 'Romance', 'Musical', 'Documentary', 'Western', 'Fantasy', 'Adventure'];

  // Generate archetypes and personality traits
  const archetype = generateArchetypeForRole(params.role, params.tier, rng);
  const personality = generatePersonalityTrait(rng);
  const careerTrajectory = generateCareerTrajectory(params.tier, rng);

  // Generate comfort levels for casting constraints
  const comfortData = applyComfortLevelToTalent({ personality, prestige, tier: params.tier } as Talent, rng);

  // Set role-specific archetype fields
  let actorArchetype, writerArchetype, producerArchetype, personalityArchetype, directorArchetype;

  if (params.role === 'actor') {
    actorArchetype = archetype as any;
  } else if (params.role === 'writer' || params.role === 'showrunner') {
    writerArchetype = archetype as any;
  } else if (params.role === 'producer') {
    producerArchetype = archetype as any;
  } else if (params.role === 'personality') {
    personalityArchetype = archetype as any;
  } else if (params.role === 'director') {
    // Use existing directorArchetype system
    const directorArchetypes: DirectorArchetype[] = ['auteur', 'journeyman', 'visionary', 'commercial_hack'];
    const tierBias = params.tier === 1 ? ['auteur', 'visionary'] : params.tier === 2 ? ['auteur', 'visionary', 'journeyman'] : ['journeyman', 'commercial_hack'];
    const availableArchetypes = directorArchetypes.filter(a => tierBias.includes(a));
    directorArchetype = availableArchetypes[Math.floor(rng.next() * availableArchetypes.length)] || 'journeyman';
  }

  return {
    id: rng.uuid('TAL'),
    name,
    role: params.role,
    roles: [params.role],
    tier: params.tier,
    demographics,
    psychology,
    accessLevel: isGlobalSuperstar ? 'legacy' : 'outsider' as any,
    skills: {
      acting: params.role === 'actor' ? rng.rangeInt(40, 95) : rng.rangeInt(10, 40),
      directing: params.role === 'director' ? rng.rangeInt(40, 95) : rng.rangeInt(10, 40),
      writing: params.role === 'writer' ? rng.rangeInt(40, 95) : rng.rangeInt(10, 40),
      stardom: rng.rangeInt(10, 90),
    },
    prestige: Math.max(0, Math.min(100, prestige)),
    draw: Math.max(0, Math.min(100, draw)),
    fee,
    momentum: rng.rangeInt(40, 60),
    starMeter: Math.floor((prestige * 0.4) + (draw * 0.4) + (prestige * 0.2)),
    bio: `${name} is a Tier ${params.tier} ${params.role}.`,
    motivationProfile: {
        financial: rng.rangeInt(20, 80),
        prestige: rng.rangeInt(20, 80),
        legacy: rng.rangeInt(10, 70),
        aggression: rng.rangeInt(10, 60)
    },
    currentMotivation: 'NONE',
    motivationImpulse: 'NONE',
    commitments: [],
    fatigue: 0,
    preferredGenres: Array.from({ length: rng.rangeInt(1, 3) }, () => rng.pick(GENRES)),
    // Role-specific archetypes
    actorArchetype,
    writerArchetype,
    producerArchetype,
    personalityArchetype,
    directorArchetype,
    // Universal personality trait
    personality,
    // Career trajectory
    careerTrajectory,
    // Casting constraint comfort levels
    comfortLevel: comfortData.comfortLevel,
    comfortPremiumRates: comfortData.comfortPremiumRates
  };
}

export function generateFamilies(rng: RandomGenerator, count: number): Family[] {
