import { tickDeathSystem } from '../../systems/talent/DeathSystem';
import { tickDynastySystem } from '../../systems/talent/DynastySystem';
import { tickRelationshipSystem } from '../../systems/talent/RelationshipSystem';
import { tickCliqueSystem } from '../../systems/talent/CliqueSystem';
import { tickProductionEnhancementSystem } from '../../systems/talent/ProductionEnhancementSystem';
import { tickMarketingPromotionSystem } from '../../systems/talent/MarketingPromotionSystem';
import { tickTalentDiscoverySystem } from '../../systems/talent/TalentDiscoverySystem';
import { tickCastingConstraintSystem } from '../../systems/talent/CastingConstraintSystem';
import { tickBiographyGenerator } from '../../systems/talent/BiographyGenerator';
import { tickOrganicEvents } from '../../systems/talent/OrganicEventEnhancer';
import { tickTVRecommendationSystem } from '../../systems/talent/TVRecommendationSystem';
import { TalentMoraleSystem } from '../../systems/talent/TalentMoraleSystem';
import { shouldTalentHireAgent, selectAgentForTalent, shouldTalentFireAgent, createAgentHiringEvent, createAgentFiringEvent } from '../../systems/talent/talentAgentEvents';
import { TalentAgentInteractionEngine } from '../../systems/talent/talentAgentInteractions';

/**
 * Talent Filter
 * Handles talent lifecycle, morale, agent relationships, and various talent systems
 */
export class TalentFilter implements WeekFilter {
  name = 'TalentFilter';

  execute(state: GameState, context: TickContext): void {
    // Core talent systems
    context.impacts.push(TalentSystem.advance(state, context.rng));
    context.impacts.push(...TalentLifecycleSystem.tick(state, context.rng));
    context.impacts.push(...tickDeathSystem(state, context.rng));
    context.impacts.push(...tickDynastySystem(state, context.rng));
    context.impacts.push(...tickRelationshipSystem(state, context.rng));
    context.impacts.push(...tickCliqueSystem(state, context.rng));
    context.impacts.push(...tickProductionEnhancementSystem(state, context.rng));
    context.impacts.push(...tickMarketingPromotionSystem(state, context.rng));
    context.impacts.push(...tickTalentDiscoverySystem(state, context.rng));
    context.impacts.push(...tickCastingConstraintSystem(state, context.rng));
    context.impacts.push(...tickBiographyGenerator(state, context.rng));
    context.impacts.push(...tickOrganicEvents(state, context.rng));
    context.impacts.push(...tickTVRecommendationSystem(state, undefined, context.rng));

    // Phase 1: Register Weekly Morale
    const talentDict = state.entities.talents;
    const projectsDict = state.entities.projects;
    const contractsDict = state.entities.contracts;
    const moraleUpdates = TalentMoraleSystem.processWeeklyMorale(talentDict, projectsDict, contractsDict);

    for (const update of moraleUpdates) {
      context.impacts.push({
        type: 'TALENT_UPDATED',
        payload: { talentId: update.talentId, update: update.update }
      });
    }

    // Phase 3: Talent-Agent Hiring/Firing Events
    for (const [talentId, talent] of Object.entries(talentDict)) {
      const hiringCheck = shouldTalentHireAgent(talent, state, context.rng);
      if (hiringCheck.shouldHire) {
        const newAgent = selectAgentForTalent(talent, state, context.rng);
        if (newAgent) {
          // Fire current agent if exists
          if (talent.agentId) {
            const currentRelationshipId = `${talentId}-${talent.agentId}`;
            const newRelationships = { ...state.talentAgentRelationships };
            delete newRelationships[currentRelationshipId];

            context.impacts.push({
              type: 'TALENT_UPDATED',
              payload: {
                talentId,
                update: { agentId: undefined, agencyId: undefined }
              }
            });
          }

          // Create new relationship
          const agentPersonality = newAgent.personality || derivePersonalityFromAgent(newAgent);
          const agency = state.industry.agencies.find(a => a.id === newAgent.agencyId);
          TalentAgentInteractionEngine.createRelationship(
            talentId,
            newAgent.id,
            talent.personality || 'pragmatic',
            agentPersonality,
            agency?.tier
          );

          context.impacts.push({
            type: 'TALENT_UPDATED',
            payload: {
              talentId,
              update: { agentId: newAgent.id, agencyId: newAgent.agencyId }
            }
          });

          context.impacts.push({
            type: 'NEWS_ADDED',
            payload: createAgentHiringEvent(talent, newAgent, context.week)
          });
        }
      }

      if (talent.agentId) {
        const relationship = state.talentAgentRelationships[`${talentId}-${talent.agentId}`];
        if (relationship && shouldTalentFireAgent(talent, relationship, state)) {
          context.impacts.push({
            type: 'NEWS_ADDED',
            payload: createAgentFiringEvent(talent, talent.agentId, context.week)
          });

          context.impacts.push({
            type: 'TALENT_UPDATED',
            payload: {
              talentId,
              update: { agentId: undefined, agencyId: undefined }
            }
          });

          // Note: Relationship removal will be handled by impact reducer when talent agentId is cleared
        }
      }

      // Phase 6: Weekly Relationship Evolution
      if (talent.agentId) {
        const relationshipId = `${talentId}-${talent.agentId}`;
        const relationship = state.talentAgentRelationships[relationshipId];
        if (relationship) {
          // Evolve relationship over time and persist the result
          const evolved = TalentAgentInteractionEngine.evolveRelationship(
            relationship,
            0,
            context.rng
          );
          if (evolved !== relationship) {
            context.impacts.push({
              type: 'RELATIONSHIP_UPDATED',
              payload: { relationshipId, relationship: evolved }
            });
          }
        }
      }
    }

    function derivePersonalityFromAgent(agent: { negotiationTactic: string }): import('../../systems/talent/talentAgentInteractions').AgentPersonality {
      const tacticMap: Record<string, import('../../systems/talent/talentAgentInteractions').AgentPersonality> = {
        'SHARK': 'shark',
        'DIPLOMAT': 'diplomat',
        'VOLUME': 'volume',
        'PRESTIGE': 'prestige'
      };
      return tacticMap[agent.negotiationTactic] || 'diplomat';
    }
  }
}

import { GameState, StateImpact, Contract } from '@/engine/types';
import { RandomGenerator } from '../utils/rng';
import { evaluateGreenlight } from '../systems/greenlight';
import { executeGreenlight, executeMarketing } from '../systems/projects';

/**
 * Headless Controller (AI for the Player Studio)
 * Automates decision-making to prevent the simulation from stalling.
 */
export class HeadlessController {
  static tick(state: GameState, rng: RandomGenerator): StateImpact[] {
    const impacts: StateImpact[] = [];
    const internalProjects = Object.values(state.entities.projects);
    const contractsList = Object.values(state.entities.contracts || {});

    const contractsByProject = new Map<string, Contract[]>();
    contractsList.forEach((c: Contract) => {
      if (c.projectId) {
        let list = contractsByProject.get(c.projectId);
        if (!list) {
          list = [];
          contractsByProject.set(c.projectId, list);
        }
        list.push(c);
      }
    });

    internalProjects.forEach(project => {
      // 1. Auto-Greenlight
      if (project.state === 'needs_greenlight') {
        const projectContracts = contractsByProject.get(project.id) || [];
        const attachedTalent = projectContracts.map(c => state.entities.talents[c.talentId]).filter(Boolean);
        const report = evaluateGreenlight(project, state.finance.cash, attachedTalent, rng, state.week, internalProjects);

        if (report.score > 60 || (state.finance.cash > project.budget * 3)) {
          const result = executeGreenlight(project);
          impacts.push({
            type: 'PROJECT_UPDATED',
            payload: { projectId: project.id, update: result.project }
          });
          impacts.push({
            type: 'NEWS_ADDED',
            payload: {
              headline: `GREENLIGHT: ${state.studio.name} moves forward with "${project.title}"`,
              description: `Automated decision: Project evaluation score ${report.score}. ${result.update}`,
              category: 'general'
            }
          });
        }
      }

      // 2. Auto-Release (Transition from marketing to released)
      if (project.state === 'marketing' && !project.releaseWeek) {
        // In headless mode, we just release immediately once in marketing
        const campaign = {
          primaryAngle: 'SELL_THE_STORY',
          domesticBudget: project.budget * 0.1,
          foreignBudget: project.budget * 0.05,
          weeksInMarketing: 1
        };
        const result = executeMarketing(project, campaign as any);
        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: { 
            projectId: project.id, 
            update: { 
              ...result.project, 
              state: 'released',
              marketingBudget: campaign.domesticBudget + campaign.foreignBudget
            } 
          }
        });
      }
    });

    // Pre-calculate genre counts to avoid O(N) inside the loop
    const playerGenreCounts: Record<string, number> = {};
    for (let i = 0; i < internalProjects.length; i++) {
      const g = internalProjects[i].genre;
      if (g) {
        playerGenreCounts[g] = (playerGenreCounts[g] || 0) + 1;
      }
    }

    // 3. Auto-Bidding on Opportunities
    state.market.opportunities.forEach(opportunity => {
      const isAlreadyBid = !!opportunity.bids['PLAYER'];
      const isSimulation = true; // We are in headless mode

      let shouldBid = !isAlreadyBid && (state.finance.cash > opportunity.costToAcquire * 2 || isSimulation);

      // Persona Overrides
      const persona = (state as any).persona || 'balanced';

      // Genre Saturation Guard for Player (Limit to 2 same-genre projects)
      const isSaturated = (playerGenreCounts[opportunity.genre] || 0) >= 2;

      if (persona === 'frugal') {
        // Frugal only bids on low/mid if cash is tight, or any if cash is high
        if (opportunity.budgetTier === 'blockbuster' || opportunity.budgetTier === 'high') {
          if (state.finance.cash < 100000000) shouldBid = false; 
        }
      } else if (persona === 'aggressive') {
        // Aggressive always bids if not already bid
        shouldBid = !isAlreadyBid;
      }

      if (isSaturated) shouldBid = false;

      if (shouldBid) {
        let bidAmount = Math.floor(opportunity.costToAcquire * 1.05);

        // Predatory Bidding (Top the highest rival bid if Aggressive)
        if (persona === 'aggressive') {
           const rivalBids: number[] = [];
           if (opportunity.bids) {
             for (const id in opportunity.bids) {
               if (Object.prototype.hasOwnProperty.call(opportunity.bids, id)) {
                 rivalBids.push(opportunity.bids[id].amount);
               }
             }
           }
           if (rivalBids.length > 0) {
             const highestRival = Math.max(...rivalBids);
             bidAmount = Math.max(bidAmount, Math.floor(highestRival * 1.05));
           }
        }

        impacts.push({
          type: 'OPPORTUNITY_UPDATED',
          payload: {
            opportunityId: opportunity.id,
            rivalId: 'PLAYER',
            bid: { amount: bidAmount, terms: 'standard' }
          }
        });
      }
    });

    return impacts;
  }


}

import { GameState, WeekSummary } from '../types';

export interface SimulationMetrics {
  week: number;
  playerCash: number;
  rivalAvgCash: number;
  totalSystemCash: number;
  totalMarketSentiment: number;
  talentPoolSize: number;
  avgTalentPrestige: number;
  activeProjects: number;
  completedProjects: number;
  retiredCount: number;
  bankruptcyCount: number;
  marketShare: number;
  industryLeader?: string;
  topGenreROI?: { genre: string; roi: number };
  tvAwardsWon?: number;
  tvGenreROI?: { genre: string; roi: number };
  averageA_ListCount: number;
  totalBailoutCash: number;
  avgNielsenKeyDemo: number;
  cutCounts: Record<string, number>;
  activeStudioCount: number;
  consolidationCount: number;
}

export class MetricsCollector {
  private history: SimulationMetrics[] = [];
  private totalRetired = 0;
  private totalBailoutCash = 0;
  private genreStats: Record<string, { cost: number; revenue: number }> = {};
  private tvGenreStats: Record<string, { cost: number; revenue: number }> = {};
  private totalTvAwards = 0;

  public record(state: GameState, summary: WeekSummary): void {
    const rivalsList = Object.values(state.entities.rivals || {});
    const platforms = state.market.buyers.filter(b => b.archetype === 'streamer') as any[];

    // Total bails tracking (Phase 2 hardening)
    const currentBailouts = (summary as any).totalBailouts || 0;
    this.totalBailoutCash += currentBailouts;

    const rivalTotalCash = rivalsList.reduce((sum, r) => sum + (Number(r.cash) || 0), 0);
    const platformTotalCash = platforms.reduce((sum, p) => sum + (Number(p.cash) || 0), 0);
    const playerCash = Number(state.finance.cash) || 0;

    // Increment total retirements
    this.totalRetired += (summary as any).retiredCount || 0;

    // Track total completed & Genre ROI
    let worldCompletedCount = 0;

    const allStudios = [
        { id: 'PLAYER', projects: Object.values(state.entities.projects), cash: Number(state.finance.cash) || 0, name: state.studio.name },
        ...rivalsList.map(r => ({ id: r.id, projects: Object.values(r.projects || {}), cash: Number(r.cash) || 0, name: r.name }))
    ];

    allStudios.forEach(studio => {
        studio.projects.forEach(p => {
            const isFinished = ['released', 'archived', 'post_release'].includes(p.state);
            if (isFinished) worldCompletedCount++;

            // ROI Tracking
            if (p.budget > 0 && (p.revenue > 0 || isFinished)) {
                const genre = p.genre || 'Unknown';
                if (!this.genreStats[genre]) this.genreStats[genre] = { cost: 0, revenue: 0 };
                this.genreStats[genre].cost += p.budget;
                this.genreStats[genre].revenue += p.revenue;

                const formatMatch = (p.format || '').toLowerCase();
                if (formatMatch === 'tv' || formatMatch === 'series') {
                  if (!this.tvGenreStats[genre]) this.tvGenreStats[genre] = { cost: 0, revenue: 0 };
                  this.tvGenreStats[genre].cost += p.budget;
                  this.tvGenreStats[genre].revenue += p.revenue;
                }
            }
        });
    });

    // Track TV Awards dominance
    const tvAwardEvents = (summary.newsEvents || []).filter(e => e.type === 'AWARD' && e.headline.includes('Best'));
    this.totalTvAwards += tvAwardEvents.length;

    // Find Industry Leader (Highest Cash)
    const leader = allStudios.sort((a, b) => b.cash - a.cash)[0];

    // Find Top Genre ROI
    let topGenre = 'None';
    let maxROI = 0;
    Object.entries(this.genreStats).forEach(([genre, stats]) => {
        const roi = stats.cost > 0 ? (stats.revenue / stats.cost) : 0;
        if (roi > maxROI) {
            maxROI = roi;
            topGenre = genre;
        }
    });

    // Find Top TV Genre ROI
    let topTvGenre = 'None';
    let maxTvROI = 0;
    Object.entries(this.tvGenreStats).forEach(([genre, stats]) => {
        const roi = stats.cost > 0 ? (stats.revenue / stats.cost) : 0;
        if (roi > maxTvROI) {
            maxTvROI = roi;
            topTvGenre = genre;
        }
    });

    // Total industry cash (for market share)
    const totalAssets = playerCash + rivalTotalCash + platformTotalCash;
    const marketShare = totalAssets > 0 ? (playerCash / totalAssets) * 100 : 0;

    // totalSystemCash = player + rivals + platforms + (active budgets estimate)
    const activeBudgets = Object.values(state.entities.projects)
      .filter(p => !['released', 'archived', 'post_release'].includes(p.state))
      .reduce((sum, p) => sum + (p.budget || 0), 0);

    // Nielsen & Cut Analytics
    let totalNielsenDemo = 0;
    let tvProjectCount = 0;
    const cutCounts: Record<string, number> = { 'theatrical': 0, 'directors_cut': 0, 'sanitized': 0, 'unrated': 0 };

    allStudios.forEach(studio => {
        studio.projects.forEach(p => {
            const formatMatch = (p.format || '').toLowerCase();
            const nProfile = (p as any).nielsenProfile;
            if ((formatMatch === 'tv' || formatMatch === 'series') && nProfile) {
                totalNielsenDemo += Number(nProfile.seasonAvgKeyDemo) || 0;
                tvProjectCount++;
            }
            if (p.activeCut) {
                cutCounts[p.activeCut] = (cutCounts[p.activeCut] || 0) + 1;
            }
        });
    });

    // 10. Talent Pool Analysis (Optimized single-pass)
    let totalPrestige = 0;
    let aListCount = 0;
    const talentValues = Object.values(state.entities.talents || {});
    const talentPoolSize = talentValues.length;

    talentValues.forEach(t => {
        totalPrestige += t.prestige || 0;
        if (t.prestige >= 80) aListCount++;
    });

    const metrics: SimulationMetrics = {
      week: state.week,
      playerCash: playerCash,
      rivalAvgCash: rivalsList.length > 0 ? rivalTotalCash / rivalsList.length : 0,
      totalSystemCash: totalAssets + activeBudgets,
      totalMarketSentiment: state.finance.marketState?.sentiment || 50,
      talentPoolSize: talentPoolSize,
      avgTalentPrestige: totalPrestige / (talentPoolSize || 1),
      activeProjects: Object.values(state.entities.projects).reduce((acc, p) => acc + (!['released', 'archived', 'post_release'].includes(p.state) ? 1 : 0), 0),
      completedProjects: worldCompletedCount,
      retiredCount: this.totalRetired,
      bankruptcyCount: rivalsList.filter(r => (Number(r.cash) || 0) <= -50000000).length,
      marketShare: marketShare,
      industryLeader: leader?.name,
      topGenreROI: { genre: topGenre, roi: maxROI },
      tvAwardsWon: this.totalTvAwards,
      tvGenreROI: { genre: topTvGenre, roi: maxTvROI },
      averageA_ListCount: aListCount,
      totalBailoutCash: this.totalBailoutCash,
      avgNielsenKeyDemo: tvProjectCount > 0 ? totalNielsenDemo / tvProjectCount : 0,
      cutCounts: cutCounts,
      activeStudioCount: rivalsList.length + 1,
      consolidationCount: 11 - (rivalsList.length + 1)
    };

    this.history.push(metrics);
  }

  public getHistory(): SimulationMetrics[] {
    return this.history;
  }

  public getSummaryReport(): string {
    if (this.history.length === 0) return 'No data recorded.';

    const last = this.history[this.history.length - 1];
    const initial = this.history[0];

    const format = (n: number) => {
      if (Math.abs(n) > 1000000000) return (n / 1000000000).toFixed(2) + 'B';
      return (n / 1000000).toFixed(1) + 'M';
    };

    return `
--- SIMULATION REPORT (Week ${last.week}) ---
Player Cash: ${format(initial.playerCash)} -> ${format(last.playerCash)}
Active Studios: ${last.activeStudioCount} / 11 (Mergers: ${last.consolidationCount})
Total System Cash: ${format(last.totalSystemCash)}
Industry Leader: ${last.industryLeader || 'None'}
Talent Pool Size: ${last.talentPoolSize} (Avg Prestige: ${last.avgTalentPrestige.toFixed(1)})
Top Genre ROI: ${last.topGenreROI?.genre} (${last.topGenreROI?.roi.toFixed(2)}x)
Total Bankruptcies: ${last.bankruptcyCount}
World Releases: ${last.completedProjects}
Player Active Projects: ${last.activeProjects}
Total Retirements: ${last.retiredCount}
Player Market Share: ${last.marketShare.toFixed(2)}%
TV Awards Won: ${last.tvAwardsWon}
Top TV Genre ROI: ${last.tvGenreROI?.genre} (${last.tvGenreROI?.roi.toFixed(2)}x)
A-List Count: ${last.averageA_ListCount}
Avg TV Rating (18-49): ${last.avgNielsenKeyDemo.toFixed(2)}
Cut Variety: Theatrical (${last.cutCounts['theatrical']}), DirCut (${last.cutCounts['directors_cut']}), Sanitized (${last.cutCounts['sanitized']})
Total Bailout Cash (Artifical): ${format(last.totalBailoutCash)}
------------------------------------------
    `;
  }
}

import { GameState, ArchetypeKey } from '../types';
import { initializeGame } from '../core/gameInit';
import { advanceWeek } from '../core/weekAdvance';
import { RandomGenerator } from '../utils/rng';

export interface SimulationResult {
  finalState: GameState;
  durationWeeks: number;
  anomalies: string[];
  metrics: {
    totalIndustryCash: number;
    avgRivalCash: number;
    totalActiveProjects: number;
    marketShareConcentration: number; // HHI or similar
    talentBurnoutRate: number;
  }[];
}

/**
 * SimulationHarness: Headless execution engine for long-term stability testing.
 * Runs the simulation for a specified number of weeks without UI overhead.
 */
export class SimulationHarness {
  static run(
    studioName: string = "Stress Test Studios", 
    archetype: ArchetypeKey = "major", 
    weeks: number = 260,
    seed: number = 42
  ): SimulationResult {

    let state = initializeGame(studioName, archetype, seed);
    const anomalies: string[] = [];
    const metrics: SimulationResult['metrics'] = [];

    for (let w = 1; w <= weeks; w++) {
      const rng = new RandomGenerator(state.gameSeed + w + state.tickCount);

      try {
        const { newState } = advanceWeek(state, rng);
        state = newState;

        const rivalsList = Object.values(state.entities.rivals || {});
        const projectsList = Object.values(state.entities.projects || {});

        // Collect Snapshot Metrics
        const totalRivalCash = rivalsList.reduce((sum, r) => sum + r.cash, 0);
        const totalIndustryCash = totalRivalCash + state.finance.cash;
        const totalProjects = Object.keys(state.entities.projects).length + 
          rivalsList.reduce((sum, r) => sum + r.projectIds.length, 0);

        // Calculate Market Share Concentration (HHI - Herfindahl-Hirschman Index)
        const marketShares = rivalsList.map(r => r.marketShare || 0);
        const hhi = marketShares.reduce((sum, ms) => sum + (ms * 100) ** 2, 0);

        // Talent Burnout Audit
        const talentPool = Object.values(state.entities.talents || {});
        const burntOutCount = talentPool.filter(t => t.fatigue > 80).length;
        const burnoutRate = talentPool.length > 0 ? burntOutCount / talentPool.length : 0;

        metrics.push({
          totalIndustryCash,
          avgRivalCash: rivalsList.length > 0 ? totalRivalCash / rivalsList.length : 0,
          totalActiveProjects: totalProjects,
          marketShareConcentration: hhi,
          talentBurnoutRate: burnoutRate
        });

        // Anomaly Detection
        if (state.finance.cash < -100_000_000) {
            anomalies.push(`Week ${w}: Player deep in debt ($${state.finance.cash})`);
        }
        if (totalProjects < 5) {
            anomalies.push(`Week ${w}: Industrial collapse warning - only ${totalProjects} projects in production`);
        }
        if (hhi > 4000) {
            anomalies.push(`Week ${w}: Monopolistic concentration detected (HHI: ${hhi.toFixed(0)})`);
        }

        if (w % 52 === 0) {
            const avgRivalCash = rivalsList.length > 0 ? totalRivalCash / rivalsList.length : 0;
            console.log(`📍 Week ${w} Milestone: Industry Cash $${(totalIndustryCash / 1e9).toFixed(2)}B | Avg Rival Cash $${(avgRivalCash / 1e6).toFixed(1)}M`);
        }

      } catch (error) {
        anomalies.push(`Week ${w}: CRITICAL ENGINE FAILURE - ${error instanceof Error ? error.message : String(error)}`);
        break;
      }
    }


    return {
      finalState: state,
      durationWeeks: state.week,
      anomalies,
      metrics
    };
  }
}

import { GameState } from '../types';
import { initializeGame } from '../core/gameInit';
import { WeekCoordinator } from '../services/WeekCoordinator';
import { TalentLifecycleSystem } from '../systems/talent/TalentLifecycleSystem';
import { HeadlessController } from './HeadlessController';
import { MetricsCollector } from './MetricsCollector';
import { RandomGenerator } from '../utils/rng';
import { applyImpacts } from '../core/impactReducer';
import { StudioAutomation } from './StudioAutomation';

export interface SimulationResult {
  finalState: GameState;
  metrics: MetricsCollector;
}

/**
 * Simulation Runner
 * Orchestrates the headless execution of the Studio Boss engine.
 */
export class SimulationRunner {
  static run(
    weeks: number, 
    seed: number = 42, 
    archetype: any = 'major', 
    persona: string = 'balanced',
    autoPilot: boolean = true
  ): SimulationResult {
    const metrics = new MetricsCollector();
    let state = initializeGame('Headless Studio', archetype, seed);
    (state as any).persona = persona;

    // Initial record
    metrics.record(state, { fromWeek: 0, toWeek: 1 } as any);

    for (let i = 0; i < weeks; i++) {
      const rng = new RandomGenerator(state.gameSeed + state.week + (state.tickCount || 0));

      // 1. Core Engine Tick
      const { newState: steppedState, summary, impacts: engineImpacts } = WeekCoordinator.execute(state, rng);
      state = steppedState;

      // 3. Studio Automation (Greenlights, Pitches, Releases)
      // This handles the operational "blocking" states for both player and rivals
      const playerAutomation = autoPilot ? StudioAutomation.tick(state, rng) : [];
      const rivalAutomation = StudioAutomation.tick(state, rng);

      // 4. Headless Bidding/Buying for Player
      const playerBidding = autoPilot ? HeadlessController.tick(state, rng) : [];

      // 5. Talent Lifecycle (Aging/Retirement)
      const lifecycleImpacts = TalentLifecycleSystem.tick(state, rng);

      // 6. Consolidate and Apply side-effect impacts ONLY
      // Note: engineImpacts are already applied inside WeekCoordinator.execute
      const allImpacts = [
          ...playerAutomation, 
          ...rivalAutomation, 
          ...playerBidding, 
          ...lifecycleImpacts
      ];
      state = applyImpacts(state, allImpacts);

      // 7. Update Metrics (Inject summary data for reporting)
      const retiredCount = allImpacts.filter(imp => imp.type === 'TALENT_REMOVED').length;
      (summary as any).retiredCount = retiredCount;

      metrics.record(state, summary);
    }

    return {
      finalState: state,
      metrics
    };
  }
}

import { GameState, StateImpact, Project, RivalStudio } from '@/engine/types';
import { BudgetTierKey } from '@/engine/types/project.types';
import { RandomGenerator } from '../utils/rng';
import { calculateOpeningWeekend } from '../systems/releaseSimulation';
import { StreamingViewershipTracker } from '../systems/production/StreamingViewershipTracker';
import { StudioArchetype, AI_ARCHETYPES } from '../data/aiArchetypes';

export class StudioAutomation {
  /**
   * Helper function to get the StudioArchetype for a rival studio.
   * Uses archetypeId if available, falls back to behaviorId for backward compatibility.
   */
  private static getRivalArchetype(rival: RivalStudio): StudioArchetype {
    const archetypeId = rival.archetypeId || ('behaviorId' in rival ? (rival as any).behaviorId : undefined);
    if (archetypeId) {
      const archetype = AI_ARCHETYPES.find(a => a.id === archetypeId);
      if (archetype) return archetype;
    }
    // Default to BALANCED_GIANT if no archetype found
    return AI_ARCHETYPES.find(a => a.id === 'BALANCED_GIANT') || AI_ARCHETYPES[5];
  }

  /**
   * Main simulation tick for rival studios.
   * Handles project pitching, production, and high-level strategic adaptation.
   */
  static tick(state: GameState, rng: RandomGenerator): StateImpact[] {
    const impacts: StateImpact[] = [];

    const rivalsList = Object.values(state.entities.rivals || {});

    rivalsList.forEach(rival => {
      // Get archetype for archetype-driven decisions
      const archetype = this.getRivalArchetype(rival);

      // 1. Studio Status & Liquidation (use ma_willingness for platform launch decision)
      const isDistressed = (Number(rival.cash) || 0) < -50000000;

      if (isDistressed && (state.week % 4 === 0) && rng.next() < 0.1) {
          this.triggerLiquidation(rival, state, rng, impacts);
      } else if (rival.cash > 500000000 && (!rival.ownedPlatforms || rival.ownedPlatforms.length === 0)) {
          // Use ma_willingness for platform launch decision
          if (rng.next() < (0.05 * archetype.ma_willingness)) {
              this.triggerPlatformLaunch(rival, state, rng, impacts);
          }
      }

      if (isDistressed !== rival.isAcquirable) {
          impacts.push({
            type: 'RIVAL_UPDATED',
            payload: { rivalId: rival.id, update: { isAcquirable: isDistressed } }
          });
      }

      // 2. Process Individual Projects (backward compatibility for projects field)
      let activeCount = 0;
      const expiredProjectIds: string[] = [];
      const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};

      // ⚡ Bolt: Consolidated project iteration to prevent multiple filter/map array allocations
      for (const id in rivalProjects) {
        const p = rivalProjects[id];
        this.processProject(p, rival.id, state, rng, impacts, archetype);

        if (p.state !== 'archived') {
            if (p.state === 'released' && (state.week - (p.releaseWeek || 0)) > 4) {
                expiredProjectIds.push(p.id);
            } else {
                activeCount++;
            }
        }
      }

      // ⚡ Project Recycling (Keep memory usage low in long-term sims)
      if (expiredProjectIds.length > 0) {
          const updatedProjects = { ...rivalProjects };
          for (let i = 0; i < expiredProjectIds.length; i++) {
              const id = expiredProjectIds[i];
              updatedProjects[id] = { ...updatedProjects[id], state: 'archived' as any };
          }
          impacts.push({
              type: 'RIVAL_UPDATED',
              payload: { rivalId: rival.id, update: { projects: updatedProjects } }
          });
      }

      // 3. Pitch New Projects (If slot available) - use archetype for decisions
      if (activeCount < 5 && rng.next() < 0.1) {
        this.pitchNewProject(rival, state, rng, impacts, archetype);
      }
    });

    return impacts;
  }

  private static processProject(p: Project, studioId: string, state: GameState, rng: RandomGenerator, impacts: StateImpact[], archetype: StudioArchetype): void {
    // 1. Resolve Pitching (Random buyer pickup)
    if (p.state === 'pitching') {
      const eligibleBuyers = state.market.buyers.filter(b => b.archetype === 'streamer' || b.archetype === 'network');
      const buyer = rng.pick(eligibleBuyers);
      if (buyer && rng.next() < 0.3) {
        const update: Partial<Project> = { state: 'production', weeksInPhase: 0 };
        impacts.push(this.createUpdateImpact(studioId, p.id, { 
          ...update,
          buyerId: buyer.id,
          distributionStatus: buyer.archetype === 'streamer' ? 'streaming' : 'theatrical'
        }, state));
      }
    }

    // 2. Resolve Greenlight (Immediate)
    if (p.state === 'needs_greenlight') {
      const { update, subImpacts } = this.initializeProduction(p, studioId, state, rng);
      impacts.push(...subImpacts);
      impacts.push(this.createUpdateImpact(studioId, p.id, update, state));
    }

    // 3. Resolve Marketing -> Release
    if (p.state === 'marketing') {
      const tiers: ('none' | 'basic' | 'blockbuster')[] = ['none', 'basic', 'blockbuster'];
      const tier = rng.pick(tiers);
      const budgetMap = { 'none': 0, 'basic': 5000000, 'blockbuster': 25000000 };
      const marketingBudget = budgetMap[tier];

      const rivalPrestige = studioId === 'PLAYER' ? state.studio.prestige : (state.entities.rivals[studioId]?.prestige || 50);
      const { project: releasedProject } = calculateOpeningWeekend(
          { ...p, marketingLevel: tier, marketingBudget }, 
          [], 
          rivalPrestige,
          rng
      );

      // Status Transition (TV Special Case)
      let nextStatus = 'released';
      let tvUpdate = {};
      if ((p.format === 'tv' || p.type === 'SERIES') && (p as any).tvDetails) {
          nextStatus = 'ON_AIR';
          tvUpdate = { tvDetails: { ...(p as any).tvDetails, status: 'ON_AIR' } };
      }

      // Initialize streaming viewership for streaming distribution
      let streamingUpdate = {};
      if (p.distributionStatus === 'streaming' && p.buyerId) {
        const platform = state.market.buyers.find(b => b.id === p.buyerId);
        if (platform) {
          const streamingViewership = StreamingViewershipTracker.initializeViewership(
            p,
            platform.id,
            platform,
            state.week,
            rng
          );
          // Store as array to match type definition (streamingViewership?: StreamingViewershipHistory[])
          streamingUpdate = { streamingViewership: [streamingViewership] };
        }
      }

      impacts.push(this.createUpdateImpact(studioId, p.id, {
        ...releasedProject,
        ...tvUpdate,
        ...streamingUpdate,
        state: nextStatus as any,
        weeksInPhase: 0,
        releaseWeek: state.week,
        activeCrisis: null
      }, state));
    }
  }

  private static triggerLiquidation(rival: RivalStudio, state: GameState, rng: RandomGenerator, impacts: StateImpact[]): void {
      // Backward compatibility for ipAssets field
      const ipAssets = ('ipAssets' in rival && rival.ipAssets) ? Object.values((rival as any).ipAssets) : [];
      if (ipAssets.length === 0) return;

      const asset = rng.pick(ipAssets) as any;
      const bidPrice = (asset.baseValue || 10000000) * (0.5 + rng.next() * 0.5);

      impacts.push({
          type: 'NEWS_ADDED',
          payload: {
              id: rng.uuid('NWS'),
              headline: `LIQUIDATION: ${rival.name} auctions IP!`,
              description: `Facing financial pressure, ${rival.name} has sold ${asset.title} to the highest bidder for $${(bidPrice / 1000000).toFixed(1)}M.`,
              category: 'business',
              week: state.week
          }
      });

      impacts.push({
          type: 'RIVAL_UPDATED',
          payload: {
              rivalId: rival.id,
              update: {
                  cash: (Number(rival.cash) || 0) + bidPrice,
                  ipAssets: Object.fromEntries(Object.entries((rival as any).ipAssets || {}).filter(([id]) => id !== asset.id))
              }
          }
      });
  }

  private static triggerPlatformLaunch(rival: RivalStudio, state: GameState, rng: RandomGenerator, impacts: StateImpact[]): void {
      const cost = 200000000;
      impacts.push({
          type: 'NEWS_ADDED',
          payload: {
              id: rng.uuid('NWS'),
              headline: `BUSINESS: ${rival.name} launches streaming service!`,
              description: `Aiming for vertical integration, ${rival.name} has invested $200M in a new SVOD platform.`,
              category: 'business',
              week: state.week
          }
      });
      impacts.push({
          type: 'RIVAL_UPDATED',
          payload: { rivalId: rival.id, update: { cash: (Number(rival.cash) || 0) - cost } }
      });
  }

  private static pitchNewProject(rival: RivalStudio, state: GameState, rng: RandomGenerator, impacts: StateImpact[], archetype: StudioArchetype): void {
    const id = rng.uuid('PRJ');

    // Use archetype properties for decision making
    // greenlight_bias: ProjectFormat[] - determines format bias
    const formatBias = archetype.greenlight_bias;
    const format = formatBias.length > 0 ? rng.pick(formatBias) : (rng.next() < 0.3 ? 'tv' : 'film');

    // genreFocus: string[] - determines genre preference
    const genreFocus = archetype.genreFocus;
    const genres = genreFocus.length > 0 && genreFocus[0] !== 'Any' ? genreFocus : ['Action', 'Drama', 'Comedy', 'Sci-Fi', 'Horror', 'Family'];
    const genre = rng.pick(genres);

    // budget_tier_weights: Record<BudgetTierKey, number> - determines budget tier
    const budgetTiers: BudgetTierKey[] = ['indie', 'low', 'mid', 'high', 'blockbuster'];
    const weights = budgetTiers.map(tier => archetype.budget_tier_weights[tier]);
    const budgetTier = this.weightedRandom(budgetTiers, weights, rng);

    const project: any = {
      id,
      title: `${genre} ${rng.rangeInt(1, 100)}`,
      genre,
      format,
      type: format === 'tv' ? 'SERIES' : 'FILM',
      state: 'pitching',
      weeksInPhase: 0,
      budgetTier,
      buzz: rng.rangeInt(20, 50),
      reviewScore: rng.rangeInt(40, 75),
      ownerId: rival.id, // Set ownerId for unified storage
      archetypeId: archetype.id, // Set archetypeId for archetype-driven behavior
    };

    if (format === 'tv') {
        project.tvDetails = {
            status: 'IN_DEVELOPMENT',
            episodesOrdered: rng.rangeInt(8, 13),
            episodesAired: 0,
            averageRating: 0
        };
    }

    // Backward compatibility for projects field
    const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
    impacts.push({
      type: 'RIVAL_UPDATED',
      payload: { rivalId: rival.id, update: { projects: { ...rivalProjects, [id]: project } } }
    });
  }

  /**
   * Helper function for weighted random selection based on weights
   */
  private static weightedRandom<T>(items: T[], weights: number[], rng: RandomGenerator): T {
    const totalWeight = weights.reduce((sum, w) => sum + w, 0);
    let random = rng.next() * totalWeight;
    for (let i = 0; i < items.length; i++) {
      random -= weights[i];
      if (random <= 0) return items[i];
    }
    return items[items.length - 1];
  }

  private static initializeProduction(p: Project, studioId: string, state: GameState, rng: RandomGenerator): { update: Partial<Project>; subImpacts: StateImpact[] } {
    const subImpacts: StateImpact[] = [];
    const update: Partial<Project> = {
      state: 'production',
      weeksInPhase: 0,
      productionWeeks: rng.rangeInt(12, 26),
      budget: p.budget || rng.rangeInt(10, 80) * 1_000_000,
      buzz: p.buzz || 40,
      rating: 'PG-13',
      activeCut: rng.next() < 0.2 ? 'sanitized' : 'theatrical'
    };
    return { update, subImpacts };
  }

  private static createUpdateImpact(studioId: string, projectId: string, update: Partial<Project>, state: GameState): StateImpact {
    if (studioId === 'PLAYER') {
      return { type: 'PROJECT_UPDATED', payload: { projectId, update } };
    } else {
      const rival = state.entities.rivals[studioId];
      // Backward compatibility for projects field
      const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
      const existingProject = rivalProjects[projectId] || {};
      return {
        type: 'RIVAL_UPDATED',
        payload: { rivalId: studioId, update: { projects: { ...rivalProjects, [projectId]: { ...existingProject, ...update } } } }
      };
    }
  }
}

