/**
 * Simulate weekly buyer/platform dynamics — financial health and M&A activity.
 * Subscriber fluctuations are handled by platformEngine.ts.
 */
export function advanceBuyers(state: GameState, rng: RandomGenerator): StateImpact {
  const impact: StateImpact = {
    buyerUpdates: [],
    newHeadlines: [],
  };

  const currWeek = state.week;
  const buyers = state.market.buyers;
  const activeBuyers = buyers.filter(b => !b.acquiredBy);

  // Update each active buyer's financial health
  for (const buyer of activeBuyers) {
    const update: Partial<Buyer> = {};
    const currentCash = buyer.cash ?? 50_000_000;
    const currentStrength = buyer.strength ?? 60;

    let performance = 0;

    if (buyer.archetype === 'streamer') {
      const streamer = buyer as StreamerPlatform;
      // Financials based on existing subscribers (updated in platformEngine)
      const revenue = streamer.subscribers * 0.8; 
      const costs = (streamer.marketingSpend || 0) + (streamer.contentLibraryQuality * 50_000);
      const newCash = currentCash + revenue - costs;

      update.cash = newCash;
      // Strength drifts based on financial performance
      performance = (revenue - costs) / 1_000_000;
      update.strength = Math.max(10, Math.min(100, currentStrength + performance));

      if (rng.next() < 0.02) {
        impact.newHeadlines!.push({
          id: rng.uuid('NWS'),
          week: currWeek,
          category: 'market',
          text: BardResolver.resolve({
            domain: 'Market',
            subDomain: 'StreamerEvent',
            intensity: performance > 0 ? 80 : 20,
            context: { actor: buyer.name },
            rng
          })
        });
      }
    } else {
      const cashDelta = Math.floor(rng.range(-2_000_000, 5_000_000));
      update.cash = currentCash + cashDelta;
      update.strength = Math.max(10, Math.min(100, currentStrength + Math.floor(rng.range(-2, 2))));
    }

    // Vulnerability Check
    const finalCash = update.cash ?? currentCash;
    const finalStrength = update.strength ?? currentStrength;

    if (finalCash < 10_000_000 && finalStrength < 35) {
      if (!buyer.isAcquirable) {
        update.isAcquirable = true;
        impact.newHeadlines!.push({
          id: rng.uuid('NWS'),
          week: currWeek,
          category: 'market',
          text: BardResolver.resolve({
            domain: 'Industry',
            subDomain: 'Vulnerability',
            intensity: 10,
            context: { actor: buyer.name },
            rng
          })
        });
      }
    } else {
      update.isAcquirable = false;
    }

    impact.buyerUpdates!.push({ buyerId: buyer.id, update });
  }

  // M&A Execution
  if (rng.next() < 0.08) {
    const vulnerable = activeBuyers.filter(b => b.isAcquirable);
    const strong = activeBuyers.filter(b => !b.isAcquirable && (b.strength ?? 60) > 70);

    if (vulnerable.length > 0 && strong.length > 0) {
      const acquirer = pick(strong, rng);
      const target = pick(vulnerable, rng);

      if (acquirer.id !== target.id) {
        const maHistory = [...(target.maHistory || [])];
        maHistory.push({
          week: currWeek,
          event: `Acquired by ${acquirer.name}`,
          value: target.cash // Using cash as proxy for valuation
        });

        impact.buyerUpdates!.push({
          buyerId: target.id,
          update: {
            acquiredBy: acquirer.id,
            parentCompany: acquirer.name,
            maHistory
          }
        });

        impact.buyerUpdates!.push({
          buyerId: acquirer.id,
          update: {
            ownedPlatforms: [...(acquirer.ownedPlatforms || []), target.id],
            strength: Math.min(100, (acquirer.strength ?? 60) + 12),
          }
        });

        impact.newHeadlines!.push({
          id: rng.uuid('NWS'),
          week: currWeek,
          category: 'market',
          text: BardResolver.resolve({
            domain: 'Industry',
            subDomain: 'Merger',
            intensity: 90,
            context: { actor: acquirer.name, target: target.name },
            rng
          })
        });
      }
    }
  }

  const mandateImpact = updateBuyers(activeBuyers, currWeek, rng);

  return mergeImpacts(impact, mandateImpact);
}

import { Buyer, MandateType, Project, ProjectContractType, StateImpact } from '@/engine/types';
import { RandomGenerator } from '../utils/rng';

const MANDATE_TYPES: MandateType[] = [
  'sci-fi', 'comedy', 'drama', 'budget_freeze', 'broad_appeal', 'prestige'
];

const AVAILABLE_MANDATES = new Map<string, MandateType[]>();
AVAILABLE_MANDATES.set('none', MANDATE_TYPES);
for (let i = 0; i < MANDATE_TYPES.length; i++) {
  const type = MANDATE_TYPES[i];
  AVAILABLE_MANDATES.set(type, MANDATE_TYPES.filter(m => m !== type));
}

export function updateBuyers(buyers: Buyer[], currentWeek: number, rng: RandomGenerator): StateImpact {
  const impact: StateImpact = {
    buyerUpdates: [],
    newHeadlines: []
  };

  buyers.forEach((buyer) => {
    if (!buyer.currentMandate || buyer.currentMandate.activeUntilWeek <= currentWeek || rng.next() < 0.05) {
      const currentType = buyer.currentMandate?.type || 'none';
      const availableTypes = AVAILABLE_MANDATES.get(currentType) || MANDATE_TYPES;
      const newMandateType = rng.pick(availableTypes);
      const duration = Math.floor(rng.range(12, 36));

      impact.buyerUpdates!.push({
        buyerId: buyer.id,
        update: {
          currentMandate: {
            type: newMandateType,
            activeUntilWeek: currentWeek + duration,
          }
        }
      });

      let headlineText = "";
      switch (newMandateType) {
        case 'sci-fi':
          headlineText = `Industry chatter: ${buyer.name} is desperately looking for the next big Sci-Fi hit.`;
          break;
        case 'comedy':
          headlineText = `${buyer.name} shifts focus, seeking half-hour comedies for their upcoming slate.`;
          break;
        case 'drama':
          headlineText = `New mandate at ${buyer.name}: high-stakes drama is the priority.`;
          break;
        case 'budget_freeze':
          headlineText = `Austerity hits ${buyer.name}! Execs are instituting a sudden budget freeze on new pitches.`;
          break;
        case 'broad_appeal':
          headlineText = `${buyer.name} pivots to four-quadrant, broad appeal projects after subscriber churn.`;
          break;
        case 'prestige':
          headlineText = `Awards chase: ${buyer.name} announces a massive fund specifically for prestige projects.`;
          break;
      }

      if (headlineText && rng.next() < 0.6) { 
        impact.newHeadlines!.push({
          id: rng.uuid('NWS'),
          week: currentWeek,
          category: 'market',
          text: headlineText
        });
      }
    }
  });

  return impact;
}

export function calculateFitScore(project: Project, buyer: Buyer, currentWeek: number, allProjects: Record<string, Project>, rng: RandomGenerator): number {
  let score = 50; 

  let recentSimilarProjectsCount = 0;
  for (const key in allProjects) {
    if (!Object.prototype.hasOwnProperty.call(allProjects, key)) continue;
    const p = allProjects[key];
    if (
      p.state === 'released' &&
      p.genre === project.genre &&
      p.releaseWeek !== null &&
      (currentWeek - p.releaseWeek) <= 52 &&
      p.id !== project.id
    ) {
      recentSimilarProjectsCount++;
    }
  }

  let saturationPenalty = recentSimilarProjectsCount * 5;
  if (recentSimilarProjectsCount >= 5) {
    saturationPenalty += 20;
  }

  if (recentSimilarProjectsCount >= 5 && project.genre?.toLowerCase().includes('superhero')) {
    saturationPenalty *= 3;
    saturationPenalty += 75;
  }

  if (saturationPenalty > 0) {
    score -= saturationPenalty;
  }

  if (recentSimilarProjectsCount === 0) {
    score += 15;
  }

  if (buyer.currentMandate) {
    const mandate = buyer.currentMandate.type;
    const lowerGenre = project.genre.toLowerCase();
    if (mandate === 'sci-fi' && (lowerGenre.includes('sci-fi') || lowerGenre.includes('fantasy'))) score += 30;
    if (mandate === 'comedy' && lowerGenre.includes('comedy')) score += 30;
    if (mandate === 'drama' && lowerGenre.includes('drama')) score += 30;

    if (mandate === 'prestige' && project.budgetTier === 'high') score += 20;
    if (mandate === 'prestige' && project.budgetTier === 'blockbuster') score += 10;
    if (mandate === 'prestige' && project.budgetTier === 'low') score -= 20;

    if (mandate === 'broad_appeal' && (project.budgetTier === 'mid' || project.budgetTier === 'high')) score += 20;
    if (mandate === 'broad_appeal' && project.targetAudience.toLowerCase().includes('family')) score += 15;

    // 🎭 The Method Actor Tuning: Buyers experiencing a "budget_freeze" mandate will aggressively target low-budget projects and heavily penalize blockbusters.
    if (mandate === 'budget_freeze') {
      if (project.budgetTier === 'blockbuster') score -= 60;
      if (project.budgetTier === 'high') score -= 40;
      if (project.budgetTier === 'low') score += 35;
    }
  }

  if (buyer.archetype === 'network' && project.budgetTier === 'blockbuster') score -= 20;
  if (buyer.archetype === 'premium' && project.budgetTier === 'low') score -= 30;

  // 🎭 The Method Actor Tuning: Network buyers heavily penalize low-buzz projects as they require immediate viewership, whereas Premium buyers take risks on low-budget prestige projects.
  if (buyer.archetype === 'network' && project.buzz < 40) score -= 25;
  const scriptHeat = 'scriptHeat' in project ? project.scriptHeat : 50;
  if (buyer.archetype === 'premium' && project.budgetTier === 'low' && scriptHeat > 70) score += 20;

  // 🎭 The Method Actor Tuning: Streamers bid aggressively on franchise IP genres (Action/Sci-Fi/Fantasy).
  if (buyer.archetype === 'streamer' && ['action', 'sci-fi', 'fantasy'].includes(project.genre.toLowerCase())) {
    score += 25;
  }

  // 🎭 The Method Actor Tuning: Streamers prioritize serialized content and established IPs to build subscriber loyalty.
  if (buyer.archetype === 'streamer') {
    if (project.type === 'SERIES') {
      score += 20;
    } else {
      // 🎭 The Method Actor Tuning: Streamers penalize standalone movies unless they are established franchise IPs.
      if (!project.franchiseId) {
         score -= 15;
      }
    }
  }

  const buzzFactor = (project.buzz / 100) * 20; 
  score += buzzFactor;
  score += rng.range(-10, 10);

  return Math.max(0, Math.min(100, score));
}

export function negotiateContract(project: Project, buyer: Buyer, requestedType: ProjectContractType, currentWeek: number, allProjects: Record<string, Project>, rng: RandomGenerator): boolean {
    const fitScore = calculateFitScore(project, buyer, currentWeek, allProjects, rng);
    const requiredScore = requestedType === 'upfront' ? 65 : 40;
    return fitScore >= requiredScore;
}

import { pick } from '../utils';
import { Project, ActiveCrisis, GameState } from '@/engine/types';
import { StateImpact } from '../types/state.types';
import { CRISIS_POOLS } from '../data/crises.data';
import { RandomGenerator } from '../utils/rng';
import { BardResolver } from './bardResolver';
import { StudioArchetype } from '../data/aiArchetypes';
import { calculateSocialCrisisModifier } from './talent/OrganicEventEnhancer';

/**
 * Procedural Crisis Generation (Hardened)
 * Returns a StateImpact that adds a crisis to a project.
 * Uses archetype strategy to determine crisis type preferences if archetype is provided.
 */
export function generateCrisis(project: Project, rng: RandomGenerator, archetype?: StudioArchetype): StateImpact | null {
  // Use archetype strategy to determine crisis type preferences
  let crisisPool = CRISIS_POOLS;

  if (archetype) {
    // Risk-averse archetypes avoid production crises (prefer PR/financial crises)
    // Production crises have descriptions containing "PRODUCTION" or "SAFETY"
    if (archetype.strategy === 'prestige_chaser' || archetype.riskAppetite < 40) {
      crisisPool = crisisPool.filter(c => !c.description.includes('PRODUCTION') && !c.description.includes('SAFETY'));
    }
    // Risk-seeking archetypes have higher chance of production crises
    else if (archetype.strategy === 'acquirer' || archetype.riskAppetite > 60) {
      // Give higher weight to production crises by duplicating them in the pool
      const productionCrises = crisisPool.filter(c => c.description.includes('PRODUCTION') || c.description.includes('SAFETY'));
      crisisPool = [...crisisPool, ...productionCrises];
    }
  }

  const template = pick(crisisPool, rng);
  if (!template) return null;

  const crisis: ActiveCrisis = {
    id: rng.uuid('CRS'),
    crisisId: template.id,
    triggeredWeek: 0,
    haltedProduction: false,
    description: BardResolver.resolve({
      domain: 'Crisis',
      subDomain: template.description, // e.g., 'PR' or 'Production'
      intensity: 75,
      context: { project: project.title },
      rng
    }),
    options: template.options.map(opt => ({
      ...opt,
      text: BardResolver.resolve({
        domain: 'Crisis',
        subDomain: `${template.description}.Options`, // e.g., 'PR.Options'
        variant: opt.text, // e.g., 'Aggressive'
        intensity: 50,
        rng
      })
    })),
    resolved: false,
    severity: 'medium'
  };

  return {
    projectUpdates: [{
      projectId: project.id,
      update: { activeCrisis: crisis }
    }],
    uiNotifications: [`CRISIS: "${project.title}" - ${crisis.description}`]
  };
}

/**
 * Weekly roll for a production crisis.
 * Integrated into the WeekCoordinator pipeline.
 * Uses archetype riskAppetite to adjust crisis probability if archetype is provided.
 */
export function checkAndTriggerCrisis(project: Project, state: GameState, rng: RandomGenerator, archetype?: StudioArchetype): StateImpact | null {
  const studioProjectsCount = Object.keys(state.entities.projects || {}).length;
  const contractCount = Object.keys(state.entities.contracts || {}).length;

  // The PR Spin Doctor: Heavily scale crises with studio size
  // Adjusted: Base 5% chance, plus 5.0% for every concurrent project and 2.5% for every contract
  let baseChance = Math.min(0.8, 0.05 + (studioProjectsCount * 0.050) + (contractCount * 0.025));

  // Adjust crisis probability based on archetype riskAppetite (0-100)
  // Higher riskAppetite = higher crisis probability
  if (archetype) {
    const riskMultiplier = 0.5 + (archetype.riskAppetite / 100); // 0.5x to 1.5x multiplier
    baseChance = Math.min(0.9, baseChance * riskMultiplier);
  }

  // Apply social crisis modifier (feuds, toxic cliques increase crisis chance)
  const socialModifier = calculateSocialCrisisModifier(project.id, state);
  baseChance = Math.min(0.95, baseChance * socialModifier);

  if (rng.next() < baseChance) {
    return generateCrisis(project, rng, archetype);
  }
  return null;
}

/**
 * Resolves a crisis through player (or AI) choice.
 * Always returns a deterministic impact based on the selected option.
 */
export function resolveCrisis(state: GameState, projectId: string, optionIndex: number, rng: RandomGenerator): StateImpact {
  const project = state.entities.projects[projectId];
  if (!project || !project.activeCrisis || project.activeCrisis.resolved) {
    return {};
  }

  const option = project.activeCrisis.options[optionIndex];
  if (!option) return {};

  const impact: StateImpact = {
    cashChange: option.cashPenalty ? -option.cashPenalty : 0,
    prestigeChange: option.reputationPenalty ? -option.reputationPenalty : 0,
    projectUpdates: [],
    removeContracts: [],
    newHeadlines: [],
    newsEvents: []
  };

  const projectUpdate: Partial<Project> = {
    activeCrisis: {
      ...project.activeCrisis,
      resolved: true
    }
  };

  if (option.weeksDelay) {
    projectUpdate.productionWeeks = (project.productionWeeks || 0) + option.weeksDelay;
  }

  if (option.buzzPenalty) {
    projectUpdate.buzz = Math.max(0, (project.buzz || 0) - option.buzzPenalty);
  }

  impact.projectUpdates!.push({
    projectId,
    update: projectUpdate
  });

  if (option.removeTalentId) {
    impact.removeContracts!.push(`${projectId}:${option.removeTalentId}`);
  }

  impact.newHeadlines!.push({
    id: rng.uuid('NWS'),
    week: state.week,
    category: 'general',
    text: `Crisis resolved for "${project.title}": ${option.text}`
  });

  impact.newsEvents!.push({
    id: rng.uuid('NWS'),
    week: state.week,
    type: 'CRISIS',
    headline: `Crisis at ${project.title}`,
    description: `The production faced a major setback: ${project.activeCrisis.description.slice(0, 100)}... Studio resolved it by: ${option.text}`,
  });

  return impact;
}

import { Project, AudienceQuadrant, DemographicGroup, GameState } from '@/engine/types';

/**
 * Evaluates how strongly a project resonates with a specific marketing target audience.
 * Returns a score between 0.0 and 2.0 (where >1.0 means highly efficient reach).
 */
export function calculateAudienceIndex(project: Project, target: AudienceQuadrant): number {
  let index = 1.0;

  // Genre affinities
  if (target.includes('male')) {
    if (project.genre === 'Action' || project.genre === 'Sci-Fi') index += 0.3;
    if (project.genre === 'Romance') index -= 0.3;
  }

  if (target.includes('female')) {
    if (project.genre === 'Romance' || project.genre === 'Drama') index += 0.3;
    if (project.genre === 'Action') index -= 0.2;
  }

  if (target.includes('under_25')) {
    if (project.genre === 'Horror' || project.genre === 'Animation') index += 0.4;
    if (project.genre === 'Documentary' || project.genre === 'Historical') index -= 0.4;
  }

  if (target.includes('over_25')) {
    if (project.genre === 'Documentary' || project.genre === 'Thriller') index += 0.2;
    if (project.genre === 'Animation') index -= 0.3;
  }

  if (target === 'four_quadrant') {
    // Four quadrant requires high budget / broad appeal
    if (project.budgetTier === 'blockbuster') index += 0.5;
    else if (project.budgetTier === 'low') index -= 0.4;

    // Niche genres hurt 4-quadrant
    if (project.genre === 'Horror' || project.genre === 'Documentary') index -= 0.5;
  }

  // Content Rating affinity
  if (project.rating === 'R' || project.rating === 'NC-17') {
    if (target.includes('under_25') || target === 'four_quadrant') {
      index -= 0.5; // Restricting access drops efficiency massively
    } else {
      index += 0.2; // Over_25 might actually like edgy content more
    }
  }

  if (project.rating === 'G' || project.rating === 'PG') {
    if (target.includes('over_25') && project.genre !== 'Animation') {
      index -= 0.3; // Adults might find it boring
    }
  }

  return Math.max(0.1, Math.min(2.0, index));
}

/**
 * Executes a marketing push, spending cash to generate buzz.
 */
export function simulateMarketingCampaign(
  state: GameState, 
  projectId: string, 
  spend: number, 
  target: AudienceQuadrant
): GameState {

  const project = state.entities.projects[projectId];

  if (!project || state.finance.cash < spend) return state;

  // Calculate how much buzz this spend buys
  const baseBuzzGain = (spend / 100_000); // 1 buzz point per 100k

  // Modify by audience index
  const alignment = calculateAudienceIndex(project, target);

  const finalBuzzGain = Math.floor(baseBuzzGain * alignment);

  // Record marketing spend in the project
  const updatedProject = {
    ...project,
    buzz: Math.min(100, project.buzz + finalBuzzGain),
    marketingBudget: (project.marketingBudget || 0) + spend,
    targetDemographic: target
  };

  return {
    ...state,
    finance: { ...state.finance, cash: state.finance.cash - spend },
    entities: {
      ...state.entities,
      projects: {
        ...state.entities.projects,
        [projectId]: updatedProject
      }
    }
  };
}

import { Project, Talent, Contract, StateImpact, GameState } from '@/engine/types';
import { DirectorArchetype } from '@/engine/types/talent.types';
import { RandomGenerator } from '../utils/rng';

/**
 * Checks if the director for a given project has final cut / creative control.
 */
export function hasCreativeControl(projectId: string, state: GameState): boolean {
  const directorContract = Object.values(state.entities.contracts).find(c =>
    c.projectId === projectId &&
    state.entities.talents[c.talentId]?.roles.includes('director')
  );

  if (!directorContract) return false;
  return !!directorContract.creativeControl;
}

/**
 * Returns the probability (0–1) that a director of the given archetype
 * will demand creative control as part of contract negotiations.
 */
export function getCreativeControlDemandChance(archetype: DirectorArchetype): number {
  switch (archetype) {
    case 'auteur':       return 0.70;
    case 'visionary':    return 0.60;
    case 'journeyman':   return 0.20;
    case 'commercial_hack': return 0.05;
    default:             return 0.10;
  }
}

export interface CreativeControlNegotiationResult {
  willingnessModifier: number;  // Added to willingness score
  feeModifier: number;          // Fractional change to demanded fee (e.g. -0.10 = 10% discount)
  directorWalks: boolean;       // True if director refuses and leaves the negotiation
}

/**
 * Evaluates the outcome of offering or denying creative control to a director.
 * Call this during contract negotiation UI flow before finalizing the deal.
 */
export function evaluateCreativeControlOffer(
  director: Talent,
  playerOffersControl: boolean,
  rng: RandomGenerator
): CreativeControlNegotiationResult {
  const archetype = director.directorArchetype ?? 'journeyman';

  if (playerOffersControl) {
    return {
      willingnessModifier: 20,
      feeModifier: -0.10,
      directorWalks: false
    };
  }

  // Director denied creative control
  switch (archetype) {
    case 'auteur':
      return {
        willingnessModifier: -15,
        feeModifier: 0,
        directorWalks: rng.next() < 0.60
      };
    case 'visionary':
      return {
        willingnessModifier: -10,
        feeModifier: 0,
        directorWalks: rng.next() < 0.30
      };
    case 'journeyman':
      return {
        willingnessModifier: -5,
        feeModifier: 0,
        directorWalks: false
      };
    case 'commercial_hack':
    default:
      return {
        willingnessModifier: -2,
        feeModifier: 0,
        directorWalks: false
      };
  }
}

/**
 * Periodically called during the 'production' phase to randomly spawn disputes.
 * Handles both budget disputes (existing) and vision-compromise disputes (new).
 */
export function processDirectorDisputes(
  project: Project,
  projectContracts: Contract[],
  talentPool: Record<string, Talent>,
  rng: RandomGenerator
): StateImpact {
  const impact: StateImpact = {
    projectUpdates: [],
    uiNotifications: []
  };

  if (project.state !== 'production') return impact;

  const dirContract = projectContracts.find(c => c.projectId === project.id);
  if (!dirContract) return impact;

  const director = talentPool[dirContract.talentId];
  if (!director || !director.roles.includes('director')) return impact;

  const archetype: DirectorArchetype = director.directorArchetype ?? 'journeyman';

  // Budget dispute (existing behavior)
  const budgetDisputeChance = archetype === 'auteur' ? 0.05
    : archetype === 'visionary' ? 0.04
    : 0.01;

  if (rng.next() < budgetDisputeChance && !project.activeCrisis) {
    impact.projectUpdates!.push({
      projectId: project.id,
      update: {
        activeCrisis: {
          id: rng.uuid('CRS'),
          crisisId: rng.uuid('CRS'),
          triggeredWeek: 0,
          haltedProduction: false,
          description: `Director ${director.name} is demanding an immediate $5M budget increase to shoot a highly ambitious sequence, threatening to walk off set!`,
          resolved: false,
          severity: 'high',
          options: [
            {
              text: "Approve the $5M increase",
              effectDescription: "Lose $5M but keep the director happy.",
              cashPenalty: 5_000_000
            },
            {
              text: "Deny request",
              effectDescription: "Saves cash, but delays production by 2 weeks and furious director tanks buzz.",
              weeksDelay: 2,
              buzzPenalty: 15
            }
          ]
        }
      }
    });
    impact.uiNotifications!.push(`A massive creative dispute erupted on the set of "${project.title}"!`);
    return impact;
  }

  // Vision-compromise dispute — auteurs without final cut, 3%/week
  const visionDisputeChance = (archetype === 'auteur' || archetype === 'visionary') && !dirContract.creativeControl ? 0.03 : 0;

  if (visionDisputeChance > 0 && rng.next() < visionDisputeChance && !project.activeCrisis) {
    impact.projectUpdates!.push({
      projectId: project.id,
      update: {
        activeCrisis: {
          id: rng.uuid('CRS'),
          crisisId: rng.uuid('CRS'),
          triggeredWeek: 0,
          haltedProduction: false,
          description: `Director ${director.name} is threatening to publicly disown "${project.title}" unless given creative approval over the final cut.`,
          resolved: false,
          severity: 'medium',
          options: [
            {
              text: "Grant Creative Control",
              effectDescription: "Amend the contract to give the director final cut. Boosts their mood significantly."
            },
            {
              text: "Hold the Line",
              effectDescription: "Deny the request. The director stays but morale craters and buzz takes a hit.",
              buzzPenalty: 10,
              reputationPenalty: 3
            }
          ]
        }
      }
    });
    impact.uiNotifications!.push(`A vision dispute erupted on the set of "${project.title}"!`);
  }

  return impact;
}

import { GameState, StateImpact, Project, RivalStudio, FestivalSubmission, AwardBody } from '@/engine/types';
import { RandomGenerator } from '../utils/rng';
import { BardResolver } from './bardResolver';
import { StudioArchetype, AI_ARCHETYPES } from '../data/aiArchetypes';

export const FESTIVALS: { body: AwardBody, name: string, weeks: number[], cost: number, prestigeNeeded: number, buzzReward: number }[] = [
  { body: 'Sundance Film Festival', name: 'Sundance', weeks: [3, 4], cost: 25000, prestigeNeeded: 40, buzzReward: 30 },
  { body: 'Cannes Film Festival', name: 'Cannes', weeks: [20, 21], cost: 50000, prestigeNeeded: 60, buzzReward: 50 },
  { body: 'Venice Film Festival', name: 'Venice', weeks: [35, 36], cost: 50000, prestigeNeeded: 70, buzzReward: 40 },
  { body: 'Berlin International Film Festival', name: 'Berlinale', weeks: [8, 9], cost: 35000, prestigeNeeded: 50, buzzReward: 35 }
];

export const FESTIVAL_BY_BODY = FESTIVALS.reduce((acc, f) => {
  acc[f.body] = f;
  return acc;
}, {} as Partial<Record<AwardBody, typeof FESTIVALS[0]>>);

/**
 * Helper function to get the StudioArchetype for a rival studio.
 */
function getRivalArchetype(rival: RivalStudio): StudioArchetype | undefined {
  const archetypeId = rival.archetypeId || ('behaviorId' in rival ? (rival as any).behaviorId : undefined);
  if (archetypeId) {
    const archetype = AI_ARCHETYPES.find(a => a.id === archetypeId);
    if (archetype) return archetype;
  }
  return undefined;
}

/**
 * Weekly Festival Resolver
 * Processes submissions from ALL studios.
 * Uses archetype properties to adjust festival behavior if archetypes are provided.
 */
export function resolveFestivals(state: GameState, rng: RandomGenerator, rivalArchetypes?: Record<string, StudioArchetype>): StateImpact[] {
  if (!state.industry.festivalSubmissions || state.industry.festivalSubmissions.length === 0) return [];

  const impacts: StateImpact[] = [];
  const updatedSubmissions: FestivalSubmission[] = [];
  const rivalsList = Object.values(state.entities.rivals || {});

  for (const sub of state.industry.festivalSubmissions) {
    if (sub.status !== 'submitted') {
        updatedSubmissions.push(sub);
        continue;
    }

    const fest = FESTIVAL_BY_BODY[sub.festivalBody];
    if (!fest) {
        updatedSubmissions.push(sub);
        continue;
    }

    const weekOfCycle = state.week % 52 === 0 ? 52 : state.week % 52;
    if (fest.weeks.includes(weekOfCycle)) {
      // Find the project and its owner from unified storage
      const project = state.entities.projects[sub.projectId];
      if (!project) {
          updatedSubmissions.push(sub);
          continue;
      }

      const ownerId = project.ownerId || 'PLAYER';
      const rival = ownerId !== 'PLAYER' ? rivalsList.find(r => r.id === ownerId) : null;

      const ownerPrestige = ownerId === 'PLAYER' ? state.studio.prestige : (rival?.prestige || 50);
      const baseChance = (project.reviewScore || 50) + (ownerPrestige * 0.5);

      // Use archetype properties to adjust acceptance chance if available
      let adjustedChance = baseChance;
      if (ownerId !== 'PLAYER' && rival && rivalArchetypes?.[rival.id]) {
        const archetype = rivalArchetypes[rival.id];
        // Higher awardObsession = higher acceptance chance
        const awardMultiplier = 0.8 + (archetype.awardObsession / 250); // 0.8x to 1.2x multiplier
        adjustedChance = baseChance * awardMultiplier;
      }

      const isAccepted = adjustedChance > (fest.prestigeNeeded + rng.range(-20, 20));

      if (isAccepted) {
        // Success: Buzz and Prestige
        const buzzGain = Math.min(100, project.buzz + fest.buzzReward);

        if (ownerId === 'PLAYER') {
            impacts.push({
                type: 'PROJECT_UPDATED',
                payload: { projectId: project.id, update: { buzz: buzzGain } }
            });
            impacts.push({ type: 'PRESTIGE_CHANGED', payload: 2 });
        } else {
            impacts.push({
                type: 'PROJECT_UPDATED',
                payload: { projectId: project.id, update: { buzz: buzzGain } }
            });
            impacts.push({
                type: 'RIVAL_UPDATED',
                payload: {
                    rivalId: ownerId,
                    update: {
                        prestige: Math.min(100, (rival?.prestige || 50) + 2)
                    }
                }
            });
        }

        impacts.push({
            type: 'NEWS_ADDED',
            payload: {
                headline: `FESTIVALS: ${project.title}`,
                description: BardResolver.resolve({
                    domain: 'Festival',
                    subDomain: 'Reaction',
                    intensity: 90,
                    context: { project: project.title, body: fest.body },
                    rng
                }),
                category: 'awards'
            }
        });

        updatedSubmissions.push({ ...sub, status: 'selected' as const, buzzGain: fest.buzzReward });
      } else {
        updatedSubmissions.push({ ...sub, status: 'rejected' as const });
      }
    } else {
      updatedSubmissions.push(sub);
    }
  }

  // Update state with a rolling 8-week TTL for all submissions to prevent state bloat
  impacts.push({
    type: 'INDUSTRY_UPDATE',
    payload: {
        update: { 'industry.festivalSubmissions': updatedSubmissions.filter(s => (state.week - s.week) < 8) }
    }
  });

  return impacts;
}

/**
 * Submits a project to a festival.
 * Phase 2: Deducts entry fee and adds to global submissions list.
 */
export function submitToFestival(
  state: GameState, 
  projectId: string, 
  festivalBody: AwardBody, 
  rng: RandomGenerator
): StateImpact[] | null {
  const project = state.entities.projects[projectId];
  const fest = FESTIVAL_BY_BODY[festivalBody];

  if (!project || !fest) return null;
  if (state.finance.cash < fest.cost) return null;

  const impacts: StateImpact[] = [
    {
      type: 'FUNDS_DEDUCTED',
      payload: { amount: fest.cost }
    },
    {
      type: 'INDUSTRY_UPDATE',
      payload: {
        update: {
          'industry.festivalSubmissions': [
            ...(state.industry.festivalSubmissions || []),
            {
              id: rng.uuid('SUB'),
              projectId,
              festivalBody,
              status: 'submitted',
              week: state.week
            }
          ]
        }
      }
    },
    {
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        headline: `Submission: ${project.title}`,
        description: BardResolver.resolve({
            domain: 'Festival',
            subDomain: 'Buzz',
            intensity: 40,
            context: { project: project.title, body: fest.body },
            rng
        }),
        category: 'awards'
      }
    }
  ];

  return impacts;
}

import { GameState, StateImpact, Project, RivalStudio } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';
import { FestivalSubmission } from '@/engine/types/project.types';

// Festival market weeks: Sundance (4), Cannes (20), TIFF (36)
export const FESTIVAL_MARKET_WEEKS = [4, 20, 36] as const;

export interface FestivalBid {
  bidderId: string;
  bidderName: string;
  amount: number;
  terms: string;
}

export interface FestivalAuctionResult {
  projectId: string;
  projectTitle: string;
  festivalBody: string;
  bids: FestivalBid[];
  winnerId: string | null;
  winningAmount: number;
  isPlayerProject: boolean;
}

function getActiveFestivalBody(week: number): string | null {
  if (week === 4) return 'Sundance Film Festival';
  if (week === 20) return 'Cannes Film Festival';
  if (week === 36) return 'Toronto International Film Festival';
  return null;
}

/**
 * Generates a bid amount for an NPC buyer at a festival market.
 * Returns null if the buyer has no interest.
 */
export function generateNPCBid(
  project: Project,
  buyerCash: number,
  rng: RandomGenerator
): FestivalBid | null {
  const reviewScore = project.reviewScore ?? 60;
  const buzz = project.buzz ?? 50;
  const baseInterest = (reviewScore * 0.6 + buzz * 0.4) / 100;

  // Low-quality films get no bids
  if (baseInterest < 0.45 && rng.next() > 0.2) return null;

  const baseBidMultiplier = rng.range(0.5, 1.5);
  const budget = project.budget ?? 1_000_000;
  const bidAmount = Math.round(budget * baseInterest * baseBidMultiplier * rng.range(0.8, 1.8));
  const cappedBid = Math.min(bidAmount, buyerCash * 0.3);

  if (cappedBid < 100_000) return null;

  return {
    bidderId: rng.uuid('SUB'),
    bidderName: 'NPC Buyer',
    amount: cappedBid,
    terms: reviewScore > 75 ? 'theatrical + streaming rights' : 'streaming rights only',
  };
}

/**
 * Resolves festival market auctions for the current week.
 * Generates NPC bids, determines winners, and triggers modals for player projects.
 */
export function runFestivalMarket(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];

  const festivalBody = getActiveFestivalBody(state.week % 52 || state.week);
  if (!festivalBody) return impacts;

  const submissions: FestivalSubmission[] = state.industry.festivalSubmissions ?? [];
  const activeSubmissions = submissions.filter(
    s => s.festivalBody === festivalBody && (s.status === 'submitted' || s.status === 'selected')
  );

  if (activeSubmissions.length === 0) return impacts;

  const buyers = state.market.buyers;
  const auctionResults: FestivalAuctionResult[] = [];
  const rivalsList = Object.values(state.entities.rivals || {});

  activeSubmissions.forEach(sub => {
    const project = state.entities.projects[sub.projectId];
    if (!project) return;

    const bids: FestivalBid[] = [];

    // Generate NPC bids from all buyers
    buyers.forEach(buyer => {
      const buyerCash = (buyer as any).cash ?? 50_000_000;
      const bid = generateNPCBid(project, buyerCash, rng);
      if (bid) {
        bids.push({ ...bid, bidderId: buyer.id, bidderName: buyer.name });
      }
    });

    // Add NPC rival bids
    rivalsList.slice(0, 3).forEach(rival => {
      const bid = generateNPCBid(project, rival.cash, rng);
      if (bid) {
        bids.push({ ...bid, bidderId: rival.id, bidderName: rival.name });
      }
    });

    bids.sort((a, b) => b.amount - a.amount);
    const winner = bids[0] ?? null;

    const isPlayerProject = project.ownerId === 'PLAYER' || !project.ownerId;

    auctionResults.push({
      projectId: project.id,
      projectTitle: project.title,
      festivalBody,
      bids,
      winnerId: winner?.bidderId ?? null,
      winningAmount: winner?.amount ?? 0,
      isPlayerProject,
    });

    if (!isPlayerProject && winner) {
      // NPC project sold — update submission status
      const updatedSubs = submissions.map(s =>
        s.projectId === sub.projectId ? { ...s, status: 'selected' as const } : s
      );
      impacts.push({
        type: 'INDUSTRY_UPDATE',
        payload: { update: { 'industry.festivalSubmissions': updatedSubs } }
      });
    }
  });

  const playerResults = auctionResults.filter(r => r.isPlayerProject);

  if (playerResults.length > 0) {
    // Trigger FESTIVAL_MARKET modal so player can review bids and accept/decline
    impacts.push({
      type: 'MODAL_TRIGGERED',
      payload: {
        modalType: 'FESTIVAL_MARKET',
        priority: 40,
        payload: { results: playerResults, festivalBody, week: state.week }
      }
    });
  }

  // Headline for the festival market opening
  impacts.push({
    type: 'NEWS_ADDED',
    payload: {
      id: rng.uuid('NWS'),
      headline: `${festivalBody} market opens — acquisition frenzy underway`,
      description: `Buyers and sellers converge as distribution rights go up for grabs.`,
      category: 'festival',
      publication: 'Variety'
    }
  });

  return impacts;
}

