/**
 * ExpenseProcessor handles all loss-related calculations for the studio.
 */
export class ExpenseProcessor {
  /**
   * Calculates studio burn based on studio level and the number of active projects.
   */
  static calculateStudioBurn(level: number, activeProjectsCount: number): number {
    // The Studio Comptroller: Increased base rent to 2M, project penalty to 600k, and level scale to 1.8 to mathematically crush passive studio empires.
    const baseRent = 2000000;
    const levelScale = Math.pow(1.8, Math.max(0, level - 1));
    const projectPenalty = 600000;
    const burn = (baseRent * levelScale) + (activeProjectsCount * projectPenalty);
    return Math.round(burn);
  }

  /**
   * Calculates the 'Credit Spread'.
   */
  static calculateCreditSpread(prestige: number, awards: import('../../types').Award[] = []): number {
    let spread = (100 - Math.min(100, Math.max(0, prestige))) / 1000;
    const oscarWins = (awards || []).filter(a => a.body === 'Academy Awards' && a.category === 'Best Picture' && a.status === 'won').length;
    spread -= Math.min(0.03, oscarWins * 0.01);
    const razzieWins = (awards || []).filter(a => a.body === 'The Razzies' && a.status === 'won').length;
    spread += (razzieWins * 0.005);
    return Math.max(0, spread);
  }

  /**
   * Calculates weekly interest penalty for negative balances.
   */
  static calculateDebtInterest(cash: number, debtRate: number, prestige: number = 70, awards: import('../../types').Award[] = []): number {
    if (cash >= 0) return 0;
    const riskPremium = this.calculateCreditSpread(prestige, awards);
    const effectiveAnnualRate = debtRate + riskPremium;
    const weeklyRate = effectiveAnnualRate / 52;
    return Math.abs(Math.round(cash * weeklyRate));
  }

  /**
   * Calculates weekly interest yield for positive balances.
   */
  static calculateSavingsYield(cash: number, savingsYield: number): number {
    if (cash <= 0) return 0;
    const weeklyRate = savingsYield / 52;
    return Math.round(cash * weeklyRate);
  }

  /**
   * Calculates weekly marketing burn.
   */
  static calculateMarketingBurn(projects: Project[]): number {
    let totalBurn = 0;
    projects.forEach((p) => {
      if (p.state === 'marketing' && p.marketingBudget) {
        totalBurn += p.marketingBudget / 4;
      }
    });
    return Math.round(totalBurn);
  }

  /**
   * Calculates production costs.
   * Phase 2: TV projects use fractional burn (budget / episodes).
   */
  static calculateProductionBurn(projects: Project[]): number {
    let totalBurn = 0;
    projects.forEach((p) => {
      if (p.state === 'production') {
        if (p.type === 'SERIES' && (p as any).tvDetails) {
          const episodes = (p as any).tvDetails.episodesOrdered || 10;
          totalBurn += p.budget / episodes;
        } else {
          totalBurn += p.weeklyCost;
        }
      }
    });
    return Math.round(totalBurn);
  }

  /**
   * Calculates weekly overhead for TalentPacts.
   */
  static calculatePactOverhead(pacts: TalentPact[]): number {
    return (pacts || []).reduce((total, pact) => total + (pact.weeklyOverhead || 0), 0);
  }

  /**
   * Calculates total consolidated expenses for the studio.
   */
  static calculateConsolidatedExpenses(
    projects: Project[],
    state: GameState,
    market: import('../../types/state.types').MarketState,
    studioArchetype: string,
    studioCash: number,
    studioPrestige: number,
    pacts: TalentPact[]
  ): {
    production: number;
    marketing: number;
    overhead: number;
    interest: number;
    pacts: number;
  } {
    const studioLevel = studioArchetype === 'major' ? 3 : (studioArchetype === 'mid-tier' ? 2 : 1);
    const production = this.calculateProductionBurn(projects);
    const marketing = this.calculateMarketingBurn(projects);
    const overhead = this.calculateStudioBurn(studioLevel, projects.filter(p => p.state !== 'released' && p.state !== 'archived').length);
    const pactsBurn = this.calculatePactOverhead(pacts);

    const isDebt = studioCash < 0;
    const interest = isDebt 
      ? this.calculateDebtInterest(studioCash, market.debtRate, studioPrestige, state.industry.awards || [])
      : -this.calculateSavingsYield(studioCash, market.savingsYield);

    return { production, marketing, overhead, interest, pacts: pactsBurn };
  }
}

import { Project, GameState, WeeklyFinancialReport, Buyer, Contract, TalentPact } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';
import { StateImpact, FinancialSnapshot } from '../../types/state.types';
import { RevenueProcessor } from './RevenueProcessor';
import { ExpenseProcessor } from './ExpenseProcessor';
import { InterestRateSimulator } from '../market/InterestRateSimulator';

export function generateWeeklyFinancialReport(
  state: GameState,
  studioId: string,
  projectsMap: Record<string, Project>,
  studioCash: number,
  studioArchetype: string,
  studioPrestige: number,
  contracts: Contract[],
  pacts: TalentPact[],
  rng: RandomGenerator,
  pendingImpacts: StateImpact[] = []
): { report: WeeklyFinancialReport; snapshot: FinancialSnapshot } {
  const projects = Object.values(projectsMap || {});
  const market = state.finance.marketState || InterestRateSimulator.initialize();

  const passive = RevenueProcessor.calculateVaultDividends(state.ip.vault, studioId);

  const { boxOffice, distribution, merch, totalRoyalties, projectRecoupment } = 
    RevenueProcessor.calculateActiveRevenue(projects, state, contracts, state.ip.vault, studioId);

  const expenses = ExpenseProcessor.calculateConsolidatedExpenses(
      projects, 
      state, 
      market, 
      studioArchetype, 
      studioCash, 
      studioPrestige, 
      pacts
  );

  let otherRevenue = 0;
  let otherExpenses = 0;

  for (let i = 0; i < pendingImpacts.length; i++) {
    const impact = pendingImpacts[i];
    const isTarget = impact.payload && (impact.payload as any).targetId === studioId;
    const isGenericPlayer = studioId === 'player' && !impact.payload?.targetId;

    if (isTarget || isGenericPlayer) {
        if (impact.type === 'FINANCE_TRANSACTION' && impact.payload) {
            const amount = (impact.payload as { amount: number }).amount || 0;
            if (amount > 0) otherRevenue += amount;
            else otherExpenses += Math.abs(amount);
        } else if (impact.cashChange) {
            const change = impact.cashChange as number;
            if (change > 0) otherRevenue += change;
            else otherExpenses += Math.abs(change);
        }
    }
  }

  const netProfit = (boxOffice + distribution + merch + passive + (expenses.interest < 0 ? Math.abs(expenses.interest) : 0)) 
                  - (expenses.production + expenses.marketing + expenses.overhead + expenses.pacts + totalRoyalties + (expenses.interest > 0 ? expenses.interest : 0));

  const report: WeeklyFinancialReport = {
    id: rng.uuid('SNP'),
    week: state.week,
    year: Math.floor((state.week - 1) / 52) + 1,
    startingCash: studioCash,
    revenue: { 
      boxOffice, 
      distribution, 
      other: merch + passive + otherRevenue 
    },
    expenses: { 
      production: expenses.production, 
      marketing: expenses.marketing, 
      overhead: expenses.overhead,
      pacts: expenses.pacts
    },
    endingCash: studioCash + netProfit,
    netProfit,
  };

  const snapshot: FinancialSnapshot = {
    id: rng.uuid('SNP'),
    week: state.week,
    revenue: {
      theatrical: boxOffice,
      streaming: distribution,
      merch: merch,
      passive: passive + otherRevenue
    },
    expenses: {
      production: expenses.production,
      burn: expenses.overhead,
      marketing: expenses.marketing,
      royalties: totalRoyalties,
      interest: expenses.interest,
      pacts: expenses.pacts
    },
    net: netProfit,
    cash: studioCash + netProfit,
    projectRecoupment
  };

  return { report, snapshot };
}

import { Project, Buyer, Contract, GameState } from '../../types';
import { ProjectRating } from '../../types/project.types';
import { IPAsset } from '../../types/state.types';
import { calculateWeeklyIPRevenue } from '../ip/merchandisingEngine';
import { getRatingEconomics } from '../ratings';
import { calculateAudienceIndex } from '../demographics';
import { StreamingViewershipTracker } from '../production/StreamingViewershipTracker';
import { RandomGenerator } from '../../utils/rng';

/**
 * RevenueProcessor handles all income-related calculations for the studio.
 */
export class RevenueProcessor {
  /**
   * Calculates total active revenue and recoupment for all studio projects.
   */
  static calculateActiveRevenue(
    projects: Project[],
    state: GameState,
    contracts: Contract[],
    vault: IPAsset[],
    studioId: string
  ): {
    boxOffice: number;
    distribution: number;
    merch: number;
    totalRoyalties: number;
    projectRecoupment: Record<string, number>;
  } {
    let boxOffice = 0;
    let distribution = 0;
    let merch = 0;
    let totalRoyalties = 0;
    const projectRecoupment: Record<string, number> = {};

    // ⚡ Bolt: Precompute buyers map to avoid O(N) lookup per project during iteration.
    const buyersMap = new Map<string, Buyer>();
    state.market.buyers.forEach(b => buyersMap.set(b.id, b));

    projects.forEach(p => {
      const totalCost = p.budget + (p.marketingBudget || 0);
      if (totalCost > 0) {
        projectRecoupment[p.id] = Math.min(100, Math.floor((p.revenue / totalCost) * 100));
      }

      if (p.state === 'released') {
        const talentMultiplier = this.calculateTalentRevenueMultiplier(p, state, contracts);
        const target = p.targetDemographic || 'four_quadrant';
        const demographicMultiplier = calculateAudienceIndex(p, target);
        let weeklyGross = 0;

        let banMultiplier = 1.0;
        if (p.regionalRatings) {
            const banCount = p.regionalRatings.filter(r => r.isBanned).length;
            if (banCount > 0) banMultiplier = Math.max(0.2, 1.0 - (banCount * 0.15));
        }

        if (p.distributionStatus === 'theatrical') {
          // The Studio Comptroller: Base theatrical decay rate lowered from 0.22 to 0.18 representing an incredibly ruthless front-loaded drop.
          weeklyGross = this.calculateTheatricalDecay(p.weeklyRevenue || 0, 0.18, p.isCultClassic) * talentMultiplier * banMultiplier * demographicMultiplier;
          boxOffice += weeklyGross;
        } else if (p.distributionStatus === 'streaming') {
          const platform = p.buyerId ? buyersMap.get(p.buyerId) : undefined;
          if (platform) {
            weeklyGross = this.calculateStreamingRevenue(p, platform) * talentMultiplier * banMultiplier * demographicMultiplier;
            distribution += weeklyGross;
          }
        }

        const franchiseId = p.franchiseId;
        const franchise = franchiseId ? state.ip.franchises[franchiseId] : null;
        const weeklyMerch = this.calculateMerchRevenue(p.buzz, franchise?.relevanceScore || 0, p.rating ?? 'PG-13');
        merch += weeklyMerch;

        if (p.backendPoints && p.backendPoints > 0 && weeklyGross > 0) {
          distribution += Math.round(weeklyGross * (p.backendPoints / 100));
        }

        totalRoyalties += this.calculateNetPointsRoyalty(p, weeklyGross + weeklyMerch, contracts);
      }
    });

    // 🌌 PHASE 2: Backend Streaming (Royalties from Rival Projects)
    const rivalsList = Object.values(state.entities.rivals || {});
    rivalsList.forEach(rival => {
      // Backward compatibility for projects field
      const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
      Object.values(rivalProjects).forEach((rp: any) => {
        if (rp.state === 'released') {
          const weeklyGross = (rp.weeklyRevenue || 0);
          if (weeklyGross <= 0) return;

          // Check if any player contract is on this project
          contracts.forEach(c => {
            if (c.projectId === rp.id && c.backendPercent > 0) {
              const royalty = Math.round(weeklyGross * (c.backendPercent / 100));
              distribution += royalty; // Streaming into player's distribution bucket
            }
          });
        }
      });
    });

    return { boxOffice, distribution, merch, totalRoyalties, projectRecoupment };
  }

  /**
   * Stage 2.2: Calculates a revenue multiplier based on the collective 'Draw' and 'Prestige' 
   * of attached talent. High-value stars act as a force multiplier for box office.
   */
  static calculateTalentRevenueMultiplier(project: Project, state: GameState, contracts: Contract[]): number {
    let totalBonus = 0;
    let hasContract = false;

    for (let i = 0; i < contracts.length; i++) {
      const contract = contracts[i];
      if (contract.projectId === project.id) {
        hasContract = true;
        const talent = state.entities.talents[contract.talentId];
        if (talent) {
          // Draw contribution: 100 draw = +0.25 bonus
          const drawBonus = (talent.draw - 50) * 0.005;
          // Prestige contribution: 100 prestige = +0.10 bonus
          const prestigeBonus = (talent.prestige - 50) * 0.002;
          totalBonus += (drawBonus + prestigeBonus);
        }
      }
    }

    if (!hasContract) return 1.0;

    // Clamp multiplier between 0.5x and 2.5x
    return Math.min(2.5, Math.max(0.5, 1.0 + totalBonus));
  }

  /**
   * Calculates weekly streaming revenue for a project on a specific platform.
   * Applies a streaming premium for adult/specialty ratings (TV-MA, NC-17, Unrated).
   */
  static calculateStreamingRevenue(project: Project, platform: Buyer): number {
    const quality = project.reviewScore || 50;
    const marketShare = platform.marketShare || 0.10;
    const baseFeePerUnit = 2000;
    const shareUnits = marketShare * 100;
    const baseRevenue = Math.round(baseFeePerUnit * shareUnits * (quality / 100));
    const streamingPremium = getRatingEconomics(project.rating ?? 'PG-13').streamingPremium;
    return Math.round(baseRevenue * (1 + streamingPremium));
  }

  /**
   * Calculates box office decay for a project in a given week.
   */
  static calculateTheatricalDecay(currentRevenue: number, decayRate: number, isCultClassic: boolean = false): number {
    let revenue = Math.round(currentRevenue * decayRate);
    if (isCultClassic) {
      // The Studio Comptroller: Modified cult classic bump to prevent flat minimums and enforce long-tail decay instead
      revenue = Math.max(revenue * 2.0, 100000);
    }
    return revenue;
  }

  /**
   * Calculates passive merchandise revenue based on hype, franchise strength, and rating.
   * G/PG-rated projects earn a merch bonus; R/NC-17/Unrated earn far less.
   */
  static calculateMerchRevenue(hype: number, franchiseRelevance: number, rating: ProjectRating = 'PG-13'): number {
    if (rating === 'Unrated') return 0; // Unrated releases cannot merchandise
    const h = hype || 0;
    const f = franchiseRelevance || 0;
    if (h < 70) return 0;
    const base = 5000;
    const hypeFactor = (h - 70) / 30;
    const relevanceFactor = f / 100;
    const baseRevenue = Math.round(base + (base * 5 * hypeFactor * relevanceFactor));
    const merchMultiplier = getRatingEconomics(rating).merchMultiplier;
    return Math.round(baseRevenue * merchMultiplier);
  }

  /**
   * Calculates passive revenue generated by the archived IP vault.
   */
  static calculateVaultDividends(vault: IPAsset[], studioId?: string): number {
    if (!vault || vault.length === 0) return 0;
    let total = 0;
    for (let i = 0; i < vault.length; i++) {
      const asset = vault[i];
      // Filter by owner if provided (Phase 5 hardening)
      if (studioId && asset.ownerStudioId !== studioId && asset.rightsOwner !== 'STUDIO') continue;

      total += calculateWeeklyIPRevenue(asset);
    }
    return total;
  }

  /**
   * Calculates talent royalties (Net Points) for a project.
   */
  static calculateNetPointsRoyalty(project: Project, weeklyRevenue: number, contracts: Contract[]): number {
    const totalCost = project.budget + (project.marketingBudget || 0);
    const totalRevenue = project.revenue || 0;

    if (totalRevenue < totalCost) return 0;

    let totalRoyalty = 0;
    for (let i = 0; i < contracts.length; i++) {
      const contract = contracts[i];
      if (contract.projectId === project.id && contract.backendPercent > 0) {
        let percent = contract.backendPercent / 100;
        if (contract.backendEscalator && totalRevenue > totalCost * 2) {
          percent += 0.05;
        }
        totalRoyalty += weeklyRevenue * percent;
      }
    }

    return Math.round(totalRoyalty);
  }

  /**
   * Calculates streaming revenue from viewership data.
   * Real-world: ~$0.015 per hour watched (varies by platform).
   */
  static calculateStreamingRevenueFromViewership(history: any): number {
    const latestEntry = history.entries[history.entries.length - 1];
    const revenuePerHour = 0.015;
    return Math.round(latestEntry.hoursWatched * revenuePerHour);
  }
}

import { GameState, StateImpact, Project } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';
import { generateWeeklyFinancialReport } from '../finance';
import { StreamingViewershipTracker } from '../production/StreamingViewershipTracker';
import { StudioArchetype, AI_ARCHETYPES } from '../../data/aiArchetypes';

/**
 * Helper function to get the StudioArchetype for a rival studio.
 */
function getRivalArchetype(rival: any): StudioArchetype | undefined {
  const archetypeId = rival.archetypeId || ('behaviorId' in rival ? rival.behaviorId : undefined);
  if (archetypeId) {
    const archetype = AI_ARCHETYPES.find(a => a.id === archetypeId);
    if (archetype) return archetype;
  }
  return undefined;
}

/**
 * Weekly Finance Tick (Target A4/B).
 * Calculates overhead, production burn, and revenue for the player studio.
 * Returns discrete StateImpacts for cash changes and ledger updates.
 */
export function tickFinance(state: GameState, rng: RandomGenerator, pendingImpacts: StateImpact[] = []): StateImpact[] {
  const impacts: StateImpact[] = [];

  const contractsList = Object.values(state.entities.contracts || {});

  // 1. Player Finance Tick
  const { report, snapshot } = generateWeeklyFinancialReport(
      state,
      state.studio.id, // 🌌 Standardized ID
      state.entities.projects,
      state.finance.cash,
      state.studio.archetype,
      state.studio.prestige,
      contractsList,
      state.deals?.activeDeals || [],
      rng,
      pendingImpacts
  );

  impacts.push({
    type: 'FUNDS_CHANGED',
    payload: { amount: report.netProfit }
  });

  impacts.push({
    type: 'LEDGER_UPDATED',
    payload: { report }
  });

  impacts.push({
    type: 'FINANCE_SNAPSHOT_ADDED',
    payload: { snapshot }
  });

  // Update streaming viewership for all projects with streaming distribution (player and rival)
  const allProjects = Object.values(state.entities.projects || {});
  allProjects.forEach(project => {
    if (project.state === 'released' && project.distributionStatus === 'streaming' && project.streamingViewership && project.streamingViewership.length > 0) {
      // Find the viewership history for this project's platform
      const platformId = project.buyerId || '';
      const historyIndex = project.streamingViewership.findIndex(v => v.platform === platformId);

      if (historyIndex >= 0) {
        const updatedViewership = StreamingViewershipTracker.updateViewership(
          project.streamingViewership[historyIndex],
          state.week,
          project,
          rng
        );

        // Update the specific history in the array
        const updatedArray = [...project.streamingViewership];
        updatedArray[historyIndex] = updatedViewership;

        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: {
            projectId: project.id,
            update: { streamingViewership: updatedArray }
          }
        });
      }
    }
  });

  // 2. Rival Finance Tick (Phase 5: Industry Symmetry)
  const rivalsList = Object.values(state.entities.rivals || {});

  // Pre-group all rival projects by ownerId
  const rivalProjectsMap: Record<string, Record<string, Project>> = {};
  for (const p of allProjects) {
    if (p.ownerId && p.ownerId !== state.studio.id) {
      if (!rivalProjectsMap[p.ownerId]) rivalProjectsMap[p.ownerId] = {};
      rivalProjectsMap[p.ownerId][p.id] = p;
    }
  }

  for (const rival of rivalsList) {
    // Use unified storage for rival projects
    const rivalProjectsDict = rivalProjectsMap[rival.id] || {};
    const archetype = getRivalArchetype(rival);

    const { report: rivalReport } = generateWeeklyFinancialReport(
        state,
        rival.id,
        rivalProjectsDict,
        rival.cash,
        rival.archetype,
        rival.prestige,
        [], // Rivals don't use player contracts (simplified for now)
        [], // Rivals don't have pacts yet
        rng,
        pendingImpacts
    );

    impacts.push({
        type: 'RIVAL_UPDATED',
        payload: {
            rivalId: rival.id,
            update: { cash: rival.cash + rivalReport.netProfit }
        }
    });
  }

  return impacts;
}

import { GameState, RivalStudio, StateImpact, StreamerPlatform } from '@/engine/types';
import { BrandSystem } from '../../generators/BrandSystem';
import { ARCHETYPES } from '../../data/archetypes';
import { generateMotto } from '../../generators/names';
import { RandomGenerator } from '../../utils/rng';

/**
 * Studio Boss - Industry Upstarts
 * Spawns new companies to ensure the market doesn't become a ghost town after mergers.
 */
export function tickIndustryUpstarts(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  const rivalsList = Object.values(state.entities.rivals || {});
  const currentRivals = rivalsList.length;
  const currentStreamers = state.market.buyers.filter(b => b.archetype === 'streamer').length;

  const usedNames = new Set(rivalsList.map(r => r.name));
  state.market.buyers.forEach(b => usedNames.add(b.name));

  // Minimum thresholds
  const MIN_RIVALS = 8;
  const MIN_STREAMERS = 10;

  // Spawn Studio Upstart
  if (currentRivals < MIN_RIVALS && rng.next() < 0.1) {
    const ident = BrandSystem.generateIdentity(usedNames, rng);
    const name = BrandSystem.getStudioName(ident, rng);
    const archetype = 'indie'; // Upstarts usually start small
    const archData = ARCHETYPES[archetype];

    const newStudio: RivalStudio = {
      id: rng.uuid('RIV'),
      name,
      motto: generateMotto(rng),
      archetype: archetype as any,
      foundedWeek: state.week,
      parentBrand: ident.core,
      strength: 30 + Math.floor(rng.next() * 20),
      cash: archData.startingCash * 0.8,
      prestige: 50 + Math.floor(rng.range(0, 20)),
      recentActivity: 'A new boutique studio enters the fray with big ambitions.',
      projects: {},
      contracts: [],
      projectCount: 0,
      motivationProfile: { financial: 50, prestige: 80, legacy: 40, aggression: 70 },
      currentMotivation: 'MARKET_DISRUPTION',
      ownedPlatforms: []
    };

    impacts.push({
      type: 'RIVAL_UPDATED',
      payload: { 
        rivalId: newStudio.id, 
        update: newStudio 
      }
    });

    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        week: state.week,
        headline: `NEW PLAYER: ${name} launches as artisanal studio`,
        description: `With a focus on quality over volume, ${name} has officially entered the market as a boutique ${archetype} studio.`,
        category: 'general'
      }
    });
  }

  // Spawn Streamer Upstart
  if (currentStreamers < MIN_STREAMERS && rng.next() < 0.1) {
     const ident = BrandSystem.generateIdentity(usedNames, rng);
     const name = BrandSystem.getStreamingName(ident, rng);

     const newStreamer: StreamerPlatform = {
        id: rng.uuid('BUY'),
        name,
        archetype: 'streamer',
        foundedWeek: state.week,
        parentBrand: ident.core,
        subscribers: 2_000_000,
        churnRate: 0.08,
        contentLibraryQuality: 30,
        marketingSpend: 1_000_000,
        subscriberHistory: [{ week: state.week, count: 2_000_000 }],
        marketShare: 0.02,
        reach: 40,
        activeLicenses: [] // 🌌 PHASE 2: Initializing empty license ledger.
     };

     impacts.push({
        type: 'BUYER_UPDATED',
        payload: {
           buyerId: newStreamer.id,
           update: newStreamer
        }
     });

     impacts.push({
        type: 'NEWS_ADDED',
        payload: {
           id: rng.uuid('NWS'),
           week: state.week,
           headline: `DISRUPTOR: ${name} enters the streaming wars`,
           description: `A new streaming platform, ${name}, has launched today with an aggressive subscriber acquisition strategy.`,
           category: 'market'
        }
     });
  }

  return impacts;
}

import { GameState, StateImpact } from '../../types';
import { RandomGenerator } from '../../utils/rng';

/**
 * IndustryRegulator - Anti-Trust & Economic Replenishment
 */
export class RegulatorSystem {
  static tick(state: GameState, rng: RandomGenerator): StateImpact[] {
    const impacts: StateImpact[] = [];

    // 1. Calculate Trailing 4-Week Revenue for all studios
    const calculateTrailingRevenue = (history: any[]) => {
      return (history || []).slice(0, 4).reduce((sum, h) => sum + (h.revenue?.theatrical || 0) + (h.revenue?.streaming || 0), 0);
    };

    const rivalsList = Object.values(state.entities.rivals || {});

    const studios = [
      { 
        id: 'player', 
        name: state.studio.name, 
        revenue: calculateTrailingRevenue(state.finance.weeklyHistory), 
        type: state.studio.archetype 
      },
      ...rivalsList.map(r => ({ 
        id: r.id, 
        name: r.name, 
        revenue: calculateTrailingRevenue(r.weeklyHistory || []), 
        type: r.archetype 
      }))
    ];

    const totalIndustryRevenue = studios.reduce((sum, s) => sum + s.revenue, 1);
    const threshold = 0.40; 

    studios.forEach(s => {
      const share = s.revenue / totalIndustryRevenue;
      if (share > threshold && s.type === 'major' && totalIndustryRevenue > 50_000_000) {
        const fine = 25_000_000; 

        impacts.push({
          type: 'FINANCE_TRANSACTION',
          payload: {
            amount: -fine,
            category: 'EXPENSE',
            description: `Anti-Trust Fine: ${s.name} Market Share (${Math.round(share * 100)}%)`,
            week: state.week,
            targetId: s.id // Route to the specific studio
          }
        });

        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `Federal Trade Commission Fines ${s.name}`,
            description: `Cited for market dominance (${Math.round(share * 100)}%), ${s.name} has been issued a $25M penalty.`,
            category: 'market',
            publication: 'Financial Journal',
            week: state.week
          }
        });
      }
    });

    return impacts;
  }

  /**
   * 🌌 PHASE 2: Consolidation Check.
   * prevents M&A that would result in >40% market share.
   */
  static isBlocked(
    state: GameState, 
    acquirerId: string, 
    targetId: string, 
    rng: RandomGenerator
  ): { blocked: boolean; reason?: string } {
    const calculateTrailingRevenue = (history: any[]) => {
      return (history || []).slice(0, 4).reduce((sum, h) => sum + (h.revenue?.theatrical || 0) + (h.revenue?.streaming || 0), 0);
    };

    const rivalsList = Object.values(state.entities.rivals || {});

    const totalRev = calculateTrailingRevenue(state.finance.weeklyHistory) + 
                   rivalsList.reduce((sum, r) => sum + calculateTrailingRevenue(r.weeklyHistory || []), 0);

    let acquirerRev = 0;
    if (acquirerId === 'player') {
      acquirerRev = calculateTrailingRevenue(state.finance.weeklyHistory);
    } else {
      const acquirer = state.entities.rivals[acquirerId];
      acquirerRev = calculateTrailingRevenue(acquirer?.weeklyHistory || []);
    }

    // Check if acquirer current share > 40% (Consolidation Barrier)
    if (acquirerRev > totalRev * 0.40 && totalRev > 100_000_000) {
      return { blocked: true, reason: 'Market Dominance Threshold' };
    }

    // Regulatory Random Audit (5% chance of block)
    if (rng.next() < 0.05) {
      return { blocked: true, reason: 'Ongoing Anti-Trust Investigation' };
    }

    return { blocked: false };
  }

  /**
   * Calculate market share for a specific studio.
   */
  static getMarketShare(state: GameState, studioId: string): number {
    const calculateTrailingRevenue = (history: any[]) => {
      return (history || []).slice(0, 4).reduce((sum, h) => sum + (h.revenue?.theatrical || 0) + (h.revenue?.streaming || 0), 0);
    };

    const rivalsList = Object.values(state.entities.rivals || {});

    const studios = [
      { id: 'player', revenue: calculateTrailingRevenue(state.finance.weeklyHistory) },
      ...rivalsList.map(r => ({ id: r.id, revenue: calculateTrailingRevenue(r.weeklyHistory || []) }))
    ];

    const totalIndustryRevenue = studios.reduce((sum, s) => sum + s.revenue, 1);
    const target = studios.find(s => s.id === studioId);
    return (target?.revenue || 0) / (totalIndustryRevenue || 1);
  }
}

import { GameState, StateImpact, StreamerPlatform, RivalStudio } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';

/**
 * Studio Boss - Vertical Integration Processor
 * Handles the financial link between studios and their owned platforms.
 */
export function tickVerticalIntegration(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];

  // Find all platforms with an ownerId
  const ownedPlatforms = state.market.buyers.filter(
    b => b.archetype === 'streamer' && b.ownerId
  ) as StreamerPlatform[];

  ownedPlatforms.forEach(platform => {
    // Calculate weekly P&L for the platform
    // Simplified: Revenue = subscribers * $0.20 (average weekly ARPU)
    // Costs = marketingSpend + contentLibraryQuality * $50k
    const weeklyRevenue = platform.subscribers * 0.20;
    const weeklyCosts = (platform.marketingSpend || 1_000_000) / 4 + (platform.contentLibraryQuality * 20_000);
    const netProfit = weeklyRevenue - weeklyCosts;

    // Apply netProfit to the owner's cash
    if (platform.ownerId === 'player') {
      impacts.push({
        type: 'FINANCE_TRANSACTION',
        payload: {
          amount: netProfit,
          description: `Platform P&L: ${platform.name}`,
        }
      });
    } else if (platform.ownerId) {
      // Rival owner
      const rival = state.entities.rivals[platform.ownerId];
      if (rival) {
        impacts.push({
          type: 'RIVAL_UPDATED',
          payload: {
            rivalId: rival.id,
            update: { cash: rival.cash + netProfit }
          }
        });
      }
    }

    // Add news if profit/loss is massive
    if (Math.abs(netProfit) > 5_000_000 && rng.next() < 0.1) {
      impacts.push({
        type: 'NEWS_ADDED',
        payload: {
          headline: netProfit > 0 
            ? `${platform.name} reports record weekly profits` 
            : `${platform.ownerId === 'player' ? state.studio.name : platform.name} shares tumble on streaming losses`,
          description: `Weekly platform earnings signal a major shift in distribution economics for ${platform.name}.`,
          category: 'market',
        }
      });
    }
  });

  return impacts;
}

import { Project, Franchise, IPAsset } from '../../types';
import { clamp } from '../../utils';
import { CROSSOVER_AFFINITY } from '../../data/genres';

// Pre-compute lowercased keys for O(1) lookups
const CROSSOVER_AFFINITY_LOWER_KEYS = Object.keys(CROSSOVER_AFFINITY).reduce((acc, key) => {
  acc[key.toLowerCase()] = key;
  return acc;
}, {} as Record<string, string>);

/**
 * Calculates total equity for a franchise including the "Shared Universe Premium".
 * Real-world: A 'brand' is worth more than the sum of its individual box office takes.
 */
export function calculateFranchiseEquity(
  franchise: Franchise,
  assets: IPAsset[],
  sourceProjects?: Record<string, Project>
): number {
  const baseEquity = assets.reduce((sum, a) => sum + (a.baseValue * a.decayRate), 0);

  // 1. Shared Universe Premium
  let crossoverBonus = assets.length >= 3 ? 1.20 : 1.05;
  let genres: string[] = [];

  // 1b. Genre Crossover Events Hook
  if (sourceProjects && assets.length > 1) {
    const uniqueGenres = new Set<string>();
    assets.forEach(a => {
      const p = sourceProjects[a.originalProjectId];
      if (p && p.genre) {
        // Normalize to Title Case to match CROSSOVER_AFFINITY keys
        const lowerGenre = p.genre!.toLowerCase();
        const normalizedGenre = CROSSOVER_AFFINITY_LOWER_KEYS[lowerGenre] || p.genre;
        uniqueGenres.add(normalizedGenre);
      }
    });

    genres = Array.from(uniqueGenres);
    let synergyHits = 0;
    for (let i = 0; i < genres.length; i++) {
      for (let j = i + 1; j < genres.length; j++) {
        const g1 = genres[i];
        const g2 = genres[j];
        if (CROSSOVER_AFFINITY[g1]?.includes(g2) || CROSSOVER_AFFINITY[g2]?.includes(g1)) {
          synergyHits++;
        }
      }
    }
    // Boost bonus significantly if diverse compatible genres cross over
    crossoverBonus += Math.min(0.5, synergyHits * 0.15);

    // Golden Age of Crossovers
    if (synergyHits >= 4) {
      crossoverBonus += 0.35;
    }

    // Superhero + Multiverse Cross-over event bonus
    if (genres.includes('Superhero') && genres.includes('Multiverse')) {
      crossoverBonus += 0.20;
    }

    // Avengers-style crossover event check
    if (assets.length >= 3 && genres.some(g => g === 'Multiverse' || g === 'IP Mashup')) {
      crossoverBonus += 0.45;
    }

    // 🌌 The Universe Builder: Added a 15% synergy bonus when combining two Level 3 franchises in a crossover event.
    if (assets.length >= 5) {
      crossoverBonus += 0.15;
    }

    // Synergy bonus for massive crossover events linking 4 or more distinct IPs via IP Mashup
    if (assets.length >= 4 && genres.some(g => g === 'IP Mashup' || g === 'Multiverse')) {
      crossoverBonus += 0.25;
    }

    // Legacy Character Return Massive Crossover
    if (assets.length >= 4 && genres.some(g => g === 'Legacy Sequel')) {
      crossoverBonus += 0.35;
    }

    // Penalty for chaotic crossovers (too many genres, not enough synergy)
    if (genres.length >= 4 && synergyHits < 2) {
      crossoverBonus -= 0.20;
    }

    // Desperate IP Mashup penalty
    if (genres.length >= 5 && franchise.audienceLoyalty < 50) {
      crossoverBonus = Math.max(0.1, crossoverBonus - 0.35);
    }
  }

  // Endgame/Culmination bonus for massive, highly relevant cinematic universes
  if (assets.length >= 8 && franchise.relevanceScore >= 85) {
    crossoverBonus += 0.50;
  }

  // Curated Universe Premium
  if (assets.length >= 5 && franchise.activeProjectIds.length <= 2) {
    crossoverBonus += 0.30;
  }

  // Transmedia Universe Event synergy bonus
  if (assets.length >= 6 && genres.some(g => g === 'Superhero' || g === 'Video Game Adaptation')) {
    crossoverBonus += 0.40;
  }

  // 🌌 The Universe Builder: Transmedia Empire Bonus for franchises spanning 3+ genres including Video Game Adaptation.
  if (genres.length >= 3 && genres.includes('Video Game Adaptation')) {
    crossoverBonus += 0.25;
  }

  // 2. Format Diversity Multiplier
  const multiplier = franchise.synergyMultiplier;

  // Mega-franchise cultural premium
  const megaFranchisePremium = assets.length >= 10 ? 1.25 : 1.0;

  // Cinematic Universe Phase Fatigue
  if (assets.length >= 10 && franchise.relevanceScore < 50 && franchise.activeProjectIds.length >= 3) {
    crossoverBonus -= 0.25;
  }

  // Cinematic Universe Phase Fatigue (Poorly Performing Spin-offs)
  if (assets.length >= 5 && franchise.audienceLoyalty < 40 && franchise.activeProjectIds.length >= 3) {
    crossoverBonus -= 0.35;
  }

  // Penalty for diluting the franchise brand with too many concurrent projects
  const overSaturationPenalty = franchise.activeProjectIds && franchise.activeProjectIds.length >= 4 ? 0.8 : 1.0;

  // Massive penalty to valuation if the franchise is heavily fatigued
  const fatiguePenalty = franchise.fatigueLevel > 0.8 ? 0.5 : 1.0;

  return Math.floor(baseEquity * crossoverBonus * multiplier * megaFranchisePremium * overSaturationPenalty * fatiguePenalty);
}

import { GameState, Project, Franchise, StateImpact } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import { clamp } from '../../utils';

/**
 * Identifies projects released in the current simulation week and triggers franchise evolution.
 */
export function calculateFranchiseEvolutionImpacts(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  const projects = Object.values(state.entities.projects);

  projects.forEach(project => {
    if (project.state === 'released' && project.releaseWeek === state.week) {
      let franchiseId = project.franchiseId;
      const isBreakout = project.revenue > (project.budget * 2.5);
      const isPrestigeHit = (project.awardsProfile?.prestigeScore || 0) > 85;

      // 1. Breakout Hub Creation
      if (!franchiseId && (isBreakout || isPrestigeHit)) {
        franchiseId = rng.uuid('IPH');
        const newFranchise: Franchise = {
          id: franchiseId,
          name: project.title,
          description: `The ${project.title} Universe`,
          relevanceScore: 100,
          fatigueLevel: 0,
          audienceLoyalty: isBreakout ? 65 : 50,
          totalEquity: Math.floor(project.revenue * 0.2),
          synergyMultiplier: 1.0,
          assetIds: [`ip-${project.id}`],
          activeProjectIds: [],
          lastReleaseWeeks: [state.week],
          creationWeek: state.week
        };

        impacts.push({
          type: 'FRANCHISE_UPDATED',
          payload: { franchiseId, update: newFranchise }
        });

        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: { projectId: project.id, update: { franchiseId } }
        });

        impacts.push({
          type: 'VAULT_ASSET_UPDATED',
          payload: { assetId: `ip-${project.id}`, update: { franchiseId } }
        });
      }

      // 2. Mainstream Hub Maintenance
      else if (franchiseId && state.ip.franchises[franchiseId]) {
        const hub = state.ip.franchises[franchiseId];
        const newAssetId = `ip-${project.id}`;

        if (!hub.assetIds.includes(newAssetId)) {
          const nextAssetIds = [...hub.assetIds, newAssetId];
          const nextReleaseWeeks = [...hub.lastReleaseWeeks, state.week];

          let updatedLoyalty = hub.audienceLoyalty;
          if (hub.activeProjectIds.length >= 3) {
            updatedLoyalty = clamp(updatedLoyalty - 5, 0, 100);
          }

          let newSynergy = hub.synergyMultiplier + 0.15;
          if (!isBreakout && !isPrestigeHit && project.revenue < project.budget) {
            newSynergy = hub.synergyMultiplier - 0.10;
          }

          impacts.push({
            type: 'FRANCHISE_UPDATED',
            payload: {
              franchiseId,
              update: {
                assetIds: nextAssetIds,
                lastReleaseWeeks: nextReleaseWeeks,
                audienceLoyalty: updatedLoyalty,
                synergyMultiplier: clamp(newSynergy, 1.0, 3.0),
                relevanceScore: clamp(
                  hub.relevanceScore - (hub.activeProjectIds.length >= 5 ? 15 : 0),
                  0,
                  100
                )
              }
            }
          });

          impacts.push({
            type: 'VAULT_ASSET_UPDATED',
            payload: { assetId: newAssetId, update: { franchiseId } }
          });
        }
      }
    }
  });

  return impacts;
}

import { GameState, StateImpact } from '../../types';
import { evaluateVaultSynergy } from './synergyEvaluator';
import { applyIPDecay } from './ipValuation';
import { calculateFranchiseFatigue } from './fatigueEngine';
import { determineSyndicationTier } from './syndicationEngine';

/**
 * Weekly IP Vault Tick.
 * Orchestrates synergy evaluation and cultural decay for the entire studio vault.
 * Uses archetype properties to adjust IP behavior if archetype is provided.
 */
export function tickIPVault(state: GameState, archetype?: any): StateImpact[] {
  const impacts: StateImpact[] = [];
  const activeProjects = Object.values(state.entities.projects);

  let decayMultiplier = 1.0;
  const genreFocusBonus: Record<string, number> = {};
  let festivalPrestigeBonus = 0;

  if (archetype) {
    if (archetype.strategy === 'acquirer') {
      decayMultiplier = 0.8;
    } else if (archetype.strategy === 'prestige_chaser') {
      decayMultiplier = 1.2;
    }

    if (archetype.genreFocus && archetype.genreFocus.length > 0) {
      archetype.genreFocus.forEach((genre: string) => {
        genreFocusBonus[genre.toLowerCase()] = 0.15;
      });
    }

    if (archetype.festivalParticipation && archetype.festivalParticipation > 50) {
      festivalPrestigeBonus = 10;
    }
  }

  const updatedVault = evaluateVaultSynergy(activeProjects, state.ip.vault).map(asset => {
    let updatedAsset = applyIPDecay(asset);

    if (decayMultiplier !== 1.0) {
      const adjustedDecay = Math.max(0.1, updatedAsset.decayRate * decayMultiplier);
      updatedAsset = { ...updatedAsset, decayRate: adjustedDecay };
    }

    if (Object.keys(genreFocusBonus).length > 0) {
      const sourceProject = state.studio.internal.projectHistory.find(p => p.id === updatedAsset.originalProjectId);
      if (sourceProject && sourceProject.genre) {
        const genreBonus = genreFocusBonus[sourceProject.genre.toLowerCase()] || 0;
        if (genreBonus > 0) {
          updatedAsset = {
            ...updatedAsset,
            baseValue: Math.floor(updatedAsset.baseValue * (1 + genreBonus))
          };
        }
      }
    }

    if (festivalPrestigeBonus > 0) {
      updatedAsset = {
        ...updatedAsset,
        baseValue: updatedAsset.baseValue + festivalPrestigeBonus * 1000
      };
    }

    if (updatedAsset.totalEpisodes > 0) {
      const sourceProject = state.studio.internal.projectHistory.find(p => p.id === updatedAsset.originalProjectId);
      const genre = sourceProject?.genre || 'DRAMA';

      const newTier = determineSyndicationTier(updatedAsset.totalEpisodes, genre);
      if (newTier !== updatedAsset.syndicationTier) {
        updatedAsset = {
          ...updatedAsset,
          syndicationTier: newTier,
          syndicationStatus: newTier !== 'NONE' ? 'SYNDICATED' : 'NONE'
        };
      }
    }

    return updatedAsset;
  });

  updatedVault.forEach(asset => {
    impacts.push({
      type: 'VAULT_ASSET_UPDATED',
      payload: { assetId: asset.id, update: asset }
    });
  });

  const genreSaturation: Record<string, number> = {};
  [
    ...Object.values(state.entities.projects),
    ...Object.values(state.entities.rivals).flatMap(r => {
      const rivalProjects = ('projects' in r && r.projects) ? (r as any).projects : {};
      return Object.values(rivalProjects);
    })
  ].forEach((p: any) => {
    if (p.genre) {
      const g = p.genre.toUpperCase();
      genreSaturation[g] = (genreSaturation[g] || 0) + 1;
    }
  });

  Object.values(state.ip.franchises).forEach(franchise => {
    const firstAssetId = franchise.assetIds[0];
    const firstAsset = state.ip.vault.find(a => a.id === firstAssetId);
    const sourceProject = firstAsset?.originalProjectId ? (state.entities.projects[firstAsset.originalProjectId] || state.studio.internal.projectHistory.find(p => p.id === firstAsset.originalProjectId)) : undefined;

    const genre = sourceProject?.genre || 'Action';
    const saturation = genreSaturation[genre.toUpperCase()] || 0;
    const newFatigue = calculateFranchiseFatigue(franchise, saturation, genre);

    if (newFatigue !== franchise.fatigueLevel) {
      impacts.push({
        type: 'FRANCHISE_UPDATED',
        payload: {
          franchiseId: franchise.id,
          update: { fatigueLevel: newFatigue }
        }
      });
    }
  });

  return impacts;
}

