/**
 * Generates a new project proposal based on an existing IP asset (Hardened).
 */
export function generateSpinoffProposal(
  rng: RandomGenerator,
  sourceProject: Project, 
  status: 'FATIGUED' | 'HEALTHY' | 'LEGACY' | 'OVERALL_DEAL',
  relatedCount: number = 0,
  sourceAsset?: IPAsset
): Partial<Project> {
  const pool = SPINOFF_TEMPLATES[status];
  const template = rng.pick(pool);

  // Standard Sequel Check: If healthy and not reached many entries
  if (status === 'HEALTHY' && rng.next() > 0.5) {
     const sequelNum = relatedCount + 2;

     if (sequelNum >= 3) {
       return {
         title: `${sourceProject.title} ${sequelNum}: Part 1`,
         format: sourceProject.format,
         genre: sourceProject.genre,
         budgetTier: 'blockbuster', // Finale bloat
         buzz: 20,
         flavor: `The epic first half of the massive conclusion to the ${sourceProject.title} saga.`,
         parentProjectId: sourceProject.id,
         isSpinoff: true
       };
     }

     return {
       title: `${sourceProject.title} ${sequelNum}`,
       format: sourceProject.format,
       genre: sourceProject.genre,
       budgetTier: sourceProject.budgetTier,
       buzz: 15,
       flavor: `The next highly anticipated chapter in the blockbuster ${sourceProject.title} franchise.`,
       parentProjectId: sourceProject.id,
       isSpinoff: true
     };
  }

  const proposal = {
    title: `${sourceProject.title}: ${template.titleSuffix}`,
    format: template.format || sourceProject.format,
    tvFormat: template.tvFormat,
    unscriptedFormat: template.unscriptedFormat,
    genre: template.genre || sourceProject.genre,
    budgetTier: template.budgetTier || (sourceProject.budgetTier as any),
    buzz: template.buzzBonus,
    flavor: template.flavorTemplate.replace('{title}', sourceProject.title),
    parentProjectId: sourceProject.id,
    isSpinoff: true
  };

  // Apply nostalgia bonus if source asset is available
  if (sourceAsset) {
    return applyRebootNostalgia(proposal, sourceAsset);
  }

  return proposal;
}

import { SYNDICATION_TIERS, GENRE_SYNDICATION_MODIFIERS, SyndicationTier } from '../../data/syndicationConfig';
import { IPAsset } from '../../types/state.types';

/**
 * Pure logic for determining the syndication package tier.
 * Accounts for genre-specific flexibility (Animation/Kids).
 */
export function determineSyndicationTier(episodes: number, genre: string = 'DRAMA'): SyndicationTier {
  const modifier = GENRE_SYNDICATION_MODIFIERS[genre.toUpperCase()] || 1.0;

  // Check from highest to lowest
  if (episodes >= Math.ceil(SYNDICATION_TIERS.GOLD.minEpisodes * modifier)) return 'GOLD';
  if (episodes >= Math.ceil(SYNDICATION_TIERS.SILVER.minEpisodes * modifier)) return 'SILVER';
  if (episodes >= Math.ceil(SYNDICATION_TIERS.BRONZE.minEpisodes * modifier)) return 'BRONZE';

  return 'NONE';
}

/**
 * Returns the impact configuration (revenue mult, decay shield) for a given tier.
 */
export function getSyndicationImpact(tier: SyndicationTier) {
  return SYNDICATION_TIERS[tier] || SYNDICATION_TIERS.NONE;
}

/**
 * Calculates the "Syndication Potential" of a show.
 * Used for AI value estimation and UI progress tracking.
 */
export function calculateSyndicationProgress(episodes: number, genre: string = 'DRAMA') {
  const modifier = GENRE_SYNDICATION_MODIFIERS[genre.toUpperCase()] || 1.0;
  const nextTarget = episodes < 65 * modifier ? 65 * modifier : (episodes < 88 * modifier ? 88 * modifier : 100 * modifier);

  return {
    progress: Math.min(100, (episodes / nextTarget) * 100),
    episodesNeeded: Math.max(0, Math.ceil(nextTarget - episodes))
  };
}

import { Project } from '@/engine/types';
import { StateImpact } from '../types/state.types';

export function calculateIPValue(project: Project): number {
  if (project.state === 'development' || project.state === 'pitching' || project.state === 'needs_greenlight') {
    return project.budget * 0.1; // Base speculative value
  }

  // Real value comes from box office and buzz
  let value = project.revenue * 0.4; // 40% of theatrical as baseline catalog value

  if (project.awardsProfile && project.awardsProfile.prestigeScore > 80) {
    value *= 1.5; // Prestige titles hold more long-term value
  }

  if (project.genre === 'Sci-Fi' || project.genre === 'Horror' || project.genre === 'Animation') {
    value *= 1.25; // Franchise friendly genres hold more value
  }

  return value;
}

export function checkRightsExpiry(project: Project, currentWeek: number): string | null {
  if (project.ipRights && project.ipRights.reversionWeek) {
    const weeksLeft = project.ipRights.reversionWeek - currentWeek;
    if (weeksLeft === 4) {
      return `WARNING: Rights to "${project.title}" revert in 4 weeks. Exploit or renew now!`;
    }
    if (weeksLeft === 0) {
      return `CRITICAL: Rights to "${project.title}" have reverted. You no longer control this IP.`;
    }
  }
  return null;
}

export function advanceIPRights(projects: Project[], currentWeek: number): StateImpact {
   const impact: StateImpact = {
       projectUpdates: [],
       uiNotifications: []
   };

   for (const p of projects) {
     if (p.ipRights && p.ipRights.reversionWeek !== undefined) {
        if (currentWeek >= p.ipRights.reversionWeek) {
          impact.uiNotifications!.push(`You lost the exclusive IP rights to ${p.title}.`);
          impact.projectUpdates!.push({
            projectId: p.id,
            update: {
                ipRights: {
                    ...p.ipRights,
                    rightsOwner: 'external' as const
                }
            }
          });
          continue;
        }
     }

     if (p.ipRights && p.ipRights.rightsOwner === 'studio') {
        impact.projectUpdates!.push({
            projectId: p.id,
            update: {
                ipRights: {
                    ...p.ipRights,
                    catalogValue: calculateIPValue(p)
                }
            }
        });
     }
   }

   return impact;
}

export function catalogValue(projects: Project[]): number {
  let total = 0;
  for (let i = 0; i < projects.length; i++) {
    const p = projects[i];
    if (p.ipRights) {
      if (p.ipRights.rightsOwner === 'studio') {
        total += (p.ipRights.catalogValue || calculateIPValue(p));
      } else if (p.ipRights.rightsOwner === 'shared') {
        total += ((p.ipRights.catalogValue || calculateIPValue(p)) * 0.5);
      }
    }
  }
  return total;
}

import { MarketState, StateImpact } from '../../types/state.types';
