import { RandomGenerator } from '../../utils/rng';

/**
 * Global Market Simulation: Interest Rate Simulator.
 * Handles the background "Economy" that dictates yields and debt costs.
 */
export class InterestRateSimulator {
  private static BASE_RATE_MIN = 0.0025; // 0.25%
  private static BASE_RATE_MAX = 0.15;   // 15.0%
  private static VOLATILITY = 0.0015;    // 0.15% max move per week

  /**
   * Initializes the market state if it doesn't exist.
   */
  static initialize(): MarketState {
    const baseRate = 0.045; // Start at 4.5%
    return {
      baseRate,
      savingsYield: baseRate - 0.02, // 2.5%
      debtRate: baseRate + 0.05,     // 9.5%
      loanRate: baseRate + 0.025,    // 7.0%
      rateHistory: [{ week: 1, rate: baseRate }],
      sentiment: 50,
      cycle: 'STABLE'
    };
  }

  /**
   * Weekly Tick: Fluctuates the base rate and derives other rates.
   */
  static advance(state: GameState, rng: RandomGenerator): StateImpact {
    const market = state.finance.marketState || this.initialize();
    const currentRate = market.baseRate;

    // Random Walk
    const delta = (rng.next() - 0.5) * this.VOLATILITY;
    const newRate = clamp(currentRate + delta, this.BASE_RATE_MIN, this.BASE_RATE_MAX);

    const updatedMarket: MarketState = {
      ...market,
      baseRate: newRate,
      savingsYield: Math.max(0.001, newRate - 0.02),
      debtRate: newRate + 0.05,
      loanRate: newRate + 0.025,
      rateHistory: [
        ...market.rateHistory,
        { week: state.week, rate: newRate }
      ].slice(-52) // Keep 1 year of history
    };

    const impact: StateImpact = {
      type: 'MARKET_EVENT_UPDATED',
      payload: { marketState: updatedMarket }
    };

    // Headline generation for significant shifts (cumulative > 0.5% shift or crossing thresholds)
    if (Math.abs(newRate - currentRate) > 0.001) {
       // Only add a headline if it's a "big" enough weekly move (rare for random walk, usually via events)
       // But for now, let's just trigger a notification if we hit historical highs/lows
    }

    if (rng.next() < 0.05) { // 5% chance of a "Market Analysis" headline
      const trend = newRate > currentRate ? 'rising' : 'falling';
      impact.newHeadlines = [{
        id: rng.uuid('NWS'),
        week: state.week,
        category: 'market',
        text: `Market Brief: Interest rates are ${trend} as the global economy shifts.`
      } as Headline];
    }

    return impact;
  }

  /**
   * Helper: Returns week and year for display.
   */
  static getWeekDisplay(week: number): { week: number; year: number } {
    const year = Math.floor((week - 1) / 52) + 1;
    const weekInYear = ((week - 1) % 52) + 1;
    return { week: weekInYear, year };
  }
}

import { GameState, StateImpact, Opportunity, Project, Contract, RivalStudio } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';
import { buildProjectAndContracts } from '../../../store/storeUtils';
import { generateOpportunity } from '../../generators/opportunities';

/**
 * Opportunity System
 * Handles the resolution of expired project auctions.
 */
export class OpportunitySystem {
  static tick(state: GameState, rng: RandomGenerator): StateImpact[] {
    const impacts: StateImpact[] = [];
    const expired = state.market.opportunities.filter(o => o.expirationWeek <= state.week);

    expired.forEach(opp => {
      // 1. Resolve Highest Bidder
      const bidders = Object.entries(opp.bids);
      if (bidders.length === 0) {
        // No one bid, just expire it
        impacts.push({
            type: 'OPPORTUNITY_UPDATED', // We'll use this to signal removal in the future or just handle it below
            payload: { opportunityId: opp.id, action: 'EXPIRE' } 
        });
        return;
      }

      // Find winner
      const sortedBids = bidders.sort((a, b) => b[1].amount - a[1].amount);
      const [winnerId, bidData] = sortedBids[0];

      // 2. Build Project
      const params = {
        title: opp.title,
        format: opp.format,
        genre: opp.genre,
        budgetTier: opp.budgetTier,
        targetAudience: opp.targetAudience,
        flavor: opp.flavor,
        tvFormat: opp.tvFormat,
        unscriptedFormat: opp.unscriptedFormat,
        episodes: opp.episodes,
        releaseModel: opp.releaseModel,
        initialBuzzBonus: opp.qualityBonus || 0,
        attachedTalentIds: opp.attachedTalentIds
      };

      const { project, newContracts } = buildProjectAndContracts(state, params as any, rng);

      // Update project with auction specific data
      const winnerProject = { 
        ...project, 
        budget: project.budget + bidData.amount, // Acquisition cost added to budget? Or just paid from cash?
        isAcquired: true 
      };

      // 3. Apply Impacts based on Winner
      if (winnerId === 'PLAYER') {
        impacts.push({
          type: 'FUNDS_DEDUCTED',
          payload: { amount: bidData.amount }
        });
        impacts.push({
          type: 'PROJECT_ADDED_FROM_AUCTION', // Custom type just for clarity
          newProjects: [winnerProject],
          newContracts: (newContracts as any)
        } as any);
        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            headline: `AUCTION WON: ${state.studio.name} acquires "${opp.title}"`,
            description: `After a competitive bidding process, ${state.studio.name} secured the rights for $${(bidData.amount / 1000000).toFixed(1)}M.`,
            category: 'general'
          }
        });
      } else {
        // Rival Winner
        const rival = state.entities.rivals[winnerId];
        if (rival) {
          impacts.push({
            type: 'PROJECT_UPDATED',
            payload: { projectId: winnerProject.id, update: { ...winnerProject, ownerId: rival.id } }
          });
          impacts.push({
            type: 'RIVAL_UPDATED',
            payload: {
              rivalId: winnerId,
              update: {
                cash: rival.cash - bidData.amount
              }
            }
          });
          impacts.push({
            type: 'NEWS_ADDED',
            payload: {
              headline: `AUCTION LOST: ${rival.name} outbids competition for "${opp.title}"`,
              description: `${rival.name} has emerged victorious in the bidding for ${opp.title}, paying a premium $${(bidData.amount / 1000000).toFixed(1)}M.`,
              category: 'general'
            }
          });
        }
      }
    });

    // 5. Cleanup & Replenishment
    const remainingOpportunities = state.market.opportunities.filter(o => o.expirationWeek > state.week);

    if (expired.length > 0 || remainingOpportunities.length < 8) {
        const toGenerate = Math.max(0, 8 - remainingOpportunities.length);
        const talentPoolIds = Object.keys(state.entities.talents);
        const newOpps = Array.from({ length: toGenerate }, () => generateOpportunity(rng, state.week, talentPoolIds));

        impacts.push({
            type: 'INDUSTRY_UPDATE',
            payload: { 'market.opportunities': [...remainingOpportunities, ...newOpps] }
        });
    }

    return impacts;
  }
}

import { pick } from '../utils';
