export function getActiveMarketEvent(state: GameState): MarketEvent | undefined {
  if (!state.market.activeMarketEvents || state.market.activeMarketEvents.length === 0) return undefined;
  return state.market.activeMarketEvents[0]; // For simplicity, only 1 global event at a time
}

export function advanceMarketEvents(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  let activeEvents = state.market.activeMarketEvents || [];

  // Tick active events down
  activeEvents = activeEvents.map(e => ({
    ...e,
    weeksRemaining: e.weeksRemaining - 1
  }));

  // Resolve expired events
  const expired = activeEvents.filter(e => e.weeksRemaining <= 0);
  activeEvents = activeEvents.filter(e => e.weeksRemaining > 0);

  for (const exp of expired) {
    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        week: state.week,
        headline: 'Market Normalizes',
        description: `The ${exp.name} has finally ended.`,
      }
    });
  }

  // Chance to spawn new event if none active
  if (activeEvents.length === 0 && rng.next() < 0.02) {
    const type = rng.next() > 0.5 ? 'BOOM' : 'CRASH';
    const id = rng.uuid('EVT');
    const intensity = type === 'BOOM' ? 80 : 20;

    const newEvent: MarketEvent = {
        id,
        type: type === 'BOOM' ? 'streaming_boom' : 'market_crash',
        name: BardResolver.resolve({
            domain: 'Market',
            subDomain: 'Headline',
            intensity,
            context: {},
            rng
        }),
        description: BardResolver.resolve({
            domain: 'Market',
            subDomain: 'Event',
            intensity,
            context: {},
            rng
        }),
        weeksRemaining: Math.floor(rng.range(12, 52)),
        revenueMultiplier: type === 'BOOM' ? 1.5 : 0.7,
        costMultiplier: type === 'BOOM' ? 1.2 : 0.9,
        talentAvailabilityModifier: type === 'BOOM' ? -0.1 : 0.3,
        economicShock: { sentimentShift: type === 'BOOM' ? 20 : -50, baseRateShift: type === 'BOOM' ? -0.01 : 0.04 }
    };

    activeEvents.push(newEvent);
    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        week: state.week,
        headline: `MAJOR INDUSTRY EVENT: ${newEvent.name}`,
        description: newEvent.description,
      }
    });
  }

  impacts.push({
    type: 'MARKET_EVENT_UPDATED',
    payload: { events: activeEvents }
  });

  return impacts;
}

import { MarketingCampaign, BoxOfficeResult } from '../../types';

export function calculateTerritorySplit(
  baseGross: number,
  campaign: MarketingCampaign,
  genre: string
): BoxOfficeResult {
  const { domesticBudget, foreignBudget } = campaign;
  const totalBudget = domesticBudget + foreignBudget;

  const domesticWeight = domesticBudget / Math.max(1, totalBudget);
  const foreignWeight = foreignBudget / Math.max(1, totalBudget);

  // Genre skews (e.g., Action/Sci-Fi performs better foreign, Drama/Comedy domestic)
  let genreDomesticSkew = 0.5;
  const g = genre.toUpperCase();

  if (['ACTION', 'SCI-FI', 'ANIMATION'].includes(g)) {
    genreDomesticSkew = 0.4; // 60% foreign base
  } else if (['DRAMA', 'COMEDY', 'ROMANCE'].includes(g)) {
    genreDomesticSkew = 0.65; // 35% foreign base
  }

  // Combined Weight (Budget is more impactful than base genre skew)
  const finalDomesticPct = (domesticWeight * 0.6) + (genreDomesticSkew * 0.4);
  const finalForeignPct = 1 - finalDomesticPct;

  const totalDomestic = baseGross * finalDomesticPct;
  const totalForeign = baseGross * finalForeignPct;

  return {
    openingWeekendDomestic: totalDomestic * 0.35,
    openingWeekendForeign: totalForeign * 0.35,
    totalDomestic,
    totalForeign,
    multiplier: finalForeignPct / 0.5 // Relative foreign strength factor
  };
}

import { GameState, IPAsset, Project, RivalStudio, StateImpact } from '@/engine/types';
import { RandomGenerator } from '../utils/rng';

export function evaluateAcquisitionTarget(
  target: RivalStudio, 
  buyerCash: number, 
  buyerMarketShare: number = 0
): { viable: boolean; price: number; reason?: string } {
  // ⚖️ Anti-Trust Barrier: FTC blocks any acquisition that pushes combined market share past 40%.
  const targetShare = target.marketShare || 0;
  if (buyerMarketShare + targetShare > 0.40) {
    return { viable: false, price: 0, reason: 'FTC BLOCK: Combined market share would exceed the 40% anti-trust threshold.' };
  }

  let basePrice = Math.max(10_000_000, (target.strength * 2_000_000) + target.cash);
  if (target.archetype === 'major') basePrice *= 2.0;
  if (target.archetype === 'indie') basePrice *= 1.2;
  const finalPrice = Math.round(basePrice);
  if (buyerCash < finalPrice) {
    return { viable: false, price: finalPrice, reason: 'Insufficient funds for acquisition.' };
  }
  return { viable: true, price: finalPrice };
}

export function executeAcquisition(state: GameState, targetId: string, rng: RandomGenerator): StateImpact | null {
  const target = state.entities.rivals[targetId];
  if (!target) return null;

  const evalResult = evaluateAcquisitionTarget(target, state.finance.cash);
  if (!evalResult.viable) return null;

  // Transfer projects
  const targetProjects = target.projects || {};
  const newProjects: Project[] = [];
  for (const id in targetProjects) {
    if (!Object.prototype.hasOwnProperty.call(targetProjects, id)) continue;
    const p = targetProjects[id];
      // Active projects get stuck in turnaround
      const newState = (p.state === 'production' || p.state === 'marketing') ? 'turnaround' : p.state;
      newProjects.push({ 
        ...p, 
        state: newState as any,
        isAcquired: true 
      });
  }

  // Transfer IP assets
  const vault = state.ip.vault || [];
  const targetName = target.name;
  const newIPAssets: IPAsset[] = [];

  for (let i = 0; i < vault.length; i++) {
    const a = vault[i];
    if (a.rightsOwner === 'RIVAL' && (Object.prototype.hasOwnProperty.call(targetProjects, a.originalProjectId) || a.title.includes(targetName))) {
      newIPAssets.push({
        ...a,
        rightsOwner: 'STUDIO' as const
      });
    }
  }

  return {
    cashChange: -evalResult.price + (target.cash || 0),
    prestigeChange: Math.min(100, state.studio.prestige + (target.strength * 0.2)) - state.studio.prestige,
    newProjects,
    newIPAssets,
    newHeadlines: [
      {
        id: rng.uuid('NWS'),
        week: state.week,
        category: 'market' as const,
        text: `CONSOLIDATED: ${state.studio.name} absorbs ${target.name}!`
      }
    ],
    newsEvents: [
      {
        id: rng.uuid('NWS'),
        week: state.week,
        type: 'STUDIO_EVENT' as const,
        headline: `M&A Finalized`,
        description: `The acquisition of ${target.name} is complete. ${newProjects.length} projects and ${newIPAssets.length} IP assets have been integrated.`,
      }
    ]
  };
}

export function executeSabotage(state: GameState, targetId: string, rng: RandomGenerator): StateImpact | null {
  const target = state.entities.rivals[targetId];
  if (!target || state.finance.cash < 1_000_000) return null;

  return {
    cashChange: -1_000_000,
    newRumors: [
      {
        id: rng.uuid('RMR'),
        week: state.week,
        text: `Rumors swirl that ${target.name}'s upcoming blockbuster is facing massive reshoots.`,
        truthful: false,
        category: 'rival' as const,
        resolved: false,
        resolutionWeek: state.week + 4
      }
    ]
  };
}

export function executePoach(state: GameState, targetId: string, rng: RandomGenerator): StateImpact | null {
  const target = state.entities.rivals[targetId];
  if (!target || state.finance.cash < 3_000_000) return null;

  const stealAmount = Math.min(5, target.strength);

  return {
    cashChange: -3_000_000,
    prestigeChange: stealAmount,
    rivalUpdates: [
      {
        rivalId: target.id,
        update: { strength: target.strength - stealAmount }
      }
    ],
    newHeadlines: [
      {
        id: rng.uuid('NWS'),
        week: state.week,
        category: 'talent' as const,
        text: `${state.studio.name} poaches top executive from ${target.name}!`
      }
    ]
  };
}

import { pick } from '../../utils';
import { Project, ScriptEvent, CharacterArchetype, StateImpact } from '@/engine/types/index';
import { RandomGenerator } from '../../utils/rng';
import { ScriptMetricsCalculator } from './ScriptMetricsCalculator';

/**
 * Studio Boss - Script Drafting System
 * Manages dynamic script evolution during the development phase.
 */

export function tickScriptDevelopment(
  project: Project,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  // Only evolve during development phase
  if (project.state !== 'development') return [];

  // Only evolve scripted projects
  if (!('scriptHeat' in project)) return [];

  const p = project as import('@/engine/types').ScriptedProject;
  const roll = rng.next();

  // 1. Script Heat Drift
  const heatDrift = rng.rangeInt(-3, 5); // Slight upward bias
  const newScriptHeat = Math.max(0, Math.min(100, p.scriptHeat + heatDrift));
  let newBuzz = p.buzz;
  let newActiveRoles = [...p.activeRoles];
  const newScriptEvents = [...p.scriptEvents];

  // 2. Evolution Events (Low Probability)
  if (roll < 0.15) {
    const evolutionRoll = rng.next();

    // ROLE MERGE (Low Heat or Budget Constraint)
    if (evolutionRoll < 0.4 && p.activeRoles.length > 3) {
      if (p.scriptHeat < 40) {
        const r1 = p.activeRoles[p.activeRoles.length - 1];
        const r2 = p.activeRoles[p.activeRoles.length - 2];
        newActiveRoles = p.activeRoles.slice(0, -2);
        newActiveRoles.push(r1); // Merge r2 into r1

        const event: import('@/engine/types').ScriptEvent = {
          week: p.weeksInPhase,
          type: 'ROLE_MERGE',
          description: `The writer suggested merging "${r1}" and "${r2}" into a single composite character to tighten the plot.`,
          qualityImpact: -5,
          heatGain: -2
        };
        newScriptEvents.push(event);
        newBuzz = Math.max(0, p.buzz - 5);
      }
    } 
    // ROLE SPLIT (High Heat)
    else if (evolutionRoll > 0.8 && p.activeRoles.length < 6) {
      if (p.scriptHeat > 70) {
        const archetype: CharacterArchetype = pick(['sidekick', 'love_interest', 'loose_cannon', 'femme_fatale'], rng);
        newActiveRoles = [...p.activeRoles, archetype];

        const event: import('@/engine/types').ScriptEvent = {
          week: p.weeksInPhase,
          type: 'ROLE_SPLIT',
          description: `Industry interest in the script has led to the expansion of a minor role into a full-fledged ${archetype}.`,
          qualityImpact: 10,
          heatGain: 5
        };
        newScriptEvents.push(event);
        newBuzz = p.buzz + 10;
      }
    }
    // PLOT TWIST / DIALOGUE POLISH
    else {
      const type = evolutionRoll > 0.5 ? 'PLOT_TWIST_ADDED' : 'DIALOGUE_POLISH';
      const impact = type === 'PLOT_TWIST_ADDED' ? 12 : 5;

      const event: import('@/engine/types').ScriptEvent = {
        week: p.weeksInPhase,
        type: type,
        description: type === 'PLOT_TWIST_ADDED' ? `A major third-act twist has redefined the script's commercial potential.` : `The latest draft features significantly improved dialogue and pacing.`,
        qualityImpact: impact,
        heatGain: type === 'PLOT_TWIST_ADDED' ? 8 : 3
      };
      newScriptEvents.push(event);
      newBuzz = p.buzz + impact;
    }
  }

  // Calculate script metrics
  const newScriptMetrics = ScriptMetricsCalculator.calculateMetrics(
    p as import('@/engine/types').ScriptedProject,
    p.weeksInPhase,
    (p as any).scriptMetrics
  );

  impacts.push({
    type: 'PROJECT_UPDATED',
    payload: {
      projectId: project.id,
      update: {
        scriptHeat: newScriptHeat,
        buzz: newBuzz,
        activeRoles: newActiveRoles,
        scriptEvents: newScriptEvents,
        scriptMetrics: newScriptMetrics
      }
    }
  });

  return impacts;
}

import { ScriptedProject, ScriptEvent, ScriptMetrics } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';

/**
 * Calculates script quality metrics from scriptEvents and scriptHeat.
 * Uses real-world screenwriting principles for scoring.
 */
export class ScriptMetricsCalculator {
  /**
   * Calculate all script metrics for a project.
   * Called during development phase evolution and on project creation.
   */
  static calculateMetrics(
    project: ScriptedProject,
    currentWeek: number,
    previousMetrics?: ScriptMetrics
  ): ScriptMetrics {
    const events = project.scriptEvents || [];
    const heat = project.scriptHeat || 50;

    // Structure: Based on archetype balance and role management
    const structure = this.calculateStructureScore(project, events);

    // Dialogue: Based on dialogue polish events
    const dialogue = this.calculateDialogueScore(events);

    // Originality: Based on plot twist events and unique archetypes
    const originality = this.calculateOriginalityScore(project, events);

    // Pacing: Based on scriptHeat (higher = more kinetic) and event density
    const pacing = this.calculatePacingScore(project, events, heat);

    // Emotional Impact: Directly tied to scriptHeat
    const emotionalImpact = this.calculateEmotionalImpactScore(heat);

    // Commercial Viability: Balance of quality and mass appeal
    const commercialViability = this.calculateCommercialViabilityScore(
      project, structure, originality, emotionalImpact
    );

    // Overall Score: Weighted average (structure and dialogue most important)
    const overallScore = Math.round(
      (structure * 0.25) +
      (dialogue * 0.25) +
      (originality * 0.15) +
      (pacing * 0.15) +
      (emotionalImpact * 0.1) +
      (commercialViability * 0.1)
    );

    // Trend: Compare with previous metrics
    const trend = this.calculateTrend(overallScore, previousMetrics?.overallScore);

    return {
      structure,
      dialogue,
      originality,
      pacing,
      emotionalImpact,
      commercialViability,
      overallScore,
      trend,
      lastCalculatedWeek: currentWeek
    };
  }

  /**
   * Structure score: Balanced archetypes = good structure.
   * Too many or too few roles indicates structural issues.
   */
  private static calculateStructureScore(
    project: ScriptedProject,
    events: ScriptEvent[]
  ): number {
    const roleCount = project.activeRoles.length;
    // Ideal: 4-6 roles for feature film structure
    let score = 50;

    if (roleCount >= 4 && roleCount <= 6) score += 30;
    else if (roleCount === 3 || roleCount === 7) score += 15;
    else score -= 10;

    // Role merge events hurt structure
    const merges = events.filter(e => e.type === 'ROLE_MERGE').length;
    score -= merges * 5;

    // Role split events help structure (expansion)
    const splits = events.filter(e => e.type === 'ROLE_SPLIT').length;
    score += splits * 5;

    return Math.min(100, Math.max(0, score));
  }

  /**
   * Dialogue score: Based on DIALOGUE_POLISH events.
   */
  private static calculateDialogueScore(events: ScriptEvent[]): number {
    const polishEvents = events.filter(e => e.type === 'DIALOGUE_POLISH');
    const base = 50;
    const bonus = polishEvents.reduce((sum, e) => sum + e.qualityImpact, 0);
    return Math.min(100, Math.max(0, base + bonus));
  }

  /**
   * Originality score: Based on plot twists and unique archetype combinations.
   */
  private static calculateOriginalityScore(
    project: ScriptedProject,
    events: ScriptEvent[]
  ): number {
    const twists = events.filter(e => e.type === 'PLOT_TWIST_ADDED').length;
    const base = 40;
    const bonus = twists * 12; // Each twist adds significant originality

    // Genre bonus: some genres are inherently more original
    const genre = project.genre?.toLowerCase();
    if (genre && ['sci-fi', 'fantasy', 'horror'].includes(genre)) {
      return Math.min(100, base + bonus + 10);
    }

    return Math.min(100, Math.max(0, base + bonus));
  }

  /**
   * Pacing score: Higher scriptHeat = more kinetic pacing.
   * Event density also contributes.
   */
  private static calculatePacingScore(
    project: ScriptedProject,
    events: ScriptEvent[],
    heat: number
  ): number {
    const eventDensity = events.length / Math.max(project.weeksInPhase || 1, 1);
    const base = heat * 0.6; // Heat contributes 60% to pacing
    const densityBonus = eventDensity * 20;
    return Math.min(100, Math.max(0, base + densityBonus));
  }

  /**
   * Emotional impact: Direct mapping from scriptHeat.
   * ScriptHeat represents audience emotional investment.
   */
  private static calculateEmotionalImpactScore(heat: number): number {
    return heat;
  }

  /**
   * Commercial viability: Balance of artistic merit and mass appeal.
   * Family-friendly and broad appeal genres score higher.
   */
  private static calculateCommercialViabilityScore(
    project: ScriptedProject,
    structure: number,
    originality: number,
    emotionalImpact: number
  ): number {
    const genre = project.genre?.toLowerCase();
    let base = 50;

    // Broad appeal genres
    if (genre && ['family', 'animation', 'action', 'comedy'].includes(genre)) {
      base += 20;
    }

    // Prestige genres have lower commercial viability
    if (genre && ['drama', 'thriller', 'crime'].includes(genre)) {
      base -= 10;
    }

    // Too original can hurt commercial appeal
    if (originality > 80) base -= 15;
    // Too little originality also hurts
    if (originality < 40) base -= 10;

    // Good structure helps commercial viability
    if (structure > 70) base += 10;

    // Emotional impact drives word-of-mouth
    base += (emotionalImpact - 50) * 0.2;

    return Math.min(100, Math.max(0, base));
  }

  /**
   * Determine trend based on score change.
   */
  private static calculateTrend(
    currentScore: number,
    previousScore?: number
  ): 'improving' | 'stable' | 'declining' {
    if (previousScore === undefined) return 'stable';

    const change = currentScore - previousScore;
    if (change > 3) return 'improving';
    if (change < -3) return 'declining';
    return 'stable';
  }
}

import { Project, Buyer, StreamingViewershipEntry, StreamingViewershipHistory } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';

/**
 * Tracks streaming viewership for projects distributed to streaming platforms.
 * Uses real-world streaming metrics: binge vs weekly release patterns, completion rates.
 */
export class StreamingViewershipTracker {
  /**
   * Initialize viewership tracking when a project goes to streaming.
   */
  static initializeViewership(
    project: Project,
    platformId: string,
    platform: Buyer,
    currentWeek: number,
    rng: RandomGenerator
  ): StreamingViewershipHistory {
    const quality = project.reviewScore || 50;
    const buzz = project.buzz || 50;
    const platformReach = (platform as any).subscribers || 10_000_000;

    // Initial viewership estimate based on quality, buzz, and platform reach
    const initialViewers = Math.round(
      platformReach * 
      (quality / 100) * 
      (buzz / 100) * 
      0.05 // 5% of platform subscribers tune in week 1
    );

    const initialEntry: StreamingViewershipEntry = {
      week: currentWeek,
      hoursWatched: Math.round(initialViewers * 2.5), // Avg 2.5 hours per viewer
      uniqueViewers: initialViewers,
      completionRate: this.calculateInitialCompletionRate(quality, project.genre),
      dropoffRate: 0,
      platform: platformId
    };

    return {
      platform: platformId,
      entries: [initialEntry],
      totalHoursWatched: initialEntry.hoursWatched,
      peakViewers: initialViewers,
      peakWeek: currentWeek,
      averageCompletionRate: initialEntry.completionRate
    };
  }

  /**
   * Update weekly viewership for a streaming project.
   * Called in the finance tick for all released streaming projects.
   */
  static updateViewership(
    history: StreamingViewershipHistory,
    currentWeek: number,
    project: Project,
    rng: RandomGenerator
  ): StreamingViewershipHistory {
    const entries = [...history.entries];
    const lastEntry = entries[entries.length - 1];

    // Weeks since release
    const weeksSinceRelease = currentWeek - entries[0].week;

    // Decay pattern: streaming has longer tail than theatrical
    const decayFactor = this.calculateStreamingDecay(weeksSinceRelease, project);

    // Completion rate improves over time (word-of-mouth)
    const completionTrend = this.calculateCompletionTrend(weeksSinceRelease, lastEntry.completionRate);

    const newViewers = Math.max(
      Math.round(lastEntry.uniqueViewers * decayFactor),
      Math.round(lastEntry.uniqueViewers * 0.3) // Never below 30% of peak
    );

    const dropoffRate = lastEntry.uniqueViewers > 0
      ? ((lastEntry.uniqueViewers - newViewers) / lastEntry.uniqueViewers) * 100
      : 0;

    const newEntry: StreamingViewershipEntry = {
      week: currentWeek,
      hoursWatched: Math.round(newViewers * 2.5 * completionTrend),
      uniqueViewers: newViewers,
      completionRate: completionTrend,
      dropoffRate,
      platform: history.platform
    };

    entries.push(newEntry);

    // Update aggregates
    const totalHours = entries.reduce((sum, e) => sum + e.hoursWatched, 0);
    const peakEntry = entries.reduce((max, e) => e.uniqueViewers > max.uniqueViewers ? e : max, entries[0]);
    const avgCompletion = entries.reduce((sum, e) => sum + e.completionRate, 0) / entries.length;

    return {
      platform: history.platform,
      entries,
      totalHoursWatched: totalHours,
      peakViewers: peakEntry.uniqueViewers,
      peakWeek: peakEntry.week,
      averageCompletionRate: Math.round(avgCompletion)
    };
  }

  /**
   * Calculate streaming decay based on weeks since release.
   * Streaming has longer tail than theatrical (binge watching).
   */
  private static calculateStreamingDecay(weeksSinceRelease: number, project: Project): number {
    // Binge releases: sharp drop after week 1-2, then long tail
    const isBinge = (project as any).releaseModel === 'binge';

    if (isBinge) {
      if (weeksSinceRelease === 1) return 0.5; // 50% drop week 2
      if (weeksSinceRelease === 2) return 0.7; // 30% drop week 3
      if (weeksSinceRelease <= 4) return 0.85; // Gradual decay
      return 0.95; // Long tail
    }

    // Weekly releases: more gradual decay
    if (weeksSinceRelease === 1) return 0.8;
    if (weeksSinceRelease <= 4) return 0.9;
    return 0.95;
  }

  /**
   * Calculate initial completion rate based on quality and genre.
   * High-quality dramas have higher completion rates.
   */
  private static calculateInitialCompletionRate(quality: number, genre: string): number {
    let base = quality * 0.8; // Quality is primary driver

    const genreLower = genre.toLowerCase();
    if (['drama', 'thriller', 'crime'].includes(genreLower)) {
      base += 10; // Drama genres have higher completion
    }
    if (['comedy', 'animation', 'family'].includes(genreLower)) {
      base -= 5; // Lighter content may be sampled more
    }

    return Math.min(95, Math.max(20, base));
  }

  /**
   * Calculate completion rate trend over time.
   * Word-of-mouth improves completion for good shows.
   */
  private static calculateCompletionTrend(weeksSinceRelease: number, currentRate: number): number {
    if (weeksSinceRelease <= 2) return currentRate;

    // Gradual improvement due to word-of-mouth
    const improvement = Math.min(5, weeksSinceRelease * 0.5);
    return Math.min(95, currentRate + improvement);
  }
}

import { GameState, Project, StateImpact, Contract, Talent } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import { TalentMoraleSystem } from '../talent/TalentMoraleSystem';
import { processDirectorDisputes } from '../directors';
import { SchedulingEngine } from '../schedulingEngine';
import { advanceProject } from '../projects';
import { getAttachedTalent } from '../../utils/talentHelpers';

function tickProject(
  project: Project, 
  projectContracts: Contract[],
  talentPool: Record<string, Talent>,
  rng: RandomGenerator,
  studioPrestige: number,
  currentWeek: number
): StateImpact[] {
  if (project.state === 'archived') {
    return [];
  }

  const impacts: StateImpact[] = [];

  const advancementImpacts = advanceProject(
    project,
    currentWeek,
    studioPrestige,
    projectContracts,
    talentPool,
    rng
  );

  impacts.push(...advancementImpacts);

  if (project.state === 'production') {
    const targetWeeks = Math.max(4, Math.min(30, project.productionWeeks || 20));
    const attachedTalent = getAttachedTalent(projectContracts, talentPool);
    const moraleMult = TalentMoraleSystem.getProductionSpeedMultiplier(attachedTalent);

    attachedTalent.forEach(t => {
      const newFatigue = SchedulingEngine.updateTalentFatigue(t, true);
      if (newFatigue !== t.fatigue) {
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: { talentId: t.id, update: { fatigue: newFatigue } }
        });
      }
    });

    const baseProgress = (1 / targetWeeks) * 100;
    const variance = rng.range(0.8, 1.2);
    const actualProgressIncrement = baseProgress * variance * moraleMult; 
    const newProgress = Math.min(100, (project.progress || 0) + actualProgressIncrement);

    let qualityShift = 0;
    if (rng.next() < 0.2) {
      qualityShift = rng.range(-2, 3);
    }

    const progressUpdateImpact = {
      type: 'PROJECT_UPDATED' as const,
      payload: {
        projectId: project.id,
        update: {
          progress: newProgress,
          reviewScore: Math.min(100, Math.max(0, (project.reviewScore || 50) + qualityShift))
        }
      }
    };
    impacts.push(progressUpdateImpact);
  }

  return impacts;
}

export function tickProduction(state: GameState, rng: RandomGenerator): StateImpact[] {
  const allImpacts: StateImpact[] = [];
  const contractMap = new Map<string, Contract[]>();
  const activeTalentIds = new Set<string>();

  const contractsObj = state.entities.contracts || {};
  for (const key in contractsObj) {
    if (!Object.prototype.hasOwnProperty.call(contractsObj, key)) continue;
    const contract = contractsObj[key];
    const list = contractMap.get(contract.projectId) || [];
    list.push(contract);
    contractMap.set(contract.projectId, list);
    activeTalentIds.add(contract.talentId);
  }

  const rivalsMap = state.entities.rivals || {};

  const rivalIds = new Set<string>();
  for (const key in rivalsMap) {
    if (Object.prototype.hasOwnProperty.call(rivalsMap, key)) {
      rivalIds.add(rivalsMap[key].id);
    }
  }

  const contractsRaw = state.entities.contracts;
  for (const key in contractsRaw) {
    if (Object.prototype.hasOwnProperty.call(contractsRaw, key)) {
      const contract = contractsRaw[key];
      if (contract.ownerId && rivalIds.has(contract.ownerId)) {
        const list = contractMap.get(contract.projectId) || [];
        list.push(contract);
        contractMap.set(contract.projectId, list);
      }
    }
  }

  const allProjects = { ...state.entities.projects };
  let projectsChanged = false;

  const rivalPrestigeMap = new Map<string, number>();
  for (const key in rivalsMap) {
    if (Object.prototype.hasOwnProperty.call(rivalsMap, key)) {
      rivalPrestigeMap.set(rivalsMap[key].id, rivalsMap[key].prestige);
    }
  }

  for (const key in allProjects) {
    const project = allProjects[key];
    const ownerId = project.ownerId || 'player';

    let studioPrestige: number;
    if (ownerId === 'player') {
      studioPrestige = state.studio.prestige;
    } else {
      studioPrestige = rivalPrestigeMap.get(ownerId) || 50;
    }

    const projectContracts = contractMap.get(project.id) || [];

    const projectImpacts = tickProject(project, projectContracts, state.entities.talents, rng, studioPrestige, state.week);

    projectImpacts.forEach(imp => {
        if (imp.type === 'PROJECT_UPDATED') {
            allProjects[imp.payload.projectId] = {
                ...allProjects[imp.payload.projectId],
                ...imp.payload.update
            };
            projectsChanged = true;
        } else {
            allImpacts.push(imp);
        }
    });

    const disputeImpact = processDirectorDisputes(project, projectContracts, state.entities.talents, rng);
    if (disputeImpact && (disputeImpact.projectUpdates?.length || disputeImpact.uiNotifications?.length)) {
        allImpacts.push(disputeImpact);
    }
  }

  if (projectsChanged) {
      allImpacts.push({
          type: 'INDUSTRY_UPDATE',
          payload: { update: { 'entities.projects': allProjects } }
      } as any);
  }

  for (const talentId in state.entities.talents) {
    if (!Object.prototype.hasOwnProperty.call(state.entities.talents, talentId)) continue;
    const talent = state.entities.talents[talentId];
    if (!activeTalentIds.has(talent.id)) {
      const newFatigue = SchedulingEngine.updateTalentFatigue(talent, false);
      if (newFatigue !== talent.fatigue) {
        allImpacts.push({
          type: 'TALENT_UPDATED',
          payload: { talentId: talent.id, update: { fatigue: newFatigue } }
        });
      }
    }
  }

  return allImpacts;
}

import { GameState, Project, StateImpact, ProjectUpdateImpact } from '@/engine/types';

/**
 * Strategy Pattern for Crisis Resolution (Target A3).
 * Each handler processes a specific type of impact from a crisis option.
 */
const CrisisHandlers: Record<string, (project: Project, option: any) => StateImpact[]> = {
  CASH: (project, option) => 
    option.cashPenalty ? [{ type: 'FUNDS_CHANGED', payload: { amount: -option.cashPenalty } }] : [],

  DELAY: (project, option) => 
    option.weeksDelay ? [{ 
      type: 'PROJECT_UPDATED', 
      payload: { projectId: project.id, update: { productionWeeks: (project.productionWeeks || 0) + option.weeksDelay } } 
    }] : [],

  BUZZ: (project, option) => 
    option.buzzPenalty ? [{ 
      type: 'PROJECT_UPDATED', 
      payload: { projectId: project.id, update: { buzz: Math.max(0, project.buzz - option.buzzPenalty) } } 
    }] : [],

  PRESTIGE: (project, option) => 
    option.reputationPenalty ? [{ type: 'PRESTIGE_CHANGED', payload: { amount: -option.reputationPenalty } }] : [],

  NEWS: (project, option) => [{
    type: 'NEWS_ADDED',
    payload: { 
      headline: `Crisis resolved for "${project.title}"`, 
      description: `Studio opted to: ${option.text}` 
    }
  }]
};

/**
 * Resolves a project crisis using the registered handlers.
 * Kept under 50 lines per mandate.
 */
export function resolveCrisisWithHandlers(state: GameState, projectId: string, optionIndex: number): StateImpact[] {
  const project = state.entities.projects[projectId];
  if (!project?.activeCrisis || project.activeCrisis.resolved) return [];

  const option = project.activeCrisis.options[optionIndex];
  if (!option) return [];

  const rawImpacts = Object.values(CrisisHandlers).flatMap(handler => handler(project, option));

  // Merge all PROJECT_UPDATED impacts for this specific project into one
  const projectImpacts = rawImpacts.filter(
    (i): i is ProjectUpdateImpact => i.type === 'PROJECT_UPDATED' && i.payload.projectId === projectId
  );

  const mergedUpdate = projectImpacts.reduce<Partial<Project>>(
    (acc, i) => ({ ...acc, ...i.payload.update }),
    { activeCrisis: { ...project.activeCrisis, resolved: true } }
  );

  const otherImpacts = rawImpacts.filter(
    i => !(i.type === 'PROJECT_UPDATED' && (i as ProjectUpdateImpact).payload.projectId === projectId)
  );

  return [
    ...otherImpacts,
    { type: 'PROJECT_UPDATED', payload: { projectId, update: mergedUpdate } }
  ];
}

