/**
 * Checks if a project is eligible to release a director's cut.
 */
export function checkDirectorsCutEligibility(
  project: Project,
  currentWeek: number
): { eligible: boolean; weeksUntilEarliestRelease: number } {
  const isReleased = project.state === 'released' || project.state === 'post_release';
  const wasSanitized = project.availableCuts?.some(c => c.type === 'sanitized') ?? false;
  const alreadyReleased = project.availableCuts?.some(c => c.type === 'directors_cut') ?? false;
  const alreadyNotified = project.directorsCutNotified ?? false;

  if (!isReleased || !wasSanitized || alreadyReleased || alreadyNotified) {
    return { eligible: false, weeksUntilEarliestRelease: 0 };
  }

  const weeksSinceRelease = project.releaseWeek !== null ? (currentWeek - (project.releaseWeek ?? 0)) : 0;
  const minWeeks = 4;

  if (weeksSinceRelease >= minWeeks) {
    return { eligible: true, weeksUntilEarliestRelease: 0 };
  }

  return { eligible: false, weeksUntilEarliestRelease: minWeeks - weeksSinceRelease };
}

/**
 * Releases a director's cut of a sanitized film.
 * Player-triggered action. Returns StateImpact[] for engine consumption.
 */
export function releaseDirectorsCut(
  project: Project,
  directorId: string | null,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  const openingDomestic = project.boxOffice?.openingWeekendDomestic ?? project.budget * 0.1;
  const revenueShare = 0.20 + rng.next() * 0.20; // 20-40%
  const cutRevenue = Math.round(openingDomestic * revenueShare);

  const directorsCut: RatingCut = {
    type: 'directors_cut',
    rating: project.contentFlags ? evaluateFilmRating(project.contentFlags) : 'R',
    contentFlags: project.contentFlags || [],
    buzzCost: 0,
    revenueMultiplier: revenueShare
  };

  const updatedCuts = [...(project.availableCuts || []), directorsCut];

  const awardsUpdate = project.awardsProfile
    ? {
        awardsProfile: {
          ...project.awardsProfile,
          academyAppeal: Math.min(100, project.awardsProfile.academyAppeal + 5),
          festivalBuzz: Math.min(100, project.awardsProfile.festivalBuzz + 8)
        }
      }
    : {};

  impacts.push({
    cashChange: cutRevenue,
    prestigeChange: 8,
    projectUpdates: [{
      projectId: project.id,
      update: {
        buzz: Math.min(100, project.buzz + 15),
        activeCut: 'directors_cut',
        availableCuts: updatedCuts,
        ...awardsUpdate
      }
    }],
    newHeadlines: [{
      id: rng.uuid('NWS'),
      text: `Director's Cut of "${project.title}" arrives to critical acclaim`,
      week: 0, // will be set by coordinator context
      category: 'box_office',
      publication: 'Variety'
    }]
  });

  if (directorId) {
    const director = {} as any; // we only need the update, not the full talent
    impacts.push({
      type: 'TALENT_UPDATED',
      payload: {
        talentId: directorId,
        update: { prestige: undefined } // prestige will be incremented via a separate helper
      }
    });
    // Prestige increment via the TALENT_UPDATED mechanism needs current value.
    // Push a raw prestige-style note as a headline — director's actual prestige
    // change happens via the TalentSystem weekly cycle. We mark it via a news event.
    impacts.push({
      newsEvents: [{
        id: rng.uuid('NWS'),
        week: 0,
        type: 'MILESTONE',
        headline: "DIRECTOR'S VISION VINDICATED",
        description: `The director's cut release has significantly boosted their critical standing.`,
        publication: 'IndieWire'
      }]
    });
  }

  return impacts;
}

/**
 * Marks a project for unrated release. Player-triggered at greenlight or post-theatrical.
 */
export function releaseUnrated(
  project: Project,
  week: number,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  const unratedCut: RatingCut = {
    type: 'unrated',
    rating: 'Unrated',
    contentFlags: project.contentFlags || [],
    buzzCost: 0,
    revenueMultiplier: 0.15 // very limited theatrical
  };

  const newRegional = evaluateRegionalRatings(project.contentFlags || [], 'Unrated');
  const updatedCuts = [...(project.availableCuts || []).filter(c => c.type !== 'unrated'), unratedCut];

  impacts.push({
    type: 'PROJECT_UPDATED',
    payload: {
      projectId: project.id,
      update: {
        rating: 'Unrated',
        activeCut: 'unrated',
        availableCuts: updatedCuts,
        regionalRatings: newRegional
      }
    }
  });

  // Extreme content stack triggers controversy
  const flags = project.contentFlags || [];
  const hasExtremeStack = flags.includes('gore') && flags.includes('sexual_content') && flags.includes('nudity');
  if (hasExtremeStack && rng.next() < 0.40) {
    impacts.push({
      newsEvents: [{
        id: rng.uuid('NWS'),
        week,
        type: 'SCANDAL',
        headline: 'CONTROVERSY ERUPTS',
        description: `The unrated release of "${project.title}" has sparked industry outrage over extreme content.`,
        publication: 'TMZ'
      }],
      prestigeChange: -5
    });
  }

  return impacts;
}

import { RivalStudio, Project, GameState } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';

/**
 * Calculates rival studio revenue using the same model as the player.
 * Ensures fair comparison in market share calculations.
 */
export class RivalRevenueCalculator {
  /**
   * Calculate weekly revenue for a rival studio.
   * Uses the same RevenueProcessor logic as the player.
   */
  static calculateWeeklyRevenue(
    rival: RivalStudio,
    currentWeek: number,
    rng: RandomGenerator,
    state?: GameState
  ): {
    boxOffice: number;
    streaming: number;
    merch: number;
    total: number;
  } {
    // Use unified storage if state is provided, otherwise fall back to backward compatibility
    let projects: Project[];
    projects = [];
    if (state && state.entities.projects) {
      const allProjects = state.entities.projects;
      for (const id in allProjects) {
        if (Object.prototype.hasOwnProperty.call(allProjects, id)) {
          const p = allProjects[id];
          if (p.ownerId === rival.id && p.state === 'released') {
            projects.push(p);
          }
        }
      }
    } else {
      // Backward compatibility for projects field
      const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
      for (const id in rivalProjects) {
        if (Object.prototype.hasOwnProperty.call(rivalProjects, id)) {
          const p = rivalProjects[id];
          if (p.state === 'released') {
            projects.push(p as Project);
          }
        }
      }
    }

    if (projects.length === 0) {
      return { boxOffice: 0, streaming: 0, merch: 0, total: 0 };
    }

    let boxOffice = 0;
    let streaming = 0;
    let merch = 0;

    projects.forEach((p: any) => {
      if (p.distributionStatus === 'theatrical') {
        // Use same decay model as player
        const weeklyGross = this.calculateTheatricalRevenue(p, currentWeek);
        boxOffice += weeklyGross;
      } else if (p.distributionStatus === 'streaming') {
        const weeklyGross = this.calculateStreamingRevenue(p);
        streaming += weeklyGross;
      }

      merch += this.calculateMerchRevenue(p);
    });

    return {
      boxOffice,
      streaming,
      merch,
      total: boxOffice + streaming + merch
    };
  }

  /**
   * Calculate annual revenue totals for a rival.
   */
  static calculateAnnualRevenue(
    rival: RivalStudio,
    currentWeek: number
  ): {
    boxOfficeTotal: number;
    annualRevenue: number;
  } {
    const history = rival.revenueHistory || [];

    // Filter to last 52 weeks (1 year) - only include weeks in the past
    const yearHistory = history.filter(h => h.week <= currentWeek && currentWeek - h.week <= 52);

    const boxOfficeTotal = yearHistory.reduce((sum, h) => sum + h.boxOffice, 0);
    const annualRevenue = yearHistory.reduce((sum, h) => sum + h.revenue, 0);

    return { boxOfficeTotal, annualRevenue };
  }

  /**
   * Theatrical revenue using same decay model as RevenueProcessor.
   */
  private static calculateTheatricalRevenue(project: Project, currentWeek: number): number {
    const weeksSinceRelease = currentWeek - (project.releaseWeek || 0);
    if (weeksSinceRelease < 0) return 0;

    const openingWeekend = project.boxOffice?.openingWeekendDomestic || 0;
    const reviewScore = project.reception?.metaScore || project.reviewScore || 50;

    // Same decay logic as RevenueProcessor.calculateTheatricalDecay
    let decayFactor = 0.28; // Base decay
    if (reviewScore > 80) decayFactor = 0.35; // Leggy
    else if (reviewScore > 60) decayFactor = 0.30;
    else if (reviewScore < 40) decayFactor = 0.20; // Front-loaded

    const weeklyGross = openingWeekend * Math.pow(decayFactor, weeksSinceRelease);

    // Cult classic boost
    if (project.isCultClassic) {
      return Math.max(weeklyGross * 2.0, 100000);
    }

    return Math.max(0, Math.round(weeklyGross));
  }

  /**
   * Streaming revenue using same model as RevenueProcessor.
   */
  private static calculateStreamingRevenue(project: Project): number {
    // Use the same formula as RevenueProcessor.calculateStreamingRevenue
    // Since we don't have the Buyer object, we estimate
    const quality = project.reviewScore || 50;
    const baseFeePerUnit = 2000;
    const shareUnits = 10; // Assume 10% market share average for rivals
    const baseRevenue = Math.round(baseFeePerUnit * shareUnits * (quality / 100));

    // Rating premium
    const ratingPremium = this.getRatingStreamingPremium(project.rating);
    return Math.round(baseRevenue * (1 + ratingPremium));
  }

  private static getRatingStreamingPremium(rating?: string): number {
    if (!rating) return 0;
    const r = rating.toUpperCase();
    if (r === 'TV-MA' || r === 'NC-17' || r === 'UNRATED') return 0.15;
    if (r === 'R') return 0.10;
    return 0;
  }

  /**
   * Merchandise revenue using same formula as RevenueProcessor.
   */
  private static calculateMerchRevenue(project: Project): number {
    const hype = project.buzz || 0;
    if (hype < 70) return 0;

    const base = 5000;
    const hypeFactor = (hype - 70) / 30;
    const franchiseRelevance = project.franchiseId ? 50 : 0; // Simplified
    const relevanceFactor = franchiseRelevance / 100;

    const baseRevenue = Math.round(base + (base * 5 * hypeFactor * relevanceFactor));

    // Rating multiplier
    const rating = project.rating || 'PG-13';
    const merchMultiplier = this.getRatingMerchMultiplier(rating);

    return Math.round(baseRevenue * merchMultiplier);
  }

  private static getRatingMerchMultiplier(rating: string): number {
    const r = rating.toUpperCase();
    if (r === 'UNRATED') return 0;
    if (r === 'G' || r === 'PG') return 1.3;
    if (r === 'PG-13') return 1.0;
    if (r === 'R') return 0.7;
    if (r === 'NC-17') return 0.3;
    return 1.0;
  }
}

import { GameState, StateImpact, RatingMarket, Project } from '@/engine/types';
