export {
  generateScandals,
  advanceScandals,
  generateStudioRatingEvent,
  generateMarketBanScandal
} from './scandals/index';
export type { RatingEventType } from './scandals/index';

import { pick } from '../../utils';
import { GameState, Scandal, ScandalType } from '@/engine/types';
import { StateImpact } from '../../types/state.types';
import { RandomGenerator } from '../../utils/rng';
import { BardResolver } from '../bardResolver';

export function generateScandals(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impactsToReturn: StateImpact[] = [];
  const impact: StateImpact = {
    newScandals: [],
    newHeadlines: [],
    newsEvents: [],
    projectUpdates: [],
    uiNotifications: []
  };

  const contractsList = Object.values(state.entities.contracts || {});
  const talentToProjectMap = new Map<string, string>();
  for (const c of contractsList) {
    talentToProjectMap.set(c.talentId, c.projectId);
  }

  const studioProjects = state.entities.projects || {};

  const numContracts = contractsList.length;
  const studioProjectsCount = Object.keys(studioProjects).length;
  const sizeModifier = 1.0 + (numContracts * 0.50) + (studioProjectsCount * 0.75);

  const talentPool = state.entities.talents || {};
  for (const talentId in talentPool) {
    const talent = talentPool[talentId];
    const risk = talent.psychology?.scandalRisk || 5; 
    if (rng.next() * 1000 < (risk * sizeModifier)) {
       const types: ScandalType[] = ['financial', 'personal', 'onset_behavior', 'legal', 'feud'];
       const type = pick(types, rng);

       const s: Scandal = {
         id: rng.uuid('SND'),
         talentId: talent.id,
         severity: 20 + Math.floor(rng.next() * 80),
         type,
         weeksRemaining: 4 + Math.floor(rng.next() * 8)
       };

       impact.newScandals!.push(s);

       impact.newsEvents!.push({
         id: rng.uuid('NWS'),
         week: state.week,
         type: 'CRISIS',
         headline: BardResolver.resolve({
            domain: 'Industry',
            subDomain: 'Scandal',
            intensity: s.severity,
            tone: 'Trade',
            context: { actor: talent.name, type },
            rng
         }),
         description: BardResolver.resolve({
            domain: 'Industry',
            subDomain: 'Scandal',
            intensity: s.severity,
            tone: 'Tabloid',
            context: { actor: talent.name, type },
            rng
         }),
       });

       const projectId = talentToProjectMap.get(talent.id);
       if (projectId && studioProjects[projectId]) {
         const project = studioProjects[projectId];
         const crisisId = rng.uuid('CRS');

         const crisisPayload = {
            id: crisisId,
            crisisId,
            triggeredWeek: state.week,
            haltedProduction: false,
            description: BardResolver.resolve({
               domain: 'Crisis',
               subDomain: 'PR',
               intensity: s.severity,
               context: { actor: talent.name, project: project.title, type },
               rng
            }),
            resolved: false,
            severity: s.severity > 75 ? 'high' as const : 'medium' as const,
            options: [
              {
                text: "Fire Them",
                effectDescription: "Remove talent from project, +2 week delay, preserve reputation.",
                weeksDelay: 2,
                removeTalentId: talent.id,
              },
              {
                text: "Pay off the Press",
                effectDescription: `Deduct $${(s.severity * 10000).toLocaleString()} to bury the story. Keep talent.`,
                cashPenalty: s.severity * 10000,
                reputationPenalty: 2
              },
              {
                text: "Double Down",
                effectDescription: "Cost nothing, but lose 10% reputation and tank project buzz.",
                reputationPenalty: 10,
                buzzPenalty: 30
              }
            ]
         };

         impact.projectUpdates!.push({
            projectId,
            update: {
               activeCrisis: crisisPayload
            }
         });

         impact.uiNotifications!.push(`A crisis has hit "${project.title}"!`);

         impactsToReturn.push({
           type: 'MODAL_TRIGGERED',
           payload: {
             modalType: 'CRISIS',
             priority: 100,
             payload: {
               projectId,
               crisis: crisisPayload
             }
           }
         });
       }
    }
  }

  impactsToReturn.push(impact);
  return impactsToReturn;
}

import { Project, Contract, Talent, TalentPact, GameState, StateImpact } from '@/engine/types';
import { RandomGenerator } from '../utils/rng';

export class SchedulingEngine {
  static tick(state: GameState, rng: RandomGenerator): StateImpact[] {
    const impacts: StateImpact[] = [];
    const projects = Object.values(state.entities.projects) as Project[];
    const contractsList = Object.values(state.entities.contracts || {});
    const talentPool = state.entities.talents;

    projects.forEach(project => {
      if (project.state !== 'production') return;

      const { hasConflict, conflicts } = this.evaluateSchedulingConflicts(project, contractsList, talentPool, state.week);

      if (hasConflict) {
        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: {
            projectId: project.id,
            update: { 
              weeksInPhase: Math.max(0, project.weeksInPhase - 1) // Delay progress
            }
          }
        });

        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `Scheduling Conflict Halts "${project.title}"`,
            description: conflicts.join('. '),
            category: 'talent'
          }
        });
      }
    });

    return impacts;
  }

  static evaluateSchedulingConflicts(
    project: Project,
    contracts: Contract[],
    talentPool: Record<string, Talent>,
    currentWeek: number
  ): { hasConflict: boolean; conflicts: string[] } {
    const conflicts: string[] = [];

    // Check all contracts for this project
    const projectContracts = contracts.filter(c => c.projectId === project.id);

    for (const contract of projectContracts) {
      const talent = talentPool[contract.talentId];
      if (!talent || !talent.commitments) continue;

      // Find other active commitments that overlap with THE CURRENT WEEK
      for (const commitment of talent.commitments) {
        if (commitment.projectId === project.id) continue;

        // Deterministic check: Is the talent working on ANOTHER project THIS week?
        const isWorkingElsewhere = currentWeek >= commitment.startWeek && currentWeek <= commitment.endWeek;

        if (isWorkingElsewhere) {
          conflicts.push(`${talent.name} is currently filming "${commitment.projectTitle}" (Week ${currentWeek} overlap)`);
        }
      }
    }
    return { hasConflict: conflicts.length > 0, conflicts };
  }

  static processPacts(pacts: TalentPact[]): TalentPact[] {
    return (pacts || []).map(p => ({ ...p, weeksRemaining: (p as any).weeksRemaining - 1 })).filter(p => (p as any).weeksRemaining > 0);
  }

  static updateTalentFatigue(talent: Talent, isWorking: boolean): number {
    const f = talent.fatigue || 0;
    return isWorking ? Math.min(100, f + 5) : Math.max(0, f - 10);
  }
}

import { GameState, StateImpact, Talent } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import { TalentRelationship } from '../../types/relationship.types';
import { BreakoutStar } from '../../types/discovery.types';
import { Clique } from '../../types/clique.types';
import { TVShowRecommendation } from '../../types/tv-recommendations.types';

/**
 * Biography Generator System
 * Auto-generates and updates talent biographies based on life events,
 * relationships, cliques, breakouts, and career trajectory.
 */

interface BioSection {
  header: string;
  content: string;
}

/**
 * Generate TV recommendations section
 */
function generateTVRecommendationsSection(talent: Talent, state: GameState): string | null {
  const tvRecommendations = (state as any).tvRecommendations?.recommendations || {};
  const talentRecommendations = Object.values(tvRecommendations)
    .filter((r: any) => r.talentId === talent.id && r.expiresWeek > state.week && !r.accepted) as TVShowRecommendation[];

  if (talentRecommendations.length === 0) return null;

  // Get the highest-scoring recommendation
  const topRecommendation = talentRecommendations.sort((a, b) => b.matchScore - a.matchScore)[0];

  const parts: string[] = [];

  parts.push(`Considered a strong fit for ${topRecommendation.roleType.replace('_', ' ')} roles in ${topRecommendation.genre} series.`);

  if (topRecommendation.matchScore > 75) {
    parts.push(`Excellent match with ${topRecommendation.platform.replace('_', '-')} platforms.`);
  }

  if (topRecommendation.suggestedShowTitles.length > 0) {
    parts.push(`Potential projects include ${topRecommendation.suggestedShowTitles.slice(0, 2).join(' and ')}.`);
  }

  return parts.join(' ');
}

/**
 * Generate a comprehensive biography for a talent
 */
export function generateBiography(
  talent: Talent,
  state: GameState,
  rng: RandomGenerator
): string {
  const sections: string[] = [];

  // Opening: Basic info
  sections.push(generateOpening(talent, rng));

  // Career Summary
  sections.push(generateCareerSummary(talent, state));

  // Relationships
  const relationshipSection = generateRelationshipsSection(talent, state);
  if (relationshipSection) sections.push(relationshipSection);

  // Personal Life (family, children)
  const personalSection = generatePersonalSection(talent, state);
  if (personalSection) sections.push(personalSection);

  // Recent Events
  const recentSection = generateRecentEventsSection(talent, state);
  if (recentSection) sections.push(recentSection);

  // TV Role Recommendations
  const tvSection = generateTVRecommendationsSection(talent, state);
  if (tvSection) sections.push(tvSection);

  // Personality/Work Style
  sections.push(generatePersonalitySection(talent));

  return sections.join(' ');
}

/**
 * Generate opening paragraph
 */
function generateOpening(talent: Talent, rng: RandomGenerator): string {
  const age = talent.demographics?.age || 30;
  const ageBracket = age < 30 ? 'rising' : age < 50 ? 'established' : 'veteran';
  const role = talent.role || 'performer';
  const tier = talent.tier === 1 ? 'A-list' : talent.tier === 2 ? 'respected' : talent.tier === 3 ? 'working' : 'up-and-coming';

  const openers = [
    `${talent.name} is a ${ageBracket} ${tier} ${role} in Hollywood, currently ${age} years old.`,
    `At ${age}, ${talent.name} has become one of the industry's ${ageBracket} ${tier} ${role}s.`,
    `${talent.name}, ${age}, is a ${tier} talent known for their work as a ${role}.`,
  ];

  return openers[Math.floor(rng.next() * openers.length)];
}

/**
 * Generate career summary
 */
function generateCareerSummary(talent: Talent, state: GameState): string {
  const parts: string[] = [];

  // Star meter/prestige
  const starMeter = talent.starMeter || 50;
  const prestige = talent.prestige || 50;

  if (starMeter > 80) {
    parts.push(`Currently at the peak of their fame with a Star Meter of ${starMeter}, they are one of the most sought-after talents in the industry.`);
  } else if (starMeter > 60) {
    parts.push(`With a solid Star Meter of ${starMeter}, they maintain steady industry relevance.`);
  } else if (starMeter < 30) {
    parts.push(`Currently experiencing a quieter period in their career with lower visibility.`);
  }

  // Breakout status
  const isBreakout = (talent as any).isBreakout;
  if (isBreakout) {
    const breakouts = Object.values((state as any).relationships?.discovery?.breakoutStars || {})
      .filter((b: any) => b.talentId === talent.id) as BreakoutStar[];

    if (breakouts.length > 0) {
      const breakout = breakouts[0];
      parts.push(`Recently broke out as a major star, jumping ${breakout.starMeterJump} points in Star Meter following their breakout performance.`);
    }
  }

  // Awards
  const awards = (talent as any).awards || [];
  if (awards.length > 0) {
    const majorWins = awards.filter((a: any) => a.status === 'won').length;
    if (majorWins > 0) {
      parts.push(`An acclaimed talent with ${majorWins} major award${majorWins > 1 ? 's' : ''} to their name.`);
    }
  }

  // Career trajectory
  if (talent.careerTrajectory) {
    const trajectoryDescriptions: Record<string, string> = {
      'rising': 'Their career is on a clear upward trajectory.',
      'plateau': 'They have maintained consistent success over the years.',
      'declining': 'Recently facing career challenges but with potential for a comeback.',
      'comeback': 'In the midst of an impressive career resurgence.',
    };
    parts.push(trajectoryDescriptions[talent.careerTrajectory] || '');
  }

  return parts.filter(p => p).join(' ');
}

/**
 * Generate relationships section
 */
function generateRelationshipsSection(talent: Talent, state: GameState): string | null {
  const relationships = Object.values((state as any).relationships?.relationships || {})
    .filter((r: any) => r.talentAId === talent.id || r.talentBId === talent.id) as TalentRelationship[];

  if (relationships.length === 0) return null;

  const parts: string[] = [];

  // Romantic relationships
  const romances = relationships.filter(r => r.type === 'romantic');
  if (romances.length > 0) {
    const currentRomance = romances.find(r => r.strength > 50); // Strong relationship
    if (currentRomance) {
      const partnerId = currentRomance.talentAId === talent.id ? currentRomance.talentBId : currentRomance.talentAId;
      const partner = state.entities.talents?.[partnerId];
      if (partner) {
        parts.push(`Currently in a high-profile relationship with ${partner.name}.`);
      }
    }
  }

  // Famous friends
  const friends = relationships.filter(r => r.type === 'friend' && r.strength > 30);
  if (friends.length > 0) {
    const friendNames = friends
      .slice(0, 2)
      .map(r => {
        const friendId = r.talentAId === talent.id ? r.talentBId : r.talentAId;
        return state.entities.talents?.[friendId]?.name;
      })
      .filter(Boolean);

    if (friendNames.length > 0) {
      parts.push(`Known to be close friends with ${friendNames.join(' and ')}.`);
    }
  }

  // Rivals
  const rivals = relationships.filter(r => r.type === 'rival');
  if (rivals.length > 0) {
    const rivalNames = rivals
      .slice(0, 2)
      .map(r => {
        const rivalId = r.talentAId === talent.id ? r.talentBId : r.talentAId;
        return state.entities.talents?.[rivalId]?.name;
      })
      .filter(Boolean);

    if (rivalNames.length > 0) {
      parts.push(`Has a well-documented rivalry with ${rivalNames.join(' and ')}.`);
    }
  }

  // Clique membership
  const memberCliqueMap = (state as any).relationships?.cliques?.memberCliqueMap || {};
  const cliqueIds = memberCliqueMap[talent.id] || [];
  if (cliqueIds.length > 0) {
    const cliques = (state as any).relationships?.cliques?.cliques || {};
    const cliqueNames = cliqueIds
      .map((id: string) => (cliques[id] as Clique)?.name)
      .filter(Boolean);

    if (cliqueNames.length > 0) {
      parts.push(`Member of the exclusive Hollywood group "${cliqueNames[0]}"."`);
    }
  }

  return parts.length > 0 ? parts.join(' ') : null;
}

/**
 * Generate personal life section
 */
function generatePersonalSection(talent: Talent, state: GameState): string | null {
  const parts: string[] = [];

  // Nepo baby
  if (talent.isNepoBaby && talent.parentIds && talent.parentIds.length > 0) {
    const parent = state.entities.talents?.[talent.parentIds[0]];
    if (parent) {
      parts.push(`The ${talent.demographics?.gender === 'FEMALE' ? 'daughter' : 'son'} of acclaimed ${parent.role} ${parent.name}, they entered the industry with significant family connections.`);
    }
  }

  // Spouse
  if (talent.spouseId) {
    const spouse = state.entities.talents?.[talent.spouseId];
    if (spouse) {
      parts.push(`Married to fellow industry professional ${spouse.name}.`);
    }
  }

  // Children
  if (talent.childIds && talent.childIds.length > 0) {
    const childCount = talent.childIds.length;
    parts.push(`Parent to ${childCount} ${childCount === 1 ? 'child' : 'children'} in the industry.`);
  }

  return parts.length > 0 ? parts.join(' ') : null;
}

/**
 * Generate recent events section
 */
function generateRecentEventsSection(talent: Talent, state: GameState): string | null {
  const parts: string[] = [];

  // Breakout star status
  const isBreakout = (talent as any).isBreakout;
  if (isBreakout) {
    const breakouts = Object.values((state as any).relationships?.discovery?.breakoutStars || {})
      .filter((b: any) => b.talentId === talent.id && (b as BreakoutStar).hypeWeeksRemaining > 0) as BreakoutStar[];

    if (breakouts.length > 0) {
      parts.push(`Currently experiencing breakout star status with intense media attention.`);
    }
  }

  // Recent scandal
  const scandals = Object.values(state.industry?.scandals || {})
    .filter((s: any) => s.talentId === talent.id && (s as any).weeksRemaining > 0);

  if (scandals.length > 0) {
    parts.push(`Recently navigated through personal challenges that captured public attention.`);
  }

  // Medical leave
  if ((talent as any).onMedicalLeave) {
    parts.push(`Currently taking time away from the spotlight for personal health.`);
  }

  return parts.length > 0 ? parts.join(' ') : null;
}

/**
 * Generate personality section
 */
function generatePersonalitySection(talent: Talent): string {
  const personality = talent.personality;
  if (!personality) return '';

  const descriptions: Record<string, string> = {
    'charismatic': 'Known for their magnetic screen presence and ability to light up any set.',
    'difficult': 'Their intense dedication to craft sometimes creates on-set tension, but yields powerful results.',
    'perfectionist': 'A meticulous artist who demands excellence from themselves and their collaborators.',
    'collaborative': 'Prized for their team-first attitude and ability to elevate everyone around them.',
  };

  return descriptions[personality] || '';
}

/**
 * Main biography tick - updates bios weekly
 */
export function tickBiographyGenerator(
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const talents = Object.values(state.entities.talents || {});

  for (const talent of talents) {
    // Only update bio if significant events occurred or bio is empty/default
    const currentBio = talent.bio || '';
    const isDefaultBio = currentBio.includes('Tier') && currentBio.includes('is a');

    // Check for triggers that warrant bio update
    const shouldUpdate = isDefaultBio || shouldUpdateBio(talent, state);

    if (shouldUpdate) {
      const newBio = generateBiography(talent, state, rng);

      if (newBio !== currentBio) {
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: {
            talentId: talent.id,
            update: {
              bio: newBio,
            },
          },
        });
      }
    }
  }

  return impacts;
}

/**
 * Determine if bio should be updated based on recent events
 */
function shouldUpdateBio(talent: Talent, state: GameState): boolean {
  // Update if breakout just happened
  if ((talent as any).isBreakout) return true;

  // Update if relationship status changed recently
  const relationships = Object.values((state as any).relationships?.relationships || {})
    .filter((r: any) => (r.talentAId === talent.id || r.talentBId === talent.id) && r.formedWeek > state.week - 4);
  if (relationships.length > 0) return true;

  // Update if clique membership changed
  const memberCliqueMap = (state as any).relationships?.cliques?.memberCliqueMap || {};
  const recentCliqueActivity = Object.values((state as any).relationships?.cliques?.cliques || {})
    .some((c: any) => c.memberIds?.includes(talent.id) && c.formedWeek > state.week - 4);
  if (recentCliqueActivity) return true;

  // Update if major award won recently
  // Update if scandal active
  const activeScandal = Object.values(state.industry?.scandals || {})
    .some((s: any) => s.talentId === talent.id && (s as any).weeksRemaining > 0);
  if (activeScandal) return true;

  return false;
}

/**
 * Generate a brief bio update for a specific event
 */
export function generateEventBioUpdate(
  talent: Talent,
  eventType: 'breakout' | 'relationship' | 'clique' | 'award' | 'scandal',
  eventData: any,
  state: GameState
): string {
  const currentBio = talent.bio || '';

  switch (eventType) {
    case 'breakout':
      return `${currentBio} Recently skyrocketed to fame as Hollywood's newest breakout sensation.`;

    case 'relationship':
      if (eventData.type === 'romantic' && eventData.status === 'active') {
        return `${currentBio} Currently in a high-profile relationship with ${eventData.partnerName}.`;
      }
      return currentBio;

    case 'clique':
      return `${currentBio} Member of the exclusive Hollywood group "${eventData.cliqueName}".`;

    case 'award':
      return `${currentBio} Award-winning talent with recent recognition for excellence.`;

    case 'scandal':
      return `${currentBio} Recently navigated through public challenges with resilience.`;

    default:
      return currentBio;
  }
}

import { GameState, StateImpact, Talent, Project } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import {
  TalentComfortLevel,
  ComfortPremiumRates,
  ScriptRequirement,
  ScriptRequirementType,
  ScriptRequirementLevel,
  CastingConstraintCheck,
  CastingConstraintViolation,
  CastingConstraintOption,
  REQUIREMENT_COMFORT_MAPPING,
  NUDITY_PREMIUM_RATES,
  STUNT_PREMIUM_RATES,
  INTIMACY_PREMIUM_RATES,
  RISK_PREMIUM_RATES,
  ComfortLevelNudity,
  ComfortLevelStunts,
  ComfortLevelIntimacy,
  ComfortLevelRisk,
} from '../../types/casting.types';
import { getTalentRelationships, areRomantic } from './RelationshipSystem';

/**
 * Casting Constraint System
 * Manages script requirements (nudity, stunts, intimacy) and checks talent willingness.
 * Handles premium negotiations and suggests alternatives.
 */

// Base comfort levels by personality
const PERSONALITY_COMFORT_BASE: Record<string, Partial<TalentComfortLevel>> = {
  'charismatic': { intimacy: 'passionate', risk: 'adventurous' },
  'difficult': { nudity: 'none', risk: 'conservative' },
  'perfectionist': { stunts: 'moderate', risk: 'moderate' },
  'collaborative': { nudity: 'tasteful', intimacy: 'tasteful' },
};

// Prestige affects comfort (higher prestige = more selective)
const PRESTIGE_COMFORT_MODIFIER = (prestige: number): Partial<TalentComfortLevel> => {
  if (prestige > 80) return { nudity: 'tasteful', risk: 'conservative' };
  if (prestige > 60) return { nudity: 'partial' };
  return {};
};

/**
 * Generate comfort levels for a talent based on personality and prestige
 */
export function generateTalentComfortLevel(
  talent: Talent,
  rng: RandomGenerator
): { comfort: TalentComfortLevel; rates: ComfortPremiumRates } {
  const baseComfort: TalentComfortLevel = {
    nudity: 'tasteful',
    stunts: 'minor',
    intimacy: 'tasteful',
    risk: 'moderate',
  };

  // Apply personality modifiers
  const personalityMods = talent.personality ? PERSONALITY_COMFORT_BASE[talent.personality] : {};
  const prestigeMods = PRESTIGE_COMFORT_MODIFIER(talent.prestige || 50);

  // Merge modifiers
  const comfort: TalentComfortLevel = {
    nudity: personalityMods?.nudity || prestigeMods?.nudity || baseComfort.nudity,
    stunts: personalityMods?.stunts || baseComfort.stunts,
    intimacy: personalityMods?.intimacy || prestigeMods?.intimacy || baseComfort.intimacy,
    risk: personalityMods?.risk || prestigeMods?.risk || baseComfort.risk,
  };

  // Random variation
  if (rng.next() < 0.2) {
    const nudityLevels: Array<'none' | 'tasteful' | 'partial' | 'full'> = ['none', 'tasteful', 'partial', 'full'];
    const currentIdx = nudityLevels.indexOf(comfort.nudity);
    const shift = rng.next() < 0.5 ? -1 : 1;
    const newIdx = Math.max(0, Math.min(nudityLevels.length - 1, currentIdx + shift));
    comfort.nudity = nudityLevels[newIdx];
  }

  // Calculate premium rates based on comfort
  const rates: ComfortPremiumRates = {
    nudityMultiplier: NUDITY_PREMIUM_RATES[comfort.nudity as keyof typeof NUDITY_PREMIUM_RATES] || 1.5,
    stuntMultiplier: STUNT_PREMIUM_RATES[comfort.stunts as keyof typeof STUNT_PREMIUM_RATES] || 1.2,
    intimacyMultiplier: INTIMACY_PREMIUM_RATES[comfort.intimacy as keyof typeof INTIMACY_PREMIUM_RATES] || 1.3,
  };

  return { comfort, rates };
}

/**
 * Check if talent is willing to fulfill a requirement
 */
export function checkTalentWillingness(
  talent: Talent,
  requirement: ScriptRequirement,
  state: GameState,
  rng: RandomGenerator
): CastingConstraintCheck {
  // Get or generate comfort level
  let comfort = (talent as any).comfortLevel as TalentComfortLevel | undefined;
  let rates = (talent as any).comfortPremiumRates as ComfortPremiumRates | undefined;

  if (!comfort || !rates) {
    const generated = generateTalentComfortLevel(talent, rng);
    comfort = generated.comfort;
    rates = generated.rates;
  }

  const acceptableLevels = REQUIREMENT_COMFORT_MAPPING[requirement.level];
  let willing = false;
  let requiresPremium = false;
  let requestedPremium = 0;
  let refusalReason: string | undefined;

  // Check willingness based on requirement type
  switch (requirement.type) {
    case 'nudity':
      willing = acceptableLevels.includes(comfort.nudity);
      if (!willing) {
        refusalReason = `${talent.name} is not comfortable with ${requirement.level} nudity scenes`;
      } else if (comfort.nudity === 'tasteful' && requirement.level === 'extreme') {
        requiresPremium = true;
        requestedPremium = Math.floor(talent.fee * (rates.nudityMultiplier - 1));
      }
      break;

    case 'stunts':
      willing = acceptableLevels.includes(comfort.stunts);
      if (!willing) {
        refusalReason = `${talent.name} refuses to perform ${requirement.level} stunt work`;
      } else if (rates.stuntMultiplier > 1.2) {
        requiresPremium = true;
        requestedPremium = Math.floor(talent.fee * (rates.stuntMultiplier - 1));
      }
      break;

    case 'intimacy':
      willing = acceptableLevels.includes(comfort.intimacy);
      if (!willing) {
        refusalReason = `${talent.name} is not comfortable with ${requirement.level} intimacy scenes`;
      } else if (rates.intimacyMultiplier > 1.3) {
        requiresPremium = true;
        requestedPremium = Math.floor(talent.fee * (rates.intimacyMultiplier - 1));
      }
      break;

    case 'physical_risk':
    case 'emotionally_intense':
      willing = comfort.risk !== 'conservative' || requirement.level === 'mild';
      if (!willing) {
        refusalReason = `${talent.name} prefers to avoid high-risk or emotionally intense content`;
      }
      break;
  }

  // Find alternative talent if not willing
  const alternativeTalentIds: string[] = [];
  if (!willing) {
    const allTalents = Object.values(state.entities.talents || {});
    for (const other of allTalents) {
      if (other.id === talent.id) continue;

      const otherComfort = (other as any).comfortLevel || generateTalentComfortLevel(other, rng).comfort;
      const otherAcceptable = REQUIREMENT_COMFORT_MAPPING[requirement.level];

      let otherWilling = false;
      switch (requirement.type) {
        case 'nudity': otherWilling = otherAcceptable.includes(otherComfort.nudity); break;
        case 'stunts': otherWilling = otherAcceptable.includes(otherComfort.stunts); break;
        case 'intimacy': otherWilling = otherAcceptable.includes(otherComfort.intimacy); break;
        case 'physical_risk':
        case 'emotionally_intense': otherWilling = otherComfort.risk !== 'conservative'; break;
      }

      if (otherWilling && other.tier <= talent.tier + 1) {
        alternativeTalentIds.push(other.id);
        if (alternativeTalentIds.length >= 3) break;
      }
    }
  }

  return {
    talentId: talent.id,
    requirement,
    willing,
    requiresPremium,
    requestedPremium,
    refusalReason,
    alternativeTalentIds,
  };
}

/**
 * Generate script requirements from screenplay notes
 */
export function generateRequirementsFromNotes(
  project: Project,
  state: GameState,
  rng: RandomGenerator
): ScriptRequirement[] {
  const requirements: ScriptRequirement[] = [];
  const notes = (state as any).relationships?.productionEnhancements?.screenplayNotes || {};

  for (const note of Object.values(notes)) {
    const n = note as any;
    if (n.projectId !== project.id || n.status !== 'implemented') continue;

    // Check note type for requirements
    if (n.type === 'emotional_beat' && n.intensity === 'high') {
      requirements.push({
        id: rng.uuid('REQ'),
        projectId: project.id,
        type: 'emotionally_intense',
        level: 'extreme',
        description: `Intense emotional scene requiring deep vulnerability`,
        requiredTalentIds: n.suggestedTalentIds || [],
        premiumBonus: 50000,
        screenplayNoteId: n.id,
      });
    }

    if (n.type === 'plot_twist' && n.description?.toLowerCase().includes('intimate')) {
      requirements.push({
        id: rng.uuid('REQ'),
        projectId: project.id,
        type: 'intimacy',
        level: 'moderate',
        description: `Intimate scene as part of plot twist`,
        requiredTalentIds: n.suggestedTalentIds || [],
        premiumBonus: 75000,
        screenplayNoteId: n.id,
      });
    }
  }

  // Add requirements based on project genre
  if (project.genre?.toLowerCase().includes('action')) {
    requirements.push({
      id: rng.uuid('REQ'),
      projectId: project.id,
      type: 'stunts',
      level: 'moderate',
      description: 'Action sequences requiring physical performance',
      requiredTalentIds: [],
      premiumBonus: 100000,
    });
  }

  return requirements;
}

/**
 * Create a casting constraint violation event
 */
export function createConstraintViolation(
  check: CastingConstraintCheck,
  project: Project,
  state: GameState,
  rng: RandomGenerator
): CastingConstraintViolation {
  const options: CastingConstraintOption[] = [
    {
      id: 'negotiate',
      label: 'Negotiate Premium',
      description: `Pay $${check.requestedPremium.toLocaleString()} to convince them`,
      cashCost: check.requestedPremium,
    },
    {
      id: 'rewrite',
      label: 'Rewrite Scene',
      description: 'Remove the requirement (may reduce quality)',
      removeRequirement: true,
      prestigeCost: 5,
    },
    {
      id: 'delay',
      label: 'Find Replacement',
      description: 'Delay production by 2 weeks to recast',
      weeksDelay: 2,
    },
  ];

  // Add replacement option if alternatives exist
  if (check.alternativeTalentIds.length > 0) {
    const altTalent = state.entities.talents?.[check.alternativeTalentIds[0]];
    options.push({
      id: 'replace',
      label: `Replace with ${altTalent?.name}`,
      description: `Swap talent for someone more comfortable`,
      replaceTalentId: altTalent?.id,
      weeksDelay: 1,
    });
  }

  return {
    id: rng.uuid('VIO'),
    week: state.week,
    projectId: project.id,
    talentId: check.talentId,
    requirement: check.requirement,
    severity: check.requirement.level === 'extreme' ? 'dealbreaker' : 'major',
    options,
  };
}

/**
 * Main casting constraint tick
 */
export function tickCastingConstraintSystem(
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const projects = Object.values(state.entities.projects || {});

  for (const project of projects) {
    // Only check projects in pre-production or production
    const projectState = (project as any).status || (project as any).state;
    if (!['PRE_PRODUCTION', 'IN_PRODUCTION', 'scripting', 'casting', 'production'].some(s =>
      projectState?.toLowerCase().includes(s.toLowerCase())
    )) {
      continue;
    }

    // Generate requirements from notes
    const requirements = generateRequirementsFromNotes(project, state, rng);

    // Get attached talent
    const contracts = Object.values(state.entities.contracts || {})
      .filter(c => c.projectId === project.id);
    const talentIds = contracts.map(c => c.talentId);

    for (const requirement of requirements) {
      // Check which talent are required for this requirement
      const targetTalentIds = requirement.requiredTalentIds.length > 0
        ? requirement.requiredTalentIds
        : talentIds;

      for (const talentId of targetTalentIds) {
        const talent = state.entities.talents?.[talentId];
        if (!talent) continue;

        const check = checkTalentWillingness(talent, requirement, state, rng);

        // Store the check
        impacts.push({
          type: 'CASTING_CONSTRAINT_CHECKED',
          payload: {
            check,
            comfortLevel: (talent as any).comfortLevel || generateTalentComfortLevel(talent, rng).comfort,
            premiumRates: (talent as any).comfortPremiumRates || generateTalentComfortLevel(talent, rng).rates,
          },
        } as any);

        // If not willing, create violation
        if (!check.willing) {
          const violation = createConstraintViolation(check, project, state, rng);

          impacts.push({
            type: 'CASTING_CONSTRAINT_VIOLATION',
            payload: {
              violation,
              notification: `Casting Issue: ${talent.name} refuses ${requirement.type} requirement in "${project.title}"`,
            },
          } as any);

          // Modal for player decision
          impacts.push({
            type: 'MODAL_TRIGGERED',
            payload: {
              modalType: 'CASTING_CONSTRAINT',
              violationId: violation.id,
              projectId: project.id,
              talentId: talent.id,
              options: violation.options,
            },
          });
        }

        // If willing but wants premium
        if (check.willing && check.requiresPremium) {
          impacts.push({
            type: 'CASTING_PREMIUM_DEMAND',
            payload: {
              talentId: talent.id,
              projectId: project.id,
              requirement,
              requestedPremium: check.requestedPremium,
              notification: `${talent.name} requests $${check.requestedPremium.toLocaleString()} premium for ${requirement.type} scenes`,
            },
          } as any);
        }

        // Suggest alternatives if not willing
        if (!check.willing && check.alternativeTalentIds.length > 0) {
          impacts.push({
            type: 'CASTING_ALTERNATIVE_SUGGESTED',
            payload: {
              projectId: project.id,
              originalTalentId: talent.id,
              alternativeTalentIds: check.alternativeTalentIds,
              requirement,
            },
          } as any);
        }
      }
    }
  }

  return impacts;
}

/**
 * Apply comfort level to a talent (called on talent creation)
 */
export function applyComfortLevelToTalent(
  talent: Talent,
  rng: RandomGenerator
): Partial<Talent> {
  const { comfort, rates } = generateTalentComfortLevel(talent, rng);

  return {
    comfortLevel: comfort as any,
    comfortPremiumRates: rates as any,
  };
}

import { GameState, StateImpact, Talent } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import {
  Clique,
  CliqueStatus,
  CliqueReputation,
  CliqueFormation,
  CLIQUE_NAME_PATTERNS,
} from '../../types/clique.types';
import {
  getTalentRelationships,
  areFriends,
} from './RelationshipSystem';

/**
 * Clique System
 * Manages talent cliques (Rat Pack style groups) that form, gain fame together, and sometimes break up.
 * Cliques provide fame bonuses but may have drama and conflicts.
 */

// Minimum members to form a clique
const MIN_CLIQUE_SIZE = 3;
const MAX_CLIQUE_SIZE = 8;

// Friendship strength threshold for clique formation
const CLIQUE_FRIENDSHIP_THRESHOLD = 60;

// Fame bonus per member (capped)
const FAME_BONUS_PER_MEMBER = 8; // 8% per member, max 48% for 6 members

/**
 * Generate a clique name based on era, location, or personality
 */
function generateCliqueName(members: Talent[], week: number, rng: RandomGenerator): string {
  const decade = Math.floor((week / 52 + 2020) / 10) * 10;
  const locations = ['Hollywood', 'Beverly Hills', 'Malibu', 'New York', 'London'];
  const location = rng.pick(locations);

  const patterns = [
    ...CLIQUE_NAME_PATTERNS.eraBased.map(p => p.replace('{decade}', String(decade))),
    ...CLIQUE_NAME_PATTERNS.locationBased.map(p => p.replace('{location}', location)),
    ...CLIQUE_NAME_PATTERNS.personalityBased,
  ];

  return rng.pick(patterns);
}

/**
 * Calculate clique reputation based on member personalities and scandals
 */
function calculateCliqueReputation(members: Talent[], rng: RandomGenerator): CliqueReputation {
  const scandalRisks = members.map(m => m.psychology?.scandalRisk || 50);
  const avgScandalRisk = scandalRisks.reduce((a, b) => a + b, 0) / scandalRisks.length;

  const difficultCount = members.filter(m => m.personality === 'difficult').length;
  const prestigiousCount = members.filter(m => m.prestige > 80).length;

  // Determine reputation
  if (avgScandalRisk > 70 || difficultCount >= 2) {
    return rng.next() < 0.5 ? 'scandalous' : 'toxic';
  }
  if (prestigiousCount >= members.length / 2) {
    return 'prestigious';
  }
  if (members.every(m => m.accessLevel === 'dynasty' || m.accessLevel === 'legacy')) {
    return 'elitist';
  }

  return 'cool';
}

/**
 * Calculate combined star power of clique
 */
function calculateCombinedStarPower(members: Talent[]): number {
  return members.reduce((sum, m) => sum + (m.starMeter || 50), 0);
}

/**
 * Calculate clique exclusivity (how hard to join)
 */
function calculateExclusivity(members: Talent[]): number {
  // Based on member tier and dynasty status
  let exclusivity = 50;

  const dynastyMembers = members.filter(m => m.accessLevel === 'dynasty').length;
  const tier1Count = members.filter(m => m.tier === 1).length;

  exclusivity += dynastyMembers * 10;
  exclusivity += tier1Count * 15;

  return Math.min(100, exclusivity);
}

/**
 * Find potential cliques (groups of mutually friendly talents)
 */
function findPotentialCliques(state: GameState, rng: RandomGenerator): string[][] {
  const talents = Object.values(state.entities.talents || {});
  const potentialCliques: string[][] = [];

  // Check each talent as a potential clique center
  for (const center of talents) {
    // Get all friends of this talent
    const centerRelationships = getTalentRelationships(center.id, state);
    const friendIds = centerRelationships
      .filter(r => r.type === 'friend' && r.strength >= CLIQUE_FRIENDSHIP_THRESHOLD)
      .map(r => r.talentAId === center.id ? r.talentBId : r.talentAId);

    if (friendIds.length < MIN_CLIQUE_SIZE - 1) continue; // Need at least 2 other friends

    // Check which friends are also friends with each other
    const mutuallyFriendly: string[] = [center.id];

    for (const friendId of friendIds) {
      let mutualFriendCount = 0;

      for (const otherFriendId of friendIds) {
        if (friendId === otherFriendId) continue;
        if (areFriends(friendId, otherFriendId, state)) {
          mutualFriendCount++;
        }
      }

      // If this friend is friends with at least half the others, include them
      if (mutualFriendCount >= Math.floor(friendIds.length / 2)) {
        mutuallyFriendly.push(friendId);
      }
    }

    // Check if we have enough for a clique
    if (mutuallyFriendly.length >= MIN_CLIQUE_SIZE) {
      // Sort to ensure consistent keys
      const sortedIds = mutuallyFriendly.slice(0, MAX_CLIQUE_SIZE).sort();

      // Check if this exact clique already exists
      const existingCliques = Object.values(state.relationships?.cliques?.cliques || {});
      const alreadyExists = existingCliques.some(c =>
        c.members.length === sortedIds.length &&
        c.members.every(id => sortedIds.includes(id))
      );

      if (!alreadyExists) {
        potentialCliques.push(sortedIds);
      }
    }
  }

  return potentialCliques;
}

/**
 * Form a new clique
 */
function formClique(
  memberIds: string[],
  week: number,
  state: GameState,
  rng: RandomGenerator
): { clique: Clique; impacts: StateImpact[] } {
  const impacts: StateImpact[] = [];

  const members = memberIds
    .map(id => state.entities.talents?.[id])
    .filter((m): m is Talent => !!m);

  const name = generateCliqueName(members, week, rng);
  const reputation = calculateCliqueReputation(members, rng);
  const fameBonus = Math.min(50, members.length * FAME_BONUS_PER_MEMBER);
  const combinedStarPower = calculateCombinedStarPower(members);
  const exclusivity = calculateExclusivity(members);

  const clique: Clique = {
    id: rng.uuid('CLQ'),
    name,
    members: memberIds,
    formedWeek: week,
    status: 'active',
    fameBonus,
    reputation,
    exclusivity,
    combinedStarPower,
    reunionPotential: 50,
    internalConflicts: [],
  };

  // News about new clique formation
  const memberNames = members.map(m => m.name).join(', ');
  impacts.push({
    type: 'NEWS_ADDED',
    payload: {
      id: rng.uuid('NWS'),
      headline: `Hollywood's New Power Clique: "${name}"`,
      description: `${memberNames} have formed an exclusive ${reputation} clique that everyone wants to join. Industry insiders say this group is reshaping Hollywood's social hierarchy.`,
      category: 'talent',
      publication: 'The Hollywood Reporter',
    },
  });

  return { clique, impacts };
}

/**
 * Evolve an existing clique
 */
function evolveClique(
  clique: Clique,
  state: GameState,
  rng: RandomGenerator
): { updated: Clique; impacts: StateImpact[] } {
  const impacts: StateImpact[] = [];
  let updated = { ...clique };

  // Get current members (filter out deceased)
  const livingMembers = clique.members
    .map(id => state.entities.talents?.[id])
    .filter((m): m is Talent => !!m);

  // Check if clique should disband
  if (livingMembers.length < MIN_CLIQUE_SIZE) {
    updated.status = 'disbanded';
    updated.disbandedWeek = state.week;

    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        headline: `"${clique.name}" Disbands`,
        description: `After losing key members, the famous clique has officially disbanded. Fans are mourning the end of an era.`,
        category: 'talent',
        publication: 'Variety',
      },
    });

    return { updated, impacts };
  }

  // Update combined star power
  updated.combinedStarPower = calculateCombinedStarPower(livingMembers);

  // Internal conflicts (5% chance per week for active cliques)
  if (clique.status === 'active' && rng.next() < 0.05) {
    // Find two members who might have tension
    const potentialConflicts: [string, string][] = [];

    for (let i = 0; i < livingMembers.length; i++) {
      for (let j = i + 1; j < livingMembers.length; j++) {
        // Check if they're NOT friends (neutral or rivals)
        if (!areFriends(livingMembers[i].id, livingMembers[j].id, state)) {
          potentialConflicts.push([livingMembers[i].id, livingMembers[j].id]);
        }
      }
    }

    if (potentialConflicts.length > 0 && rng.next() < 0.3) {
      const [memberA, memberB] = rng.pick(potentialConflicts);
      const conflictKey = memberA < memberB ? `${memberA}-${memberB}` : `${memberB}-${memberA}`;

      if (!updated.internalConflicts.includes(conflictKey)) {
        updated.internalConflicts.push(conflictKey);

        const talentA = livingMembers.find(m => m.id === memberA);
        const talentB = livingMembers.find(m => m.id === memberB);

        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `Tension in "${clique.name}"`,
            description: `Sources report friction between ${talentA?.name} and ${talentB?.name} within the exclusive clique.`,
            category: 'talent',
            publication: 'Page Six',
          },
        });
      }
    }
  }

  // Check for disbandment due to too many conflicts
  if (updated.internalConflicts.length >= 2 && rng.next() < 0.1) {
    updated.status = 'disbanded';
    updated.disbandedWeek = state.week;

    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        headline: `"${clique.name}" Implodes Amid Drama`,
        description: `Internal conflicts have torn the clique apart. Members are going their separate ways.`,
        category: 'talent',
        publication: 'The Hollywood Reporter',
      },
    });
  }

  // Check for reunion (disbanded cliques with high reunionPotential)
  if (clique.status === 'disbanded' && rng.next() < (clique.reunionPotential / 5200)) {
    // 5200 weeks = 100 years, so very rare
    updated.status = 'active';
    updated.reunionPotential = Math.max(0, updated.reunionPotential - 20);

    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        headline: `"${clique.name}" Reunites!`,
        description: `In a stunning move, the legendary clique has reunited. Nostalgia and mutual respect brought them back together.`,
        category: 'talent',
        publication: 'Variety',
      },
    });
  }

  // Reputation can shift
  if (rng.next() < 0.02) {
    const oldReputation = updated.reputation;
    updated.reputation = calculateCliqueReputation(livingMembers, rng);

    if (updated.reputation !== oldReputation) {
      impacts.push({
        type: 'NEWS_ADDED',
        payload: {
          id: rng.uuid('NWS'),
          headline: `"${clique.name}" Rebrands as ${updated.reputation}`,
          description: `The clique's public image has shifted from ${oldReputation} to ${updated.reputation}.`,
          category: 'talent',
          publication: 'The Hollywood Reporter',
        },
      });
    }
  }

  return { updated, impacts };
}

/**
 * Main clique system tick
 */
export function tickCliqueSystem(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];

  // 1. Check for new clique formations
  const potentialCliques = findPotentialCliques(state, rng);

  for (const memberIds of potentialCliques) {
    // 20% chance to form per week when criteria met
    if (rng.next() < 0.2) {
      const { clique, impacts: formationImpacts } = formClique(memberIds, state.week, state, rng);

      impacts.push(...formationImpacts);

      // Store in state
      impacts.push({
        type: 'CLIQUE_FORMED',
        payload: {
          cliqueId: clique.id,
          clique,
        },
      } as any);

      // Update member clique map for each member
      for (const memberId of memberIds) {
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: {
            talentId: memberId,
            update: {
              // Store clique membership in talent (if we add a field for it)
              // For now, just use the clique state
            },
          },
        });
      }
    }
  }

  // 2. Evolve existing cliques
  const existingCliques = Object.values((state as any).relationships?.cliques?.cliques || {}) as Clique[];

  for (const clique of existingCliques) {
    if (rng.next() < 0.3) { // 30% chance to evolve each clique per week
      const { updated, impacts: evolutionImpacts } = evolveClique(clique, state, rng);

      if (updated !== clique) {
        impacts.push({
          type: 'CLIQUE_UPDATED',
          payload: {
            cliqueId: clique.id,
            clique: updated,
          },
        } as any);
      }

      impacts.push(...evolutionImpacts);
    }
  }

  return impacts;
}

/**
 * Get fame bonus for a talent based on clique membership
 */
export function getCliqueFameBonus(talentId: string, state: GameState): number {
  const cliques = Object.values((state as any).relationships?.cliques?.cliques || {}) as Clique[];

  const memberCliques = cliques.filter(c =>
    c.status === 'active' && c.members.includes(talentId)
  );

  if (memberCliques.length === 0) return 0;

  // Return the highest fame bonus from any clique
  return Math.max(...memberCliques.map(c => c.fameBonus));
}

/**
 * Check if casting entire clique would provide bonus
 */
export function getCliqueCastingBonus(cliqueId: string, castTalentIds: string[], state: GameState): number {
  const clique = (state as any).relationships?.cliques?.cliques?.[cliqueId] as Clique | undefined;
  if (!clique || clique.status !== 'active') return 0;

  const membersInCast = clique.members.filter(id => castTalentIds.includes(id)).length;
  const memberPercentage = membersInCast / clique.members.length;

  // If at least 60% of clique is cast, provide full bonus
  if (memberPercentage >= 0.6) {
    return clique.fameBonus;
  }

  // Partial bonus for partial casting
  return Math.floor(clique.fameBonus * memberPercentage);
}

import { GameState, StateImpact, Talent, Project, Contract } from '../../types';
import { RandomGenerator } from '../../utils/rng';

/**
 * Death System
 * Handles talent mortality including natural death, accidents, overdoses, and other causes.
 * Integrates with production to handle active projects and co-star grief.
 */

export type DeathType =
  | 'natural'           // Age-related
  | 'accident'          // On-set accident or general accident
  | 'overdose'          // Substance-related
  | 'suicide'           // Mental health
  | 'violence'          // Crime/murder
  | 'illness';          // Disease during filming

export interface DeathEvent {
  id: string;
  talentId: string;
  week: number;
  type: DeathType;
  cause: string;
  location: string;
  isPublic: boolean;
  impactsProduction: boolean;
  griefLevel: number; // 0-100, affects co-stars
  isDuringProduction: boolean;
  projectId?: string; // If died during production
}

interface DeathProbability {
  baseChance: number;
  ageMultiplier: number;
  type: DeathType;
  minAge: number;
}

// Death probabilities by age and type
const DEATH_PROBABILITIES: DeathProbability[] = [
  // Natural causes - increases exponentially with age
  { type: 'natural', baseChance: 0.0001, ageMultiplier: 1.15, minAge: 50 },
  // Accidents - constant low chance, slightly higher for action performers
  { type: 'accident', baseChance: 0.0002, ageMultiplier: 1.0, minAge: 18 },
  // Overdose - higher for younger, decreases with age
  { type: 'overdose', baseChance: 0.0003, ageMultiplier: 0.95, minAge: 18 },
  // Suicide - peaks in middle age
  { type: 'suicide', baseChance: 0.00015, ageMultiplier: 1.02, minAge: 25 },
  // Violence - rare, affects all ages
  { type: 'violence', baseChance: 0.00005, ageMultiplier: 1.0, minAge: 18 },
  // Illness - increases with age
  { type: 'illness', baseChance: 0.0002, ageMultiplier: 1.1, minAge: 40 },
];

// Death descriptions by type
const DEATH_CAUSES: Record<DeathType, string[]> = {
  natural: [
    'passed away peacefully in their sleep',
    'died of natural causes at their home',
    'succumbed to age-related complications',
    'passed away surrounded by family',
  ],
  accident: [
    'died in a tragic car accident',
    'passed away following a fall at their residence',
    'died in a plane crash',
    'passed away after a tragic accident on set',
    'died in a drowning accident',
  ],
  overdose: [
    'passed away from an accidental drug overdose',
    'died from prescription medication complications',
    'succumbed to a suspected overdose',
    'passed away after battling substance abuse',
  ],
  suicide: [
    'died by suicide',
    'passed away from self-inflicted injuries',
    'succumbed to mental health struggles',
    'died after a long battle with depression',
  ],
  violence: [
    'died in a violent attack',
    'passed away following a home invasion',
    'was tragically murdered',
    'died from injuries sustained in an assault',
  ],
  illness: [
    'passed away after a battle with cancer',
    'succumbed to complications from heart disease',
    'died from complications of pneumonia',
    'passed away after a brief illness',
    'succumbed to a rare autoimmune disorder',
  ],
};

const DEATH_LOCATIONS = [
  'Los Angeles', 'New York', 'London', 'Paris', 'Tokyo',
  'Malibu', 'Beverly Hills', 'Manhattan', 'Miami', 'Vancouver',
  'on set', 'at home', 'in hospital', 'on location',
];

/**
 * Calculate death probability for a talent based on age and type
 */
function calculateDeathProbability(age: number, prob: DeathProbability): number {
  if (age < prob.minAge) return 0;

  let chance = prob.baseChance;

  // Apply age multiplier for each year over minimum
  const yearsOverMin = age - prob.minAge;
  chance *= Math.pow(prob.ageMultiplier, yearsOverMin);

  return chance;
}

/**
 * Determine if death occurs during active production
 */
function isDeathDuringProduction(talent: Talent, state: GameState): { isDuring: boolean; projectId?: string } {
  const activeCommitments = talent.commitments?.filter(
    c => c.startWeek <= state.week && c.endWeek >= state.week
  ) || [];

  if (activeCommitments.length === 0) {
    return { isDuring: false };
  }

  // Get the most significant project (prefer film over TV, higher budget)
  const projects = activeCommitments.map(c => ({
    commitment: c,
    project: state.entities.projects?.[c.projectId],
  })).filter(p => p.project);

  if (projects.length === 0) {
    return { isDuring: false };
  }

  // Sort by significance (film > TV, higher budget)
  projects.sort((a, b) => {
    const formatA = a.project?.format === 'film' ? 2 : 1;
    const formatB = b.project?.format === 'film' ? 2 : 1;
    if (formatA !== formatB) return formatB - formatA;

    const budgetA = a.project?.budget || 0;
    const budgetB = b.project?.budget || 0;
    return budgetB - budgetA;
  });

  return {
    isDuring: true,
    projectId: projects[0].project.id,
  };
}

/**
 * Calculate grief impact on co-stars
 */
function calculateGriefImpact(deadTalent: Talent, state: GameState): { coStarIds: string[]; griefLevel: number } {
  // Find all talents who worked with the deceased
  const coStarIds: string[] = [];

  // Check current projects
  const activeProjects = Object.values(state.entities.projects || {})
    .filter(p => p.state === 'production' || p.state === 'marketing');

  for (const project of activeProjects) {
    const contracts = Object.values(state.entities.contracts || {})
      .filter(c => c.projectId === project.id);

    const isDeadTalentInProject = contracts.some(c => c.talentId === deadTalent.id);
    if (isDeadTalentInProject) {
      // Add all other talents in this project as co-stars
      contracts.forEach(c => {
        if (c.talentId !== deadTalent.id && !coStarIds.includes(c.talentId)) {
          coStarIds.push(c.talentId);
        }
      });
    }
  }

  // Calculate grief level based on relationship and talent tier
  // Higher tier talent = more grief industry-wide
  const tierGrief = deadTalent.tier === 1 ? 80 : deadTalent.tier === 2 ? 60 : 40;

  return { coStarIds, griefLevel: tierGrief };
}

/**
 * Generate a death event for a talent
 */
function generateDeathEvent(
  talent: Talent,
  deathType: DeathType,
  state: GameState,
  rng: RandomGenerator
): DeathEvent {
  const { isDuring, projectId } = isDeathDuringProduction(talent, state);
  const { griefLevel } = calculateGriefImpact(talent, state);

  const causes = DEATH_CAUSES[deathType];
  const cause = rng.pick(causes);
  const location = rng.pick(DEATH_LOCATIONS);

  // Deaths during production of major films are always public
  // Some other deaths might be kept quiet initially
  const isPublic = isDuring || rng.next() < 0.9; // 90% of deaths become public

  return {
    id: rng.uuid('DTH'),
    talentId: talent.id,
    week: state.week,
    type: deathType,
    cause,
    location,
    isPublic,
    impactsProduction: isDuring,
    griefLevel,
    isDuringProduction: isDuring,
    projectId,
  };
}

/**
 * Process death impacts on active projects
 */
function processProjectImpacts(
  deathEvent: DeathEvent,
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  if (!deathEvent.isDuringProduction || !deathEvent.projectId) {
    return impacts;
  }

  const project = state.entities.projects?.[deathEvent.projectId];
  if (!project) return impacts;

  // Project enters crisis mode
  impacts.push({
    type: 'PROJECT_UPDATED',
    payload: {
      projectId: project.id,
      update: {
        activeCrisis: {
          id: rng.uuid('CRS'),
          templateId: 'TALENT_DEATH',
          description: `${state.entities.talents?.[deathEvent.talentId]?.name} tragically died during production`,
          triggeredWeek: state.week,
          options: [
            {
              text: 'Recast Role',
              effectDescription: 'Find a replacement actor. Adds 4 weeks delay and $2M in additional costs.',
              cashPenalty: 2_000_000,
              weeksDelay: 4,
            },
            {
              text: 'Rewrite to Remove Character',
              effectDescription: 'Rewrite script to remove the character. May affect story quality.',
              buzzPenalty: 15,
            },
            {
              text: 'Use CGI and Body Double',
              effectDescription: 'Complete remaining scenes digitally. Adds $5M in CGI costs.',
              cashPenalty: 5_000_000,
            },
          ],
        },
      },
    },
  });

  // Add news about production halt
  impacts.push({
    type: 'NEWS_ADDED',
    payload: {
      id: rng.uuid('NWS'),
      headline: `Production on "${project.title}" Halted After Cast Member Death`,
      description: `Filming has been suspended following the tragic passing of ${state.entities.talents?.[deathEvent.talentId]?.name}. The studio is evaluating options to complete the project.`,
      category: 'talent',
      publication: 'Variety',
    },
  });

  return impacts;
}

/**
 * Process grief impacts on co-stars
 */
function processGriefImpacts(
  deathEvent: DeathEvent,
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const { coStarIds, griefLevel } = calculateGriefImpact(
    state.entities.talents?.[deathEvent.talentId]!,
    state
  );

  for (const coStarId of coStarIds) {
    const coStar = state.entities.talents?.[coStarId];
    if (!coStar) continue;

    // Co-stars may request time off
    if (rng.next() < griefLevel / 200) { // Up to 40% chance for high grief
      impacts.push({
        type: 'TALENT_UPDATED',
        payload: {
          talentId: coStarId,
          update: {
            onMedicalLeave: true,
            medicalLeaveEndsWeek: state.week + rng.rangeInt(2, 6),
          },
        },
      });

      impacts.push({
        type: 'NEWS_ADDED',
        payload: {
          id: rng.uuid('NWS'),
          headline: `${coStar.name} Steps Away From Production to Grieve`,
          description: `Following the death of their co-star, ${coStar.name} has temporarily left the production to process their grief.`,
          category: 'talent',
          publication: 'The Hollywood Reporter',
        },
      });
    }
  }

  return impacts;
}

/**
 * Determine if talent is owned by player or a rival studio
 */
function getTalentOwner(talent: Talent, state: GameState): string | null {
  // Check contracts
  const contracts = Object.values(state.entities.contracts || {})
    .filter(c => c.talentId === talent.id);

  for (const contract of contracts) {
    if (contract.ownerId === state.studio.id) {
      return 'player';
    }
    // Check if ownerId is a rival
    if (state.entities.rivals?.[contract.ownerId]) {
      return contract.ownerId;
    }
  }

  // Check pacts
  const pact = state.deals?.activeDeals?.find(d => d.talentId === talent.id);
  if (pact) {
    if (pact.studioId === state.studio.id) {
      return 'player';
    }
    if (state.entities.rivals?.[pact.studioId]) {
      return pact.studioId;
    }
  }

  return null;
}

/**
 * Main death system tick function
 * Called weekly to check for talent deaths
 */
export function tickDeathSystem(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  const deathEvents: DeathEvent[] = [];

  const talents = Object.values(state.entities.talents || {});

  for (const talent of talents) {
    // Skip if already on medical leave (hospitalized, protected)
    if (talent.onMedicalLeave) continue;

    const age = talent.demographics?.age || 40;

    // Check each death type
    for (const prob of DEATH_PROBABILITIES) {
      const deathChance = calculateDeathProbability(age, prob);

      if (rng.next() < deathChance) {
        // Death occurs
        const deathEvent = generateDeathEvent(talent, prob.type, state, rng);
        deathEvents.push(deathEvent);

        // Create death news
        const headline = deathEvent.isDuringProduction
          ? `${talent.name} Dies Tragically During Production`
          : `${talent.name} Passes Away at ${age}`;

        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline,
            description: `${talent.name}, ${age}, ${deathEvent.cause} ${deathEvent.location}. The industry mourns the loss of this ${talent.tier === 1 ? 'legendary' : talent.tier === 2 ? 'acclaimed' : 'beloved'} ${talent.role}.`,
            category: 'talent',
            publication: deathEvent.isPublic ? 'Variety' : 'Industry Insider',
          },
        });

        // Remove talent from pool
        impacts.push({
          type: 'TALENT_REMOVED',
          payload: {
            talentId: talent.id,
            causeOfRemoval: 'death',
            deathType: deathEvent.type,
            deathWeek: state.week,
          },
        });

        // Check if talent was owned by AI studio
        const owner = getTalentOwner(talent, state);
        if (owner && owner !== 'player') {
          impacts.push({
            type: 'RIVAL_UPDATED',
            payload: {
              rivalId: owner,
              update: {
                // AI studio loses strength/prestige from talent death
                strength: Math.max(0, (state.entities.rivals?.[owner]?.strength || 50) - 2),
                recentActivity: `Mourning the loss of ${talent.name}`,
              },
            },
          });
        }

        // Process project impacts
        impacts.push(...processProjectImpacts(deathEvent, state, rng));

        // Process grief impacts
        impacts.push(...processGriefImpacts(deathEvent, state, rng));

        // Only one death per talent per week (obviously)
        break;
      }
    }
  }

  // Store death events in state for historical tracking
  if (deathEvents.length > 0) {
    impacts.push({
      type: 'SYSTEM_TICK',
      payload: {
        deathEvents,
        deathCount: deathEvents.length,
      },
    } as any);
  }

  return impacts;
}

/**
 * Get death statistics for a given time period
 */
export function getDeathStatistics(state: GameState, weeks: number = 52): {
  totalDeaths: number;
  byType: Record<DeathType, number>;
  duringProduction: number;
} {
  // This would access stored death events from state
  // For now, return placeholder
  return {
    totalDeaths: 0,
    byType: { natural: 0, accident: 0, overdose: 0, suicide: 0, violence: 0, illness: 0 },
    duringProduction: 0,
  };
}

import { GameState, StateImpact, Talent, TalentTier, Family, DeathEvent } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import { generateTalent } from '../../generators/talent/index';

/**
 * Dynasty System
 * Handles parent-child relationships, nepo baby generation, and talent inheritance.
 * Children enter the talent pool at age 18 with traits inherited from parents.
 */

export interface Pregnancy {
  id: string;
  motherId: string;
  fatherId: string;
  conceptionWeek: number;
  birthWeek: number; // 40 weeks later
  isPublic: boolean;
}

export interface FamilyRelationship {
  parentId: string;
  childId: string;
  relationshipType: 'biological' | 'adopted' | 'step';
  acknowledged: boolean;
  influenceLevel: number; // 0-100
}

export interface Dynasty {
  id: string;
  founderId: string;
  members: string[];
  reputation: number; // Dynasty prestige
  scandals: number;
  foundedWeek: number;
}

// Pregnancy probability from romantic relationships
const PREGNANCY_BASE_CHANCE = 0.01; // 1% per week for public stable couples
const NEPO_BABY_AGE_ENTRY = 18; // Age when children enter talent pool

/**
 * Check for pregnancies from romantic couples
 */
export function checkPregnancies(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  const newPregnancies: Pregnancy[] = [];

  // Get all public romantic pairs (would come from RelationshipSystem in full implementation)
  // For now, check married/coupled talent with spouseId
  const talents = Object.values(state.entities.talents || {});

  for (const talent of talents) {
    if (!talent.spouseId) continue; // Not in a relationship

    const spouse = state.entities.talents?.[talent.spouseId];
    if (!spouse) continue;

    // Only check once per couple (talent with lower ID)
    if (talent.id > spouse.id) continue;

    // Age check - both parents should be of appropriate age
    const mother = talent.demographics.gender === 'FEMALE' ? talent : spouse;
    const father = talent.demographics.gender === 'FEMALE' ? spouse : talent;

    if (mother.demographics.age < 18 || mother.demographics.age > 45) continue;
    if (father.demographics.age < 18 || father.demographics.age > 70) continue;

    // Check if already pregnant
    // In full implementation, check state.dynasty?.pregnancies
    // For now, skip if either already has children in pool (simplification)

    // Pregnancy check
    if (rng.next() < PREGNANCY_BASE_CHANCE) {
      const pregnancy: Pregnancy = {
        id: rng.uuid('PRG'),
        motherId: mother.id,
        fatherId: father.id,
        conceptionWeek: state.week,
        birthWeek: state.week + 40,
        isPublic: true, // Public couple = public pregnancy
      };

      newPregnancies.push(pregnancy);

      impacts.push({
        type: 'NEWS_ADDED',
        payload: {
          id: rng.uuid('NWS'),
          headline: `${mother.name} and ${father.name} Expecting!`,
          description: `The Hollywood power couple announced they are expecting their ${getChildOrdinal(mother.id, state)} child together.`,
          category: 'talent',
          publication: 'People Magazine',
        },
      });
    }
  }

  // Store pregnancies in state (would be in dynasty state slice)
  if (newPregnancies.length > 0) {
    impacts.push({
      type: 'SYSTEM_TICK',
      payload: {
        newPregnancies,
      },
    } as any);
  }

  return impacts;
}

/**
 * Process births from pregnancies reaching term
 */
