import { GameState, Talent } from '@/engine/types';
import { TalentUpdate } from '../../types/state.types';
import { SchedulingEngine } from '../schedulingEngine';
import { BardResolver } from '../bardResolver';
import { RandomGenerator } from '../../utils/rng';

export function advanceTalentLifecycle(state: GameState, rng: RandomGenerator): TalentUpdate[] {
  const talentUpdates: TalentUpdate[] = [];

  for (const id in state.entities.talents) {
    const talent = state.entities.talents[id];
    const update: Partial<Talent> = {};
    let changed = false;

    if (talent.onMedicalLeave) {
      if (state.week >= (talent.medicalLeaveEndsWeek || 0)) {
        update.onMedicalLeave = false;
        update.fatigue = 20;
        changed = true;
      }
    } else if ((talent.fatigue || 0) > 95) {
      update.onMedicalLeave = true;
      update.medicalLeaveEndsWeek = state.week + 12;
      changed = true;
    }

    if (!update.onMedicalLeave && !talent.onMedicalLeave) {
      const nextFatigue = SchedulingEngine.updateTalentFatigue(talent, false);
      if (nextFatigue !== (talent.fatigue || 0)) {
        update.fatigue = nextFatigue;
        changed = true;
      }
    }

    let nextCommitments = talent.commitments;
    if (talent.commitments && talent.commitments.length > 0) {
      let hasExpired = false;
      for (let i = 0; i < talent.commitments.length; i++) {
        if (talent.commitments[i].endWeek < state.week) {
          hasExpired = true;
          break;
        }
      }

      if (hasExpired) {
        nextCommitments = talent.commitments.filter(c => c.endWeek >= state.week);
        update.commitments = nextCommitments;
        changed = true;
      }
    }

    if (changed) {
      talentUpdates.push({
        talentId: id,
        update
      });
    }
  }

  return talentUpdates;
}

import { GameState, StateImpact, Talent, Project } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import {
  TalkShowAppearance,
  TalkShowType,
  MagazinePhotoshoot,
  PhotoshootType,
  PressTour,
  FAMOUS_TALK_SHOWS,
  PRESTIGIOUS_MAGAZINES,
} from '../../types/marketing.types';
import { areRomantic, areFriends, getTalentRelationships } from './RelationshipSystem';
import { getCliqueFameBonus } from './CliqueSystem';

/**
 * Marketing & Promotion System
 * Manages talk show appearances, magazine photoshoots, and press tours.
 * These boost Star Meter and can create viral moments or scandals.
 */

// Appearance generation thresholds
const TALK_SHOW_CHANCE = 0.08; // 8% per week per talent
const PHOTOSHOOT_CHANCE = 0.05; // 5% per week per talent
const PRESS_TOUR_CHANCE = 0.15; // 15% chance when releasing major film

// Performance factors
const BASE_PERFORMANCE = 50;
const CHARISMA_BONUS = 15;
const SCANDAL_RISK_BASE = 5;

/**
 * Generate talk show appearance for a talent
 */
function generateTalkShowAppearance(
  talent: Talent,
  state: GameState,
  rng: RandomGenerator,
  project?: Project
): TalkShowAppearance | null {
  // Check if talent is available (not on medical leave, etc)
  if ((talent as any).status === 'MEDICAL_LEAVE') return null;

  const showTypes: TalkShowType[] = [
    'late_night', 'morning_show', 'podcast', 'variety', 'comedy_central', 'serious_interview'
  ];

  // Match show type to talent personality
  let preferredTypes = showTypes;
  if (talent.personality === 'charismatic') {
    preferredTypes = ['late_night', 'variety', 'comedy_central'];
  } else if (talent.prestige > 80) {
    preferredTypes = ['serious_interview', 'morning_show'];
  }

  const showType = rng.pick(preferredTypes);
  const showName = rng.pick(FAMOUS_TALK_SHOWS[showType]);

  // Calculate performance
  let performance = BASE_PERFORMANCE;
  if (talent.personality === 'charismatic') performance += CHARISMA_BONUS;
  if (talent.personality === 'difficult') performance -= 10;
  performance += rng.rangeInt(-15, 25);
  performance = Math.max(0, Math.min(100, performance));

  // Viral moment chance (higher for high performance)
  const viralThreshold = 85;
  const viralMoment = performance > viralThreshold && rng.next() < 0.3;

  // Scandal risk (difficult personalities + live TV = risk)
  let scandalChance = SCANDAL_RISK_BASE;
  if (talent.personality === 'difficult') scandalChance += 20;
  if (showType === 'comedy_central') scandalChance += 10;
  if (showType === 'variety') scandalChance += 5;
  const scandalGenerated = rng.next() < (scandalChance / 100);

  // Calculate reach based on show type and talent fame
  const baseReach: Record<TalkShowType, number> = {
    'late_night': 2000000,
    'morning_show': 3500000,
    'podcast': 500000,
    'variety': 1500000,
    'comedy_central': 800000,
    'serious_interview': 1200000,
  };
  const reach = Math.floor(baseReach[showType] * (talent.starMeter || 50) / 50);

  // Calculate boosts
  const prestigeChange = performance > 70 ? 1 : (performance < 40 ? -1 : 0);
  const starMeterBoost = Math.floor((performance - 50) / 10) + (viralMoment ? 10 : 0);

  return {
    id: rng.uuid('TSH'),
    talentId: talent.id,
    projectId: project?.id,
    showName,
    showType,
    week: state.week,
    performance,
    viralMoment,
    scandalGenerated,
    audienceReach: reach,
    prestigeChange,
    starMeterBoost,
    chemistryBonus: 0, // Could be calculated if we track host relationships
  };
}

/**
 * Generate magazine photoshoot for a talent
 */
function generatePhotoshoot(
  talent: Talent,
  state: GameState,
  rng: RandomGenerator,
  coTalent?: Talent // For couple/clique shoots
): MagazinePhotoshoot | null {
  const shootTypes: PhotoshootType[] = [
    'magazine_cover', 'fashion_editorial', 'promotional', 'candid', 'red_carpet', 'controversial'
  ];

  // Choose shoot type based on talent
  let preferredTypes = shootTypes;
  if (talent.accessLevel === 'dynasty' || talent.tier === 1) {
    preferredTypes = ['magazine_cover', 'fashion_editorial'];
  } else if (talent.psychology?.scandalRisk && talent.psychology.scandalRisk > 60) {
    preferredTypes = ['controversial', 'candid'];
  }

  const shootType = rng.pick(preferredTypes);
  const magazineName = rng.pick(PRESTIGIOUS_MAGAZINES);

  // Quality based on talent prestige + photographer skill (random)
  let quality = (talent.prestige || 50) * 0.5 + rng.rangeInt(20, 50);
  if (shootType === 'controversial') quality += 10; // Edgy shoots get attention
  quality = Math.min(100, quality);

  // Controversy level
  let controversy = 0;
  if (shootType === 'controversial') controversy = rng.rangeInt(40, 80);
  else if (shootType === 'candid') controversy = rng.rangeInt(10, 30);
  else if (talent.psychology?.scandalRisk && talent.psychology.scandalRisk > 60) {
    controversy = rng.rangeInt(20, 50);
  }

  // Publication happens 1-3 weeks after shoot
  const publicationWeek = state.week + rng.rangeInt(1, 3);

  // Calculate boosts
  const starMeterBoost = Math.floor(quality / 10) + (controversy > 50 ? 5 : 0);
  const prestigeChange = shootType === 'magazine_cover' && quality > 80 ? 2 :
                         shootType === 'controversial' ? -1 : 0;

  const coTalentIds = coTalent ? [coTalent.id] : [];
  const isCoupleShoot = coTalent ? areRomantic(talent.id, coTalent.id, state) : false;

  return {
    id: rng.uuid('PHS'),
    talentId: talent.id,
    magazineName,
    shootType,
    week: state.week,
    quality,
    controversy,
    publicationWeek,
    starMeterBoost,
    prestigeChange,
    coTalentIds,
    isCoupleShoot,
  };
}

/**
 * Generate press tour for major release
 */
function generatePressTour(
  project: Project,
  talents: Talent[],
  state: GameState,
  rng: RandomGenerator
): PressTour | null {
  if (talents.length === 0) return null;

  const duration = rng.rangeInt(2, 4); // 2-4 weeks

  const tour: PressTour = {
    id: rng.uuid('PRT'),
    projectId: project.id,
    talentIds: talents.map(t => t.id),
    startWeek: state.week,
    endWeek: state.week + duration,
    appearances: [],
    photoshoots: [],
    totalCost: talents.length * duration * 50000, // $50k per talent per week
    effectiveness: 0, // Calculated after generation
  };

  // Generate appearances for each week
  for (let week = 0; week < duration; week++) {
    for (const talent of talents) {
      // 70% chance of appearance per talent per week
      if (rng.next() < 0.7) {
        const appearance = generateTalkShowAppearance(talent, state, rng, project);
        if (appearance) {
          appearance.week = state.week + week;
          tour.appearances.push(appearance);
        }
      }

      // 40% chance of photoshoot per talent
      if (rng.next() < 0.4) {
        const photoshoot = generatePhotoshoot(talent, state, rng);
        if (photoshoot) {
          photoshoot.week = state.week + week;
          tour.photoshoots.push(photoshoot);
        }
      }
    }

    // Couple shoots for romantic partners on same tour
    for (let i = 0; i < talents.length; i++) {
      for (let j = i + 1; j < talents.length; j++) {
        if (areRomantic(talents[i].id, talents[j].id, state) && rng.next() < 0.3) {
          const coupleShoot = generatePhotoshoot(talents[i], state, rng, talents[j]);
          if (coupleShoot) {
            coupleShoot.week = state.week + week;
            tour.photoshoots.push(coupleShoot);
          }
        }
      }
    }
  }

  // Calculate effectiveness
  const avgPerformance = tour.appearances.length > 0
    ? tour.appearances.reduce((sum, a) => sum + a.performance, 0) / tour.appearances.length
    : 50;
  tour.effectiveness = Math.floor(avgPerformance);

  return tour;
}

/**
 * Main marketing promotion tick
 */
export function tickMarketingPromotionSystem(
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const talents = Object.values(state.entities.talents || {});

  // 1. Individual talk show appearances
  for (const talent of talents) {
    if (rng.next() < TALK_SHOW_CHANCE * (talent.starMeter || 50) / 50) {
      const appearance = generateTalkShowAppearance(talent, state, rng);

      if (appearance) {
        impacts.push({
          type: 'TALK_SHOW_APPEARANCE_CREATED',
          payload: {
            talentId: talent.id,
            appearance,
          },
        } as any);

        // Apply star meter boost
        if (appearance.starMeterBoost !== 0) {
          impacts.push({
            type: 'TALENT_UPDATED',
            payload: {
              talentId: talent.id,
              update: {
                starMeter: Math.max(0, Math.min(100, (talent.starMeter || 50) + appearance.starMeterBoost)),
              },
            },
          });
        }

        // Viral moment news
        if (appearance.viralMoment) {
          impacts.push({
            type: 'NEWS_ADDED',
            payload: {
              id: rng.uuid('NWS'),
              headline: `${talent.name} Goes Viral on ${appearance.showName}`,
              description: `A clip from the appearance has taken over social media, boosting their profile significantly.`,
              category: 'talent',
              publication: 'Entertainment Weekly',
            },
          });
        }

        // Scandal from appearance
        if (appearance.scandalGenerated) {
          impacts.push({
            type: 'SCANDAL_ADDED',
            payload: {
              scandal: {
                id: rng.uuid('SCD'),
                talentId: talent.id,
                week: state.week,
                type: 'CONTROVERSY',
                description: `${talent.name} made controversial remarks during their ${appearance.showName} appearance`,
                severity: 'medium',
                publicAwareness: 60,
                careerImpact: -5,
              },
            },
          });
        }
      }
    }
  }

  // 2. Individual photoshoots
  for (const talent of talents) {
    // Higher chance for top-tier talent
    const photoshootChance = PHOTOSHOOT_CHANCE * (talent.tier === 1 ? 2 : 1);

    if (rng.next() < photoshootChance) {
      const photoshoot = generatePhotoshoot(talent, state, rng);

      if (photoshoot) {
        impacts.push({
          type: 'PHOTOSHOOT_CREATED',
          payload: {
            talentId: talent.id,
            photoshoot,
          },
        } as any);

        // Apply boosts when published
        if (photoshoot.publicationWeek === state.week) {
          impacts.push({
            type: 'TALENT_UPDATED',
            payload: {
              talentId: talent.id,
              update: {
                starMeter: Math.max(0, Math.min(100, (talent.starMeter || 50) + photoshoot.starMeterBoost)),
                prestige: talent.prestige + photoshoot.prestigeChange,
              },
            },
          });

          // News about cover
          if (photoshoot.shootType === 'magazine_cover') {
            impacts.push({
              type: 'NEWS_ADDED',
              payload: {
                id: rng.uuid('NWS'),
                headline: `${talent.name} Graces Cover of ${photoshoot.magazineName}`,
                description: `The stunning cover shoot is generating major buzz in the industry.`,
                category: 'talent',
                publication: photoshoot.magazineName,
              },
            });
          }

          // News about controversy
          if (photoshoot.controversy > 60) {
            impacts.push({
              type: 'NEWS_ADDED',
              payload: {
                id: rng.uuid('NWS'),
                headline: `${photoshoot.magazineName} ${photoshoot.magazineName} Shoot Sparks Controversy`,
                description: `${talent.name}'s edgy photoshoot is dividing fans and critics alike.`,
                category: 'talent',
                publication: 'Page Six',
              },
            });
          }

          // Couple shoot news
          if (photoshoot.isCoupleShoot && photoshoot.coTalentIds.length > 0) {
            const coTalent = state.entities.talents?.[photoshoot.coTalentIds[0]];
            impacts.push({
              type: 'NEWS_ADDED',
              payload: {
                id: rng.uuid('NWS'),
                headline: `Power Couple: ${talent.name} and ${coTalent?.name} on ${photoshoot.magazineName}`,
                description: `Hollywood's hottest couple poses together in an exclusive shoot.`,
                category: 'talent',
                publication: photoshoot.magazineName,
              },
            });
          }
        }
      }
    }
  }

  // 3. Press tours for upcoming releases
  const upcomingReleases = Object.values(state.entities.projects || {})
    .filter(p => {
      const releaseWeek = (p as any).releaseWeek;
      return releaseWeek && releaseWeek - state.week >= 2 && releaseWeek - state.week <= 6;
    });

  for (const project of upcomingReleases) {
    if (rng.next() < PRESS_TOUR_CHANCE) {
      // Get attached talent
      const projectContracts = Object.values(state.entities.contracts || {})
        .filter(c => c.projectId === project.id);
      const talentIds = projectContracts.map(c => c.talentId);
      const talents = talentIds
        .map(id => state.entities.talents?.[id])
        .filter((t): t is Talent => !!t);

      if (talents.length > 0) {
        const tour = generatePressTour(project, talents, state, rng);

        if (tour) {
          impacts.push({
            type: 'PRESS_TOUR_CREATED',
            payload: {
              projectId: project.id,
              tour,
              notification: `Press tour launched for "${project.title}" with ${talents.length} talents`,
            },
          } as any);

          // Deduct cost
          impacts.push({
            type: 'FUNDS_DEDUCTED',
            cashChange: -tour.totalCost,
          });

          // News about tour
          impacts.push({
            type: 'NEWS_ADDED',
            payload: {
              id: rng.uuid('NWS'),
              headline: `"${project.title}" Press Tour Kicks Off`,
              description: `The cast is hitting all the major talk shows and magazines to promote the upcoming release.`,
              category: 'industry',
              publication: 'Variety',
            },
          });
        }
      }
    }
  }

  return impacts;
}

/**
 * Get active press tours for a project
 */
export function getActivePressTours(projectId: string, state: GameState): any[] {
  const marketing = (state as any).relationships?.marketingPromotions || {};
  return Object.values(marketing.activePressTours || {})
    .filter((t: any) => t.projectId === projectId);
}

/**
 * Calculate buzz bonus from marketing activities
 */
export function calculateMarketingBuzz(
  projectId: string,
  state: GameState
): { buzzScore: number; viralMoments: number } {
  const marketing = (state as any).relationships?.marketingPromotions || {};

  const appearances = Object.values(marketing.talkShowAppearances || {}) as TalkShowAppearance[];
  const relevantAppearances = appearances.filter(a => a.projectId === projectId);

  const viralMoments = relevantAppearances.filter(a => a.viralMoment).length;
  const buzzScore = relevantAppearances.reduce((sum, a) => sum + (a.performance / 10), 0);

  return { buzzScore, viralMoments };
}

import { GameState, StateImpact, Talent, Project } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import { TalentRelationship } from '../../types/relationship.types';
import { Clique } from '../../types/clique.types';

/**
 * Organic Event Enhancer
 * Extends crisis and scandal systems with relationship and social integration.
 * Generates social-drama-based events that arise from the WSE simulation.
 */

/**
 * Check for relationship-based crises on a project
 */
export function checkRelationshipCrises(
  project: Project,
  state: GameState,
  rng: RandomGenerator
): StateImpact | null {
  // Get cast members
  const contracts = Object.values(state.entities.contracts || {})
    .filter(c => c.projectId === project.id);
  const talentIds = contracts.map(c => c.talentId);

  if (talentIds.length < 2) return null;

  // Check for feuds among cast
  const relationships = Object.values((state as any).relationships?.relationships || {})
    .filter((r: any) =>
      talentIds.includes(r.talentAId) && talentIds.includes(r.talentBId)
    ) as TalentRelationship[];

  const feuds = relationships.filter(r => r.type === 'rival' || r.type === 'enemy');

  if (feuds.length > 0 && rng.next() < 0.15) { // 15% chance if feuds exist
    const feud = rng.pick(feuds);
    const talentA = state.entities.talents?.[feud.talentAId];
    const talentB = state.entities.talents?.[feud.talentBId];

    if (!talentA || !talentB) return null;

    // Determine severity based on feud strength
    const severity = Math.abs(feud.strength) > 70 ? 'high' : 'medium';

    return {
      type: 'MODAL_TRIGGERED',
      payload: {
        modalType: 'CRISIS',
        priority: severity === 'high' ? 90 : 70,
        payload: {
          projectId: project.id,
          crisis: {
            id: rng.uuid('CRS'),
            crisisId: 'RELATIONSHIP_MELTDOWN',
            triggeredWeek: state.week,
            haltedProduction: severity === 'high',
            description: `On-set tension between ${talentA.name} and ${talentB.name} has escalated due to their ongoing feud. The production environment is becoming toxic.`,
            resolved: false,
            severity,
            options: [
              {
                text: 'Mediate',
                effectDescription: 'Hire a conflict resolution specialist. Costs $200k, 1 week delay.',
                cashPenalty: 200000,
                weeksDelay: 1,
              },
              {
                text: 'Separate Schedules',
                effectDescription: 'Shoot their scenes separately. Adds 2 weeks, reduces buzz by 10.',
                weeksDelay: 2,
              },
              {
                text: 'Replace One',
                effectDescription: `Fire ${rng.next() < 0.5 ? talentA.name : talentB.name}. Immediate replacement, lose 15 buzz.`,
                removeTalentId: rng.next() < 0.5 ? talentA.id : talentB.id,
                buzzPenalty: 15,
              },
            ],
          },
        },
      },
    };
  }

  return null;
}

/**
 * Check for clique-based crises
 */
export function checkCliqueCrises(
  project: Project,
  state: GameState,
  rng: RandomGenerator
): StateImpact | null {
  const contracts = Object.values(state.entities.contracts || {})
    .filter(c => c.projectId === project.id);
  const talentIds = contracts.map(c => c.talentId);

  if (talentIds.length < 3) return null;

  const cliques = (state as any).relationships?.cliques?.cliques || {};
  const memberCliqueMap = (state as any).relationships?.cliques?.memberCliqueMap || {};

  // Find cliques that have multiple members on this project
  const cliquePresence: Record<string, number> = {};
  for (const talentId of talentIds) {
    const talentCliques = memberCliqueMap[talentId] || [];
    for (const cliqueId of talentCliques) {
      cliquePresence[cliqueId] = (cliquePresence[cliqueId] || 0) + 1;
    }
  }

  // Check for clique drama (if toxic clique has 2+ members)
  for (const [cliqueId, count] of Object.entries(cliquePresence)) {
    if (count < 2) continue;

    const clique = cliques[cliqueId] as Clique;
    if (!clique || clique.reputation === 'toxic') {
      if (rng.next() < 0.1) { // 10% chance
        const members = talentIds.filter(id =>
          (memberCliqueMap[id] || []).includes(cliqueId)
        );

        return {
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `Clique Drama on "${project.title}" Set`,
            description: `Members of the ${clique?.name || 'controversial group'} are reportedly creating tension with other cast members.`,
            category: 'talent',
            publication: 'Page Six',
          },
        };
      }
    }
  }

  return null;
}

/**
 * Generate relationship scandals
 */
export function generateRelationshipScandals(
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  const relationships = Object.values((state as any).relationships?.relationships || {}) as TalentRelationship[];

  // Check for affair scandals (secret romantic relationships becoming public)
  const secretRomances = relationships.filter(r =>
    r.type === 'romantic' && !r.isPublic && r.strength > 60
  );

  for (const romance of secretRomances) {
    if (rng.next() < 0.05) { // 5% chance per secret romance
      const talentA = state.entities.talents?.[romance.talentAId];
      const talentB = state.entities.talents?.[romance.talentBId];

      if (!talentA || !talentB) continue;

      // Check if either has a spouse
      const spouseA = talentA.spouseId ? state.entities.talents?.[talentA.spouseId] : null;
      const spouseB = talentB.spouseId ? state.entities.talents?.[talentB.spouseId] : null;

      if (spouseA || spouseB) {
        // AFFAIR SCANDAL
        impacts.push({
          type: 'SCANDAL_ADDED',
          payload: {
            scandal: {
              id: rng.uuid('SND'),
              talentId: romance.talentAId,
              week: state.week,
              type: 'CONTROVERSY',
              description: `${talentA.name} rumored to be having an affair with ${talentB.name}`,
              severity: 'high',
              publicAwareness: 70,
              careerImpact: -8,
            },
          },
        });

        // Also add scandal for other party
        impacts.push({
          type: 'SCANDAL_ADDED',
          payload: {
            scandal: {
              id: rng.uuid('SND'),
              talentId: romance.talentBId,
              week: state.week,
              type: 'CONTROVERSY',
              description: `${talentB.name} involved in affair scandal with ${talentA.name}`,
              severity: 'high',
              publicAwareness: 70,
              careerImpact: -8,
            },
          },
        });

        // Make relationship public
        impacts.push({
          type: 'RELATIONSHIP_UPDATED',
          payload: {
            relationshipId: romance.id,
            update: { isPublic: true },
          },
        } as any);

        // News
        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `Cheating Scandal Rocks Hollywood`,
            description: `${talentA.name} and ${talentB.name} caught in explosive affair revelation.`,
            category: 'talent',
            publication: 'TMZ',
          },
        });
      }
    }
  }

  // Check for public breakups
  const publicRomances = relationships.filter(r =>
    r.type === 'romantic' && r.isPublic
  );

  for (const romance of publicRomances) {
    // Check for negative events in history
    const breakupEvent = romance.history.find(h =>
      h.type === 'breakup' && h.week > state.week - 4
    );

    if (breakupEvent) {
      const talentA = state.entities.talents?.[romance.talentAId];
      const talentB = state.entities.talents?.[romance.talentBId];

      if (talentA && talentB) {
        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `Hollywood Power Couple Splits`,
            description: `${talentA.name} and ${talentB.name} have ended their high-profile relationship.`,
            category: 'talent',
            publication: 'People Magazine',
          },
        });
      }
    }
  }

  return impacts;
}

/**
 * Main organic events tick - extends existing crisis/scandal systems
 */
export function tickOrganicEvents(
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  // 1. Check projects for relationship-based crises
  const projects = Object.values(state.entities.projects || {});
  for (const project of projects) {
    const projectState = (project as any).status || (project as any).state;
    if (['IN_PRODUCTION', 'production', 'filming'].some(s =>
      projectState?.toLowerCase().includes(s.toLowerCase())
    )) {
      const relationshipCrisis = checkRelationshipCrises(project, state, rng);
      if (relationshipCrisis) {
        impacts.push(relationshipCrisis);
      }

      const cliqueCrisis = checkCliqueCrises(project, state, rng);
      if (cliqueCrisis) {
        impacts.push(cliqueCrisis);
      }
    }
  }

  // 2. Generate relationship scandals
  const relationshipScandals = generateRelationshipScandals(state, rng);
  impacts.push(...relationshipScandals);

  return impacts;
}

/**
 * Calculate crisis chance modifier based on social factors
 */
export function calculateSocialCrisisModifier(
  projectId: string,
  state: GameState
): number {
  let modifier = 1.0;

  // Get cast
  const contracts = Object.values(state.entities.contracts || {})
    .filter(c => c.projectId === projectId);
  const talentIds = contracts.map(c => c.talentId);

  if (talentIds.length < 2) return modifier;

  // Check for feuds
  const relationships = Object.values((state as any).relationships?.relationships || {})
    .filter((r: any) =>
      talentIds.includes(r.talentAId) && talentIds.includes(r.talentBId)
    ) as TalentRelationship[];

  const feuds = relationships.filter(r => r.type === 'rival' || r.type === 'enemy');
  modifier += feuds.length * 0.15; // +15% per feud

  // Check for toxic cliques
  const memberCliqueMap = (state as any).relationships?.cliques?.memberCliqueMap || {};
  const cliques = (state as any).relationships?.cliques?.cliques || {};

  const toxicCliqueMembers = talentIds.filter(id => {
    const talentCliques = memberCliqueMap[id] || [];
    return talentCliques.some((cid: string) =>
      (cliques[cid] as Clique)?.reputation === 'toxic'
    );
  });

  modifier += toxicCliqueMembers.length * 0.10; // +10% per toxic clique member

  return Math.min(2.0, modifier); // Cap at 2x
}

import { Talent, Project, Contract, Award } from '@/engine/types';
import { clamp } from '../../utils';
import { applyAwardBoostsToTalent } from '../talentStats';

export function applyProjectResults(
  project: Project,
  contracts: Contract[],
  talentPool: Record<string, Talent> | Talent[],
  projectAwards: Award[] = []
): Talent[] {
  if (contracts.length === 0) return [];

  const isArray = Array.isArray(talentPool);
  const talentPoolMap = isArray ? new Map<string, Talent>() : null;
  if (isArray) {
    for (const t of (talentPool as Talent[])) {
      talentPoolMap!.set(t.id, t);
    }
  }

  const totalCost = project.budget + (project.marketingBudget || 0);
  const ROI = totalCost > 0 ? project.revenue / totalCost : 0;

  let drawChange = 0;
  let prestigeChange = 0;
  let feeMultiplier = 1.0;

  if (ROI > 4.0) { drawChange = 12; prestigeChange = 6; feeMultiplier = 1.6; }
  else if (ROI > 2.0) { drawChange = 6; prestigeChange = 3; feeMultiplier = 1.3; }
  else if (ROI > 1.0) { drawChange = 2; prestigeChange = 1; feeMultiplier = 1.1; }
  else if (ROI < 0.4) { drawChange = -12; prestigeChange = -6; feeMultiplier = 0.75; }
  else if (ROI < 0.8) { drawChange = -6; prestigeChange = -3; feeMultiplier = 0.85; }

  const updatedTalent: Talent[] = [];

  for (const contract of contracts) {
    const talent = talentPoolMap ? talentPoolMap.get(contract.talentId) : (talentPool as Record<string, Talent>)[contract.talentId];
    if (!talent) continue;

    let talentAwardsDrawBonus = 0;
    let talentAwardsPrestigeBonus = 0;
    let talentAwardsFeeMultiplier = 1.0;
    let talentAwardsEgoBoost = 0;

    for (const award of projectAwards) {
      const isDirector = talent.roles.includes('director');
      const isActor = talent.roles.includes('actor');
      const isWriter = talent.roles.includes('writer');

      let qualifiesForBonus;
      if (award.category.includes('Director')) { qualifiesForBonus = isDirector; }
      else if (award.category.includes('Actor') || award.category.includes('Actress') || award.category.includes('Ensemble')) { qualifiesForBonus = isActor; }
      else if (award.category.includes('Screenplay')) { qualifiesForBonus = isWriter; }
      else { qualifiesForBonus = true; }

      if (qualifiesForBonus) {
        const multiplier = (award.category.includes('Director') || award.category.includes('Actor') || award.category.includes('Actress') || award.category.includes('Screenplay')) ? 1.0 : 0.5;
        const isPrestige = ['Academy Awards', 'Primetime Emmys', 'Cannes Film Festival', 'Venice Film Festival'].includes(award.body);

        const boosts = applyAwardBoostsToTalent(talent, award, multiplier, isPrestige);

        talentAwardsPrestigeBonus += boosts.prestigeBoost;
        talentAwardsDrawBonus += boosts.drawBoost;

        talentAwardsFeeMultiplier += (boosts.feeMultiplier - 1.0);
        talentAwardsEgoBoost += boosts.egoBoost;
      }
    }

    const finalFeeMultiplier = feeMultiplier * talentAwardsFeeMultiplier;

    const newTalent = {
      ...talent,
      draw: clamp(talent.draw + drawChange + talentAwardsDrawBonus, 0, 100),
      prestige: clamp(talent.prestige + prestigeChange + talentAwardsPrestigeBonus, 0, 100),
      fee: Math.round(clamp(talent.fee * finalFeeMultiplier, 10000, 75000000)),
      psychology: {
        ...talent.psychology,
        ego: clamp((talent.psychology?.ego || 50) + talentAwardsEgoBoost, 0, 100)
      }
    };

    updatedTalent.push(newTalent);
  }

  return updatedTalent;
}

import { GameState, StateImpact, Talent, Project, Contract } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import {
  ScreenplayNote,
