/**
 * Generate credit scenes for franchise/sequel potential
 */
function generateCreditScenes(
  project: Project,
  state: GameState,
  rng: RandomGenerator
): CreditScene[] {
  const scenes: CreditScene[] = [];

  // Only for films with franchise potential
  const isFranchiseProject = project.type === 'FILM' && project.budget > 50000000;
  if (!isFranchiseProject) return scenes;

  // 40% chance to have credit scenes
  if (rng.next() > 0.4) return scenes;

  const types: CreditSceneType[] = ['mid_credits', 'post_credits', 'teaser', 'joke', 'emotional_button'];
  const type = rng.pick(types);

  const unlockConditions: Array<'franchise_member' | 'boxoffice_threshold' | 'sequels' | 'standalone'> = ['franchise_member', 'boxoffice_threshold', 'sequels', 'standalone'];
  const unlockCondition = rng.pick(unlockConditions);

  const scene: CreditScene = {
    id: rng.uuid('CRD'),
    projectId: project.id,
    type,
    description: generateCreditSceneDescription(type, rng),
    unlockCondition,
    cost: Math.floor(project.budget * 0.02),
    audienceBonus: type === 'emotional_button' ? 15 : (type === 'joke' ? 8 : 5),
    franchiseValue: type === 'teaser' ? 20 : (type === 'mid_credits' ? 15 : 10),
    surpriseFactor: rng.rangeInt(40, 80),
    spoiledByRumors: false, // Will be determined by rumor system
  };

  scenes.push(scene);

  // Maybe add a second scene (mid + post credits)
  if (rng.next() < 0.3 && type === 'mid_credits') {
    const secondTypes: CreditSceneType[] = ['post_credits', 'joke', 'emotional_button'];
    const secondType = rng.pick(secondTypes);
    const secondScene: CreditScene = {
      id: rng.uuid('CRD'),
      projectId: project.id,
      type: secondType,
      description: generateCreditSceneDescription(secondType, rng),
      unlockCondition,
      cost: Math.floor(project.budget * 0.01),
      audienceBonus: secondType === 'emotional_button' ? 12 : 6,
      franchiseValue: 8,
      surpriseFactor: rng.rangeInt(30, 60),
      spoiledByRumors: false,
    };
    scenes.push(secondScene);
  }

  return scenes;
}

/**
 * Generate description for credit scene
 */
function generateCreditSceneDescription(type: CreditSceneType, rng: RandomGenerator): string {
  const descriptions: Record<CreditSceneType, string[]> = {
    'mid_credits': [
      'Tease the next installment with a mysterious reveal',
      'New character introduction for sequel setup',
      'Major plot twist revelation',
    ],
    'post_credits': [
      'Final stinger for dedicated fans',
      'Comic relief moment after heavy ending',
      'Sequel hook with major implications',
    ],
    'teaser': [
      'First look at sequel villain',
      'Spin-off character introduction',
      'New team formation reveal',
    ],
    'joke': [
      'Comedic button on the story',
      'Funny outtake moment',
      'Meta-commentary on the film',
    ],
    'emotional_button': [
      'Quiet emotional resolution',
      'Character closure moment',
      'Tribute to cast/crew',
    ],
  };

  return rng.pick(descriptions[type]);
}

/**
 * Calculate total quality bonus from implemented notes
 */
export function getProjectQualityBonus(
  projectId: string,
  state: GameState
): { screenplayBonus: number; additionBonus: number; creditSceneBonus: number } {
  const enhancements = (state as any).productionEnhancements || {};

  const screenplayBonus = (Object.values(enhancements.screenplayNotes || {}) as ScreenplayNote[])
    .filter(n => n.projectId === projectId && n.implemented)
    .reduce((sum, n) => sum + n.qualityBonus, 0);

  const additionBonus = (Object.values(enhancements.productionAdditions || {}) as ProductionAddition[])
    .filter(a => a.projectId === projectId)
    .reduce((sum, a) => sum + a.qualityBonus, 0);

  const creditSceneBonus = (Object.values(enhancements.creditScenes || {}) as CreditScene[])
    .filter(c => c.projectId === projectId)
    .reduce((sum, c) => sum + c.audienceBonus, 0);

  return { screenplayBonus, additionBonus, creditSceneBonus };
}

/**
 * Main production enhancement tick
 */
export function tickProductionEnhancementSystem(
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  // Get active projects in production or pre-production
  const activeProjects = Object.values(state.entities.projects || {})
    .filter(p => (p as any).status === 'PRE_PRODUCTION' || (p as any).status === 'IN_PRODUCTION');

  for (const project of activeProjects) {
    const projectStatus = (project as any).status;

    // Generate screenplay notes during pre-production
    if (projectStatus === 'PRE_PRODUCTION') {
      const notes = generateScreenplayNotes(project, state, rng);
      for (const note of notes) {
        impacts.push({
          type: 'SCREENPLAY_NOTE_CREATED',
          payload: {
            projectId: project.id,
            note,
            notification: `${state.entities.talents?.[note.authorId]?.name} has provided screenplay notes for "${project.title}"`,
          },
        } as any);
      }
    }

    // Generate production additions during production
    if (projectStatus === 'IN_PRODUCTION') {
      const additions = generateProductionAdditions(project, state, rng);
      for (const addition of additions) {
        impacts.push({
          type: 'PRODUCTION_ADDITION_CREATED',
          payload: {
            projectId: project.id,
            addition,
            notification: `New production addition for "${project.title}": ${addition.description}`,
          },
        } as any);

        // Add cost to project
        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: {
            projectId: project.id,
            update: {
              budget: project.budget + addition.cost,
              weeklyCost: (project.weeklyCost || 0) + Math.floor(addition.cost / 10),
            },
          },
        });
      }
    }

    // Generate credit scenes during production
    if (projectStatus === 'IN_PRODUCTION' && project.type === 'FILM') {
      const scenes = generateCreditScenes(project, state, rng);
      for (const scene of scenes) {
        impacts.push({
          type: 'CREDIT_SCENE_CREATED',
          payload: {
            projectId: project.id,
            scene,
            notification: `Credit scene planned for "${project.title}"`,
          },
        } as any);
      }
    }
  }

  return impacts;
}

/**
 * Apply an unimplemented screenplay note
 */
export function implementScreenplayNote(
  noteId: string,
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const enhancements = (state as any).productionEnhancements || {};
  const note = enhancements.screenplayNotes?.[noteId] as ScreenplayNote | undefined;

  if (!note || note.implemented) return impacts;

  // Deduct cost
  impacts.push({
    type: 'FUNDS_DEDUCTED',
    cashChange: -note.cost,
  });

  // Mark as implemented
  impacts.push({
    type: 'SCREENPLAY_NOTE_IMPLEMENTED',
    payload: {
      noteId,
      note: { ...note, implemented: true, implementedWeek: state.week },
    },
  } as any);

  // Apply quality bonus to project
  const project = state.entities.projects?.[note.projectId];
  if (project) {
    // Quality will be calculated from notes in production system
    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        headline: `"${project.title}" Incorporates Talent Feedback`,
        description: `The production team has implemented screenplay suggestions from the cast, potentially improving the final product.`,
        category: 'industry',
        publication: 'Deadline',
      },
    });
  }

  return impacts;
}

/**
 * Spoil a credit scene via rumors (affects surprise value)
 */
export function spoilCreditScene(
  sceneId: string,
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const enhancements = (state as any).productionEnhancements || {};
  const scene = enhancements.creditScenes?.[sceneId] as CreditScene | undefined;

  if (!scene || scene.spoiledByRumors) return impacts;

  const updatedScene: CreditScene = {
    ...scene,
    spoiledByRumors: true,
  };

  impacts.push({
    type: 'CREDIT_SCENE_UPDATED',
    payload: {
      sceneId,
      scene: updatedScene,
    },
  } as any);

  // News about leak
  const project = state.entities.projects?.[scene.projectId];
  if (project) {
    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        headline: `"${project.title}" Credit Scene Leaked`,
        description: `Spoilers are circulating about the film's post-credits content. The studio is scrambling to control the narrative.`,
        category: 'industry',
        publication: 'The Hollywood Reporter',
      },
    });
  }

  return impacts;
}

import { GameState, StateImpact, Talent } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import {
  TalentRelationship,
  RelationshipEvent,
  RomanceData
} from '../../types/relationship.types';
import { getRelationshipKey } from './relationshipCompatibility';
import {
  getRelationship,
  haveWorkedTogether,
  haveCompeted,
  checkNaturalFormation,
  formRelationship,
} from './relationshipFormation';

export { haveCompeted } from './relationshipFormation';

function evolveRelationship(
  relationship: TalentRelationship,
  state: GameState,
  rng: RandomGenerator
): { updated: TalentRelationship; impacts: StateImpact[] } {
  const impacts: StateImpact[] = [];
  const talentA = state.entities.talents?.[relationship.talentAId];
  const talentB = state.entities.talents?.[relationship.talentBId];

  if (!talentA || !talentB) {
    return { updated: relationship, impacts };
  }

  let strengthChange = 0;
  let eventType: RelationshipEvent['type'] | null = null;
  let description = '';

  strengthChange += rng.rangeInt(-5, 5);

  if (haveWorkedTogether(talentA.id, talentB.id, state)) {
    if (relationship.type === 'friend') {
      strengthChange += 5;
      eventType = 'strengthened';
      description = 'Reunited on set and their friendship deepened';
    } else if (relationship.type === 'rival') {
      strengthChange -= 5;
      eventType = 'weakened';
      description = 'Being forced to work together intensified their feud';
    }
  }

  if (relationship.type === 'rival' && haveCompeted(talentA.id, talentB.id, state)) {
    strengthChange -= 10;
    eventType = 'weakened';
    description = `Competing for the same award reignited their rivalry`;
  }

  if (relationship.type === 'romantic') {
    const romanceData = (relationship as any).romanceData as RomanceData;

    if (romanceData?.isSecret && rng.next() < 0.1) {
      strengthChange -= 3;
      description = 'The pressure of keeping their relationship secret is taking a toll';
    }

    const weeksTogether = state.week - relationship.formedWeek;
    if (weeksTogether > 52 && rng.next() < 0.3) {
      strengthChange += 10;
      eventType = 'strengthened';
      description = `Celebrated ${Math.floor(weeksTogether / 52)} year anniversary`;
    }

    if (relationship.strength < 30 && rng.next() < 0.2) {
      relationship.type = 'ex';
      relationship.strength = -20;
      eventType = 'breakup';
      description = `${talentA.name} and ${talentB.name} have called it quits`;

      impacts.push({
        type: 'NEWS_ADDED',
        payload: {
          id: rng.uuid('NWS'),
          headline: `It's Over: ${talentA.name} and ${talentB.name} Split`,
          description: `After weeks of speculation, sources confirm the couple has gone their separate ways.`,
          category: 'talent',
          publication: 'People Magazine',
        },
      });

      if (talentA.spouseId === talentB.id) {
        impacts.push({ type: 'TALENT_UPDATED', payload: { talentId: talentA.id, update: { spouseId: undefined } } });
      }
      if (talentB.spouseId === talentA.id) {
        impacts.push({ type: 'TALENT_UPDATED', payload: { talentId: talentB.id, update: { spouseId: undefined } } });
      }
    }
  }

  const newStrength = Math.max(-100, Math.min(100, relationship.strength + strengthChange));

  if (newStrength !== relationship.strength && eventType) {
    relationship.strength = newStrength;
    relationship.lastUpdatedWeek = state.week;
    relationship.history.push({ week: state.week, type: eventType, impact: strengthChange, description });
  }

  return { updated: relationship, impacts };
}

export function tickRelationshipSystem(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  const talents = Object.values(state.entities.talents || {});
  // ⚡ Bolt: Use Object.keys iteration to prevent massive intermediate array allocation
  const projectsDict = state.entities.projects || {};
  const projects = Object.keys(projectsDict).map(pid => projectsDict[pid]);
  const awards = state.industry?.awards || [];
  const awardedProjectIds = new Set(awards.map(a => a.projectId));

  // ⚡ The Framerate Fanatic: Massive O(N²) optimization.
  // Instead of checking all pairs, we check project interactions and a random sample of the rest.

  // 1. Pre-index talent clusters by project
  const projectTalentMap = new Map<string, Set<string>>();
  const awardedProjectsTalentSets: Set<string>[] = [];

  for (const project of projects) {
    const attachedIds = (project as any).attachedTalentIds || [];
    if (attachedIds.length < 2) continue;

    const set = new Set<string>(attachedIds);
    projectTalentMap.set(project.id, set);
    if (awardedProjectIds.has(project.id)) {
      awardedProjectsTalentSets.push(set);
    }
  }

  // Candidates for relationship formation
  const formationCandidates: [Talent, Talent][] = [];

  // A. Same project candidates (High probability)
  for (const talentSet of projectTalentMap.values()) {
    const ids = Array.from(talentSet);
    for (let i = 0; i < ids.length; i++) {
      for (let j = i + 1; j < ids.length; j++) {
        const tA = state.entities.talents[ids[i]];
        const tB = state.entities.talents[ids[j]];
        if (tA && tB) formationCandidates.push([tA, tB]);
      }
    }
  }

  // B. Random sample for world events (Prevents O(N²) cross-product)
  const RANDOM_SAMPLES = 200;
  for (let i = 0; i < RANDOM_SAMPLES; i++) {
    const idxA = rng.rangeInt(0, talents.length - 1);
    const idxB = rng.rangeInt(0, talents.length - 1);
    if (idxA === idxB) continue;
    formationCandidates.push([talents[idxA], talents[idxB]]);
  }

  // 2. Process Candidates
  for (const [talentA, talentB] of formationCandidates) {
    const formation = checkNaturalFormation(talentA, talentB, state, rng, projectTalentMap, awardedProjectsTalentSets);

    if (formation) {
      const { relationship, impacts: formationImpacts } = formRelationship(
        formation,
        state.week,
        state,
        rng
      );

      impacts.push(...formationImpacts);

      // Add to state
      const key = getRelationshipKey(formation.talentAId, formation.talentBId);
      impacts.push({
        type: 'RELATIONSHIP_FORMED',
        payload: {
          key,
          relationship,
        },
      } as any);

      // Update spouseId for public romantic relationships
      if (relationship.type === 'romantic' && relationship.isPublic) {
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: {
            talentId: relationship.talentAId,
            update: { spouseId: relationship.talentBId },
          },
        });
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: {
            talentId: relationship.talentBId,
            update: { spouseId: relationship.talentAId },
          },
        });
      }
    }
  }

  // 2. Evolve existing relationships
  const existingRelationships = Object.values((state as any).relationships?.relationships || {}) as TalentRelationship[];
  for (const relationship of existingRelationships) {
    // 30% chance to evolve each existing relationship per week
    if (rng.next() < 0.3) {
      const { updated, impacts: evolutionImpacts } = evolveRelationship(relationship, state, rng);

      if (updated !== relationship) {
        const key = getRelationshipKey(relationship.talentAId, relationship.talentBId);
        impacts.push({
          type: 'RELATIONSHIP_UPDATED',
          payload: {
            key,
            relationship: updated,
          },
        } as any);
      }

      impacts.push(...evolutionImpacts);
    }
  }

  return impacts;
}

/**
 * Check if two talents are friends
 */
export function areFriends(talentAId: string, talentBId: string, state: GameState): boolean {
  const rel = getRelationship(talentAId, talentBId, state);
  return rel?.type === 'friend' && rel.strength > 40;
}

/**
 * Check if two talents are rivals/enemies
 */
export function areRivals(talentAId: string, talentBId: string, state: GameState): boolean {
  const rel = getRelationship(talentAId, talentBId, state);
  return (rel?.type === 'rival' || rel?.type === 'enemy') && rel.strength < -40;
}

/**
 * Check if two talents are romantically involved
 */
export function areRomantic(talentAId: string, talentBId: string, state: GameState): boolean {
  const rel = getRelationship(talentAId, talentBId, state);
  return rel?.type === 'romantic' && rel.strength > 50;
}

/**
 * Get all relationships for a talent
 */
export function getTalentRelationships(talentId: string, state: GameState): TalentRelationship[] {
  return Object.values((state as any).relationships?.relationships || {})
    .filter((r: any) => r.talentAId === talentId || r.talentBId === talentId) as TalentRelationship[];
}

/**
 * Get casting chemistry modifier for two talents
 * Returns bonus/penalty (-20 to +20) to project quality
 */
export function getCastingChemistry(
  talentAId: string,
  talentBId: string,
  state: GameState,
  rng?: RandomGenerator
): number {
  const rel = getRelationship(talentAId, talentBId, state);

  if (!rel) return 0; // Neutral

  switch (rel.type) {
    case 'friend':
    case 'mentor':
      return Math.floor(rel.strength / 10); // Up to +10 for best friends
    case 'romantic':
      return Math.floor(rel.strength / 8) + 5; // Bonus for real couples +5
    case 'rival':
    case 'enemy':
      return Math.floor(rel.strength / 10); // Negative, up to -10
    case 'ex':
      return -15; // Awkward!
    case 'frenemy':
      return rng && rng.next() < 0.5 ? 5 : -5; // Unpredictable
    default:
      return 0;
  }
}

import { GameState, StateImpact, Talent } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import {
  TVShowRecommendation,
  TVRecommendationCriteria,
  TVRecommendationConfig,
  TVRoleType,
  TVGenre,
  TVPlatform,
  DEFAULT_TV_RECOMMENDATION_CONFIG,
  PLATFORM_PRESTIGE,
  ROLE_PRESTIGE_MULTIPLIERS,
  TV_SHOW_TEMPLATES,
} from '../../types/tv-recommendations.types';

/**
 * TV Show Recommendation System
 * Generates intelligent TV role recommendations for talents based on their attributes,
  career trajectory, and market conditions.
 */

/**
 * Calculate match score between talent and TV role
 */
function calculateMatchScore(
  criteria: TVRecommendationCriteria,
  roleType: TVRoleType,
  genre: TVGenre,
  platform: TVPlatform,
  config: TVRecommendationConfig
): number {
  let score = 50; // Base score

  // Tier alignment
  const tierRoleMap: Record<number, TVRoleType[]> = {
    1: ['lead', 'showrunner', 'creator'],
    2: ['lead', 'series_regular', 'showrunner'],
    3: ['series_regular', 'recurring', 'guest_star'],
    4: ['guest_star', 'recurring'],
  };

  const appropriateRoles = tierRoleMap[criteria.currentTier] || ['guest_star'];
  if (appropriateRoles.includes(roleType)) {
    score += 20;
  } else {
    score -= 15;
  }

  // Genre preference alignment
  if (criteria.preferredGenres.some(g => g.toLowerCase().includes(genre))) {
    score += 15;
  }

  // Platform prestige alignment with talent prestige
  const platformPrestige = PLATFORM_PRESTIGE[platform];
  if (Math.abs(platformPrestige - criteria.currentPrestige) < 20) {
    score += 10;
  } else if (platformPrestige > criteria.currentPrestige + 30) {
    score -= 10; // Platform too prestigious
  }

  // Personality fit
  const personalityGenreMap: Record<string, TVGenre[]> = {
    'charismatic': ['comedy', 'romance', 'action'],
    'difficult': ['drama', 'thriller'],
    'perfectionist': ['drama', 'thriller', 'sci-fi'],
    'collaborative': ['comedy', 'drama'],
  };

  if (criteria.personality && personalityGenreMap[criteria.personality]?.includes(genre)) {
    score += 10;
  }

  // Career trajectory alignment
  if (criteria.careerTrajectory === 'rising' && roleType === 'series_regular') {
    score += 15;
  } else if (criteria.careerTrajectory === 'comeback' && roleType === 'guest_star') {
    score += 10;
  } else if (criteria.careerTrajectory === 'plateau' && roleType === 'recurring') {
    score += 10;
  }

  // Skill alignment
  if (roleType === 'showrunner' || roleType === 'creator') {
    score += (criteria.skills.writing * 0.3) + (criteria.skills.directing * 0.2);
  } else if (roleType === 'lead') {
    score += (criteria.skills.acting * 0.4) + (criteria.skills.stardom * 0.3);
  } else {
    score += (criteria.skills.acting * 0.3) + (criteria.skills.stardom * 0.2);
  }

  // Age appropriateness for role
  if (criteria.age < 25 && (roleType === 'lead' || roleType === 'showrunner')) {
    score -= 10;
  } else if (criteria.age > 55 && roleType === 'guest_star') {
    score += 10; // Veteran guest stars
  }

  // Apply genre and platform weights
  score *= (config.genreWeights[genre] || 1.0);
  score *= (config.platformWeights[platform] || 1.0);

  return Math.max(0, Math.min(100, score));
}

/**
 * Generate reasoning for a recommendation
 */
function generateReasoning(
  criteria: TVRecommendationCriteria,
  roleType: TVRoleType,
  genre: TVGenre,
  platform: TVPlatform,
  matchScore: number
): string[] {
  const reasons: string[] = [];

  if (matchScore > 75) {
    reasons.push(`Strong match based on ${criteria.preferredGenres[0] || 'genre'} preference`);
  }

  if (criteria.preferredGenres.some(g => g.toLowerCase().includes(genre))) {
    reasons.push(`Aligns with preferred genre: ${genre}`);
  }

  if (PLATFORM_PRESTIGE[platform] > 60 && criteria.currentPrestige > 60) {
    reasons.push(`High-prestige platform matches talent's current status`);
  }

  if (criteria.personality) {
    reasons.push(`${criteria.personality} personality suits ${genre} content`);
  }

  if (criteria.careerTrajectory === 'rising' && roleType === 'series_regular') {
    reasons.push(`Career trajectory suggests ready for series regular role`);
  }

  if (criteria.skills.acting > 70 && roleType !== 'showrunner' && roleType !== 'creator') {
    reasons.push(`Strong acting skills (${criteria.skills.acting}) support this role`);
  }

  if (criteria.skills.writing > 70 && (roleType === 'showrunner' || roleType === 'creator')) {
    reasons.push(`Strong writing skills (${criteria.skills.writing}) suitable for creative leadership`);
  }

  if (reasons.length === 0) {
    reasons.push(`Based on overall talent profile and market fit`);
  }

  return reasons;
}

/**
 * Generate suggested show titles
 */
function generateShowTitles(
  genre: TVGenre,
  platform: TVPlatform,
  rng: RandomGenerator
): string[] {
  const templates = TV_SHOW_TEMPLATES[genre]?.[platform] || ['Untitled Series'];
  const titles: string[] = [];

  for (let i = 0; i < 3; i++) {
    const template = rng.pick(templates);
    const adjectives = ['The New', 'Lost', 'Dark', 'Secret', 'American', 'Modern', 'Final', 'Eternal'];
    const nouns = ['Chronicles', 'Stories', 'Legacy', 'Mystery', 'Saga', 'Tales', 'Files', 'Diaries'];
    const locations = ['of Hollywood', 'in the City', 'from the Studio', 'Behind the Scenes', 'Uncovered'];

    if (rng.next() < 0.3) {
      titles.push(`${rng.pick(adjectives)} ${template}`);
    } else if (rng.next() < 0.5) {
      titles.push(`${template} ${rng.pick(locations)}`);
    } else {
      titles.push(`${template}: ${rng.pick(nouns)}`);
    }
  }

  return titles;
}

/**
 * Generate a single TV recommendation
 */
function generateRecommendation(
  criteria: TVRecommendationCriteria,
  config: TVRecommendationConfig,
  rng: RandomGenerator
): TVShowRecommendation | null {
  // Determine eligible role types based on tier
  const eligibleRoles: TVRoleType[] = [];
  if (criteria.currentTier === 1) {
    eligibleRoles.push('lead', 'showrunner', 'creator');
  } else if (criteria.currentTier === 2) {
    eligibleRoles.push('lead', 'series_regular', 'showrunner', 'recurring');
  } else if (criteria.currentTier === 3) {
    eligibleRoles.push('series_regular', 'recurring', 'guest_star');
  } else {
    eligibleRoles.push('guest_star', 'recurring');
  }

  const roleType = rng.pick(eligibleRoles);

  // Select genre (weighted by preferences)
  const genres: TVGenre[] = ['drama', 'comedy', 'thriller', 'sci-fi', 'horror', 'action', 'romance', 'reality', 'documentary'];
  let genre = rng.pick(genres);

  // Prefer talent's preferred genres
  if (criteria.preferredGenres.length > 0 && rng.next() < 0.6) {
    const preferredGenre = rng.pick(criteria.preferredGenres);
    const matchedGenre = genres.find(g => preferredGenre.toLowerCase().includes(g));
    if (matchedGenre) genre = matchedGenre;
  }

  // Select platform
  const platforms: TVPlatform[] = ['broadcast', 'cable', 'streaming', 'premium_cable'];
  const platform = rng.pick(platforms);

  // Calculate match score
  const matchScore = calculateMatchScore(criteria, roleType, genre, platform, config);

  if (matchScore < config.minMatchScore) {
    return null;
  }

  // Generate reasoning
  const reasoning = generateReasoning(criteria, roleType, genre, platform, matchScore);

  // Generate show titles
  const suggestedShowTitles = generateShowTitles(genre, platform, rng);

  // Calculate estimated fee and boosts
  const baseFee = criteria.currentTier === 1 ? 500000 : criteria.currentTier === 2 ? 200000 : criteria.currentTier === 3 ? 50000 : 10000;
  const roleMultiplier = ROLE_PRESTIGE_MULTIPLIERS[roleType];
  const platformMultiplier = PLATFORM_PRESTIGE[platform] / 50;
  const estimatedFee = Math.floor(baseFee * roleMultiplier * platformMultiplier);

  const prestigeBoost = Math.floor((PLATFORM_PRESTIGE[platform] * roleMultiplier) / 10);
  const starMeterBoost = Math.floor((platformMultiplier * 10) + (matchScore / 10));

  return {
    id: rng.uuid('TVR'),
    talentId: criteria.talentId,
    roleType,
    genre,
    platform,
    matchScore,
    reasoning,
    suggestedShowTitles,
    estimatedFee,
    prestigeBoost,
    starMeterBoost,
    generatedWeek: criteria.currentTier, // This should be the actual week, will fix in main function
    expiresWeek: criteria.currentTier + config.recommendationLifetimeWeeks,
  };
}

/**
 * Generate TV recommendations for a talent
 */
export function generateTVRecommendationsForTalent(
  talent: Talent,
  state: GameState,
  config: TVRecommendationConfig = DEFAULT_TV_RECOMMENDATION_CONFIG,
  rng: RandomGenerator
): TVShowRecommendation[] {
  const recommendations: TVShowRecommendation[] = [];

  // Build criteria from talent
  const criteria: TVRecommendationCriteria = {
    talentId: talent.id,
    currentTier: talent.tier,
    currentPrestige: talent.prestige || 50,
    starMeter: talent.starMeter || 50,
    preferredGenres: talent.preferredGenres || [],
    personality: talent.personality || '',
    careerTrajectory: talent.careerTrajectory || 'plateau',
    skills: talent.skills || { acting: 50, writing: 50, directing: 50, stardom: 50 },
    recentProjectTypes: [],
    age: talent.demographics?.age || 30,
    gender: talent.demographics?.gender || 'MALE',
  };

  // Generate multiple recommendations
  const attempts = config.maxRecommendationsPerTalent * 3;
  for (let i = 0; i < attempts; i++) {
    if (recommendations.length >= config.maxRecommendationsPerTalent) break;

    const recommendation = generateRecommendation(criteria, config, rng);
    if (recommendation) {
      // Fix the week fields
      recommendation.generatedWeek = state.week;
      recommendation.expiresWeek = state.week + config.recommendationLifetimeWeeks;

      // Check for duplicates
      const isDuplicate = recommendations.some(
        r => r.roleType === recommendation.roleType && r.genre === recommendation.genre
      );

      if (!isDuplicate) {
        recommendations.push(recommendation);
      }
    }
  }

  // Sort by match score
  recommendations.sort((a, b) => b.matchScore - a.matchScore);

  return recommendations;
}

/**
 * Main tick function for TV recommendation system
 */
export function tickTVRecommendationSystem(
  state: GameState,
  config: TVRecommendationConfig = DEFAULT_TV_RECOMMENDATION_CONFIG,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  // Only generate recommendations every 4 weeks
  if (state.week % 4 !== 0) {
    return impacts;
  }

  const talents = Object.values(state.entities.talents || {});

  for (const talent of talents) {
    // Only generate for active talents (not retired, not on medical leave)
    if ((talent as any).retired || (talent as any).onMedicalLeave) {
      continue;
    }

    // Only generate for mid-tier and higher talents
    if (talent.tier > 3) {
      continue;
    }

    const recommendations = generateTVRecommendationsForTalent(talent, state, config, rng);

    if (recommendations.length > 0) {
      for (const recommendation of recommendations) {
        impacts.push({
          type: 'TV_RECOMMENDATION_CREATED',
          payload: {
            recommendation,
            notification: `TV Opportunity: ${talent.name} recommended for ${recommendation.roleType} role in ${recommendation.genre} series`,
          },
        } as any);
      }
    }
  }

  return impacts;
}

/**
 * Get TV recommendations for a specific talent
 */
export function getTVRecommendationsForTalent(
  talentId: string,
  state: GameState
): TVShowRecommendation[] {
  const recommendations = (state as any).tvRecommendations?.recommendations || {};
  return Object.values(recommendations)
    .filter((r: any) => r.talentId === talentId && r.expiresWeek > state.week) as TVShowRecommendation[];
}

/**
 * Accept a TV recommendation (would trigger a project creation or contract)
 */
export function acceptTVRecommendation(
  recommendationId: string,
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];

  const recommendations = (state as any).tvRecommendations?.recommendations || {};
  const recommendation = recommendations[recommendationId] as TVShowRecommendation | undefined;

  if (!recommendation) {
    return impacts;
  }

  // Mark as accepted
  impacts.push({
    type: 'TV_RECOMMENDATION_ACCEPTED',
    payload: {
      recommendationId,
      talentId: recommendation.talentId,
      notification: `${recommendation.talentId} accepted TV role recommendation`,
    },
  } as any);

  // This would typically trigger project creation or contract signing
  // For now, we just mark it as accepted

  return impacts;
}

import { GameState, StateImpact, Talent, Project } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import {
  BreakoutStar,
  BreakoutTrigger,
  GuestStarBooking,
  HiddenTalent,
  DiscoveryEvent,
} from '../../types/discovery.types';
import { checkForBreakout } from './discovery/BreakoutStarEngine';
import { generateGuestStarBooking } from './discovery/GuestStarEngine';
import { generateHiddenTalent, discoverHiddenTalent } from './discovery/HiddenTalentPool';

/**
 * Talent Discovery System
 * Orchestrates breakout stars, guest star appearances, and discovery of hidden talent.
 * Creates unexpected career trajectories and TV crossovers.
 */

// Guest star thresholds
const MIN_STARMETER_FOR_GUEST = 60; // Must be somewhat famous
const GUEST_STAR_CHANCE = 0.1; // 10% per series per week

// Hidden talent generation
const HIDDEN_TALENT_POOL_SIZE = 20;
const DISCOVERY_CHANCE = 0.05; // 5% per week per studio

/**
 * Main talent discovery tick
 */
export function tickTalentDiscoverySystem(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];

  // 1. Check for breakout stars from recent releases
  const recentProjects = Object.values(state.entities.projects || {})
    .filter(p => {
      const releaseWeek = (p as any).releaseWeek;
      return releaseWeek && state.week - releaseWeek >= 0 && state.week - releaseWeek <= 4;
    });

  for (const project of recentProjects) {
    // Get cast
    const projectContracts = Object.values(state.entities.contracts || {})
      .filter(c => c.projectId === project.id);
    const talents = projectContracts
      .map(c => state.entities.talents?.[c.talentId])
      .filter((t): t is Talent => !!t);

    for (const talent of talents) {
      const breakout = checkForBreakout(talent, project, state, rng);

      if (breakout) {
        // Create breakout record
        impacts.push({
          type: 'BREAKOUT_STAR_CREATED',
          payload: {
            breakout,
            notification: `${talent.name} is breaking out from "${project.title}"!`,
          },
        } as any);

        // Update talent stats
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: {
            talentId: talent.id,
            update: {
              starMeter: Math.min(100, (talent.starMeter || 50) + breakout.starMeterJump),
              tier: breakout.newTier,
              fee: Math.floor(talent.fee * breakout.feeMultiplier),
              isBreakout: true,
            },
          },
        });

        // News announcement
        const triggerDescriptions: Record<BreakoutTrigger, string> = {
          'indie_hit': 'breakout performance in an indie hit',
          'viral_scene': 'viral scene taking over social media',
          'cameo_steal': 'scene-stealing cameo',
          'tv_performance': 'standout TV performance',
          'award_nomination': 'surprise award nomination',
          'critical_praise': 'unanimous critical praise',
        };

        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `Breakout Star Alert: ${talent.name}`,
            description: `${talent.name} is Hollywood's newest breakout sensation thanks to their ${triggerDescriptions[breakout.trigger]}. Studios are scrambling to sign them.`,
            category: 'talent',
            publication: 'Variety',
          },
        });

        // Create bidding war notification for player
        impacts.push({
          type: 'MODAL_TRIGGERED',
          payload: {
            modalType: 'BREAKOUT_BIDDING_WAR',
            talentId: talent.id,
            currentFee: Math.floor(talent.fee * breakout.feeMultiplier),
            competingStudios: Object.keys(state.entities.rivals || {}).slice(0, 3),
          },
        });
      }
    }
  }

  // 2. Check for guest star opportunities on TV series
  const activeSeries = Object.values(state.entities.projects || {})
    .filter(p => p.type === 'SERIES' && (p as any).status === 'ON_AIR');

  // Get guest star candidates (famous but not lead cast)
  const guestCandidates = Object.values(state.entities.talents || {})
    .filter(t => (t.starMeter || 50) >= MIN_STARMETER_FOR_GUEST && t.tier <= 2);

  for (const series of activeSeries) {
    if (rng.next() < GUEST_STAR_CHANCE && guestCandidates.length > 0) {
      const guest = rng.pick(guestCandidates);

      // Check if already booked
      const existingBookings = Object.values((state as any).relationships?.discovery?.guestStarBookings || {})
        .filter((b: any) => b.talentId === guest.id && b.seriesId === series.id);

      if (existingBookings.length === 0) {
        const booking = generateGuestStarBooking(series, guest, state, rng);

        if (booking) {
          impacts.push({
            type: 'GUEST_STAR_OPPORTUNITY',
            payload: {
              booking,
              notification: `${guest.name} available for guest appearance on "${series.title}"`,
            },
          } as any);

          // News about exciting casting
          impacts.push({
            type: 'NEWS_ADDED',
            payload: {
              id: rng.uuid('NWS'),
              headline: `${guest.name} to Appear on "${series.title}"`,
              description: `The ${booking.roleType} appearance is expected to boost ratings significantly.`,
              category: 'talent',
              publication: 'The Hollywood Reporter',
            },
          });
        }
      }
    }
  }

  // 3. Maintain hidden talent pool
  const discoveryState = (state as any).relationships?.discovery || {};
  let hiddenPool = discoveryState.hiddenTalentPool || {};

  // Replenish pool if low
  const hiddenCount = Object.keys(hiddenPool).length;
  if (hiddenCount < HIDDEN_TALENT_POOL_SIZE) {
    const toAdd = HIDDEN_TALENT_POOL_SIZE - hiddenCount;
    for (let i = 0; i < toAdd; i++) {
      const hidden = generateHiddenTalent(rng);
      hiddenPool = { ...hiddenPool, [hidden.id]: hidden };
    }

    impacts.push({
      type: 'DISCOVERY_STATE_UPDATED',
      payload: {
        discovery: {
          ...discoveryState,
          hiddenTalentPool: hiddenPool,
        },
      },
    } as any);
  }

  // 4. Hidden talent discovery
  // Studios can discover hidden talent
  if (rng.next() < DISCOVERY_CHANCE) {
    const undiscovered = (Object.values(hiddenPool) as HiddenTalent[])
      .filter(h => !h.discoveredBy);

    if (undiscovered.length > 0) {
      const toDiscover = rng.pick(undiscovered);
      const { talent, event } = discoverHiddenTalent(
        { ...toDiscover, discoveredBy: 'player', discoveryWeek: state.week },
        'player',
        state.week,
        state,
        rng
      );

      // Add talent to pool
      impacts.push({
        type: 'TALENT_ADDED',
        payload: { talent },
      });

      // Remove from hidden pool
      const updatedPool = { ...hiddenPool };
      delete updatedPool[toDiscover.id];

      impacts.push({
        type: 'DISCOVERY_STATE_UPDATED',
        payload: {
          discovery: {
            ...discoveryState,
            hiddenTalentPool: updatedPool,
            discoveryLog: [...(discoveryState.discoveryLog || []), toDiscover.id],
          },
        },
      } as any);

      // Discovery news
      const methodDescriptions: Record<string, string> = {
        'audition': 'a stunning audition tape',
        'recommendation': 'an industry insider recommendation',
        'scouting': 'talent scouts at a local theater',
        'viral_discovery': 'a viral social media clip',
      };

      impacts.push({
        type: 'NEWS_ADDED',
        payload: {
          id: rng.uuid('NWS'),
          headline: `Hidden Gem Discovered: ${talent.name}`,
          description: `Your scouts found ${talent.name} through ${methodDescriptions[toDiscover.discoveryMethod]}. They show incredible potential.`,
          category: 'talent',
          publication: 'Deadline',
        },
      });
    }
  }

  // 5. Update existing breakout stars
  const existingBreakouts = Object.values(discoveryState.breakoutStars || {}) as BreakoutStar[];
  for (const breakout of existingBreakouts) {
    if (breakout.hypeWeeksRemaining > 0) {
      const updatedBreakout: BreakoutStar = {
        ...breakout,
        hypeWeeksRemaining: breakout.hypeWeeksRemaining - 1,
      };

      // End bidding war after 4 weeks
      if (updatedBreakout.hypeWeeksRemaining <= breakout.hypeWeeksRemaining - 4) {
        updatedBreakout.biddingWarActive = false;
      }

      impacts.push({
        type: 'BREAKOUT_STAR_UPDATED',
        payload: {
          breakoutId: breakout.id,
          breakout: updatedBreakout,
        },
      } as any);
    }
  }

  return impacts;
}

/**
 * Accept a guest star booking
 */
export function acceptGuestStarBooking(
  bookingId: string,
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const discovery = (state as any).relationships?.discovery || {};
  const booking = discovery.guestStarBookings?.[bookingId] as GuestStarBooking | undefined;

  if (!booking) return impacts;

  // Deduct cost
  impacts.push({
    type: 'FUNDS_DEDUCTED',
    cashChange: -booking.cost,
  });

  // Update booking status
  const updatedBooking = { ...booking };

  impacts.push({
    type: 'GUEST_STAR_BOOKED',
    payload: {
      bookingId,
      booking: updatedBooking,
    },
  } as any);

  // Add contract for guest appearance
  impacts.push({
    type: 'CONTRACT_ADDED',
    payload: {
      contract: {
        id: rng.uuid('CNT'),
        projectId: booking.seriesId,
        talentId: booking.talentId,
        fee: booking.cost,
        week: state.week,
        isGuestAppearance: true,
      },
    },
  } as any);

  // News
  const series = state.entities.projects?.[booking.seriesId];
  const talent = state.entities.talents?.[booking.talentId];

  impacts.push({
    type: 'NEWS_ADDED',
    payload: {
      id: rng.uuid('NWS'),
      headline: `${talent?.name} Confirmed for "${series?.title}"`,
      description: `The guest appearance has been officially confirmed. Fans are already excited.`,
      category: 'talent',
      publication: 'Variety',
    },
  });

  return impacts;
}

/**
 * Sign a breakout star
 */
export function signBreakoutStar(
  breakoutId: string,
  studioId: string,
  offerFee: number,
  state: GameState,
  rng: RandomGenerator
): StateImpact[] {
  const impacts: StateImpact[] = [];
  const discovery = (state as any).relationships?.discovery || {};
  const breakout = discovery.breakoutStars?.[breakoutId] as BreakoutStar | undefined;

  if (!breakout || !breakout.biddingWarActive) return impacts;

  // Deduct signing fee
  impacts.push({
    type: 'FUNDS_DEDUCTED',
    cashChange: -offerFee,
  });

  // Update breakout status
  const updatedBreakout: BreakoutStar = {
    ...breakout,
    signedByStudioId: studioId,
    biddingWarActive: false,
  };

  impacts.push({
    type: 'BREAKOUT_STAR_UPDATED',
    payload: {
      breakoutId,
      breakout: updatedBreakout,
    },
  } as any);

  // Update talent contract status
  const talent = state.entities.talents?.[breakout.talentId];
  if (talent) {
    impacts.push({
      type: 'TALENT_UPDATED',
      payload: {
        talentId: talent.id,
        update: {
          contractStatus: 'SIGNED',
          fee: offerFee,
        },
      },
    });

    // News
    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: rng.uuid('NWS'),
        headline: `${talent.name} Signs with Studio`,
        description: `After a fierce bidding war, the breakout star has signed a lucrative deal.`,
        category: 'talent',
        publication: 'The Hollywood Reporter',
      },
    });
  }

  return impacts;
}

import { GameState, StateImpact, Talent, TalentTier } from '../../types';
import { RandomGenerator } from '../../utils/rng';
import { generateTalent } from '../../generators/talent/index';
import { TalentDriftEngine, DEFAULT_DRIFT_CONFIG } from './driftEngine';

/**
 * Talent Lifecycle System
 * Handles aging, retirement, and recruitment to maintain a steady-state talent pool.
 */
export class TalentLifecycleSystem {
  static tick(state: GameState, rng: RandomGenerator): StateImpact[] {
    const impacts: StateImpact[] = [];
    const isYearEnd = state.week % 52 === 0;

    // Process archetype/personality drift
    const driftResults = TalentDriftEngine.processAllDrift(state.entities.talents, DEFAULT_DRIFT_CONFIG, rng);

    // Apply drift changes
    for (const [talentId, driftResult] of Object.entries(driftResults.driftResults)) {
      if (driftResult.archetypeChanged || driftResult.personalityChanged || driftResult.careerTrajectoryChanged) {
        const updatedTalent = TalentDriftEngine.applyDriftChanges(state.entities.talents[talentId], driftResult);
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: { talentId, update: updatedTalent }
        });

        // Add news event for age-based archetype transitions
        if (driftResult.archetypeChanged && updatedTalent.role === 'actor') {
          const ageTransitions = ['kid_actor', 'young_adult', 'veteran'];
          const isAgeTransition = ageTransitions.some(t => 
            driftResult.changes.oldArchetype === t || driftResult.changes.newArchetype === t
          );

          if (isAgeTransition) {
            const oldArchetype = driftResult.changes.oldArchetype || 'unknown';
            const newArchetype = driftResult.changes.newArchetype || 'unknown';
            const talentName = updatedTalent.name;
            const talentAge = updatedTalent.demographics.age;

            let headline = `${talentName} transitions from ${oldArchetype} to ${newArchetype}`;
            let description = `At age ${talentAge}, ${talentName} is evolving their career archetype.`;

            // Special messages for key transitions
            if (oldArchetype === 'kid_actor') {
              headline = `${talentName} transitions from child star to adult roles`;
              description = `After starting as a child actor, ${talentName} (now ${talentAge}) is taking on more mature roles and has adopted the ${newArchetype} archetype.`;
            } else if (newArchetype === 'veteran') {
              headline = `${talentName} enters veteran phase of career`;
              description = `With decades of experience, ${talentName} (age ${talentAge}) has transitioned to the veteran archetype, taking on mentorship and character roles.`;
            }

            impacts.push({
              type: 'NEWS_ADDED',
              payload: {
                id: `archetype-transition-${talentId}-${state.week}`,
                headline,
                description,
                category: 'talent',
                publication: 'Variety'
              }
            });
          }
        }
      }
    }

    const talentPool = Object.values(state.entities.talents) as Talent[];
    const retiredIds: string[] = [];

    talentPool.forEach(talent => {
      // 0. Medical leave expiry
      if (talent.onMedicalLeave && talent.medicalLeaveEndsWeek !== undefined && state.week >= talent.medicalLeaveEndsWeek) {
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: { talentId: talent.id, update: { onMedicalLeave: false, medicalLeaveEndsWeek: undefined } }
        });
        return; // skip rest of processing while recovering
      }
      if (talent.onMedicalLeave) return; // still on leave

      // 0b. Fatigue accumulation from active commitments
      const activeCommitments = (talent.commitments || []).filter(
        c => !c.isHoldingDeal && c.startWeek <= state.week && c.endWeek >= state.week
      );
      if (activeCommitments.length > 0) {
        const fatigueGain = activeCommitments.some(c => c.format === 'animation') ? 10 : 20;
        const newFatigue = Math.min(100, (talent.fatigue ?? 0) + fatigueGain * 0.1); // incremental weekly gain
        impacts.push({
          type: 'TALENT_UPDATED',
          payload: { talentId: talent.id, update: { fatigue: newFatigue } }
        });

        // 0c. Burnout check
        if (newFatigue > 90 && rng.next() < 0.25) {
          impacts.push({
            type: 'MEDICAL_LEAVE_TRIGGERED',
            payload: { talentId: talent.id, weeks: 8 }
          });
          impacts.push({
            type: 'NEWS_ADDED',
            payload: {
              id: `burnout-${talent.id}-${state.week}`,
              headline: `${talent.name} steps back citing exhaustion`,
              description: `The talent will be on medical leave for approximately 8 weeks.`,
              category: 'talent',
              publication: 'The Hollywood Reporter'
            }
          });
          return;
        }
      } else {
        // Natural fatigue recovery when not committed
        const recovery = Math.min((talent.fatigue ?? 0), 5);
        if (recovery > 0) {
          impacts.push({
            type: 'TALENT_UPDATED',
            payload: { talentId: talent.id, update: { fatigue: Math.max(0, (talent.fatigue ?? 0) - recovery) } }
          });
        }
      }

      // 1. Annual Aging & Prestige Decay
      if (isYearEnd) {
        // Prestige Decay: -2 per year if no projects released in the last 52 weeks
        const weeksSinceLastRelease = state.week - (talent.lastReleaseWeek || 0);
        let decay = 0;
        if (weeksSinceLastRelease > 52) {
          decay = talent.tier === 1 ? -4 : -2;
        }

        impacts.push({
          type: 'TALENT_UPDATED',
          payload: {
            talentId: talent.id,
            update: { 
              demographics: { ...talent.demographics, age: (talent.demographics.age || 40) + 1 },
              prestige: Math.max(0, (talent.prestige || 50) + decay)
            }
          }
        });
      }

      // 2. Retirement Evaluation
      const age = talent.demographics.age || 40;
      let retirementChance = 0;

      if (age > 75) retirementChance = 0.5; 
      else if (age > 65) retirementChance = 0.05; 
      else if (age > 55) retirementChance = 0.01; 

      // Momentum Traps: Burnout and Blacklisting for failing talent
      if (talent.momentum < 20 && talent.prestige < 30) {
        retirementChance += 0.02; // Significant increase for the "Momentum Trap"
      }

      if (rng.next() < 0.0001) retirementChance = 1.0; 

      if (talent.tier === 1) {
        retirementChance *= 0.2;
      }

      if (rng.next() < retirementChance) {
        impacts.push({
          type: 'TALENT_REMOVED',
          payload: { talentId: talent.id }
        });
        retiredIds.push(talent.id);
      }
    });

    // 3. Replenishment (Maintain ~2,500 talent pool)
    const targetPoolSize = 2500;
    const currentSize = talentPool.length - retiredIds.length;
    const needsReplacement = Math.max(0, targetPoolSize - currentSize);

    if (needsReplacement > 0) {
      const newTalents: Talent[] = [];
      for (let i = 0; i < needsReplacement; i++) {
        const tierRoll = rng.next();
        let tier: TalentTier = 4;
        if (tierRoll > 0.90) tier = 3;

        const roleRoll = rng.next();
        const role = roleRoll > 0.7 ? 'director' : (roleRoll > 0.5 ? 'writer' : (roleRoll > 0.4 ? 'producer' : 'actor'));

        newTalents.push(generateTalent(rng, { role: role as 'actor' | 'director' | 'writer' | 'producer', tier }));
      }
      impacts.push({
        type: 'TALENT_ADDED',
        newTalents
      } as StateImpact);
    }

    // Pass metadata to industry tick for metrics
    impacts.push({
      type: 'SYSTEM_TICK',
      payload: { 
        retiredCount: retiredIds.length 
      }
    } as StateImpact);

    return impacts;
  }
}

import { Talent, Project, Contract, StateImpact } from '@/engine/types';
import { TalentUpdate } from '@/engine/types/state.types';

/**
 * Talent Morale & Behavioral Psychology System
 * 
 * Logic:
 * - Talent mood (Morale) drifts toward 50 over time.
 * - Project delays or low momentum reduce mood.
 * - Scandals significantly tank mood.
 * - Working with "Conflict" talent (Ego clashes) reduces mood.
 */
export class TalentMoraleSystem {
  /**
   * Calculates the production speed multiplier based on the moods of attached talent.
   * If any major talent (Actor/Director) has very low mood (< 30), production slows down.
   */
  static getProductionSpeedMultiplier(talent: Talent[]): number {
    if (talent.length === 0) return 1.0;

    const lowMoraleTalent = talent.filter(t => t.psychology.mood < 30);
    if (lowMoraleTalent.length > 0) {
      // 20% drag if there's significant unhappiness
      return 0.8;
    }

    return 1.0;
  }

  /**
   * Calculates a quality multiplier for the final review score.
   * Low trust/morale leads to "onset friction" and a lower ceiling.
   */
  static getQualityMultiplier(talent: Talent[]): number {
    if (talent.length === 0) return 1.0;

    const avgMood = talent.reduce((acc, t) => acc + t.psychology.mood, 0) / talent.length;

    // Scale from 0.85 (miserable) to 1.1 (inspired)
    if (avgMood < 30) return 0.85;
    if (avgMood > 85) return 1.1;

    return 1.0;
  }

  /**
   * Updates talent psychology based on the current week's events.
   */
  static processWeeklyMorale(
    talentDict: Record<string, Talent>,
    projectsDict: Record<string, Project>,
    contractsDict: Record<string, Contract>
  ): TalentUpdate[] {
    const updates: TalentUpdate[] = [];

    // Pre-compute O(1) lookups to avoid O(N*M) nested filtering
    const contractsByTalent = new Map<string, Contract[]>();
    for (const key in contractsDict) {
      if (!Object.prototype.hasOwnProperty.call(contractsDict, key)) continue;
      const c = contractsDict[key];
      const arr = contractsByTalent.get(c.talentId);
      if (arr) {
        arr.push(c);
      } else {
        contractsByTalent.set(c.talentId, [c]);
      }
    }

    // ⚡ Bolt: Consolidated O(N) array filtering to O(1) Map lookups
    // ⚡ The Framerate Fanatic: Direct iteration over dictionaries avoids Array allocations
    for (const talentId in talentDict) {
      if (!Object.prototype.hasOwnProperty.call(talentDict, talentId)) continue;
      const t = talentDict[talentId];
      let moodChange = 0;

      // 1. Natural drift toward 50
      if (t.psychology.mood > 55) moodChange -= 1;
      else if (t.psychology.mood < 45) moodChange += 1;

      // 2. Project performance
      const activeContracts = contractsByTalent.get(t.id) || [];
      for (const c of activeContracts) {
        const p = projectsDict[c.projectId];
        if (p) {
          // Momentum impact
          if (p.momentum < 30) moodChange -= 2;
          else if (p.momentum > 80) moodChange += 1;

            // Crisis impact
            if (p.activeCrisis && !p.activeCrisis.resolved) moodChange -= 5;
          }
        }

      if (moodChange !== 0) {
        updates.push({
          talentId: t.id,
          update: {
            psychology: {
              ...t.psychology,
              mood: Math.max(0, Math.min(100, t.psychology.mood + moodChange))
            }
          }
        });
      }
    }

    return updates;
  }
}

import { GameState, Talent, Project, Contract, Award, Opportunity } from '@/engine/types';
import { StateImpact, TalentUpdate } from '../../types/state.types';
import { RandomGenerator } from '../../utils/rng';
import { BardResolver } from '../bardResolver';
import { advanceTalentLifecycle } from './LifecycleModule';
import { advanceOpportunityLifecycle } from './OpportunityModule';
