    failedDeals: number;
    totalDeals: number;
    yearsTogether: number;
  };
  synergy: number; // -50 to +50
  lastInteractionWeek?: number;
}

/**
 * Compatibility score between talent personality and agent personality
 */
export interface CompatibilityScore {
  score: number; // -100 to +100
  factors: string[];
  synergy: number; // -50 to +50
}

/**
 * Talent-Agent Interaction Engine
 * Manages the compatibility, relationships, and synergy between talents and their agents
 */
export class TalentAgentInteractionEngine {
  /**
   * Calculate compatibility between talent personality and agent personality
   */
  static calculateCompatibility(
    talentPersonality: TalentPersonality,
    agentPersonality: AgentPersonality,
    agencyArchetype?: string
  ): CompatibilityScore {
    const factors: string[] = [];
    let score = 0;

    // Personality trait compatibility matrix
    const compatibilityMatrix: Record<TalentPersonality, Record<AgentPersonality, number>> = {
      perfectionist: {
        shark: -20, diplomat: 10, prestige: 20, volume: -10, protector: 15, visionary: 10
      },
      collaborative: {
        shark: -15, diplomat: 30, prestige: 15, volume: 10, protector: 25, visionary: 20
      },
      difficult: {
        shark: 20, diplomat: -20, prestige: 10, volume: -10, protector: -15, visionary: 5
      },
      charismatic: {
        shark: 15, diplomat: 20, prestige: 25, volume: 15, protector: 10, visionary: 20
      },
      method: {
        shark: -10, diplomat: 5, prestige: 25, volume: -20, protector: 10, visionary: 20
      },
      pragmatic: {
        shark: 10, diplomat: 15, prestige: 5, volume: 25, protector: 10, visionary: 15
      },
      artistic: {
        shark: -25, diplomat: 10, prestige: 30, volume: -15, protector: 15, visionary: 25
      },
      commercial: {
        shark: 25, diplomat: 5, prestige: -10, volume: 20, protector: -5, visionary: 10
      },
      loyal: {
        shark: -20, diplomat: 30, prestige: 15, volume: 10, protector: 30, visionary: 20
      },
      ambitious: {
        shark: 20, diplomat: 10, prestige: 20, volume: 15, protector: -10, visionary: 25
      }
    };

    const baseScore = compatibilityMatrix[talentPersonality]?.[agentPersonality] || 0;
    score += baseScore;

    if (baseScore > 15) {
      factors.push(`Strong natural compatibility between ${talentPersonality} talent and ${agentPersonality} agent`);
    } else if (baseScore < -15) {
      factors.push(`Potential conflict between ${talentPersonality} talent and ${agentPersonality} agent`);
    } else {
      factors.push(`Neutral compatibility between ${talentPersonality} talent and ${agentPersonality} agent`);
    }

    // Agency archetype influence
    const agencyBonus = this.getAgencyArchetypeCompatibility(talentPersonality, agencyArchetype);
    score += agencyBonus;

    if (agencyBonus > 10) {
      factors.push('Agency archetype aligns well with talent personality');
    } else if (agencyBonus < -10) {
      factors.push('Agency archetype may clash with talent personality');
    }

    const synergy = Math.min(50, Math.max(-50, score / 2));

    return {
      score: Math.min(100, Math.max(-100, score)),
      factors,
      synergy
    };
  }

  /**
   * Get agency archetype compatibility bonus for a talent personality
   * Enhanced with more nuanced archetype matching
   */
  private static getAgencyArchetypeCompatibility(talentPersonality: TalentPersonality, agencyArchetype?: string): number {
    // Enhanced archetype compatibility matrix
    const archetypeCompatibility: Record<TalentPersonality, number> = {
      perfectionist: 5,
      collaborative: 15,
      difficult: -10,
      charismatic: 10,
      method: 5,
      pragmatic: 10,
      artistic: 15,
      commercial: -5,
      loyal: 10,
      ambitious: 5
    };

    const baseBonus = archetypeCompatibility[talentPersonality] || 0;

    // Additional bonus based on agency archetype if provided
    if (agencyArchetype) {
      const agencyBonus: Record<string, number> = {
        'powerhouse': 5,  // Major agencies have more leverage
        'major': 3,
        'boutique': 10,  // Boutique agencies offer more personalized service
        'independent': 8
      };
      return baseBonus + (agencyBonus[agencyArchetype] || 0);
    }

    return baseBonus;
  }

  /**
   * Calculate synergy between talent and agent based on their relationship history
   */
  static calculateSynergy(relationship: TalentAgentRelationship): number {
    const { relationshipScore, history } = relationship;

    // Base synergy from relationship score
    let synergy = (relationshipScore - 50) / 2; // -25 to +25

    // Bonus for successful deals
    const successRate = history.totalDeals > 0 ? history.successfulDeals / history.totalDeals : 0.5;
    synergy += (successRate - 0.5) * 20; // -10 to +10

    // Bonus for long-term relationships
    if (history.yearsTogether > 5) {
      synergy += 10;
    } else if (history.yearsTogether > 2) {
      synergy += 5;
    }

    return Math.min(50, Math.max(-50, synergy));
  }

  /**
   * Update relationship based on a deal outcome
   */
  static updateRelationship(
    relationship: TalentAgentRelationship,
    success: boolean,
    dealValue?: number
  ): TalentAgentRelationship {
    const updated = { ...relationship };

    updated.history.totalDeals++;
    if (success) {
      updated.history.successfulDeals++;
      updated.relationshipScore = Math.min(100, updated.relationshipScore + 5);
    } else {
      updated.history.failedDeals++;
      updated.relationshipScore = Math.max(0, updated.relationshipScore - 3);
    }

    // High-value deals boost relationship more
    if (success && dealValue && dealValue > 1000000) {
      updated.relationshipScore = Math.min(100, updated.relationshipScore + 3);
    }

    // Recalculate synergy
    updated.synergy = this.calculateSynergy(updated);

    return updated;
  }

  /**
   * Generate a new relationship between talent and agent
   */
  static createRelationship(
    talentId: string,
    agentId: string,
    talentPersonality: TalentPersonality,
    agentPersonality: AgentPersonality,
    agencyArchetype?: string
  ): TalentAgentRelationship {
    const compatibility = this.calculateCompatibility(talentPersonality, agentPersonality, agencyArchetype);

    return {
      talentId,
      agentId,
      relationshipScore: 50 + (compatibility.score / 4), // 25 to 75 based on compatibility
      history: {
        successfulDeals: 0,
        failedDeals: 0,
        totalDeals: 0,
        yearsTogether: 0
      },
      synergy: compatibility.synergy
    };
  }

  /**
   * Evolve relationship over time
   * Relationships naturally decay or grow based on activity
   */
  static evolveRelationship(
    relationship: TalentAgentRelationship,
    weeksSinceLastInteraction: number,
    rng: RandomGenerator
  ): TalentAgentRelationship {
    const updated = { ...relationship };

    // Relationship decay over time if no recent interaction
    if (weeksSinceLastInteraction > 52) { // 1 year
      updated.relationshipScore = Math.max(0, updated.relationshipScore - 10);
      updated.history.yearsTogether++;
    } else if (weeksSinceLastInteraction > 26) { // 6 months
      updated.relationshipScore = Math.max(0, updated.relationshipScore - 5);
    }

    // Small random fluctuation
    if (rng.next() < 0.1) {
      const fluctuation = rng.rangeInt(-2, 3);
      updated.relationshipScore = Math.min(100, Math.max(0, updated.relationshipScore + fluctuation));
    }

    // Recalculate synergy
    updated.synergy = this.calculateSynergy(updated);

    return updated;
  }

  /**
   * Get negotiation bonus based on relationship and synergy
   */
  static getNegotiationBonus(relationship: TalentAgentRelationship): number {
    const relationshipBonus = (relationship.relationshipScore - 50) / 5; // -10 to +10
    const synergyBonus = relationship.synergy / 5; // -10 to +10

    return Math.min(20, Math.max(-20, relationshipBonus + synergyBonus));
  }

  /**
   * Get loyalty bonus based on relationship and synergy
   */
  static getLoyaltyBonus(relationship: TalentAgentRelationship): number {
    const relationshipBonus = (relationship.relationshipScore - 50) / 4; // -12.5 to +12.5
    const synergyBonus = relationship.synergy / 4; // -12.5 to +12.5
    const yearsBonus = Math.min(10, relationship.history.yearsTogether * 2);

    return Math.min(30, Math.max(0, relationshipBonus + synergyBonus + yearsBonus));
  }

  /**
   * Calculate talent-agent compatibility matrix for all talents and agents
   */
  static calculateCompatibilityMatrix(
    talents: Record<string, Talent>,
    agents: Record<string, Agent>,
    agencies: Record<string, Agency>
  ): Map<string, CompatibilityScore> {
    const matrix = new Map<string, CompatibilityScore>();

    for (const [talentId, talent] of Object.entries(talents)) {
      if (!talent.personality) continue;

      for (const [agentId, agent] of Object.entries(agents)) {
        // Get agent personality from agent or agency
        let agentPersonality: AgentPersonality = 'diplomat'; // default

        if ((agent as any).personality) {
          agentPersonality = (agent as any).personality;
        } else if (agent.agencyId && agencies[agent.agencyId]) {
          // Derive from agency archetype
          const agency = agencies[agent.agencyId];
          const archetype = agency.culture ? AGENCY_ARCHETYPES[agency.culture as keyof typeof AGENCY_ARCHETYPES] : null;
          if (archetype) {
            agentPersonality = this.mapArchetypeToPersonality(archetype.key);
          }
        }

        const compatibility = this.calculateCompatibility(talent.personality, agentPersonality);
        matrix.set(`${talentId}-${agentId}`, compatibility);
      }
    }

    return matrix;
  }

  /**
   * Map agency archetype to agent personality
   */
  private static mapArchetypeToPersonality(archetypeKey: string): AgentPersonality {
    const mapping: Record<string, AgentPersonality> = {
      powerhouse: 'shark',
      boutique: 'visionary',
      shark: 'shark',
      comedy_specialist: 'volume',
      lit_agency: 'prestige',
      mega_corp: 'volume',
      streaming_titan: 'visionary',
      indie_darling: 'protector'
    };

    return mapping[archetypeKey] || 'diplomat';
  }
}

import { Talent, Project, GameState, CharacterArchetype, Contract } from '@/engine/types/index';
import { ACTOR_ARCHETYPES, WRITER_ARCHETYPES, PRODUCER_ARCHETYPES, PERSONALITY_ARCHETYPES, PERSONALITY_TRAITS } from '../../data/talentArchetypes';

/**
 * Studio Boss - Willingness Engine
 * Calculates the likelihood of a talent signing a contract.
 * Factors: Genre, Prestige, Finance, Directorial Influence, and Studio History.
 */

export interface WillingnessReport {
  score: number; // 0-100
  reasons: string[];
  finalVerdict: 'willing' | 'hesitant' | 'unwilling';
}

export function calculateWillingness(
  talent: Talent,
  project: Project,
  gameState: GameState,
  proposedRole?: CharacterArchetype
): WillingnessReport {
  let score = 60; // Baseline
  const reasons: string[] = [];

  // 1. Genre Affinity
  const isActionStar = talent.roles.includes('actor') && talent.draw > 70;
  const isPrestigeActor = talent.prestige > 80;

  if (project.genre === 'Action' && isActionStar) {
    score += 15;
    reasons.push(`${talent.name} is a proven action draw and loves the genre.`);
  } else if (project.genre === 'Drama' && isPrestigeActor) {
    score += 15;
    reasons.push(`${talent.name} is looking for prestige-driven material.`);
  } else if (project.genre === 'Horror' && isPrestigeActor && project.budgetTier === 'low') {
    score -= 25;
    reasons.push(`${talent.name} feels this "low-budget horror" is beneath their current prestige level.`);
  }

  // 🎭 The Method Actor Tuning: Auteur directors prioritize prestige over upfront cash, taking a pay cut for high-buzz projects but demanding a premium for low-buzz ones.
  const isAuteurDirector = talent.directorArchetype === 'auteur' || (talent.roles.includes('director') && talent.prestige > 80);

  // 2. Prestige Gap
  const prestigeDiff = project.buzz - talent.prestige;
  if (prestigeDiff > 20) {
    score += 10;
    reasons.push(`The high buzz around "${project.title}" is a major draw.`);
    if (isAuteurDirector) {
      score += 20;
      reasons.push(`${talent.name} considers this a guaranteed masterpiece.`);
    }
  } else if (prestigeDiff < -30) {
    score -= 20;
    reasons.push(`${talent.name} is hesitant about a project with such low industry heat.`);
    if (isAuteurDirector) {
      score -= 30;
      reasons.push(`${talent.name} refuses to tarnish their legacy with a low-buzz project.`);
    }
  }

  // 3. Financial Incentive (Fee vs Star Meter)
  const starMeter = talent.starMeter || 50;
  if (talent.fee > project.budget * 0.4) {
    // 🎭 The Method Actor Tuning: Auteur directors prioritize prestige over upfront cash, taking a pay cut for high-buzz projects but demanding a premium for low-buzz ones.
    if (isAuteurDirector && prestigeDiff > 10) {
      score += 10;
      reasons.push(`The fee is high, but ${talent.name} is willing to take a pay cut for a guaranteed masterpiece.`);
    } else if (isAuteurDirector && prestigeDiff < -10) {
      score -= 30;
      reasons.push(`${talent.name} demands a massive premium to work on such a low-buzz project.`);
    } else if (isAuteurDirector && prestigeDiff > 0) {
      score -= 5;
      reasons.push(`The fee is high, but ${talent.name} is willing to negotiate for the sake of the art.`);
    } else {
      score -= 15;
      reasons.push(`The talent's quote consumes ${Math.round((talent.fee / project.budget) * 100)}% of the production budget, causing friction.`);
    }
  }

  // 4. Script Heat
  const scriptHeat = 'scriptHeat' in project ? project.scriptHeat : 50;
  if (scriptHeat > 80) {
    score += 15;
    reasons.push(`The script is considered a "Must-Read" in town.`);
  } else if (scriptHeat < 30) {
    score -= 10;
    reasons.push(`Word of mouth on the current draft is lukewarm.`);
  }

  // 5. Studio Reputation
  const studioPrestige = gameState.studio.prestige;
  if (studioPrestige > 80) {
    score += 10;
    reasons.push(`Working with a prestigious studio like ${gameState.studio.name} is a career goal.`);
  } else if (studioPrestige < 30) {
    score -= 15;
    reasons.push(`${talent.name}'s team is wary of the studio's current market standing.`);
  }

  // 5b. Studio Infamy (Razzies & Bombs)
  const studioProjects = Object.values(gameState.entities.projects);
  const recentRazzie = studioProjects.some(p => 
    p.awards?.some(a => a.body === 'The Razzies' && a.status === 'won')
  );

  if (recentRazzie && talent.prestige > 70) {
    score -= 20;
    reasons.push(`${talent.name} is hesitant to work with a studio that recently took home a Razzie.`);
  }

  // 6. Directorial Influence (Check if a director is already attached)
  const contractsList = Object.values(gameState.entities.contracts || {});
  const directorContract = contractsList.find(
    (c: Contract) => c.projectId === project.id && gameState.entities.talents[c.talentId]?.roles.includes('director')
  );
  if (directorContract) {
    const director = gameState.entities.talents[directorContract.talentId];
    if (director && director.prestige > 80) {
      score += 20;
      reasons.push(`The chance to work with ${director.name} is a significant motivator.`);
    }
  }

  // 7. Psychology & Ego
  if (talent.psychology?.ego && talent.psychology.ego > 80) {
    score -= 10;
    reasons.push(`${talent.name} is being notoriously difficult during negotiations.`);
  }

  // 8. Personality Trait Influence
  if (talent.personality) {
    const personalityTrait = PERSONALITY_TRAITS[talent.personality];
    if (personalityTrait) {
      // Adjust based on personality negotiation modifier
      score += personalityTrait.negotiationModifier;
      if (personalityTrait.negotiationModifier > 0) {
        reasons.push(`${talent.name}'s ${talent.personality} nature makes them more open to this deal.`);
      } else if (personalityTrait.negotiationModifier < 0) {
        reasons.push(`${talent.name}'s ${talent.personality} nature makes them more cautious.`);
      }
    }
  }

  // 9. Archetype-Specific Preferences
  let archetypeConfig: any;
  if (talent.actorArchetype) {
    archetypeConfig = ACTOR_ARCHETYPES[talent.actorArchetype];
  } else if (talent.writerArchetype) {
    archetypeConfig = WRITER_ARCHETYPES[talent.writerArchetype];
  } else if (talent.producerArchetype) {
    archetypeConfig = PRODUCER_ARCHETYPES[talent.producerArchetype];
  } else if (talent.personalityArchetype) {
    archetypeConfig = PERSONALITY_ARCHETYPES[talent.personalityArchetype];
  }

  if (archetypeConfig) {
    // Check genre preferences
    if (archetypeConfig.genrePreferences && archetypeConfig.genrePreferences.includes(project.genre)) {
      score += 10;
      reasons.push(`${talent.name}'s archetype favors this genre.`);
    } else if (archetypeConfig.genreDislikes && archetypeConfig.genreDislikes.includes(project.genre)) {
      score -= 15;
      reasons.push(`${talent.name}'s archetype typically avoids this genre.`);
    }

    // Check budget tier preferences
    if (archetypeConfig.budgetPreferences) {
      const budgetMatch = archetypeConfig.budgetPreferences.includes(project.budgetTier);
      if (budgetMatch) {
        score += 5;
        reasons.push(`This budget tier aligns with ${talent.name}'s archetype preferences.`);
      }
    }
  }

  // Final Bound and Verdict
  const finalScore = Math.max(0, Math.min(100, score));
  let verdict: 'willing' | 'hesitant' | 'unwilling';

  if (finalScore >= 70) verdict = 'willing';
  else if (finalScore >= 40) verdict = 'hesitant';
  else verdict = 'unwilling';

  return {
    score: finalScore,
    reasons,
    finalVerdict: verdict
  };
}

