// --- Demographic System ---
export type NielsenDemographic = 'P2+' | 'A18-49' | 'A25-54' | 'A18-34' | 'W18-49' | 'M18-49' | 'K2-11' | 'T12-17';

export interface DemoRating {
  demo: NielsenDemographic;
  label: string;
  rating: number;   // % of that demographic watching (e.g., 2.5 = 2.5% of all A18-49 households)
  viewers: number;  // Raw viewer count in millions
}

export interface NielsenSnapshot {
  id: string; // 🌌 Standardized UUID for this snapshot instance
  week: number;
  episodeNumber: number;
  householdRating: number;    // Overall household rating (% of all TV households)
  // ...
  householdShare: number;     // Share (% of households watching TV at that time)
  totalViewers: number;       // In millions
  demoRatings: DemoRating[];
  keyDemo: number;            // A18-49 rating (the "money demo")
  timeSlot: TimeSlot;
  rank: number;               // Weekly rank among all shows
  trend: 'UP' | 'DOWN' | 'STABLE' | 'PREMIERE' | 'FINALE';
  liveSDViewers: number;      // Live + Same Day
  live7Viewers: number;       // Live + 7 day (DVR/streaming catch-up)
}

export interface NielsenProfile {
  snapshots: NielsenSnapshot[];
  seasonAvgHH: number;        // Season average household rating
  seasonAvgKeyDemo: number;   // Season average A18-49
  seasonAvgViewers: number;   // Season average total viewers (millions)
  timeSlot: TimeSlot;
  peakViewers: number;
  peakWeek: number;
  audienceRetention: number;  // % retained from premiere to latest
  dvrLift: number;            // % increase from L+SD to L+7
}

const DEMO_LABELS: Record<NielsenDemographic, string> = {
  'P2+': 'Total Viewers',
  'A18-49': 'Adults 18-49',
  'A25-54': 'Adults 25-54',
  'A18-34': 'Adults 18-34',
  'W18-49': 'Women 18-49',
  'M18-49': 'Men 18-49',
  'K2-11': 'Kids 2-11',
  'T12-17': 'Teens 12-17'
};

// --- Genre to Demographic Affinity ---
const GENRE_DEMO_AFFINITY: Record<string, Partial<Record<NielsenDemographic, number>>> = {
  'Drama': { 'A25-54': 1.3, 'W18-49': 1.2 },
  'Comedy': { 'A18-34': 1.3, 'A18-49': 1.2 },
  'Action': { 'M18-49': 1.4, 'A18-34': 1.2 },
  'Sci-Fi': { 'M18-49': 1.3, 'A18-34': 1.3 },
  'Horror': { 'A18-34': 1.4, 'T12-17': 1.2 },
  'Romance': { 'W18-49': 1.5, 'A18-34': 1.1 },
  'Family': { 'K2-11': 1.5, 'P2+': 1.2 },
  'Animation': { 'K2-11': 1.6, 'T12-17': 1.2 },
  'Crime': { 'A25-54': 1.4, 'M18-49': 1.2 },
  'Thriller': { 'A25-54': 1.2, 'M18-49': 1.3 },
  'Reality': { 'W18-49': 1.3, 'A18-34': 1.2, 'T12-17': 1.1 },
};

/**
 * Assign a time slot based on genre/format/budget.
 */
export function assignTimeSlot(project: SeriesProject): TimeSlot {
  if (project.distributionStatus === 'streaming') return 'STREAMING';
  const format = project.tvFormat || project.format;
  if (typeof format === 'string') {
    if (format.includes('late_night') || format.includes('sketch')) return 'LATE_NIGHT';
    if (format.includes('daytime') || format.includes('soap')) return 'DAYTIME';
  }
  if (project.budgetTier === 'blockbuster' || project.budgetTier === 'high') return '9PM';
  if (project.genre === 'Family' || project.genre === 'Animation') return '8PM';
  if (project.genre === 'Drama' || project.genre === 'Crime') return '10PM';
  return '9PM';
}

/**
 * Calculate a full Nielsen snapshot for a single episode airing.
 */
export function calculateNielsenRatings(
  project: SeriesProject,
  episodeNumber: number,
  totalShows: number,
  rng: RandomGenerator
): NielsenSnapshot {
  const timeSlot: TimeSlot = (project as any).nielsenProfile?.timeSlot || assignTimeSlot(project);
  const slotConfig = TIME_SLOTS[timeSlot];
  const buzz = project.buzz || 50;
  const quality = project.reviewScore || 50;

  // Base household rating: buzz and quality driven
  const buzzFactor = (buzz / 100) * 6; // 0-6 rating points from buzz
  const qualityFactor = (quality / 100) * 4; // 0-4 from quality
  let baseHHRating = (buzzFactor + qualityFactor) * slotConfig.primeTimeMultiplier;

  // Premiere/Finale boosts
  const isPremiere = episodeNumber === 1;
  const isFinalWeek = episodeNumber >= (project.tvDetails?.episodesOrdered || 8);
  if (isPremiere) baseHHRating *= 1.3;
  if (isFinalWeek) baseHHRating *= 1.25;

  // Episode decay (mid-season dip)
  const midSeasonDip = episodeNumber > 2 && !isFinalWeek
    ? Math.pow(0.97, episodeNumber - 2)
    : 1.0;
  baseHHRating *= midSeasonDip;

  // Stochastic variance +/- 8%
  const variance = 0.92 + rng.next() * 0.16;
  baseHHRating *= variance;
  baseHHRating = Math.max(0.1, Math.round(baseHHRating * 100) / 100);

  // Share = rating / HUT level (% of TVs on)
  const hutLevel = 0.55 + rng.next() * 0.15; // 55-70% of households have TV on
  const share = Math.round((baseHHRating / (hutLevel * 100)) * 1000) / 10;

  // Total viewers (millions)
  const totalHouseholds = 131; // ~131M US TV households
  const totalViewers = Math.round((baseHHRating / 100) * totalHouseholds * 2.3 * 100) / 100; // 2.3 viewers per household avg

  // Demographic breakdowns
  const genreAffinity = GENRE_DEMO_AFFINITY[project.genre] || {};
  const demoRatings: DemoRating[] = (Object.keys(DEMO_LABELS) as NielsenDemographic[]).map(demo => {
    const slotWeight = slotConfig.demographics[demo] || 1.0;
    const genreWeight = genreAffinity[demo] || 1.0;
    const demoRating = baseHHRating * slotWeight * genreWeight * (0.9 + rng.next() * 0.2);
    const demoViewers = (demoRating / 100) * totalHouseholds * (demo === 'P2+' ? 2.3 : demo.startsWith('K') ? 0.4 : demo.startsWith('T') ? 0.3 : 0.8);
    return {
      demo,
      label: DEMO_LABELS[demo],
      rating: Math.round(demoRating * 100) / 100,
      viewers: Math.round(demoViewers * 100) / 100
    };
  });

  const keyDemo = demoRatings.find(d => d.demo === 'A18-49')?.rating || 0;

  // DVR/Streaming lift (L+7 is typically 30-60% higher)
  const dvrLiftPct = 0.3 + rng.next() * 0.3;
  const live7 = Math.round(totalViewers * (1 + dvrLiftPct) * 100) / 100;

  // Trend determination
  let trend: NielsenSnapshot['trend'] = 'STABLE';
  if (isPremiere) trend = 'PREMIERE';
  else if (isFinalWeek) trend = 'FINALE';
  else if (variance > 1.04) trend = 'UP';
  else if (variance < 0.96) trend = 'DOWN';

  return {
    id: rng.uuid('SNP'), // 🌌 Standardized UUID for snapshot
    week: 0, // Set by caller
    episodeNumber,
    householdRating: baseHHRating,
    householdShare: Math.max(1, share),
    totalViewers,
    demoRatings,
    keyDemo: Math.round(keyDemo * 100) / 100,
    timeSlot,
    rank: 0, // Computed after all shows are rated
    trend,
    liveSDViewers: totalViewers,
    live7Viewers: live7
  };
}

/**
 * Build/update the NielsenProfile from snapshot history.
 */
export function buildNielsenProfile(snapshots: NielsenSnapshot[], timeSlot: TimeSlot): NielsenProfile {
  if (snapshots.length === 0) {
    return {
      snapshots: [], seasonAvgHH: 0, seasonAvgKeyDemo: 0, seasonAvgViewers: 0,
      timeSlot, peakViewers: 0, peakWeek: 0, audienceRetention: 100, dvrLift: 0
    };
  }

  const avgHH = snapshots.reduce((s, snap) => s + snap.householdRating, 0) / snapshots.length;
  const avgDemo = snapshots.reduce((s, snap) => s + snap.keyDemo, 0) / snapshots.length;
  const avgViewers = snapshots.reduce((s, snap) => s + snap.totalViewers, 0) / snapshots.length;
  const peak = snapshots.reduce((best, snap) => snap.totalViewers > best.totalViewers ? snap : best, snapshots[0]);
  const premiere = snapshots[0];
  const latest = snapshots[snapshots.length - 1];
  const retention = premiere.totalViewers > 0 ? (latest.totalViewers / premiere.totalViewers) * 100 : 100;
  const avgDvrLift = snapshots.reduce((s, snap) => s + ((snap.live7Viewers - snap.liveSDViewers) / Math.max(snap.liveSDViewers, 0.1)), 0) / snapshots.length * 100;

  return {
    snapshots,
    seasonAvgHH: Math.round(avgHH * 100) / 100,
    seasonAvgKeyDemo: Math.round(avgDemo * 100) / 100,
    seasonAvgViewers: Math.round(avgViewers * 100) / 100,
    timeSlot,
    peakViewers: peak.totalViewers,
    peakWeek: peak.week,
    audienceRetention: Math.round(retention),
    dvrLift: Math.round(avgDvrLift)
  };
}

/**
 * Rank all airing shows by A18-49 demo rating for the week.
 * Returns updated snapshots with rank fields filled in.
 */
export function rankShows(snapshots: Map<string, NielsenSnapshot>): Map<string, NielsenSnapshot> {
  const entries = Array.from(snapshots.entries());
  entries.sort((a, b) => b[1].keyDemo - a[1].keyDemo);
  const ranked = new Map<string, NielsenSnapshot>();
  entries.forEach(([id, snap], idx) => {
    ranked.set(id, { ...snap, rank: idx + 1 });
  });
  return ranked;
}

import { GameState, StateImpact } from '@/engine/types';
import { RandomGenerator } from '@/engine/utils/rng';

const PILOT_MAX_WEEKS = 2;
const PILOT_BURN_RATE = 0.30;

export function tickPilots(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  for (const key in state.entities.projects) {
    const project = state.entities.projects[key];
    if (project.type !== 'SERIES' || (project as any).stage !== 'pilot') continue;

    const weeksInPilot = (project.weeksInPhase || 0) + 1;

    if (weeksInPilot < PILOT_MAX_WEEKS) {
      impacts.push({
        type: 'PROJECT_UPDATED',
        payload: {
          projectId: project.id,
          update: {
            weeksInPhase: weeksInPilot,
            weeklyCost: Math.round(project.weeklyCost * PILOT_BURN_RATE),
          }
        }
      });
    } else {
      const quality = ((project as any).scriptHeat ?? 50) * 0.5 + (project.momentum ?? 50) * 0.5;
      const graduated = quality >= 40 || rng.next() < 0.3;

      if (graduated) {
        impacts.push({
          type: 'PILOT_GRADUATED',
          payload: { projectId: project.id, nextState: 'production' as const }
        });
        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `"${project.title}" pilot greenlit to series`,
            description: `The network has ordered a full series pickup.`,
            category: 'development',
            week: state.week
          }
        });
      } else {
        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: {
            projectId: project.id,
            update: { state: 'archived' as const }
          }
        });
        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `"${project.title}" pilot passed on`,
            description: `The network declined to order a full series.`,
            category: 'cancellation',
            week: state.week
          }
        });
      }
    }
  }
  return impacts;
}

import { GameState, StateImpact, SeriesProject } from '@/engine/types';
import { calculateWeeklyRating } from './ratingsEvaluator';
import { evaluateRenewal } from './renewalEngine';
import { RandomGenerator } from '../../utils/rng';
import { calculateNielsenRatings, buildNielsenProfile, rankShows, assignTimeSlot, NielsenSnapshot } from './nielsenSystem';
import { runUpfronts } from './upfrontsEngine';
import { tickPilots } from './pilotEvaluator';



export type TVStatus = 'IN_DEVELOPMENT' | 'ON_AIR' | 'ON_BUBBLE' | 'RENEWED' | 'CANCELLED' | 'SYNDICATED';

/**
 * Weekly TV Tick with integrated Nielsen ratings system.
 */
export function tickTelevision(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [
    ...tickPilots(state, rng),
  ];

  // The Upfronts: Week 20
  if (state.week % 52 === 20) {
    impacts.push(...runUpfronts(state, rng));
  }

  // Refactored array .find() inside map to a Set/Map lookup, improving performance from O(n^2) to O(n).
  // Loop fusion: We collect allSeries, airingShows, and identify player/rival ownership in a single pass.
  const allSeries: SeriesProject[] = [];
  const airingShows: SeriesProject[] = [];

  // Track ownership to avoid O(N) lookups later
  const isPlayerMap = new Map<string, boolean>();
  const rivalIdMap = new Map<string, string>();

  const playerProjects = state.entities.projects;
  for (const key in playerProjects) {
    if (!Object.prototype.hasOwnProperty.call(playerProjects, key)) continue;
    const p = playerProjects[key];
    if (p.type === 'SERIES' && 'tvDetails' in p) {
      const seriesProject = p as SeriesProject;
      allSeries.push(seriesProject);
      isPlayerMap.set(p.id, true);
      if (seriesProject.tvDetails.status === 'ON_AIR') {
        airingShows.push(seriesProject);
      }
    }
  }

  const rivalsMap = state.entities.rivals || {};
  const rivalsList = Object.values(rivalsMap);

  // Use unified storage for rival projects
  const rivalProjects: SeriesProject[] = [];
  const projectsDict = state.entities.projects;
  const rivalIds = new Set(rivalsList.map(r => r.id));

  for (const key in projectsDict) {
    if (!Object.prototype.hasOwnProperty.call(projectsDict, key)) continue;
    const p = projectsDict[key];
    if (p.ownerId && rivalIds.has(p.ownerId)) {
      rivalProjects.push(p as SeriesProject);
    }
  }

  for (const p of rivalProjects) {
    if (p.type === 'SERIES' && 'tvDetails' in p) {
      const seriesProject = p as SeriesProject;
      allSeries.push(seriesProject);
      rivalIdMap.set(p.id, p.ownerId || '');
      if (seriesProject.tvDetails.status === 'ON_AIR') {
        airingShows.push(seriesProject);
      }
    }
  }

  const weekSnapshots = new Map<string, NielsenSnapshot>();

  // Phase 1: Generate Nielsen snapshots for all airing shows
  for (let i = 0; i < airingShows.length; i++) {
    const project = airingShows[i];
    const aired = (project.tvDetails.episodesAired || 0) + 1;
    const snapshot = calculateNielsenRatings(project, aired, airingShows.length, rng);
    snapshot.week = state.week + 1;
    weekSnapshots.set(project.id, snapshot);
  }

  // Phase 2: Rank all shows by key demo
  const rankedSnapshots = rankShows(weekSnapshots);

  // Phase 3: Process each series
  for (let i = 0; i < allSeries.length; i++) {
    const project = allSeries[i];
    if (project.tvDetails.status !== 'ON_AIR') continue;

    const snapshot = rankedSnapshots.get(project.id);
    if (!snapshot) continue;

    const aired = (project.tvDetails.episodesAired || 0) + 1;

    // Legacy rating (keep backward compat)
    const newRating = calculateWeeklyRating(project, project.buzz || 0, rng);
    const totalRatingSum = (project.tvDetails.averageRating * (project.tvDetails.episodesAired || 0)) + newRating;
    const nextAverageRating = Math.round((totalRatingSum / aired) * 10) / 10;

    // Renewal logic
    let nextStatus: TVStatus = project.tvDetails.status;
    if (aired >= project.tvDetails.episodesOrdered) {
      nextStatus = evaluateRenewal(project, nextAverageRating) as TVStatus;
    }

    // Build updated Nielsen profile
    const existingSnapshots = project.nielsenProfile?.snapshots || [];
    const timeSlot = project.nielsenProfile?.timeSlot || assignTimeSlot(project);
    const updatedSnapshots = [...existingSnapshots, snapshot];
    const nielsenProfile = buildNielsenProfile(updatedSnapshots, timeSlot);

    const isPlayer = isPlayerMap.get(project.id);
    const rivalId = rivalIdMap.get(project.id);
    const rival = rivalId ? rivalsMap[rivalId] : undefined;

    if (isPlayer) {
      impacts.push({
        type: 'PROJECT_UPDATED',
        payload: {
          projectId: project.id,
          update: {
            tvDetails: {
              ...project.tvDetails,
              episodesAired: aired,
              averageRating: nextAverageRating,
              status: nextStatus
            },
            nielsenProfile
          }
        }
      });
    } else if (rival) {
        // Correctly update rival project
        const updatedProject = {
            ...project,
            tvDetails: { ...project.tvDetails, episodesAired: aired, averageRating: nextAverageRating, status: nextStatus },
            nielsenProfile
        };
        // Backward compatibility for projects field
        const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
        impacts.push({
            type: 'RIVAL_UPDATED',
            payload: {
                rivalId: rival.id,
                update: {
                    projects: { ...rivalProjects, [project.id]: updatedProject }
                }
            }
        });
    }

    if (nextStatus === 'CANCELLED') {
      const usesDeficit = project.dealModel === 'deficit_financing';
      if (usesDeficit) {
        // Deficit-financed cancelled show (Player or Rival) enters shopping window (4 weeks)
        const update = {
            shoppingWindow: 4
        };
        if (isPlayer) {
          impacts.push({
            type: 'PROJECT_UPDATED',
            payload: { projectId: project.id, update }
          });
        } else if (rival) {
          // Backward compatibility for projects field
          const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
          impacts.push({
            type: 'RIVAL_UPDATED',
            payload: {
                rivalId: rival.id,
                update: {
                    projects: { ...rivalProjects, [project.id]: { ...rivalProjects[project.id], ...update } }
                }
            }
          });
        }
        impacts.push({
          type: 'NEWS_ADDED',
          payload: {
            id: rng.uuid('NWS'),
            headline: `"${project.title}" cancelled — shopping for new home`,
            description: `The series is now available for pickup by another network.`,
            category: 'cancellation',
            week: state.week
          }
        });
      } else {
        // Backward compatibility for projects field
        const rivalProjectsForArchive = rival ? (('projects' in rival && rival.projects) ? (rival as any).projects : {}) : {};
        impacts.push({
          type: isPlayer ? 'PROJECT_REMOVED' : 'RIVAL_UPDATED',
          payload: isPlayer
            ? { projectId: project.id }
            : { rivalId: rival?.id, update: { projects: { ...rivalProjectsForArchive, [project.id]: { ...project, state: 'archived' } } } } as any
        });
      }
    }
  }

  // Phase 4: Handle Shopping Expiration
  // Refactored array spread and .find() inside loop to direct object iteration, improving performance from O(n^2) to O(n).
  const checkShoppingExpiration = (p: any, isPlayer: boolean, rivalId?: string) => {
    if (p.state === 'shopping' && p.shoppingExpiresWeek && state.week >= p.shoppingExpiresWeek) {
      if (isPlayer) {
        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: { projectId: p.id, update: { state: 'archived' as const } }
        });
      } else if (rivalId) {
        const rival = state.entities.rivals[rivalId];
        if (rival) {
          // Backward compatibility for projects field
          const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
          impacts.push({
            type: 'RIVAL_UPDATED',
            payload: { rivalId, update: { projects: { ...rivalProjects, [p.id]: { ...p, state: 'archived' as const } } } } as any
          });
        }
      }
    }
  };

  for (const key in playerProjects) {
    if (!Object.prototype.hasOwnProperty.call(playerProjects, key)) continue;
    checkShoppingExpiration(playerProjects[key], true);
  }

  for (let i = 0; i < rivalsList.length; i++) {
    const rival = rivalsList[i];
    // Backward compatibility for projects field
    const rivalProjects = ('projects' in rival && rival.projects) ? (rival as any).projects : {};
    for (const key in rivalProjects) {
      if (!Object.prototype.hasOwnProperty.call(rivalProjects, key)) continue;
      checkShoppingExpiration(rivalProjects[key], false, rival.id);
    }
  }

  return impacts;
}

import { GameState, StateImpact, SeriesProject } from '@/engine/types';
import { RandomGenerator } from '../../utils/rng';

export interface UpfrontResult {
  projectId: string;
  projectTitle: string;
  decision: 'pickup' | 'pass' | 'limited_order';
  episodesOrdered?: number;
  notes: string;
}

/**
 * Upfronts — fired at week 20 each year.
 * Network buyers evaluate all in-development TV projects and issue pickup orders or passes.
 * Triggers a MODAL_TRIGGERED impact for the player to review decisions.
 */
export function runUpfronts(state: GameState, rng: RandomGenerator): StateImpact[] {
  const impacts: StateImpact[] = [];
  const results: UpfrontResult[] = [];
  let pickups = 0;

  // ⚡ The Framerate Fanatic: Refactored Object.values(), .filter(), and .map() into a single O(n) loop pass
  for (const key in state.entities.projects) {
    if (!Object.prototype.hasOwnProperty.call(state.entities.projects, key)) continue;
    const project = state.entities.projects[key];

    if (
      project.type === 'SERIES' &&
      (project.state === 'development' || project.state === 'needs_greenlight') &&
      (project as any).stage !== 'pilot'
    ) {
      const seriesProject = project as SeriesProject;
      const buzz = seriesProject.buzz ?? 50;
      const scriptHeat = (seriesProject as any).scriptHeat ?? 50;
      const momentum = seriesProject.momentum ?? 50;
      const quality = (buzz * 0.4 + scriptHeat * 0.3 + momentum * 0.3) + rng.range(-10, 10);

      let decision: UpfrontResult['decision'];
      let episodesOrdered: number | undefined;
      let notes: string;

      if (quality >= 70) {
        decision = 'pickup';
        episodesOrdered = seriesProject.budgetTier === 'low' ? rng.rangeInt(6, 10) : rng.rangeInt(8, 13);
        notes = `Strong buyer interest. Full series order of ${episodesOrdered} episodes.`;
      } else if (quality >= 45) {
        decision = 'limited_order';
        episodesOrdered = rng.rangeInt(4, 7);
        notes = `Cautious interest. Limited order of ${episodesOrdered} episodes to prove concept.`;
      } else {
        decision = 'pass';
        notes = `Networks passed. Project needs rework before resubmission.`;
      }

      const result: UpfrontResult = {
        projectId: seriesProject.id,
        projectTitle: seriesProject.title,
        decision,
        episodesOrdered,
        notes
      };

      results.push(result);

      if (decision !== 'pass') {
        pickups++;
        impacts.push({
          type: 'PROJECT_UPDATED',
          payload: {
            projectId: result.projectId,
            update: {
              state: 'production' as const,
              tvDetails: {
                ...seriesProject.tvDetails,
                episodesOrdered: result.episodesOrdered ?? 10,
                status: 'IN_DEVELOPMENT',
              }
            }
          }
        });
      }
    }
  }

  if (results.length === 0) return impacts;

  // Trigger modal so player can review all decisions
  impacts.push({
    type: 'MODAL_TRIGGERED',
    payload: {
      modalType: 'UPFRONTS',
      priority: 30,
      payload: { results, week: state.week }
    }
  });

  // Add headline
  if (pickups > 0) {
    impacts.push({
      type: 'NEWS_ADDED',
      payload: {
        id: `upfronts-${state.week}`,
        headline: `${state.studio.name} announces ${pickups} series pickup${pickups > 1 ? 's' : ''} at Upfronts`,
        description: `The studio secured orders at this season's upfront presentations.`,
        category: 'development',
        publication: 'Deadline'
      }
    });
  }

  return impacts;
}

import { pick } from '../utils';
import { GenreTrend, GameState } from '@/engine/types';
import { StateImpact } from '../types/state.types';
import { RandomGenerator } from '../utils/rng';
import { BardResolver } from './bardResolver';

export const ALL_GENRES = [
  'Action', 'Comedy', 'Drama', 'Horror', 'Sci-Fi', 'Thriller', 'Romance', 'Animation', 'Documentary', 'Fantasy'
];

export function initializeTrends(rng: RandomGenerator): GenreTrend[] {
  // Pick 3 random genres to be the starting trends
  const shuffled = [...ALL_GENRES];
  // Fisher-Yates shuffle with rng
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(rng.next() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }

  return [
    {
      genre: shuffled[0],
      heat: 80,
      direction: 'hot',
      weeksRemaining: 12,
      description: BardResolver.resolve({
        domain: 'Market',
        subDomain: 'Trend',
        intensity: 80,
        context: { genre: shuffled[0] },
        rng
      })
    },
    {
      genre: shuffled[1],
      heat: 50,
      direction: 'stable',
      weeksRemaining: 24,
      description: BardResolver.resolve({
        domain: 'Market',
        subDomain: 'Trend',
        intensity: 50,
        context: { genre: shuffled[1] },
        rng
      })
    },
    {
      genre: shuffled[2],
      heat: 20,
      direction: 'cooling',
      weeksRemaining: 6,
      description: BardResolver.resolve({
        domain: 'Market',
        subDomain: 'Trend',
        intensity: 20,
        context: { genre: shuffled[2] },
        rng
      })
    }
  ];
}

export function advanceTrends(trends: GenreTrend[], rng: RandomGenerator): StateImpact[] {
  let updated = (trends || []).map(t => {
    let newHeat = t.heat;
    if (t.direction === 'rising') newHeat = Math.min(100, newHeat + 5);
    if (t.direction === 'cooling') newHeat = Math.max(0, newHeat - 5);

    // Change direction if maxed out or cooled out
    let newDirection = t.direction;
    if (newHeat >= 100) newDirection = 'stable';
    if (newHeat <= 0) newDirection = 'dead';

    return {
      ...t,
      heat: newHeat,
      direction: newDirection,
      weeksRemaining: (t.weeksRemaining || 0) - 1
    };
  });

  // Remove dead trends or those out of time
  updated = updated.filter(t => t.weeksRemaining > 0 && t.heat > 0);

  // Randomly spawn new trends if we are low
  if (updated.length < 5 && rng.next() < 0.1) {
    const activeGenres = new Set(updated.map(t => t.genre));
    const available = ALL_GENRES.filter(g => !activeGenres.has(g));
    if (available.length > 0) {
      const newGenre = rng.pick(available);
      updated.push({
        genre: newGenre,
        heat: 30,
        direction: 'rising',
        weeksRemaining: 16 + Math.floor(rng.next() * 12),
        description: BardResolver.resolve({
          domain: 'Market',
          subDomain: 'Trend',
          intensity: 30,
          context: { genre: newGenre },
          rng
        })
      });
    }
  }

  return [
    {
      type: 'TRENDS_UPDATED',
      payload: { trends: updated }
    }
  ];
}

export function getTrendMultiplier(project: { genre: string; targetAudience: string }, state: GameState): number {
  if (!state.market.trends) return 1.0;

  let trendModifier = 1.0;

  // Check both genre and audience for trend matches
  for (const trend of state.market.trends) {
    const isMatch = trend.genre === project.genre || trend.genre === project.targetAudience;

    if (isMatch) {
      if (trend.heat >= 70) {
        trendModifier += 0.3;
      } else if (trend.heat <= 30) {
        trendModifier -= 0.25;
      }
    }
  }

  return trendModifier;
}

