// Shared utilities for the engine layer — no React imports

export function getProjects(state: GameState): Project[] {
  return Object.values(state.entities.projects || {});
}

export function getTalents(state: GameState): Talent[] {
  return Object.values(state.entities.talents || {});
}

export function formatMoney(amount: number): string {
  if (Number.isNaN(amount)) return "$NaN";

  const abs = Math.abs(amount);
  const sign = amount < 0 || Object.is(amount, -0) ? '-' : '';

  if (!Number.isFinite(amount)) return `${sign}$InfinityB`;

  // Handle edge case rounding errors where .toFixed bumps up the number into the next tier
  // e.g. 999_999_999.9 becomes "1000.0M" if we don't catch it.
  if (abs >= 999_950_000) return `${sign}$${(abs / 1_000_000_000).toFixed(1)}B`;
  if (abs >= 999_950) return `${sign}$${(abs / 1_000_000).toFixed(1)}M`;
  if (abs >= 999.5) return `${sign}$${(abs / 1_000).toFixed(0)}K`;
  return `${sign}$${abs.toFixed(0)}`;
}

export function getWeekDisplay(week: number): { displayWeek: number; year: number } {
  return {
    displayWeek: ((week - 1) % 52) + 1,
    year: 2026 + Math.floor((week - 1) / 52),
  };
}

export function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}


export function groupContractsByProject(contracts: Contract[]): Map<string, Contract[]> {
  const map = new Map<string, Contract[]>();
  for (const contract of contracts) {
    if (!map.has(contract.projectId)) {
      map.set(contract.projectId, []);
    }
    map.get(contract.projectId)!.push(contract);
  }
  return map;
}

/**
 * Robust string template interpolation for both ${key} and {key} syntaxes.
 * Useful for resolving headlines, scandals, and rumors from data pools.
 */
export function fillTemplate(template: string, vars: Record<string, string | number>): string {
  return template.replace(/(\$\{([^}]+)\})|(\{([^}]+)\})/g, (match, p1, p2, p3, p4) => {
    const key = p2 || p4;
    return vars[key] !== undefined ? String(vars[key]) : match;
  });
}

export function pick<T>(arr: T[], rng?: RandomGenerator): T {
  if (rng) return rng.pick(arr);
  // 🌌 Enforcement: No non-deterministic fallbacks allowed in core engine.
  // Returning first element as a safe but deterministic fallback.
  return arr[0];
}

export function randRange(min: number, max: number, rng?: RandomGenerator): number {
  if (rng) return rng.rangeInt(min, max);
  // 🌌 Enforcement: Return min instead of Math.random()
  return min;
}

import { Project, FilmProject, SeriesProject, UnscriptedProject, BudgetTierKey } from '../types/project.types';
import { Talent } from '../types/talent.types';

const BUDGET_TIER_RANK: Record<BudgetTierKey, number> = { 'indie': 1, 'low': 2, 'mid': 3, 'high': 4, 'blockbuster': 5 };

function getTalentPrestigeTier(prestige: number): number {
  if (prestige > 80) return 5;
  if (prestige > 60) return 4;
  if (prestige > 40) return 3;
  if (prestige > 20) return 2;
  return 1;
}

/**
 * Project Type Guards for Strict Type Safety
 */

export function isFilmProject(project: Project): project is FilmProject {
  return project.type === 'FILM' && project.format === 'film';
}

export function isSeriesProject(project: Project): project is SeriesProject {
  return project.type === 'SERIES' && project.format === 'tv';
}

export function isUnscriptedProject(project: Project): project is UnscriptedProject & { type: 'SERIES' } {
  return project.type === 'SERIES' && project.format === 'unscripted';
}

/**
 * Returns the season display string for a project if applicable.
 */
export function getProjectSeasonDisplay(project: Project): string {
  if (isSeriesProject(project)) {
    return `S${project.tvDetails.currentSeason || 1}`;
  }
  if (isUnscriptedProject(project)) {
    return 'SERIES';
  }
  return project.format.toUpperCase();
}

/**
 * Calculates a match score (0-100) between a talent and a project.
 * Uses deterministic logic for scoring based on genre, tier, role fit, and power.
 */
export function calculateTalentFitScore(talent: Talent, project: Project, targetRole?: string, attachedTalentIds?: string[]): number {
  let score = 50; 

  // --- GENRE ALIGNMENT ---
  if (talent.preferredGenres?.includes(project.genre)) {
    score += 20;
  } else {
    score -= 10;
  }

  // --- TIER ALIGNMENT ---
  const tierValue = BUDGET_TIER_RANK[project.budgetTier] || 1;
  const talentTier = getTalentPrestigeTier(talent.prestige);

  if (talentTier === tierValue) score += 20;
  else if (Math.abs(talentTier - tierValue) === 1) score += 5;
  else score -= 15;

  // --- ANIMATION EXEMPTION ---
  // Animation projects are more flexible with talent fits but focus on different synergies
  if (project.format === 'animation' || project.genre === 'Animation') {
    score += 15; // Baseline boost for "The Animation Loop"
    if (talent.roles.includes('personality')) score += 10; // Personalities are great for animation
  }

  // Specific Role Buffs
  if (targetRole && (talent.roles || []).includes(targetRole as any)) {
    score += 10;
  }

  // Draw vs Budget Requirements
  if (project.budgetTier === 'blockbuster' && (talent.draw || 0) < 50) score -= 20;
  if (project.budgetTier === 'low' && talent.prestige > 90) score -= 10;

  // Synergy Afficinities & Conflicts (Phase 2)
  if (attachedTalentIds && attachedTalentIds.length > 0) {
    if (talent.psychology?.synergyAffinities?.length) {
      for (const attachedId of attachedTalentIds) {
        if (talent.psychology.synergyAffinities.includes(attachedId)) {
          score += 15;
        }
      }
    }
    if (talent.psychology?.synergyConflicts?.length) {
      for (const attachedId of attachedTalentIds) {
        if (talent.psychology.synergyConflicts.includes(attachedId)) {
          score -= 15;
        }
      }
    }
  }

  return Math.max(0, Math.min(100, score));
}

/**
 * Returns a list of talent with fit scores and recommendation tags.
 */
export function getRecommendedTalentForProject(talentPool: Talent[], project: Project, targetRole?: string, attachedTalentIds?: string[]) {
  return talentPool.map(t => {
    const score = calculateTalentFitScore(t, project, targetRole, attachedTalentIds);
    const tags: string[] = [];

    if (t.preferredGenres?.includes(project.genre)) tags.push("Genre Specialist");
    const tierValue = BUDGET_TIER_RANK[project.budgetTier] || 1;
    const talentTier = getTalentPrestigeTier(t.prestige);
    if (talentTier === tierValue) tags.push("Perfect Tier Match");
    if (t.draw > 70 && project.budgetTier === 'blockbuster') tags.push("Box Office Draw");

    if (attachedTalentIds && attachedTalentIds.length > 0) {
      const affinities = t.psychology?.synergyAffinities || [];
      const conflicts = t.psychology?.synergyConflicts || [];
      let hasAffinity = false;
      let hasConflict = false;

      for (const attachedId of attachedTalentIds) {
        if (affinities.includes(attachedId)) hasAffinity = true;
        if (conflicts.includes(attachedId)) hasConflict = true;
      }

      if (hasAffinity) tags.push("Synergy Match");
      if (hasConflict) tags.push("Synergy Conflict");
    }

    return {
      talent: t,
      score,
      tags
    };
  }).sort((a, b) => b.score - a.score);
}

/**
 * Estimates the duration (in weeks) required for a project production phase.
 */
export function getProjectEstimatedWindow(project: Project): number {
  let baseWeeks = 12;

  if (project.format === 'film') {
    switch (project.budgetTier) {
      case 'mid': baseWeeks = 20; break;
      case 'high': baseWeeks = 30; break;
      case 'blockbuster': baseWeeks = 45; break;
      case 'low': baseWeeks = 12; break;
      case 'indie': baseWeeks = 8; break;
      default: baseWeeks = 12;
    }
  } else {
    // Correctly accessing episodesOrdered from tvDetails
    const episodes = isSeriesProject(project) ? project.tvDetails.episodesOrdered : 10;
    baseWeeks = 8 + (episodes * 2);
    if (project.budgetTier === 'blockbuster') baseWeeks += 12;
    else if (project.budgetTier === 'high') baseWeeks += 6;
  }

  return baseWeeks;
}

/**
 * Studio Boss - Seeded Random Number Generator (Mulberry32)
 *
 * Provides a 100% deterministic source of randomness for the engine.
 * To ensure determinism, do NOT use Math.random() or crypto.randomUUID()
 * within engine core modules.
 */

export class RandomGenerator {
  private state: number;

  constructor(seed: number) {
    // Ensure seed is a 32-bit integer
    this.state = seed >>> 0;
  }

  /**
   * Returns a float between 0 and 1.
   */
  next(): number {
    let t = (this.state += 0x6d2b79f5);
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  }

  /**
   * Returns a random element from an array.
   */
  pick<T>(arr: T[]): T {
    if (arr.length === 0) return undefined as any;
    return arr[Math.floor(this.next() * arr.length)];
  }

  /**
   * Returns a random float between min and max.
   */
  range(min: number, max: number): number {
    return min + this.next() * (max - min);
  }

  /**
   * Returns a random integer between min and max (inclusive).
   */
  rangeInt(min: number, max: number): number {
    return Math.floor(min + this.next() * (max - min + 1));
  }

  /**
   * Returns a deterministic UUID-like string.
   */
  uuid(prefix: string = ''): string {
    const part = () => Math.floor(this.next() * 0xffffffff).toString(16).padStart(8, '0');
    const id = `${part()}-${part().slice(0, 4)}-${part().slice(0, 4)}-${part().slice(0, 4)}-${part().slice(0, 12)}`;
    const lowerPrefix = prefix.toLowerCase();
    return lowerPrefix ? `${lowerPrefix}-${id}` : id;
  }

  /**
   * Shuffles an array in place (Fisher-Yates).
   */
  shuffle<T>(arr: T[]): T[] {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(this.next() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
  }

  /**
   * Returns the current internal state (useful for snapshotting).
   */
  getState(): number {
    return this.state;
  }
}

import React, { useEffect, useCallback } from 'react';
import { useUIStore } from '@/store/uiStore';

/**
 * Keyboard shortcut definitions
 */
export const KEYBOARD_SHORTCUTS = {
  // Navigation
  'cmd+1': { action: 'hub', target: 'hq', description: 'Go to Studio HQ' },
  'cmd+2': { action: 'hub', target: 'production', description: 'Go to Production' },
  'cmd+3': { action: 'hub', target: 'talent', description: 'Go to Talent & Deals' },
  'cmd+4': { action: 'hub', target: 'intelligence', description: 'Go to Intelligence' },

  // Command palette
  'cmd+k': { action: 'commandPalette', description: 'Open command palette' },

  // Actions
  'cmd+n': { action: 'createProject', description: 'Create new project' },

  // Quick actions dock
  'cmd+shift+a': { action: 'toggleQuickActions', description: 'Toggle quick actions dock' },

  // Escape
  'escape': { action: 'escape', description: 'Close modals/panels' },
} as const;

type ShortcutKey = keyof typeof KEYBOARD_SHORTCUTS;

/**
 * Hook to enable keyboard shortcuts throughout the app
 * 
 * Provides:
 * - Hub navigation (Cmd+1, Cmd+2, etc.)
 * - Command palette (Cmd+K)
 * - Quick actions (Cmd+Shift+A)
 * - Create project (Cmd+N)
 */
export function useKeyboardShortcuts() {
  const { 
    setActiveHub, 
    openCreateProject, 
    toggleQuickActions,
    activeModal,
    resolveCurrentModal 
  } = useUIStore();

  const handleKeyDown = useCallback((event: KeyboardEvent) => {
    // Build key combination string
    const keys: string[] = [];
    if (event.metaKey || event.ctrlKey) keys.push('cmd');
    if (event.shiftKey) keys.push('shift');
    if (event.altKey) keys.push('alt');
    keys.push(event.key.toLowerCase());

    const shortcut = keys.join('+') as ShortcutKey;
    const config = KEYBOARD_SHORTCUTS[shortcut];

    if (!config) return;

    // Prevent default for all defined shortcuts
    event.preventDefault();

    // Execute action
    switch (config.action) {
      case 'hub':
        if (config.target) {
          setActiveHub(config.target as any);
        }
        break;

      case 'commandPalette':
        // Command palette is handled by its own hook
        break;

      case 'createProject':
        openCreateProject();
        break;

      case 'toggleQuickActions':
        toggleQuickActions();
        break;

      case 'escape':
        if (activeModal) {
          resolveCurrentModal();
        }
        break;
    }
  }, [setActiveHub, openCreateProject, toggleQuickActions, activeModal, resolveCurrentModal]);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);
}

/**
 * Component wrapper that enables keyboard shortcuts
 */
export const KeyboardShortcuts: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  useKeyboardShortcuts();
  return <>{children}</>;
};

export default useKeyboardShortcuts;

