/**
 * Studio Boss - Persistence Service (Core API)
 *
 * This layer handles communication with the OPFS Save Worker.
 * It manages the lifecycle of the Background I/O and exposes
 * an asynchronous interface to the Redux/Zustand store.
 */

class PersistenceService {
  private worker: Worker | null = null;
  private pendingResolves: Map<string, { resolve: (data: any) => void; slotId: string | number }> = new Map();
  private lastRequestId = 0;

  constructor() {
    this.initWorker();
  }

  private initWorker() {
    if (typeof window !== 'undefined' && 'Worker' in window) {
      this.worker = new Worker(new URL('./saveWorker.ts', import.meta.url), {
        type: 'module',
      });

      this.worker.onmessage = (e: MessageEvent) => {
        const { type, slotId, requestId, state, message } = e.data;

        if (type === 'SAVE_SUCCESS') {
          this.resolvePromise(requestId, true);
        } else if (type === 'LOAD_SUCCESS') {
          this.resolvePromise(requestId, state);
        } else if (type === 'ERROR') {
          console.error(`[PersistenceService] Worker error: ${message} (req: ${requestId})`);
          this.resolvePromise(requestId, null);
        }
      };
    }
  }

  private resolvePromise(requestId: string, result: any) {
    const entry = this.pendingResolves.get(requestId);
    if (entry) {
      entry.resolve(result);
      this.pendingResolves.delete(requestId);
    }
  }

  private generateRequestId(): string {
    return `req_${++this.lastRequestId}_${Date.now()}`;
  }

  /**
   * Save the current game state.
   * Note: The store should ideally debounce/throttle this.
   */
  async save(slotId: string | number, state: any): Promise<boolean> {
    if (!this.worker) return false;

    const requestId = this.generateRequestId();

    return new Promise((resolve) => {
      this.pendingResolves.set(requestId, { resolve, slotId });
      this.worker?.postMessage({
        type: 'SAVE_GAME',
        slotId,
        requestId,
        state
      });
    });
  }

  /**
   * Load a game state from a named slot.
   */
  async load(slotId: string | number): Promise<any | null> {
    if (!this.worker) return null;

    const requestId = this.generateRequestId();

    return new Promise((resolve) => {
      this.pendingResolves.set(requestId, { resolve, slotId });
      this.worker?.postMessage({
        type: 'LOAD_GAME',
        slotId,
        requestId
      });
    });
  }

  /**
   * Checks if a save slot exists.
   * Note: In Electron, this is handled via IPC in saveLoad.ts
   * This method is only used for web version (OPFS)
   */
  async exists(slotId: string | number): Promise<boolean> {
    // Check if running in Electron - use IPC instead
    if (typeof window !== 'undefined' && 'electronAPI' in window && window.electronAPI) {
      try {
        const saves = await window.electronAPI.listSaves();
        return saves.includes(Number(slotId));
      } catch (e) {
        console.error('Failed to check save existence via IPC:', e);
        return false;
      }
    }

    // Fallback to OPFS for web version
    try {
      const root = await navigator.storage.getDirectory();
      await root.getFileHandle(`slot_${slotId}.sb`);
      return true;
    } catch {
      return false;
    }
  }
}

export const persistenceService = new PersistenceService();

/**
 * Studio Boss - OPFS Save Worker
 *
 * This worker handles background serialization and high-performance synchronous
 * disk I/O using Origin Private File System (OPFS).
 */

self.onmessage = async (e: MessageEvent) => {
  const { type, slotId, requestId, state } = e.data;

  try {
    if (type === 'SAVE_GAME') {
      await handleSave(slotId, state);
      self.postMessage({ type: 'SAVE_SUCCESS', slotId, requestId });
    } else if (type === 'LOAD_GAME') {
      const loadedState = await handleLoad(slotId);
      self.postMessage({ type: 'LOAD_SUCCESS', slotId, requestId, state: loadedState });
    }
  } catch (error) {
    console.error(`SaveWorker Error [${type}] (req: ${requestId}):`, error);
    self.postMessage({ type: 'ERROR', requestId, message: (error as Error).message });
  }
};

async function handleSave(slotId: string | number, state: any, retries = 3) {
  const root = await navigator.storage.getDirectory();
  const fileHandle = await root.getFileHandle(`slot_${slotId}.sb`, { create: true });

  let accessHandle: any;
  let attempt = 0;

  while (attempt < retries) {
    try {
      // @ts-expect-error - createSyncAccessHandle is only in Workers
      accessHandle = await fileHandle.createSyncAccessHandle();
      break; 
    } catch (e) {
      attempt++;
      if (attempt >= retries) throw e;
      await new Promise(resolve => setTimeout(resolve, 50 * attempt)); // Exponential-ish backoff
    }
  }

  try {
    // 1. Off-thread serialization
    const encoder = new TextEncoder();
    const buffer = encoder.encode(JSON.stringify(state));

    // 2. Synchronous high-speed write
    accessHandle.truncate(0);
    accessHandle.write(buffer, { at: 0 });
    accessHandle.flush();
  } finally {
    accessHandle.close();
  }
}

async function handleLoad(slotId: string | number) {
  const root = await navigator.storage.getDirectory();
  const fileHandle = await root.getFileHandle(`slot_${slotId}.sb`);

  // @ts-expect-error - createSyncAccessHandle is only in Workers
  const accessHandle = await fileHandle.createSyncAccessHandle();

  try {
    const fileSize = accessHandle.getSize();
    const buffer = new DataView(new ArrayBuffer(fileSize));
    accessHandle.read(buffer, { at: 0 });

    const decoder = new TextDecoder();
    return JSON.parse(decoder.decode(buffer));
  } finally {
    accessHandle.close();
  }
}

