import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';
import { CreateProjectParams, buildProjectAndContracts, applyStateImpact } from '../storeUtils';
import { RandomGenerator } from '@/engine/utils/rng';
import { Project, GameState, SeriesProject } from '@/engine/types';

export interface ProjectCreationSlice {
  createProject: (params: CreateProjectParams) => void;
  renewProject: (id: string) => void;
}

export const createProjectCreationSlice: StateCreator<GameStore, [], [], ProjectCreationSlice> = (set) => ({
  createProject: (params) => {
    set((s) => {
      if (!s.gameState) return s;
      const rng = new RandomGenerator(s.gameState.rngState);
      const { project, newContracts, talentFees } = buildProjectAndContracts(s.gameState, params, rng);

      const stateWithFees = applyStateImpact(s.gameState, {
        type: 'FUNDS_DEDUCTED',
        payload: { amount: talentFees }
      });

      const contracts = { ...stateWithFees.entities.contracts };
      newContracts.forEach(c => { contracts[c.id] = c; });

      return {
        gameState: {
          ...stateWithFees,
          entities: {
            ...stateWithFees.entities,
            projects: { ...stateWithFees.entities.projects, [project.id]: project },
            contracts
          },
          rngState: rng.getState()
        }
      };
    });
  },

  renewProject: (id) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const p = state.entities.projects[id];
      if (!p) return s;

      if (p.type === 'SERIES') {
        const tv = (p as SeriesProject).tvDetails;
        if (tv && tv.status === 'RENEWED') {
          const nextSeason = (tv.currentSeason || 1) + 1;
          return {
            gameState: applyStateImpact(state, [{
              type: 'PROJECT_UPDATED',
              payload: {
                projectId: id,
                update: {
                  state: 'development',
                  accumulatedCost: 0,
                  releaseWeek: null,
                  buzz: 0,
                  revenue: 0,
                  weeklyRevenue: 0,
                  weeksInPhase: 0,
                  developmentWeeks: 0,
                  productionWeeks: 0,
                  tvDetails: {
                    ...tv,
                    currentSeason: nextSeason,
                    episodesAired: 0,
                    status: 'IN_DEVELOPMENT'
                  }
                }
              }
            }])
          };
        }
      }
      return s;
    });
  }
});

import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';
import { applyStateImpact } from '../storeUtils';
import { resolveCrisis } from '@/engine/systems/crises';
import * as festivalsEngine from '@/engine/systems/festivals';
import { releaseDirectorsCut } from '@/engine/systems/ratings/directorsCuts';
import { RandomGenerator } from '@/engine/utils/rng';
import { Project, GameState, AwardBody, MarketingCampaign } from '@/engine/types';

export interface ProjectEventsSlice {
  resolveProjectCrisis: (projectId: string, optionIndex: number) => void;
  submitToFestival: (projectId: string, festivalBody: AwardBody) => void;
  lockMarketingCampaign: (projectId: string, level: 'none' | 'basic' | 'blockbuster') => void;
  releaseDirectorsCutAction: (projectId: string) => void;
  resolveMerger: (accept: boolean, attackerId: string, targetId: string, offerAmount: number) => void;
}

export const createProjectEventsSlice: StateCreator<GameStore, [], [], ProjectEventsSlice> = (set, get) => ({
  resolveProjectCrisis: (projectId, optionIndex) => {
    const state = get().gameState;
    if (!state) return;

    const project = state.entities.projects[projectId];
    if (!project) return;

    const rng = new RandomGenerator(state.rngState); 
    const impact = resolveCrisis(state, project.id, optionIndex, rng);
    const newState = applyStateImpact(state, impact);
    newState.rngState = rng.getState();
    set({ gameState: newState });
  },

  submitToFestival: (projectId, festivalBody) => {
    set((s) => {
      if (!s.gameState) return s;
      const rng = new RandomGenerator(s.gameState.rngState);
      const impact = festivalsEngine.submitToFestival(s.gameState, projectId, festivalBody, rng);
      if (!impact) return s;
      const newState = applyStateImpact(s.gameState, impact);
      newState.rngState = rng.getState();
      return { gameState: newState };
    });
  },

  releaseDirectorsCutAction: (projectId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;
      const project = state.entities.projects[projectId];
      if (!project) return s;
      const rng = new RandomGenerator(state.rngState);
      const contractsArr = Object.values(state.entities.contracts || {});
      const directorContract = contractsArr.find(c => c.projectId === projectId && c.role === 'director');
      const directorId = directorContract?.talentId ?? null;
      const impacts = releaseDirectorsCut(project, directorId, rng);
      const newState = applyStateImpact(state, impacts);
      newState.rngState = rng.getState();
      return { gameState: newState };
    });
  },

  resolveMerger: (accept, attackerId, targetId, offerAmount) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;
      if (accept) {
        const newState = applyStateImpact(state, [
          {
            type: 'FUNDS_CHANGED',
            payload: { amount: offerAmount }
          },
          {
            type: 'INDUSTRY_UPDATE',
            payload: { mergedRivalId: targetId, acquirerId: attackerId }
          }
        ]);
        return { gameState: newState };
      }
      return s;
    });
  },

  lockMarketingCampaign: (projectId, level) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const project = state.entities.projects[projectId];
      if (!project) return s;

      let cost = 0;
      let buzzGain = 0;

      if (level === 'basic') {
        cost = Math.floor(project.budget * 0.10);
        buzzGain = 15;
      } else if (level === 'blockbuster') {
        cost = Math.floor(project.budget * 0.50);
        buzzGain = 40;
      }

      const campaign: MarketingCampaign = {
        primaryAngle: 'SELL_THE_STORY',
        domesticBudget: cost * 0.6,
        foreignBudget: cost * 0.4,
        weeksInMarketing: 1
      };

      return {
        gameState: applyStateImpact(state, [
          {
            type: 'FUNDS_DEDUCTED',
            payload: { amount: cost }
          },
          {
            type: 'PROJECT_UPDATED',
            payload: {
              projectId,
              update: {
                marketingLevel: level,
                marketingBudget: cost,
                marketingCampaign: campaign,
                buzz: Math.min(100, project.buzz + buzzGain),
                state: project.state === 'marketing' ? 'released' : project.state
              }
            }
          }
        ])
      };
    });
  }
});

import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';
import { CreateProjectParams, buildProjectAndContracts, applyStateImpact } from '../storeUtils';
import { generateSpinoffProposal } from '@/engine/systems/ip/spinoffFactory';
import { calculateFranchiseFatigue } from '@/engine/systems/ip/fatigueEngine';
import { RandomGenerator } from '@/engine/utils/rng';
import { Project, GameState, StateImpact } from '@/engine/types';

export interface ProjectIPSlice {
  exploitFranchise: (projectId: string) => void;
  acquireAndRebootIP: (ipAssetId: string) => void;
}

export const createProjectIPSlice: StateCreator<GameStore, [], [], ProjectIPSlice> = (set, get) => ({
  exploitFranchise: (projectId) => {
    const state = get().gameState;
    if (!state) return;

    const project = state.entities.projects[projectId];
    if (!project) return;

    let status: 'HEALTHY' | 'FATIGUED' | 'LEGACY' = 'HEALTHY';
    let relatedCount = 0;

    if (project.franchiseId && state.ip.franchises[project.franchiseId]) {
      const franchise = state.ip.franchises[project.franchiseId];
      relatedCount = franchise.assetIds.length;

      let genreSaturation = 0;
      for (const key in state.entities.projects) {
        if (!Object.prototype.hasOwnProperty.call(state.entities.projects, key)) continue;
        if (state.entities.projects[key].genre === project.genre) {
          genreSaturation++;
        }
      }
      const fatigue = calculateFranchiseFatigue(franchise, genreSaturation, project.genre);

      if (fatigue > 0.4) status = 'FATIGUED';

      const lastRelease = Math.max(...franchise.lastReleaseWeeks, 0);
      if (state.week - lastRelease > 520) status = 'LEGACY';
    }

    const rng = new RandomGenerator(state.rngState);
    const sourceAsset = state.ip.vault.find(a => a.originalProjectId === project.id);
    const spinoffParams = generateSpinoffProposal(rng, project, status, relatedCount, sourceAsset);

    const finalParams = {
      ...spinoffParams,
      franchiseId: project.franchiseId
    } as CreateProjectParams;

    get().createProject(finalParams);
  },

  acquireAndRebootIP: (ipAssetId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const asset = state.ip.vault.find(a => a.id === ipAssetId);
      if (!asset || asset.rightsOwner !== 'MARKET') return s;

      if (state.finance.cash < asset.baseValue) {
        return s;
      }

      const rebootParams: CreateProjectParams = {
        title: `${asset.title}`,
        format: 'film',
        genre: 'DRAMA',
        budgetTier: asset.baseValue > 100000000 ? 'blockbuster' : 'high',
        targetAudience: 'GENERAL',
        flavor: 'reboot',
        franchiseId: asset.franchiseId,
        initialBuzzBonus: Math.floor(asset.decayRate * 50) + 20
      };

      const rng = new RandomGenerator(state.rngState);
      const { project, newContracts } = buildProjectAndContracts(state, rebootParams, rng);

      const impacts: StateImpact[] = [
        {
          type: 'FUNDS_DEDUCTED' as const,
          payload: { amount: asset.baseValue }
        },
        {
          type: 'NEWS_ADDED' as const,
          payload: {
            id: rng.uuid('NWS'),
            headline: `STUDIO ACQUIRES "${asset.title}" RIGHTS`,
            description: `Major industry shift as rights for the classic property return to production slate.`
          }
        }
      ];

      const intermediateState = applyStateImpact(state, impacts);

      const contracts = { ...intermediateState.entities.contracts };
      newContracts.forEach(c => { contracts[c.id] = c; });

      return {
        gameState: {
          ...intermediateState,
          ip: {
            ...intermediateState.ip,
            vault: state.ip.vault.map(a => a.id === ipAssetId ? { ...a, rightsOwner: 'STUDIO' as const } : a)
          },
          entities: {
            ...intermediateState.entities,
            projects: { ...intermediateState.entities.projects, [project.id]: project },
            contracts
          },
          rngState: rng.getState()
        }
      };
    });
  }
});

