import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';
import { applyStateImpact } from '../storeUtils';
import * as projectsEngine from '@/engine/systems/projects';
import { updateCultureFromProject } from '@/engine/systems/culture';
import { negotiateContract } from '@/engine/systems/buyers';
import { RandomGenerator } from '@/engine/utils/rng';
import { Project, GameState, ProjectContractType, StateImpact } from '@/engine/types';

export interface ProjectWorkflowSlice {
  greenlightProject: (projectId: string) => void;
  pitchProject: (projectId: string, buyerId: string, contractType: ProjectContractType) => Promise<boolean>;
  _updateProjectToProduction: (state: GameState, projectId: string, project: Project, headlineText: string, extraProjectUpdates?: Partial<Project>) => void;
}

export const createProjectWorkflowSlice: StateCreator<GameStore, [], [], ProjectWorkflowSlice> = (set, get) => ({
  greenlightProject: async (projectId) => {
    const state = get().gameState;
    if (!state) return;

    const project = state.entities.projects[projectId];
    if (!project) return;

    if (project.state !== 'needs_greenlight') return;

    const { project: updatedProject, update } = projectsEngine.executeGreenlight(project);

    get()._updateProjectToProduction(
      state,
      projectId,
      updatedProject,
      update
    );
  },

  pitchProject: async (projectId, buyerId, contractType) => {
    const state = get().gameState;
    if (!state) return false;

    const project = state.entities.projects[projectId];
    const buyer = state.market.buyers.find(b => b.id === buyerId);

    if (!project || !buyer) return false;

    const rng = new RandomGenerator(state.rngState);
    const allProjects = state.entities.projects;
    const success = negotiateContract(project, buyer, contractType, state.week, allProjects, rng);

    if (success) {
      const { project: updatedProject, update } = projectsEngine.executePitching(project, buyer.name, contractType);

      const distributionStatus = buyer.archetype === 'streamer' ? 'streaming' : 'theatrical';
      let upfrontPayment = 0;
      if (contractType === 'upfront') {
        upfrontPayment = Math.floor(project.budget * 1.1);
      }

      get()._updateProjectToProduction(
        state,
        projectId,
        updatedProject,
        update,
        { 
          buyerId, 
          contractType, 
          distributionStatus,
          revenue: project.revenue + upfrontPayment
        }
      );

      if (upfrontPayment > 0) {
        get().addFunds(upfrontPayment);
      }
    }

    if (success) {
      set({ gameState: { ...get().gameState!, rngState: rng.getState() } });
    }
    return success;
  },

  _updateProjectToProduction: (state, projectId, project, headlineText, extraProjectUpdates = {}) => {
    const newCulture = state.studio.culture ? updateCultureFromProject(state.studio.culture, project) : undefined;
    const rng = new RandomGenerator(state.rngState);

    const impacts: StateImpact[] = [
      {
        type: 'PROJECT_UPDATED',
        payload: {
          projectId: project.id,
          update: {
            ...project,
            state: 'production' as const,
            weeksInPhase: 0,
            ...extraProjectUpdates
          }
        }
      },
      {
        type: 'NEWS_ADDED',
        payload: {
          id: rng.uuid('NWS'),
          headline: headlineText,
          description: `Strategic shift: ${project.title} enters production.`
        }
      }
    ];

    const newState = applyStateImpact(state, impacts);

    set({
      gameState: {
        ...newState,
        studio: {
          ...newState.studio,
          culture: newCulture
        },
        rngState: rng.getState()
      }
    });
  }
});

import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';
import { executeAcquisition, executeSabotage, executePoach } from '@/engine/systems/mergers';
import { RandomGenerator } from '@/engine/utils/rng';
import { applyImpacts } from '@/engine/core/impactReducer';

export interface RivalSlice {
  acquireRival: (targetId: string) => void;
  corporateSabotage: (targetId: string) => void;
  poachExec: (targetId: string) => void;
  attemptTakeover: (targetId: string) => void;
}

export const createRivalSlice: StateCreator<GameStore, [], [], RivalSlice> = (set, get) => ({
  acquireRival: (targetId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;
      const rng = new RandomGenerator(state.rngState);
      const impact = executeAcquisition(state, targetId, rng);
      if (!impact) return s;

      const newState = applyImpacts(state, [impact]);

      const rivals = { ...newState.entities.rivals };
      delete rivals[targetId];

      return { 
        gameState: {
          ...newState,
          entities: {
            ...newState.entities,
            rivals
          },
          rngState: rng.getState()
        } 
      };
    });
  },

  corporateSabotage: (targetId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;
      const rng = new RandomGenerator(state.rngState);
      const impact = executeSabotage(state, targetId, rng);
      if (!impact) return s;
      const newState = applyImpacts(state, [impact]);

      return { 
        gameState: {
          ...newState,
          rngState: rng.getState()
        } 
      };
    });
  },

  poachExec: (targetId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;
      const rng = new RandomGenerator(state.rngState);
      const impact = executePoach(state, targetId, rng);
      if (!impact) return s;
      const newState = applyImpacts(state, [impact]);

      return { 
        gameState: {
          ...newState,
          rngState: rng.getState()
        } 
      };
    });
  },

  attemptTakeover: (targetId) => {
    get().acquireRival(targetId);
  },
});

import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';
import { Contract, TalentPact, TalentRole, Talent } from '@/engine/types';
import { RandomGenerator } from '@/engine/utils/rng';
import { TalentAgentInteractionEngine } from '@/engine/systems/talent/talentAgentInteractions';

export interface TalentContractSlice {
  signContract: (talentId: string, projectId: string) => void;
  offerFirstLook: (talentId: string, duration: number, fee: number) => boolean;
  removeTalentFromProject: (talentId: string, projectId: string) => void;
  signBreakoutTalent: (talentId: string, premiumFee: number) => void;
}

export const createTalentContractSlice: StateCreator<GameStore, [], [], TalentContractSlice> = (set, get) => ({
  signContract: (talentId, projectId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const talent = state.entities.talents[talentId];
      if (!talent) return s;

      const p = state.entities.projects[projectId];
      if (!p) return s;

      let finalFee = talent.fee;
      if (state.deals?.activeDeals?.some(d => d.talentId === talentId)) {
         finalFee = talent.fee * 0.5;
      }

      let relationshipBonus = 0;
      if (talent.agentId) {
        const relationship = state.talentAgentRelationships[`${talentId}-${talent.agentId}`];
        if (relationship) {
          relationshipBonus = TalentAgentInteractionEngine.getLoyaltyBonus(relationship);
          finalFee = finalFee * (1 - (relationshipBonus / 100));
        }
      }

      const currentCash = state.finance.cash;
      if (currentCash < finalFee) return s;

      const rng = new RandomGenerator(state.rngState);

      const contract: Contract = {
        id: rng.uuid('CON'),
        projectId,
        talentId,
        fee: finalFee,
        ownerId: state.studio.id,
        backendPercent: talent.accessLevel === 'dynasty' ? 10 : 5,
        creativeControl: talent.accessLevel === 'dynasty' || talent.prestige > 85 ? true : undefined,
        sequelOption: talent.accessLevel === 'dynasty' || talent.prestige > 75 ? true : undefined,
        backendEscalator: talent.accessLevel === 'dynasty' ? 5 : undefined,
        role: (talent.role || 'actor') as TalentRole
      };

      const estimatedWeeks = 40; 
      const commitment: import('@/engine/types/talent.types').TalentCommitment = {
        projectId: p.id,
        projectTitle: p.title,
        startWeek: state.week,
        endWeek: state.week + (p.productionWeeks || estimatedWeeks),
        role: contract.role,
        format: p.format === 'film' ? 'feature' : (p.format === 'tv' ? 'series' : p.format as any)
      };

      const updatedTalent = {
        ...talent,
        commitments: [...(talent.commitments || []), commitment]
      };

      const updatedRelationships = { ...state.talentAgentRelationships };
      if (talent.agentId) {
        const relationshipId = `${talentId}-${talent.agentId}`;
        const relationship = updatedRelationships[relationshipId];
        if (relationship) {
          updatedRelationships[relationshipId] = TalentAgentInteractionEngine.updateRelationship(
            relationship,
            true,
            finalFee
          );
        }
      }

      return {
        gameState: {
          ...state,
          finance: {
            ...state.finance,
            cash: currentCash - finalFee
          },
          entities: {
            ...state.entities,
            contracts: { ...state.entities.contracts, [contract.id]: contract },
            talents: { ...state.entities.talents, [talentId]: updatedTalent }
          },
          talentAgentRelationships: updatedRelationships,
          rngState: rng.getState()
        }
      };
    });
  },

  offerFirstLook: (talentId, duration, fee) => {
    let success = false;
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const talent = state.entities.talents[talentId];
      if (!talent) return s;

      const lockFee = fee || (talent.fee * 2);
      if (state.finance.cash < lockFee) return s;

      const rng = new RandomGenerator(state.rngState);
      const acceptanceChance = 70; 
      const accepted = (rng.next() * 100) <= acceptanceChance;

      if (accepted) {
          success = true;
          const deal: TalentPact = {
            id: rng.uuid('PCT'),
            talentId,
            studioId: 'PLAYER',
            type: 'first_look',
            startDate: state.week,
            endDate: state.week + duration,
            weeklyOverhead: Math.floor(lockFee * 0.05),
            exclusivity: true,
            status: 'active'
          };
          const currentDeals = state.deals?.activeDeals || [];
          const newNewsHistory = [...state.industry.newsHistory];
          newNewsHistory.unshift({
            id: rng.uuid('NWS'),
            week: state.week,
            type: 'STUDIO_EVENT' as const,
            headline: `${talent.name} signs first-look pact with ${state.studio.name}.`,
            description: `${talent.name} has signed an exclusive first-look deal.`,
          });

          return {
            gameState: {
              ...state,
              finance: { ...state.finance, cash: state.finance.cash - lockFee },
              deals: {
                ...state.deals,
                activeDeals: [...currentDeals, deal]
              },
              industry: {
                ...state.industry,
                newsHistory: newNewsHistory,
              },
              rngState: rng.getState()
            }
          };
       } else {
          const newNewsHistory = [...state.industry.newsHistory];
          newNewsHistory.unshift({
            id: rng.uuid('NWS'),
            week: state.week,
            type: 'STUDIO_EVENT' as const,
            headline: `${talent.name} passes on first-look deal with ${state.studio.name}.`,
            description: `${talent.name} has declined an exclusive first-look pact.`,
          });

          return {
            gameState: {
              ...state,
              industry: {
                ...state.industry,
                newsHistory: newNewsHistory,
              },
              rngState: rng.getState()
            }
          };
       }
    });
    return success;
  },

  signBreakoutTalent: (talentId, premiumFee) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;
      const talent = state.entities.talents[talentId];
      if (!talent) return s;
      if (state.finance.cash < premiumFee) return s;
      const rng = new RandomGenerator(state.rngState);
      const deal: TalentPact = {
        id: rng.uuid('PCT'),
        talentId,
        studioId: 'PLAYER',
        type: 'first_look',
        startDate: state.week,
        endDate: state.week + 52,
        weeklyOverhead: Math.floor(premiumFee * 0.02),
        exclusivity: true,
        status: 'active'
      };
      const updatedTalent = { ...talent, fee: premiumFee };
      const currentDeals = state.deals?.activeDeals || [];
      const newsEntry = {
        id: rng.uuid('NWS'),
        week: state.week,
        type: 'STUDIO_EVENT' as const,
        headline: `${state.studio.name} wins bidding war, signs breakout star ${talent.name}.`,
        description: `${talent.name} signed amid heavy rival interest.`,
      };
      return {
        gameState: {
          ...state,
          finance: { ...state.finance, cash: state.finance.cash - premiumFee },
          entities: { ...state.entities, talents: { ...state.entities.talents, [talentId]: updatedTalent } },
          deals: { ...state.deals, activeDeals: [...currentDeals, deal] },
          industry: { ...state.industry, newsHistory: [newsEntry, ...state.industry.newsHistory] },
          rngState: rng.getState()
        }
      };
    });
  },

  removeTalentFromProject: (talentId, projectId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const talent = state.entities.talents[talentId];
      if (!talent) return s;

      const project = state.entities.projects[projectId];
      if (!project) return s;

      let penalty = 0;
      if (project.state === 'production') {
        penalty = Math.floor(project.budget * 0.20);
      }

      const updatedContracts = { ...state.entities.contracts };
      Object.keys(updatedContracts).forEach(id => {
        const c = updatedContracts[id];
        if (c.talentId === talentId && c.projectId === projectId) {
          delete updatedContracts[id];
        }
      });

      const updatedCommitments = (talent.commitments || []).filter(
        c => c.projectId !== projectId
      );

      const updatedTalent = {
        ...talent,
        commitments: updatedCommitments
      };

      return {
        gameState: {
          ...state,
          finance: {
            ...state.finance,
            cash: state.finance.cash - penalty
          },
          entities: {
            ...state.entities,
            talents: { ...state.entities.talents, [talentId]: updatedTalent },
            contracts: updatedContracts
          }
        }
      };
    });
  }
});

import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';
import { Opportunity, CharacterArchetype } from '@/engine/types';
import { buildProjectAndContracts, CreateProjectParams, applyStateImpact } from '../storeUtils';
import { calculateLiveCounterBid } from '@/engine/systems/ai/biddingEngine';
import { RandomGenerator } from '@/engine/utils/rng';

export interface TalentMarketplaceSlice {
  acquireOpportunity: (oppId: string) => void;
  placeBid: (oppId: string, amount: number) => void;
}

export const createTalentMarketplaceSlice: StateCreator<GameStore, [], [], TalentMarketplaceSlice> = (set, get) => ({
  acquireOpportunity: (oppId) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const oppIndex = state.market.opportunities.findIndex(o => o.id === oppId);
      if (oppIndex === -1) return s;

      const opp = state.market.opportunities[oppIndex];
      const rng = new RandomGenerator(state.rngState);
      const currentHighest = Object.values(opp.bids || {}).reduce((max: number, b) => Math.max(max, b.amount || 0), 0);
      const isWinner = opp.highestBidderId === 'PLAYER';
      const isExpired = state.week >= opp.expirationWeek;

      if (opp.costToAcquire === 0 && (!isWinner || !isExpired)) return s;

      const cost = opp.costToAcquire > 0 ? opp.costToAcquire : currentHighest;

      if (state.finance.cash < (cost + 100000)) return s; 

      const params: CreateProjectParams = {
        title: opp.title,
        format: opp.format,
        genre: opp.genre,
        budgetTier: opp.budgetTier,
        targetAudience: opp.targetAudience,
        flavor: opp.flavor,
        tvFormat: opp.tvFormat,
        unscriptedFormat: opp.unscriptedFormat,
        episodes: opp.episodes,
        releaseModel: opp.releaseModel,
        initialBuzzBonus: opp.qualityBonus,
      };

      const { project, newContracts, talentFees } = buildProjectAndContracts(state, params, rng);

      if (params.format !== 'unscripted') {
        const roles: CharacterArchetype[] = ['protagonist', 'antagonist', 'mentor', 'love_interest'];
        const activeRoles: CharacterArchetype[] = roles.slice(0, project.budgetTier === 'blockbuster' ? 4 : 3);

        if (project.type === 'FILM') {
           const film = project as import('@/engine/types').FilmProject;
           film.scriptHeat = 50;
           film.activeRoles = activeRoles;
           film.scriptEvents = [];
        } else if (project.type === 'SERIES') {
           const series = project as import('@/engine/types').SeriesProject;
           series.scriptHeat = 50;
           series.activeRoles = activeRoles;
           series.scriptEvents = [];
        }
      }
      const updatedOpportunities = [...state.market.opportunities];
      updatedOpportunities.splice(oppIndex, 1);

      const contracts = { ...state.entities.contracts };
      newContracts.forEach(c => { contracts[c.id] = c; });

      return {
        gameState: {
          ...state,
          finance: { ...state.finance, cash: state.finance.cash - cost - talentFees },
          entities: {
            ...state.entities,
            projects: { ...state.entities.projects, [project.id]: project },
            contracts
          },
          market: {
            ...state.market,
            opportunities: updatedOpportunities
          },
          rngState: rng.getState()
        }
      };
    });
  },

  placeBid: (oppId, amount) => {
    set((s) => {
      const state = s.gameState;
      if (!state) return s;

      const oppIndex = state.market.opportunities.findIndex(o => o.id === oppId);
      if (oppIndex === -1) return s;

      const opp = state.market.opportunities[oppIndex];
      if (state.finance.cash < amount) return s;

      const updatedBids = { ...opp.bids, PLAYER: { amount, terms: 'standard' } };
      const bidHistory = [...(opp.bidHistory || []), { rivalId: 'PLAYER', amount, week: state.week }];

      let nextState = {
        ...state,
        market: {
          ...state.market,
          opportunities: state.market.opportunities.map(o => 
            o.id === oppId ? { ...o, bids: updatedBids, highestBidderId: 'PLAYER', bidHistory } : o
          )
        }
      };

      const rng = new RandomGenerator(state.rngState);
      const aggressiveRivals = Object.values(state.entities.rivals).filter(r => r.cash > amount * 1.5 && r.prestige > 40);

      if (aggressiveRivals.length > 0) {
        const rivalIdx = Math.floor(rng.next() * aggressiveRivals.length);
        const rival = aggressiveRivals[rivalIdx];
        const counterImpact = calculateLiveCounterBid(opp, amount, rival, rng, state.week);

        if (counterImpact) {
          nextState = applyStateImpact(nextState, [counterImpact]);
        }
      }

      nextState.rngState = rng.getState();
      return { gameState: nextState };
    });
  }
});

import { StateCreator } from 'zustand';
import { GameStore } from '../gameStore';

export interface TalentStatsSlice {
  getTalentFilmography: (talentId: string) => import('@/engine/types/talent.types').Talent['filmography'];
  getTalentCareerStats: (talentId: string) => { 
    careerGross: number; 
    highestSalaryMovie?: import('@/engine/types/talent.types').Talent['highestSalaryMovie']; 
    highestSalaryTv?: import('@/engine/types/talent.types').Talent['highestSalaryTv']; 
    starMeter: number; 
  } | null;
  calculateStarMeter: (talentId: string) => number;
}

export const createTalentStatsSlice: StateCreator<GameStore, [], [], TalentStatsSlice> = (set, get) => ({
  getTalentFilmography: (talentId) => {
    const s = get();
    if (!s.gameState) return [] as import('@/engine/types/talent.types').Talent['filmography'];
    const talent = s.gameState.entities.talents[talentId];
    return (talent?.filmography || []) as import('@/engine/types/talent.types').Talent['filmography'];
  },

  getTalentCareerStats: (talentId) => {
    const s = get();
    if (!s.gameState) return null;
    const talent = s.gameState.entities.talents[talentId];
    if (!talent) return null;

    return {
      careerGross: talent.careerGross || 0,
      highestSalaryMovie: talent.highestSalaryMovie,
      highestSalaryTv: talent.highestSalaryTv,
      starMeter: talent.starMeter || 50
    };
  },

  calculateStarMeter: (talentId) => {
    const s = get();
    if (!s.gameState) return 50;
    const talent = s.gameState.entities.talents[talentId];
    if (!talent) return 50;

    const filmography = talent.filmography || [];
    const recentProjects = filmography.slice(0, 3);
    const momentum = recentProjects.length > 0
      ? recentProjects.reduce((sum: number, p: any) => sum + (p.gross > 50000000 ? 100 : 50), 0) / recentProjects.length
      : 50;

    return Math.floor((talent.prestige * 0.4) + (talent.draw * 0.4) + (momentum * 0.2));
  }
});

import { GameState, Project, Talent, ProjectFormat, BudgetTierKey, TvFormatKey, UnscriptedFormatKey, ReleaseModelKey, StateImpact, Contract } from '@/engine/types';
import { BUDGET_TIERS } from '@/engine/data/budgetTiers';
import { TV_FORMATS } from '@/engine/data/tvFormats';
import { UNSCRIPTED_FORMATS } from '@/engine/data/unscriptedFormats';
import { getFilmStats, getTvStats, getUnscriptedStats } from '@/engine/systems/stats';
import { RandomGenerator } from '@/engine/utils/rng';
import { applyImpacts } from '@/engine/core/impactReducer';

export interface CreateProjectParams {
    title: string;
    format: ProjectFormat;
    genre: string;
    budgetTier: BudgetTierKey;
    targetAudience: string;
    flavor: string;
    attachedTalentIds?: string[];
    tvFormat?: TvFormatKey;
    unscriptedFormat?: UnscriptedFormatKey;
    episodes?: number;
    releaseModel?: ReleaseModelKey;
    parentProjectId?: string;
    isSpinoff?: boolean;
    initialBuzzBonus?: number;
    franchiseId?: string;
}

function getProjectStats(params: CreateProjectParams, tier: typeof BUDGET_TIERS[keyof typeof BUDGET_TIERS]) {
    if (params.format === 'tv' && params.tvFormat && params.episodes) {
        return getTvStats(tier, TV_FORMATS[params.tvFormat], params.episodes);
    } else if (params.format === 'unscripted' && params.unscriptedFormat && params.episodes) {
        return getUnscriptedStats(tier, UNSCRIPTED_FORMATS[params.unscriptedFormat], params.episodes);
    }
    return getFilmStats(tier);
}

function prepareTalentAndContracts(
    state: GameState,
    attachedTalentIds: string[] | undefined,
    projectId: string,
    rng: RandomGenerator
) {
    const ids = attachedTalentIds || [];
    const talentPool = state.entities.talents;
    const attachedTalent: Talent[] = [];
    let talentFees = 0;
    const newContracts: Contract[] = [];

    for (let i = 0; i < ids.length; i++) {
        const t = talentPool[ids[i]];
        if (t) {
            attachedTalent.push(t);
            talentFees += t.fee || 0;
            newContracts.push({
                id: rng.uuid('CON'),
                talentId: t.id,
                projectId,
                fee: t.fee,
                backendPercent: t.prestige > 80 ? 10 : 0,
                role: t.role as any // Default to their base type
            });
        }
    }

    return { attachedTalent, talentFees, newContracts };
}

export function buildProjectAndContracts(state: GameState, params: CreateProjectParams, rng: RandomGenerator): { project: Project; newContracts: Contract[]; talentFees: number } {
    const tier = BUDGET_TIERS[params.budgetTier];
    const stats = getProjectStats(params, tier);
    const { budget, weeklyCost, developmentWeeks, productionWeeks, renewable } = stats;

    const projectId = rng.uuid('PRJ');
    const { talentFees, newContracts } = prepareTalentAndContracts(state, params.attachedTalentIds, projectId, rng);

    const totalBudget = budget + talentFees;
    const initialBuzz = Math.floor(rng.range(30, 70)) + (params.initialBuzzBonus || 0);

    const projectBase = {
        id: projectId,
        title: params.title,
        genre: params.genre,
        budgetTier: params.budgetTier,
        targetAudience: params.targetAudience,
        flavor: params.flavor,
        budget: totalBudget,
        weeklyCost,
        state: 'development' as const,
        renewable,
        activeCrisis: null,
        momentum: 50,
        progress: 0,
        accumulatedCost: 0,
        releaseWeek: null,
        buzz: Math.min(100, initialBuzz),
        revenue: 0,
        weeklyRevenue: 0,
        weeksInPhase: 0,
        developmentWeeks,
        productionWeeks,
        contentFlags: [],
        franchiseId: params.franchiseId,
        parentProjectId: params.parentProjectId,
        isSpinoff: params.isSpinoff,
        isRecasting: false,
        turnaroundStartWeek: undefined,
        estimatedWindow: { startWeek: state.week + 1, endWeek: state.week + 1 + developmentWeeks + productionWeeks }
    };

    if (params.format === 'film') {
        const project: Project = {
            ...projectBase,
            type: 'FILM',
            format: 'film',
            scriptHeat: 50,
            activeRoles: [],
            scriptEvents: []
        };
        return { project, newContracts, talentFees };
    }

    if (params.format === 'tv') {
        const project: Project = {
            ...projectBase,
            type: 'SERIES',
            format: 'tv',
            scriptHeat: 50,
            activeRoles: [],
            scriptEvents: [],
            tvFormat: params.tvFormat,
            tvDetails: {
                currentSeason: 1,
                episodesOrdered: params.episodes || 0,
                episodesCompleted: 0,
                episodesAired: 0,
                averageRating: 0,
                status: 'IN_DEVELOPMENT'
            },
            releaseModel: params.releaseModel
        };
        return { project, newContracts, talentFees };
    }

    // Unscripted
    const project: Project = {
        ...projectBase,
        type: 'SERIES',
        format: 'unscripted',
        unscriptedFormat: params.unscriptedFormat || 'competition',
        tvDetails: {
            currentSeason: 1,
            episodesOrdered: params.episodes || 0,
            episodesCompleted: 0,
            episodesAired: 0,
            averageRating: 0,
            status: 'IN_DEVELOPMENT'
        }
    };
    return { project, newContracts, talentFees };
}

/**
 * Bridge to the engine's impact reducer.
 * Supports passing multiple impacts for convenience in the store.
 */
export function applyStateImpact(state: GameState, impacts: StateImpact | StateImpact[]): GameState {
  const impactsArray = Array.isArray(impacts) ? impacts : [impacts];
  return applyImpacts(state, impactsArray);
}

