    // Cash on hand should be negative
    expect(screen.getByText('-$500,000')).toBeDefined();
    // Revenue is 0
    expect(screen.getByText('$0')).toBeDefined();
    // Costs are 1M
    expect(screen.getAllByText('-$1,000,000/wk').length).toBeGreaterThan(0);
  });
});

