    // Core Studios
    'state.studio.id': 'PLR',
    'state.entities.rivals.*.id': 'RIV',

    // Talent Layer
    'state.entities.talents.*.id': 'TAL',
    'state.industry.families.*.id': 'FAM',
    'state.industry.agencies.*.id': 'AGY',
    'state.industry.agents.*.id': 'AGT',

    // Project Layer
    'state.entities.projects.*.id': 'PRJ',
