import { GameState, Project } from '../../../engine/types';
import { RandomGenerator } from '../../../engine/utils/rng';
import { createMockGameState } from '../../utils/mockFactories';

describe('TV Awards Filtering & Taxonomy', () => {
  const rng = new RandomGenerator(123);

  const createTvProject = (id: string, format: any, criticScore: number, genre: string = 'Comedy'): Project => ({
    id,
    title: `${id} Show`,
    type: 'SERIES' as const,
    format: 'tv' as const,
    tvFormat: format,
    genre,
    state: 'released' as const,
    releaseWeek: 10,
    budget: 1000000,
    revenue: 0,
    buzz: 50,
    weeksInPhase: 5,
    awardsProfile: {
      criticScore,
      prestigeScore: criticScore,
      craftScore: criticScore,
      culturalHeat: 50,
      campaignStrength: 0,
      academyAppeal: 0,
      guildAppeal: 0,
      populistAppeal: 0,
      indieCredibility: 0,
      industryNarrativeScore: 0
    },
    reception: {
      metaScore: criticScore,
      audienceScore: criticScore,
      status: 'Acclaimed',
      reviews: [],
      isCultPotential: false
    },
    awards: []
  } as any);

  const baseState = (projects: Record<string, any>): GameState => {
    const state = createMockGameState({ week: 37 }); // Primetime Emmy Week
    state.entities.projects = projects;
    return state;
  };

  it('should award Best Drama Series to the highest-scoring TV project', () => {
    const dramaShow = createTvProject('drama_1', 'prestige_drama', 95, 'Drama');
    const sitcomShow = createTvProject('sitcom_1', 'sitcom', 80, 'Comedy');

    const impacts = runAwardsCeremony(
      baseState({ drama_1: dramaShow, sitcom_1: sitcomShow }),
      37, 2026, rng
    );

    // Awards are stored in INDUSTRY_UPDATE impacts as flattened keys
    const awardEntries = impacts
      .flatMap(i => Object.values(i.payload || {}));

    const dramaAward = awardEntries.find((a: any) => a.category === 'Best Drama Series');

    expect(dramaAward).toBeDefined();
    expect(dramaAward?.projectId).toBeTruthy();
  });

  it('should award Best Comedy Series to the highest-scoring TV project', () => {
    const sitcomShow = createTvProject('sitcom_1', 'sitcom', 95);

    const impacts = runAwardsCeremony(
      baseState({ sitcom_1: sitcomShow }),
      37, 2026, rng
    );

    const awardEntries = impacts
      .filter(i => i.type === 'INDUSTRY_UPDATE')
      .flatMap(i => Object.values(i.payload || {}));

    const comedyAward = awardEntries.find((a: any) => a.category === 'Best Comedy Series');

    expect(comedyAward).toBeDefined();
    expect(comedyAward?.projectId).toBe('sitcom_1');
  });
});

import { describe, it, expect } from "vitest";
import { calculateFitScore, negotiateContract } from "../../../engine/systems/buyers";
import { Buyer, StreamerPlatform, Project } from "../../../engine/types";
import { RandomGenerator } from "../../../engine/utils/rng";
import { createMockProject, createMockBuyer } from "../../utils/mockFactories";

const mockProject = createMockProject({
  id: "p1",
  title: "Sci-Fi Epic",
  genre: "Sci-Fi",
  budgetTier: "blockbuster",
  buzz: 50,
});

const mockBuyer = createMockBuyer({
  id: "b1",
  name: "Test Streamer",
  archetype: "streamer",
}) as StreamerPlatform;

describe("buyers system", () => {
  const rng = new RandomGenerator(42);

  describe("calculateFitScore", () => {
    it("calculates base fit score correctly", () => {
      const score = calculateFitScore(mockProject, mockBuyer, 10, [], rng);
      // Base (50) + Gap (15) + Buzz (10) + Streamer IP boost (25) + Rng(-10 to 10)
      expect(score).toBeGreaterThanOrEqual(65);
      expect(score).toBeLessThanOrEqual(100);
    });

    describe("Guild Auditor: Edge Cases", () => {
      it("calculates fit score correctly with empty project history", () => {
        const scoreVal = calculateFitScore(mockProject, mockBuyer, 10, [], new RandomGenerator(42));
        expect(scoreVal).toBeGreaterThanOrEqual(65);
      });
    });

    it("adds bonus for mandate match", () => {
      const buyerWithMandate = {
        ...mockBuyer,
        currentMandate: { type: "sci-fi" as const, activeUntilWeek: 50 }
      };
      const score = calculateFitScore(mockProject, buyerWithMandate, 10, [], rng);
      expect(score).toBeGreaterThanOrEqual(95);
    });
  });

  describe("negotiateContract", () => {
    it("accepts a high fit score", () => {
      expect(negotiateContract(mockProject, mockBuyer, 'standard', 10, [], rng)).toBe(true);
    });

    it("requires a higher score (65) for upfront contracts", () => {
      const buyer = { ...mockBuyer, archetype: 'network' as const, reach: 75 } as Buyer;
      const lowRng = new RandomGenerator(999);
      expect(negotiateContract(mockProject, buyer, 'upfront', 10, [], lowRng)).toBe(false);
    });
  });
});

import { describe, it, expect, vi } from "vitest";
import { resolveCrisis, checkAndTriggerCrisis } from "../../../engine/systems/crises";
import { Project, GameState } from "../../../engine/types";
import { RandomGenerator } from "../../../engine/utils/rng";
import { createMockGameState } from "../../utils/mockFactories";

describe("crises system", () => {
  const rng = new RandomGenerator(99);

  const mockProject = {
    id: "proj-1",
    title: "Test Blockbuster",
    format: "film",
    genre: "Action",
    budgetTier: "high",
    budget: 100000000,
    weeklyCost: 1000000,
    targetAudience: "Teens",
    flavor: "Massive action",
    state: "production",
    buzz: 50,
    weeksInPhase: 5,
    developmentWeeks: 10,
    productionWeeks: 20,
    revenue: 0,
    weeklyRevenue: 0,
    releaseWeek: null,
    accumulatedCost: 0,
    activeCrisis: {
      description: "Test Crisis",
      options: [
        {
          text: "Pay up",
          effectDescription: "Lose money",
          cashPenalty: 1000000
        },
        {
          text: "Delay",
          effectDescription: "Delay production",
          weeksDelay: 2
        },
        {
          text: "Scandal",
          effectDescription: "Lose buzz",
          buzzPenalty: 20,
          reputationPenalty: 5
        }
      ],
      resolved: false,
      severity: "medium"
    }
  } as unknown as Project;

  const mockGameState: GameState = createMockGameState({
      week: 1,
  });
  mockGameState.entities.projects[mockProject.id] = mockProject;

  describe("checkAndTriggerCrisis", () => {
    it("should return null if project is not in production", () => {
      const devProject = { ...mockProject, state: "marketing" as const } as unknown as Project;
      vi.spyOn(rng, 'next').mockReturnValue(0.99);
      const impact = checkAndTriggerCrisis(devProject, mockGameState, rng);
      expect(impact).toBeNull();
    });

    it("should trigger a crisis in production based on deterministic RNG", () => {
      const luckyRng = new RandomGenerator(42);
      vi.spyOn(luckyRng, 'next').mockReturnValue(0.01); // 0.01 < 0.03

      const impact = checkAndTriggerCrisis(mockProject, mockGameState, luckyRng);
      expect(impact!.projectUpdates).toHaveLength(1);
      expect(impact!.projectUpdates![0].update.activeCrisis?.resolved).toBe(false);
    });
  });

  describe("resolveCrisis", () => {
    it("should return correct impact for cash penalty option", () => {
      const impact = resolveCrisis(mockGameState, mockProject.id, 0, rng);
      expect(impact.cashChange).toBe(-1000000);
      expect(impact.projectUpdates![0].update.activeCrisis?.resolved).toBe(true);
    });

    it("should return correct impact for delay option", () => {
      const impact = resolveCrisis(mockGameState, mockProject.id, 1, rng);
      expect(impact.projectUpdates![0].update.productionWeeks).toBe(mockProject.productionWeeks + 2);
    });

    it("should return correct impact for buzz/prestige penalty option", () => {
      const impact = resolveCrisis(mockGameState, mockProject.id, 2, rng);
      expect(impact.projectUpdates![0].update.buzz).toBe(mockProject.buzz - 20);
      expect(impact.prestigeChange).toBe(-5);
    });

    it("should return empty impact if crisis already resolved", () => {
      const resolvedProject = {
        ...mockProject,
        activeCrisis: { ...mockProject.activeCrisis!, resolved: true }
      };
      const stateWithResolved = createMockGameState();
      stateWithResolved.entities.projects[resolvedProject.id] = resolvedProject as any;

      const impact = resolveCrisis(stateWithResolved, resolvedProject.id, 0, rng);
      expect(impact).toEqual({});
    });
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { evaluateFirstLookDeal, offerFirstLookDeal, advanceDeals, evaluatePackageStrength } from '../../../engine/systems/deals';
import { Talent, GameState, TalentPact, Agency } from '../../../engine/types';
import { RandomGenerator } from '../../../engine/utils/rng';
import { createMockGameState } from '../../utils/mockFactories';

describe('Deals System', () => {
  let mockTalent: Talent;
  const rng = new RandomGenerator(888);

  beforeEach(() => {
    mockTalent = {
      id: "t1",
      name: "Super Star",
      roles: ["director", "actor"],
      prestige: 90,
      draw: 85,
      fee: 2_000_000,
      personality: "Normal",
      accessLevel: "soft-access",
    } as any;
  });

  it('evaluates whether talent will accept a first-look deal based on prestige', () => {
    const poorState = createMockGameState({ studio: { prestige: 20 } as any });
    const okState = createMockGameState({ studio: { prestige: 90 } as any });

    const luckyRng = new RandomGenerator(123);
    vi.spyOn(luckyRng, 'next').mockReturnValue(0.5); // mid roll = 50

    // 20 prestige vs 90 -> chance = 50 + (20-90) = -20. Clamped to 5.
    // Random 50 <= 5 is false
    const lowOffer = evaluateFirstLookDeal(mockTalent, poorState, luckyRng);
    expect(lowOffer).toBe(false);

    // 90 vs 90 -> chance = 50 (base) + 20 (soft-access bonus) = 70. 
    // Random 50 <= 70 is true
    const highOffer = evaluateFirstLookDeal(mockTalent, okState, luckyRng);
    expect(highOffer).toBe(true);
  });

  it('offers a deal and returns newsEvents impact if accepted', () => {
    const state = createMockGameState({
        week: 10,
        studio: { name: 'Test Studio', prestige: 90 } as any
    });
    state.entities.talents[mockTalent.id] = mockTalent;

    const luckyRng = new RandomGenerator(456);
    vi.spyOn(luckyRng, 'next').mockReturnValue(0.01); // Trigger success

    const impacts = offerFirstLookDeal(state, mockTalent.id, luckyRng);
    const newsImpact = impacts.find(i => i.newsEvents && i.newsEvents.length > 0);
    expect(newsImpact).toBeDefined();
    expect(newsImpact?.newsEvents![0].headline).toContain("signs");
  });

  it('returns expiry notification in newsEvents impact during advanceDeals', () => {
    const deal = {
      id: 'd1',
      talentId: 't1',
      studioId: 's1',
      type: 'first_look',
      startDate: 1,
      endDate: 10,
      weeklyOverhead: 1000,
      exclusivity: true,
      status: 'active'
    } as any;

    const impacts = advanceDeals([deal], 10, rng);
    const newsImpact = impacts.find(i => i.newsEvents && i.newsEvents.length > 0);
    expect(newsImpact).toBeDefined();
    expect(newsImpact?.newsEvents![0].description).toContain("expired");
  });
});

