import { describe, it, expect } from 'vitest';
import { evaluateActiveMergers } from '@/engine/systems/production/MergerModule';
import { createMockGameState } from '@/test/utils/mockFactories';
import { RandomGenerator } from '@/engine/utils/rng';

describe('MergerModule', () => {
  describe('evaluateActiveMergers', () => {
    it('returns empty array when there are no active mergers', () => {
      const state = createMockGameState();
      state.industry.activeMergers = []; // Empty array
      const rng = new RandomGenerator(42);

      const impacts = evaluateActiveMergers(state, rng);
      expect(impacts).toHaveLength(0);
    });

    it('returns empty array when active mergers is undefined', () => {
      const state = createMockGameState();
      state.industry.activeMergers = undefined as any;
      const rng = new RandomGenerator(42);

      const impacts = evaluateActiveMergers(state, rng);
      expect(impacts).toHaveLength(0);
    });

    it('does not resolve mergers in the future', () => {
      const state = createMockGameState({ week: 10 });
      state.industry.activeMergers = [
        { id: 'merger-1', activeUntilWeek: 15, acquirerId: 'acq1', targetId: 'tar1' }
      ];
      const rng = new RandomGenerator(42);

      const impacts = evaluateActiveMergers(state, rng);
      expect(impacts).toHaveLength(0);
    });

    it('resolves mergers on the exact week they become active (currentWeek >= activeUntilWeek)', () => {
      const state = createMockGameState({ week: 10 });
      state.industry.activeMergers = [
        { id: 'merger-1', activeUntilWeek: 10, acquirerId: 'acq1', targetId: 'tar1' }
      ];
      const rng = new RandomGenerator(42);

      const impacts = evaluateActiveMergers(state, rng);

      expect(impacts).toHaveLength(2);

      const resolvedImpact = impacts.find(i => i.type === 'MERGER_RESOLVED');
      expect(resolvedImpact).toBeDefined();
      expect(resolvedImpact?.payload).toEqual({ mergerId: 'merger-1', status: 'completed' });

      const newsImpact = impacts.find(i => i.type === 'NEWS_ADDED');
      expect(newsImpact).toBeDefined();
      expect((newsImpact?.payload as any).headline).toBe('MERGER FINALIZED: merger-1');
      expect((newsImpact?.payload as any).category).toBe('market');
    });

    it('resolves mergers past their active week', () => {
      const state = createMockGameState({ week: 12 });
      state.industry.activeMergers = [
        { id: 'merger-1', activeUntilWeek: 10, acquirerId: 'acq1', targetId: 'tar1' }
      ];
      const rng = new RandomGenerator(42);

      const impacts = evaluateActiveMergers(state, rng);

      expect(impacts).toHaveLength(2);
      expect(impacts.find(i => i.type === 'MERGER_RESOLVED')).toBeDefined();
    });

    it('resolves multiple mergers in the same tick and ignores future ones', () => {
      const state = createMockGameState({ week: 20 });
      state.industry.activeMergers = [
        { id: 'merger-1', activeUntilWeek: 15, acquirerId: 'acq1', targetId: 'tar1' },
        { id: 'merger-2', activeUntilWeek: 20, acquirerId: 'acq2', targetId: 'tar2' },
        { id: 'merger-3', activeUntilWeek: 25, acquirerId: 'acq3', targetId: 'tar3' },
        { id: 'merger-no-week', acquirerId: 'acq4', targetId: 'tar4' } as any // Undefined activeUntilWeek defaults to 0
      ];
      const rng = new RandomGenerator(42);

      const impacts = evaluateActiveMergers(state, rng);

      // Should resolve merger-1, merger-2, and merger-no-week
      // 3 mergers resolved * 2 impacts per merger = 6 impacts
      expect(impacts).toHaveLength(6);

      const resolvedIds = impacts.filter(i => i.type === 'MERGER_RESOLVED').map(i => (i.payload as any).mergerId);
      expect(resolvedIds).toContain('merger-1');
      expect(resolvedIds).toContain('merger-2');
      expect(resolvedIds).toContain('merger-no-week');
      expect(resolvedIds).not.toContain('merger-3');
    });
  });
});

import { vi } from 'vitest';
import { describe, it, expect } from 'vitest';
import { Project, ScriptedProject } from '@/engine/types';
import { RandomGenerator } from '@/engine/utils/rng';
import { tickScriptDevelopment } from '@/engine/systems/production/ScriptDraftingSystem';
import { createMockProject } from '../../../utils/mockFactories';

describe('ScriptDraftingSystem - Edge Cases', () => {
    it('returns empty impacts if not in development state', () => {
        const rng = new RandomGenerator(555);
        const project = createMockProject({ state: 'production' });
        const impacts = tickScriptDevelopment(project, rng);
        expect(impacts).toEqual([]);
    });

    it('returns empty impacts if not scripted', () => {
        const rng = new RandomGenerator(555);
        const project = createMockProject({ state: 'development' });
        // Manually strip scripted fields to simulate non-scripted project
        const { scriptHeat, activeRoles, scriptEvents, ...nonScriptedProject } = project as any;
        const impacts = tickScriptDevelopment(nonScriptedProject as Project, rng);
        expect(impacts).toEqual([]);
    });

    it('should cap scriptHeat at 100 and 0', () => {
       const rng = new RandomGenerator(555);
       vi.spyOn(rng, 'next').mockReturnValue(0.9); // Avoid evolution events
       vi.spyOn(rng, 'rangeInt').mockReturnValue(10); // Drift up

       const p1 = createMockProject({ state: 'development', scriptHeat: 95 });
       const impacts1 = tickScriptDevelopment(p1, rng);
       const update1 = impacts1.find(i => i.type === 'PROJECT_UPDATED')?.payload.update;
       expect(update1?.scriptHeat).toBe(100);

       vi.spyOn(rng, 'rangeInt').mockReturnValue(-10); // Drift down
       const p2 = createMockProject({ state: 'development', scriptHeat: 5 });
       const impacts2 = tickScriptDevelopment(p2, rng);
       const update2 = impacts2.find(i => i.type === 'PROJECT_UPDATED')?.payload.update;
       expect(update2?.scriptHeat).toBe(0);
    });

    it('should force ROLE_MERGE on low heat', () => {
       const rng = new RandomGenerator(555);
       // 1st call (evolution check): 0.1 < 0.15
       // 2nd call (evolutionRoll): 0.1 < 0.4
       vi.spyOn(rng, 'next').mockReturnValue(0.1); 
       vi.spyOn(rng, 'rangeInt').mockReturnValue(0); // No drift

       const p = createMockProject({ 
         state: 'development', 
         scriptHeat: 20, 
         activeRoles: ['sidekick', 'love_interest', 'loose_cannon', 'femme_fatale'],
         buzz: 10 
       });
       const impacts = tickScriptDevelopment(p, rng);
       const update = impacts.find(i => i.type === 'PROJECT_UPDATED')?.payload.update;
       expect(update?.activeRoles.length).toBe(3); // 4 -> 3
       expect(update?.scriptEvents[0].type).toBe('ROLE_MERGE');
       expect(update?.buzz).toBe(5); // 10 - 5
    });

    it('should force ROLE_SPLIT on high heat', () => {
       const rng = new RandomGenerator(555);
       // 1st call (evolution check): 0.1 < 0.15
       // 2nd call (evolutionRoll): 0.9 > 0.8
       let callCount = 0;
       vi.spyOn(rng, 'next').mockImplementation(() => { 
         callCount++; 
         return callCount === 1 ? 0.1 : 0.9; 
       });
       vi.spyOn(rng, 'pick').mockReturnValue('sidekick' as any);
       vi.spyOn(rng, 'rangeInt').mockReturnValue(0);

       const p = createMockProject({ 
         state: 'development', 
         scriptHeat: 80, 
         activeRoles: ['sidekick', 'love_interest', 'loose_cannon'],
         buzz: 10 
       });
       const impacts = tickScriptDevelopment(p, rng);
       const update = impacts.find(i => i.type === 'PROJECT_UPDATED')?.payload.update;
       expect(update?.activeRoles.length).toBe(4);
       expect(update?.scriptEvents[0].type).toBe('ROLE_SPLIT');
       expect(update?.buzz).toBe(20); // 10 + 10
    });
});

describe('ScriptDraftingSystem - General Evolution', () => {
    it('triggers PLOT_TWIST_ADDED and DIALOGUE_POLISH correctly', () => {
       const rng = new RandomGenerator(555);

       let callCount = 0;
       vi.spyOn(rng, 'next').mockImplementation(() => {
         callCount++;
         return callCount === 1 ? 0.1 : 0.6; // < 0.15 for event, > 0.5 for twist
       });
       vi.spyOn(rng, 'rangeInt').mockReturnValue(0);

       const p1 = createMockProject({ state: 'development', scriptHeat: 50, buzz: 10 });
       const impacts1 = tickScriptDevelopment(p1, rng);
       const update1 = impacts1.find(i => i.type === 'PROJECT_UPDATED')?.payload.update;
       expect(update1?.scriptEvents[0].type).toBe('PLOT_TWIST_ADDED');
       expect(update1?.buzz).toBe(22); // 10 + 12

       callCount = 0;
       vi.spyOn(rng, 'next').mockImplementation(() => {
         callCount++;
         return callCount === 1 ? 0.1 : 0.45; // < 0.15 for event, <= 0.5 for polish
       });
       const p2 = createMockProject({ state: 'development', scriptHeat: 50, buzz: 10 });
       const impacts2 = tickScriptDevelopment(p2, rng);
       const update2 = impacts2.find(i => i.type === 'PROJECT_UPDATED')?.payload.update;
       expect(update2?.scriptEvents[0].type).toBe('DIALOGUE_POLISH');
       expect(update2?.buzz).toBe(15); // 10 + 5
    });
});

import { describe, it, expect, vi } from 'vitest';
import { ScriptMetricsCalculator } from '@/engine/systems/production/ScriptMetricsCalculator';
import { createMockProject } from '@/test/utils/mockFactories';
import { ScriptedProject, ScriptEvent, ScriptMetrics } from '@/engine/types';

describe('ScriptMetricsCalculator', () => {
  describe('calculateMetrics', () => {
    it('calculates metrics correctly for a basic project', () => {
      const project = createMockProject({
        scriptHeat: 50,
        genre: 'Drama',
        activeRoles: ['role1', 'role2', 'role3', 'role4', 'role5'], // 5 roles
        scriptEvents: []
      }) as ScriptedProject;

      const metrics = ScriptMetricsCalculator.calculateMetrics(project, 10);

      expect(metrics.structure).toBe(80); // base 50 + 30 for 4-6 roles
      expect(metrics.dialogue).toBe(50); // base 50 + 0 bonus
      expect(metrics.originality).toBe(40); // base 40 + 0 bonus
      expect(metrics.emotionalImpact).toBe(50); // heat 50
      expect(metrics.commercialViability).toBe(50); // base 50 - 10 prestige + 10 good structure
      expect(metrics.trend).toBe('stable');
      expect(metrics.lastCalculatedWeek).toBe(10);
    });

    it('calculates trend correctly', () => {
      const project = createMockProject({
        scriptHeat: 50,
        genre: 'Comedy',
        activeRoles: ['r1', 'r2', 'r3', 'r4', 'r5'],
      }) as ScriptedProject;

      const prevMetrics: ScriptMetrics = {
        structure: 50, dialogue: 50, originality: 50, pacing: 50, emotionalImpact: 50, commercialViability: 50,
        overallScore: 20, trend: 'stable', lastCalculatedWeek: 5
      };

      const metrics = ScriptMetricsCalculator.calculateMetrics(project, 10, prevMetrics);
      expect(metrics.trend).toBe('improving');

      prevMetrics.overallScore = 100;
      const metricsDeclining = ScriptMetricsCalculator.calculateMetrics(project, 10, prevMetrics);
      expect(metricsDeclining.trend).toBe('declining');

      prevMetrics.overallScore = metrics.overallScore; // approx equal
      const metricsStable = ScriptMetricsCalculator.calculateMetrics(project, 10, prevMetrics);
      expect(metricsStable.trend).toBe('stable');
    });

    it('handles negative events and 0 roles properly (edge case)', () => {
      const project = createMockProject({
        scriptHeat: -10, // extreme
        genre: 'Action',
        activeRoles: [], // 0 roles
        scriptEvents: [
          { type: 'ROLE_MERGE', qualityImpact: -10, heatGain: -5 } as ScriptEvent,
          { type: 'ROLE_MERGE', qualityImpact: -10, heatGain: -5 } as ScriptEvent,
        ]
      }) as ScriptedProject;

      const metrics = ScriptMetricsCalculator.calculateMetrics(project, 10);

      // Structure: 50 base - 10 (0 roles) - 10 (2 merges) = 30
      expect(metrics.structure).toBe(30);
      expect(metrics.emotionalImpact).toBe(-10); // Directly tied to heat
    });

    it('handles many roles and complex script events properly (edge case)', () => {
      const project = createMockProject({
        scriptHeat: 150,
        genre: 'Sci-Fi',
        weeksInPhase: 2,
        activeRoles: Array.from({ length: 15 }, (_, i) => `role${i}`), // 15 roles
        scriptEvents: [
          { type: 'ROLE_SPLIT', qualityImpact: 5, heatGain: 2 } as ScriptEvent,
          { type: 'ROLE_SPLIT', qualityImpact: 5, heatGain: 2 } as ScriptEvent,
          { type: 'DIALOGUE_POLISH', qualityImpact: 60, heatGain: 10 } as ScriptEvent,
          { type: 'DIALOGUE_POLISH', qualityImpact: 40, heatGain: 10 } as ScriptEvent,
          { type: 'PLOT_TWIST_ADDED', qualityImpact: 20, heatGain: 20 } as ScriptEvent,
          { type: 'PLOT_TWIST_ADDED', qualityImpact: 20, heatGain: 20 } as ScriptEvent,
          { type: 'PLOT_TWIST_ADDED', qualityImpact: 20, heatGain: 20 } as ScriptEvent,
          { type: 'PLOT_TWIST_ADDED', qualityImpact: 20, heatGain: 20 } as ScriptEvent,
          { type: 'PLOT_TWIST_ADDED', qualityImpact: 20, heatGain: 20 } as ScriptEvent,
        ]
      }) as ScriptedProject;

      const metrics = ScriptMetricsCalculator.calculateMetrics(project, 10);

      // Structure: 50 base - 10 (15 roles) + 10 (2 splits) = 50
      expect(metrics.structure).toBe(50);
      // Dialogue: 50 base + 100 polish = 150 -> maxed to 100
      expect(metrics.dialogue).toBe(100);
      // Originality: 40 base + 5*12 twist + 10 sci-fi = 110 -> maxed to 100
      expect(metrics.originality).toBe(100);

      // Pacing: base = 150*0.6 = 90. event density = 9 / 2 = 4.5. bonus = 4.5*20 = 90. total 180 -> maxed 100.
      expect(metrics.pacing).toBe(100);
      expect(metrics.commercialViability).toBeLessThanOrEqual(100);
      expect(metrics.commercialViability).toBeGreaterThanOrEqual(0);
    });

    it('calculates commercial viability correctly for various genres', () => {
      const genres = ['Family', 'Animation', 'Action', 'Comedy', 'Drama', 'Thriller', 'Crime', 'Unknown'];
      const baseExpectedViabilities = [];

      for (const genre of genres) {
        const project = createMockProject({
          scriptHeat: 50,
          genre,
          activeRoles: ['role1', 'role2', 'role3', 'role4', 'role5'],
        }) as ScriptedProject;

        const metrics = ScriptMetricsCalculator.calculateMetrics(project, 10);
        baseExpectedViabilities.push(metrics.commercialViability);
      }

      // Family should have higher base (50 + 20 + 10 (structure) = 80 - 10 (originality < 40)) = 70
      // Family index 0, Drama index 4 (50 - 10 + 10 - 10 = 40)
      expect(baseExpectedViabilities[0]).toBeGreaterThan(baseExpectedViabilities[4]);
    });
  });
});

import { describe, it, expect } from 'vitest';
import { StreamingViewershipTracker } from '@/engine/systems/production/StreamingViewershipTracker';
import { createMockProject, createMockBuyer } from '@/test/utils/mockFactories';
import { RandomGenerator } from '@/engine/utils/rng';

describe('StreamingViewershipTracker', () => {
  describe('initializeViewership', () => {
    it('initializes correctly with standard values', () => {
      const project = createMockProject();
      project.reviewScore = 80;
      project.buzz = 80;
      project.genre = 'Drama';

      // platform reach = 20M. So 20,000,000 * 0.8 * 0.8 * 0.05 = 640,000
      const platform = createMockBuyer();
      (platform as any).subscribers = 20_000_000;

      const rng = new RandomGenerator(42);

      const history = StreamingViewershipTracker.initializeViewership(project, 'platform-1', platform, 10, rng);

      expect(history.peakViewers).toBe(640000);
      expect(history.platform).toBe('platform-1');
      expect(history.peakWeek).toBe(10);
      expect(history.entries).toHaveLength(1);

      const entry = history.entries[0];
      expect(entry.uniqueViewers).toBe(640000);
      expect(entry.hoursWatched).toBe(1600000); // 640000 * 2.5
      expect(entry.dropoffRate).toBe(0);

      // Completion rate: 80 * 0.8 = 64. Genre is 'Drama' -> +10 = 74.
      expect(entry.completionRate).toBe(74);
      expect(history.averageCompletionRate).toBe(74);
    });

    it('handles extremely low quality and buzz (0 viewers)', () => {
      const project = createMockProject();
      // Use something just above 0 because `quality = project.reviewScore || 50` will reset 0 to 50
      project.reviewScore = 1;
      project.buzz = 1;

      const platform = createMockBuyer();
      (platform as any).subscribers = 10_000_000;
      const rng = new RandomGenerator(42);

      const history = StreamingViewershipTracker.initializeViewership(project, 'platform-1', platform, 10, rng);

      // 10M * 0.01 * 0.01 * 0.05 = 50
      expect(history.peakViewers).toBe(50);
      const entry = history.entries[0];
      expect(entry.uniqueViewers).toBe(50);
      expect(entry.hoursWatched).toBe(125);
    });

    it('applies genre modifiers to completion rate correctly', () => {
      const platform = createMockBuyer();
      const rng = new RandomGenerator(42);

      const dramaProject = createMockProject({ genre: 'Crime' }); // Drama genre +10
      dramaProject.reviewScore = 50;

      const comedyProject = createMockProject({ genre: 'Comedy' }); // Lighter genre -5
      comedyProject.reviewScore = 50;

      const neutralProject = createMockProject({ genre: 'Sci-Fi' }); // Neutral
      neutralProject.reviewScore = 50;

      const dramaHistory = StreamingViewershipTracker.initializeViewership(dramaProject, 'p1', platform, 1, rng);
      const comedyHistory = StreamingViewershipTracker.initializeViewership(comedyProject, 'p1', platform, 1, rng);
      const neutralHistory = StreamingViewershipTracker.initializeViewership(neutralProject, 'p1', platform, 1, rng);

      const dramaComp = dramaHistory.entries[0].completionRate;
      const comedyComp = comedyHistory.entries[0].completionRate;
      const neutralComp = neutralHistory.entries[0].completionRate;

      expect(dramaComp).toBeGreaterThan(neutralComp);
      expect(neutralComp).toBeGreaterThan(comedyComp);
    });
  });

  describe('updateViewership', () => {
    it('updates viewership correctly for binge release model', () => {
      const project = createMockProject();
      project.reviewScore = 50;
      project.buzz = 50;
      (project as any).releaseModel = 'binge';

      const platform = createMockBuyer();
      (platform as any).subscribers = 10_000_000;
      const rng = new RandomGenerator(42);

      // initial
      let history = StreamingViewershipTracker.initializeViewership(project, 'platform-1', platform, 10, rng);
      const initialViewers = history.entries[0].uniqueViewers; // 10M * 0.5 * 0.5 * 0.05 = 125,000

      // Week 2 (1 week since release, decay factor 0.5)
      history = StreamingViewershipTracker.updateViewership(history, 11, project, rng);
      expect(history.entries).toHaveLength(2);
      const week2Viewers = history.entries[1].uniqueViewers;
      expect(week2Viewers).toBe(Math.round(initialViewers * 0.5));
      expect(history.entries[1].dropoffRate).toBe(50); // 50% drop

      // Week 3 (2 weeks since release, decay factor 0.7)
      history = StreamingViewershipTracker.updateViewership(history, 12, project, rng);
      expect(history.entries).toHaveLength(3);
      expect(history.entries[2].uniqueViewers).toBe(Math.round(week2Viewers * 0.7));

      // Long tail test (decay factor 0.95 for > 4 weeks)
      let prevViewers = history.entries[2].uniqueViewers;
      for (let w = 13; w <= 16; w++) {
        history = StreamingViewershipTracker.updateViewership(history, w, project, rng);
        prevViewers = history.entries[history.entries.length - 1].uniqueViewers;
      }

      // Week 17 (> 4 weeks)
      history = StreamingViewershipTracker.updateViewership(history, 17, project, rng);
      const finalViewers = history.entries[history.entries.length - 1].uniqueViewers;

      // It should decay by 0.95, but never below 30% of previous week
      const expectedDecay = Math.max(Math.round(prevViewers * 0.95), Math.round(prevViewers * 0.3));
      expect(finalViewers).toBe(expectedDecay);
    });

    it('updates viewership correctly for weekly release model', () => {
      const project = createMockProject();
      project.reviewScore = 50;
      project.buzz = 50;
      // Not setting releaseModel makes it default/weekly
      const platform = createMockBuyer();
      (platform as any).subscribers = 10_000_000;
      const rng = new RandomGenerator(42);

      let history = StreamingViewershipTracker.initializeViewership(project, 'platform-1', platform, 10, rng);
      const initialViewers = history.entries[0].uniqueViewers;

      // Week 2 (decay factor 0.8)
      history = StreamingViewershipTracker.updateViewership(history, 11, project, rng);
      expect(history.entries[1].uniqueViewers).toBe(Math.round(initialViewers * 0.8));
      expect(history.entries[1].dropoffRate).toBe(20); // 20% drop
    });

    it('handles extremely low unique viewers correctly without NaN dropoff', () => {
      const project = createMockProject();
      project.reviewScore = 1;
      project.buzz = 1;
      const platform = createMockBuyer();
      (platform as any).subscribers = 100_000; // Small reach
      const rng = new RandomGenerator(42);

      let history = StreamingViewershipTracker.initializeViewership(project, 'platform-1', platform, 10, rng);
      // 100k * 0.01 * 0.01 * 0.05 = 0.5 -> 1
      const v = history.entries[0].uniqueViewers;

      // Force it to 0 for this specific test
      history.entries[0].uniqueViewers = 0;

      history = StreamingViewershipTracker.updateViewership(history, 11, project, rng);
      expect(history.entries[1].uniqueViewers).toBe(0);
      expect(history.entries[1].dropoffRate).toBe(0); // Should handle divide by zero safely
    });

    it('increases completion rate over time due to word of mouth', () => {
      const project = createMockProject();
      project.reviewScore = 80;
      project.buzz = 80;
      const platform = createMockBuyer();
      (platform as any).subscribers = 10_000_000;
      const rng = new RandomGenerator(42);

      let history = StreamingViewershipTracker.initializeViewership(project, 'platform-1', platform, 10, rng);
      const initialCompRate = history.entries[0].completionRate;

      // Week 1, 2 no change in comp rate
      history = StreamingViewershipTracker.updateViewership(history, 11, project, rng);
      history = StreamingViewershipTracker.updateViewership(history, 12, project, rng);
      expect(history.entries[2].completionRate).toBe(initialCompRate);

      // Week 3 (weeksSinceRelease = 3), should increase
      history = StreamingViewershipTracker.updateViewership(history, 13, project, rng);
      expect(history.entries[3].completionRate).toBeGreaterThan(initialCompRate);
    });

    it('updates aggregates correctly after multiple updates', () => {
      const project = createMockProject();
      project.reviewScore = 80;
      project.buzz = 80;
      const platform = createMockBuyer();
      (platform as any).subscribers = 10_000_000;
      const rng = new RandomGenerator(42);

      let history = StreamingViewershipTracker.initializeViewership(project, 'platform-1', platform, 10, rng);

      history = StreamingViewershipTracker.updateViewership(history, 11, project, rng);
      history = StreamingViewershipTracker.updateViewership(history, 12, project, rng);

      expect(history.entries).toHaveLength(3);
      expect(history.totalHoursWatched).toBe(
        history.entries[0].hoursWatched + history.entries[1].hoursWatched + history.entries[2].hoursWatched
      );

      expect(history.peakViewers).toBe(history.entries[0].uniqueViewers);
      expect(history.peakWeek).toBe(10);

      const avgComp = (history.entries[0].completionRate + history.entries[1].completionRate + history.entries[2].completionRate) / 3;
      expect(history.averageCompletionRate).toBe(Math.round(avgComp));
    });
  });
});

