    const mockDisputeImpact = {
      type: 'DISPUTE_HAPPENED' as any,
      projectUpdates: [{}], // simulate content
      uiNotifications: []
    };
    vi.mocked(directorsMod.processDirectorDisputes).mockReturnValueOnce(mockDisputeImpact);

    const rng = new RandomGenerator(42);
