describe('Crisis Evaluator (Target A3)', () => {
  it('should resolve a crisis using handlers and return StateImpact objects', () => {
    const project = createMockProject({
      id: 'p1',
      title: 'Star Wars Clone',
      state: 'production',
      productionWeeks: 20,
      buzz: 50,
      activeCrisis: {
        crisisId: 'c1',
