      expect(evaluateFilmRating(["violence", "political", "profanity"])).toBe("R");
    });
  });

  // ---------------------------------------------------------------------------
  // evaluateRating (backward-compat wrapper)
  // ---------------------------------------------------------------------------
  describe("evaluateRating (backward compat)", () => {
