  // ---------------------------------------------------------------------------
  // requestStudioEdit
  // ---------------------------------------------------------------------------
  describe("requestStudioEdit", () => {
    it("returns impacts when director has final cut", () => {
      const project = { ...mockProject, contentFlags: ["gore" as ContentFlag] };
      const state = {
        ...mockState,
